INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('ce61243fd52c4ce78a2a5b71', '4498845ac2264814b30a974e1d33bed2', 'Picking the Right Clients', 'how-to-find-clients', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"As someone making a living as a freelancer you get asked a lot of questions by curious friends and other freelancers looking for advice, but if there''s one question you hear more than most it''s, \\"How do I get clients?\\" I''ve never had a great answer as most of my clients have actually found me through referrals, but instead I like to push people to instead ask, \\"How do I pick the right clients?\\".\\n\\nThink of clients like any other relationship in \\n\\nNo really, don''t. There were those dark days back in college where I surfed the Craigslist [computer gigs](https://sfbay.craigslist.org/cpg/) and [web/info design](https://sfbay.craigslist.org/web/) listings, but anybody who has done this can tell you it''s not worth your time. The time spent versus clients acquired is low, and the time spent versus quality clients acquired is practically nil. I''ve had exactly two clients originate from Craigslist, and in both cases the most important thing I learned I could do was to look for better clients."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>As someone making a living as a freelancer you get asked a lot of questions by curious friends and other freelancers looking for advice, but if there''s one question you hear more than most it''s, &quot;How do I get clients?&quot; I''ve never had a great answer as most of my clients have actually found me through referrals, but instead I like to push people to instead ask, &quot;How do I pick the right clients?&quot;.</p>\n<p>Think of clients like any other relationship in</p>\n<p>No really, don''t. There were those dark days back in college where I surfed the Craigslist <a href="https://sfbay.craigslist.org/cpg/">computer gigs</a> and <a href="https://sfbay.craigslist.org/web/">web/info design</a> listings, but anybody who has done this can tell you it''s not worth your time. The time spent versus clients acquired is low, and the time spent versus quality clients acquired is practically nil. I''ve had exactly two clients originate from Craigslist, and in both cases the most important thing I learned I could do was to look for better clients.</p>\n<!--kg-card-end: markdown-->', 'As someone making a living as a freelancer you get asked a lot of questions by curious friends and other freelancers looking for advice, but if there''s one question you hear more than most it''s, "How do I get clients?" I''ve never had a great answer as most of my clients have actually found me through referrals, but instead I like to push people to instead ask, "How do I pick the right clients?".\n\n\nThink of clients like any other relationship in\n\n\nNo really, don''t. There were those dark day', NULL, 0, 'post', 'draft', 'public', 'all', '2013-10-14 23:40:24', '1', '2013-10-15 03:43:10', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('095bb7d4ca194667be18c554', '4a985bfbffe7472b9094b0ca69ba46db', 'What I''ve Learned', 'youre-more-valuable-than-you-think', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"<p class=\\"test\\">After a few years of part time web design/development and now a year of full time, I''ve learned a few lessons.</p>\\n\\n1. **Stop Calling Yourself a Freelancer** - After experimenting with positioning myself as a freelancer versus \\"Atomi Design\\", a Bay Area based one-man design/development studio, I''ve found taking the latter approach makes a big difference. It feels awkward calling just yourself a company, but your clients will take you more seriously with paychecks to match. Even if you use your personal name for the business (Robert Nealan Design, etc) you should still position it as a professional company - nothing makes you sound like a starving artist like calling yourself a freelancer.\\n\\n2. **Hold Your Client''s Hand** - Save for special circumstances, you know far more about your business than your client does. They have a lot on the line and are probably just as nervous or more nervous about the project as you are. Reassure them that you know what you''re doing and are there to provide a professional service with the primary goal being to make their mission a success because their success is your success.\\n\\n3. **Know More Than You Should** - Think outside of the fucking box and learn how your peers do their job. It may not be your responsibility, but knowing about it allows you to be more knowledgeable of the project as a whole and consequently do your job better. It forever amazes me how many \\"web designers\\" I meet that don''t have enough basic HTML/CSS knowledge to know that designing custom form dropdowns is just asking for a mafia hit.\\n\\n4. **Stop Bullshitting** - Seriously. Cut it out. I''m tired of being hired to fix projects someone else messed up because they bullshitted the client. If you''re in this job you need to be honest to yourself and your client about your capabilities _and_ your interests. Just because they''re willing to hand you a check doesn''t mean you should take it.\\n\\n5. **Be Honest** - This goes with #4. My friend Nathan will tell you I hate people, but when it comes to business I don''t beat around the bush. Is someone''s work not up to par? Tell them they need to step things up. Is the client not holding up their end of the work? Sit them down and (politely) talk about it. Yes, I''ve burned a few bridges over the years, but more often than not it saves a lot of pain and headache that''ll come from avoiding the reality of the situation until it''s too late.\\n\\n6. **Angry? It Can Wait Until Tomorrow** - Some clients just don''t \\"get it\\". Despite your best attempts to be selective about your clients, sooner or later a bad seed will sneak through and you''ll find yourself ready to scream. Don''t. Tell them you have to go, hang up, or pretend the stove just caught on fire, but whatever you do just don''t do anything to escalate the situation. Take the night off, grab a drink, and take a bubble bath (both at the same time?). Get a good night''s sleep, regroup in the morning, and send a calm email (always in writing) addressing the situation. Even if you''re sure you''re in the right, the lawsuit you''ll have to file to get paid isn''t worth the headache.\\n\\n7. **Pick the Right Clients** - I should probably cover this more in depth later, but if you''re good at what you do you probably have this luxury of picking who you work for, even if you don''t realize it. Design or development might be fun to you, but often you''re the line between success and failure of your clients company and if you''re good at what you do, they probably need you more than you need them. If there''s one thing I''ve learned in the past few years it''s that finding reliable, quality talent in this industry is hard..._real hard_.\\n\\n8. **Charge More** - You''ll find this advice all over and it''s for a good reason. In the past year since I moved to San Francisco I''ve raised my rates 233%, and the quality of client''s I''m doing work for has increased accordingly. It feels awkward at first, especially if you''re freshly escaped from the slave labor wages of your college years, but unless you''re established in a niche charging triple digits per hour, you have room to grow. Actual rates will vary depending on your skillset and location, but always be looking for where your skills will pay the best and where you can most easily improve the value you offer. Need convincing? Read this.\\n\\n9.\\n\\n\\n###So How Much Am I Worth?\\nProbably more than you think, but really it depends. I''ve met a few people out there with rates so high you want to shake their hand in congratulations, but more often than not I meet freelancers billing so low that it''s insulting.\\n\\nWhy? Because you''re building someone else''s company. You''re not someone being hired as a full time employee with \\"job security\\" and a dental plan, you''re an outside consultant being brought in for your expertise to fix your client''s problem. Frequently you might be the very backbone of the company you''re being contracted by - without you there couldn''t be any company.\\n\\n\\n\\nthe same Call it a bubble if you want as the supply will undoubtedly start catching up to the demand, but for now chances are if you''re freelancer right now - you''re probably worth more than you think.\\n\\nI''ve personally witnessed multiple situations (and heard many more) where the person or team behind a project hid so deeply behind the client''s lack of knowledge that it made Ponzi Scheme''s seem honest. If you''re someone that the client can trust not to just get the job done, but get the job done right and flat out say \\"this isn''t good enough\\" when it isn''t, then that''s one more notch that''ll pay off in the long run.\\n\\n---\\n<small>[1]: Not a real statistic but probably realistic.</small>"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p class="test">After a few years of part time web design/development and now a year of full time, I''ve learned a few lessons.</p>\n<ol>\n<li>\n<p><strong>Stop Calling Yourself a Freelancer</strong> - After experimenting with positioning myself as a freelancer versus &quot;Atomi Design&quot;, a Bay Area based one-man design/development studio, I''ve found taking the latter approach makes a big difference. It feels awkward calling just yourself a company, but your clients will take you more seriously with paychecks to match. Even if you use your personal name for the business (Robert Nealan Design, etc) you should still position it as a professional company - nothing makes you sound like a starving artist like calling yourself a freelancer.</p>\n</li>\n<li>\n<p><strong>Hold Your Client''s Hand</strong> - Save for special circumstances, you know far more about your business than your client does. They have a lot on the line and are probably just as nervous or more nervous about the project as you are. Reassure them that you know what you''re doing and are there to provide a professional service with the primary goal being to make their mission a success because their success is your success.</p>\n</li>\n<li>\n<p><strong>Know More Than You Should</strong> - Think outside of the fucking box and learn how your peers do their job. It may not be your responsibility, but knowing about it allows you to be more knowledgeable of the project as a whole and consequently do your job better. It forever amazes me how many &quot;web designers&quot; I meet that don''t have enough basic HTML/CSS knowledge to know that designing custom form dropdowns is just asking for a mafia hit.</p>\n</li>\n<li>\n<p><strong>Stop Bullshitting</strong> - Seriously. Cut it out. I''m tired of being hired to fix projects someone else messed up because they bullshitted the client. If you''re in this job you need to be honest to yourself and your client about your capabilities <em>and</em> your interests. Just because they''re willing to hand you a check doesn''t mean you should take it.</p>\n</li>\n<li>\n<p><strong>Be Honest</strong> - This goes with #4. My friend Nathan will tell you I hate people, but when it comes to business I don''t beat around the bush. Is someone''s work not up to par? Tell them they need to step things up. Is the client not holding up their end of the work? Sit them down and (politely) talk about it. Yes, I''ve burned a few bridges over the years, but more often than not it saves a lot of pain and headache that''ll come from avoiding the reality of the situation until it''s too late.</p>\n</li>\n<li>\n<p><strong>Angry? It Can Wait Until Tomorrow</strong> - Some clients just don''t &quot;get it&quot;. Despite your best attempts to be selective about your clients, sooner or later a bad seed will sneak through and you''ll find yourself ready to scream. Don''t. Tell them you have to go, hang up, or pretend the stove just caught on fire, but whatever you do just don''t do anything to escalate the situation. Take the night off, grab a drink, and take a bubble bath (both at the same time?). Get a good night''s sleep, regroup in the morning, and send a calm email (always in writing) addressing the situation. Even if you''re sure you''re in the right, the lawsuit you''ll have to file to get paid isn''t worth the headache.</p>\n</li>\n<li>\n<p><strong>Pick the Right Clients</strong> - I should probably cover this more in depth later, but if you''re good at what you do you probably have this luxury of picking who you work for, even if you don''t realize it. Design or development might be fun to you, but often you''re the line between success and failure of your clients company and if you''re good at what you do, they probably need you more than you need them. If there''s one thing I''ve learned in the past few years it''s that finding reliable, quality talent in this industry is hard...<em>real hard</em>.</p>\n</li>\n<li>\n<p><strong>Charge More</strong> - You''ll find this advice all over and it''s for a good reason. In the past year since I moved to San Francisco I''ve raised my rates 233%, and the quality of client''s I''m doing work for has increased accordingly. It feels awkward at first, especially if you''re freshly escaped from the slave labor wages of your college years, but unless you''re established in a niche charging triple digits per hour, you have room to grow. Actual rates will vary depending on your skillset and location, but always be looking for where your skills will pay the best and where you can most easily improve the value you offer. Need convincing? Read this.</p>\n</li>\n<li></li>\n</ol>\n<h3 id="sohowmuchamiworth">So How Much Am I Worth?</h3>\n<p>Probably more than you think, but really it depends. I''ve met a few people out there with rates so high you want to shake their hand in congratulations, but more often than not I meet freelancers billing so low that it''s insulting.</p>\n<p>Why? Because you''re building someone else''s company. You''re not someone being hired as a full time employee with &quot;job security&quot; and a dental plan, you''re an outside consultant being brought in for your expertise to fix your client''s problem. Frequently you might be the very backbone of the company you''re being contracted by - without you there couldn''t be any company.</p>\n<p>the same Call it a bubble if you want as the supply will undoubtedly start catching up to the demand, but for now chances are if you''re freelancer right now - you''re probably worth more than you think.</p>\n<p>I''ve personally witnessed multiple situations (and heard many more) where the person or team behind a project hid so deeply behind the client''s lack of knowledge that it made Ponzi Scheme''s seem honest. If you''re someone that the client can trust not to just get the job done, but get the job done right and flat out say &quot;this isn''t good enough&quot; when it isn''t, then that''s one more notch that''ll pay off in the long run.</p>\n<hr>\n<p><small>[1]: Not a real statistic but probably realistic.</small></p>\n<!--kg-card-end: markdown-->', 'After a few years of part time web design/development and now a year of full time, I''ve learned a few lessons.\n\n\n 1. \n    \n    \n    Stop Calling Yourself a Freelancer - After experimenting with positioning myself as a freelancer versus "Atomi Design", a Bay Area based one-man design/development studio, I''ve found taking the latter approach makes a big difference. It feels awkward calling just yourself a company, but your clients will take you more seriously with paychecks to match. Even if', NULL, 0, 'post', 'draft', 'public', 'all', '2013-10-15 03:39:10', '1', '2014-01-08 00:43:07', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('2cb746fdeed84c928b7b47c6', 'c67f5cb2992a42ab9d02f9248ba6d12f', 'Overconnected', 'overconnected', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"Several years ago I had a heated debate with a good friend of mine regarding our generation''s obsession with electronics. It was right at that tipping point when most people started switching from \\"dumb phones\\" to \\"smart phones\\", when the presence of an iPhone garnered curious and jealous looks."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>Several years ago I had a heated debate with a good friend of mine regarding our generation''s obsession with electronics. It was right at that tipping point when most people started switching from &quot;dumb phones&quot; to &quot;smart phones&quot;, when the presence of an iPhone garnered curious and jealous looks.</p>\n<!--kg-card-end: markdown-->', 'Several years ago I had a heated debate with a good friend of mine regarding our generation''s obsession with electronics. It was right at that tipping point when most people started switching from "dumb phones" to "smart phones", when the presence of an iPhone garnered curious and jealous looks.\n', NULL, 0, 'post', 'draft', 'public', 'all', '2013-10-15 23:54:46', '1', '2013-10-15 23:54:46', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('ccce094bc32c49f387fe48dc', '4cd90d5a85724f2892a4ad8b0b9260ef', 'BART Strike', 'bart-strike', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"A strike? As someone born in the late 80''s I didn''t know strikes could even happen these days. That isn''t to say I thought they were illegal, I just can''t recall ever hearing about a strike that actually had an effect large enough to take notice.\\n\\nAnd yet here we are in 2013. BART has ground to a halt and Facebook is overflowing with angry posts because BART workers make an average gross pay of $76,500/year and that''s a lot relative to most middle class jobs, but really what does that buy you?\\n\\n####How Much is How Much?\\n\\nIf you''re making a $76,500/year salary, we can estimate your take home pay is about $50,260/year at a 25% federal, 9.3% state tax rate<sup>[1][2]</sup>. \\n\\nThat puts your monthly paycheck at $4188/month. That would be pretty good if we had any kind of real social welfare in the US, but since we don''t let''s make sure you can maintain your standard of living in 40 years by taking out another 6% for your 401k retirement fund and another $380/month for your healthcare premiums<sup>[3]</sup>. That leaves you with $3556/month.\\n\\nFollowing accepted rental logic that you should never spend more than 33% of your take home pay on housing this leaves you with only $1185/month. To people living outside the Bay Area that would be a lot, but for those living anywhere but high crime areas (West Oakland, Richmond, etc) or the outer fringes (like my hometown of Benicia), it really isn''t.\\n\\n>\\"You can''t be a working class person in this area anymore,\\" said Adriana Garcia of San Jose, where a two-bedroom, two-bath apartment rents for an average $2,330 a month.<sup>[4]</sup>\\n\\nThe average rent for a one-bedroom apartment across the Bay Area was recently reported at $1800/month while more desirable locations cost even more. In San Francisco the average cost of a one bedroom has topped $2800/month<sup>[5]</sup>, while several months of experience on Craigslist hints at larger houses with new leases having an average price of almost $1500/bedroom/month.\\n\\n####Fixing the Problem\\n\\nYes, $76,500 is a lot of money to drive a train by modern standards, but this just goes to show how much the standard of living has slipped in the US over the past few decades (currently one of the lowest of any first world country). The problem isn''t that BART employees are making too much, it''s that middle class wages have grown stagnant while inflation (especially for healthcare and housing costs), corporate profits and executive pay continues to grow at an alarming rate.\\n\\n---\\n1.\\n[https://origin.bankrate.com/finance/taxes/tax-brackets.aspx](https://origin.bankrate.com/finance/taxes/tax-brackets.aspx)\\n2.\\n[http://www.tax-brackets.org/californiataxtable](http://www.tax-brackets.org/californiataxtable)\\n3.\\n[http://www.mercurynews.com/business/ci_24316730/bay-area-apartment-rent-increases-slowing-report-says](http://www.mercurynews.com/business/ci_24316730/bay-area-apartment-rent-increases-slowing-report-says)\\n4. [http://www.mercurynews.com/business/ci_24316730/bay-area-apartment-rent-increases-slowing-report-say](http://www.mercurynews.com/business/ci_24316730/bay-area-apartment-rent-increases-slowing-report-say)\\n5.\\n[http://sfist.com/2013/07/19/another_sf_rent_map.php](http://sfist.com/2013/07/19/another_sf_rent_map.php)\\n"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>A strike? As someone born in the late 80''s I didn''t know strikes could even happen these days. That isn''t to say I thought they were illegal, I just can''t recall ever hearing about a strike that actually had an effect large enough to take notice.</p>\n<p>And yet here we are in 2013. BART has ground to a halt and Facebook is overflowing with angry posts because BART workers make an average gross pay of $76,500/year and that''s a lot relative to most middle class jobs, but really what does that buy you?</p>\n<h4 id="howmuchishowmuch">How Much is How Much?</h4>\n<p>If you''re making a $76,500/year salary, we can estimate your take home pay is about $50,260/year at a 25% federal, 9.3% state tax rate<sup>[1][2]</sup>.</p>\n<p>That puts your monthly paycheck at $4188/month. That would be pretty good if we had any kind of real social welfare in the US, but since we don''t let''s make sure you can maintain your standard of living in 40 years by taking out another 6% for your 401k retirement fund and another $380/month for your healthcare premiums<sup>[3]</sup>. That leaves you with $3556/month.</p>\n<p>Following accepted rental logic that you should never spend more than 33% of your take home pay on housing this leaves you with only $1185/month. To people living outside the Bay Area that would be a lot, but for those living anywhere but high crime areas (West Oakland, Richmond, etc) or the outer fringes (like my hometown of Benicia), it really isn''t.</p>\n<blockquote>\n<p>&quot;You can''t be a working class person in this area anymore,&quot; said Adriana Garcia of San Jose, where a two-bedroom, two-bath apartment rents for an average $2,330 a month.<sup>[4]</sup></p>\n</blockquote>\n<p>The average rent for a one-bedroom apartment across the Bay Area was recently reported at $1800/month while more desirable locations cost even more. In San Francisco the average cost of a one bedroom has topped $2800/month<sup>[5]</sup>, while several months of experience on Craigslist hints at larger houses with new leases having an average price of almost $1500/bedroom/month.</p>\n<h4 id="fixingtheproblem">Fixing the Problem</h4>\n<p>Yes, $76,500 is a lot of money to drive a train by modern standards, but this just goes to show how much the standard of living has slipped in the US over the past few decades (currently one of the lowest of any first world country). The problem isn''t that BART employees are making too much, it''s that middle class wages have grown stagnant while inflation (especially for healthcare and housing costs), corporate profits and executive pay continues to grow at an alarming rate.</p>\n<hr>\n<ol>\n<li></li>\n</ol>\n<p><a href="https://origin.bankrate.com/finance/taxes/tax-brackets.aspx">https://origin.bankrate.com/finance/taxes/tax-brackets.aspx</a><br>\n2.<br>\n<a href="http://www.tax-brackets.org/californiataxtable">http://www.tax-brackets.org/californiataxtable</a><br>\n3.<br>\n<a href="http://www.mercurynews.com/business/ci_24316730/bay-area-apartment-rent-increases-slowing-report-says">http://www.mercurynews.com/business/ci_24316730/bay-area-apartment-rent-increases-slowing-report-says</a><br>\n4. <a href="http://www.mercurynews.com/business/ci_24316730/bay-area-apartment-rent-increases-slowing-report-say">http://www.mercurynews.com/business/ci_24316730/bay-area-apartment-rent-increases-slowing-report-say</a><br>\n5.<br>\n<a href="http://sfist.com/2013/07/19/another_sf_rent_map.php">http://sfist.com/2013/07/19/another_sf_rent_map.php</a></p>\n<!--kg-card-end: markdown-->', 'A strike? As someone born in the late 80''s I didn''t know strikes could even happen these days. That isn''t to say I thought they were illegal, I just can''t recall ever hearing about a strike that actually had an effect large enough to take notice.\n\n\nAnd yet here we are in 2013. BART has ground to a halt and Facebook is overflowing with angry posts because BART workers make an average gross pay of $76,500/year and that''s a lot relative to most middle class jobs, but really what does that buy yo', NULL, 0, 'post', 'draft', 'public', 'all', '2013-10-18 18:45:17', '1', '2013-10-18 18:45:17', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('be6573fa37da4af788044071', 'efafabed678640799f67ca3591dfcec2', 'Doing It Live', 'doing-it-live', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"After months of my phone asking, \\"Are you going to write 1000 words tonight?\\", I sadly only have half a dozen partial posts. I kept myself convinced that building a backlog of potential posts was the right choice so I''d still have something to post when I get busy, but ultimately that''s just an excuse to be lazy. Instead, I''m going to stop talking about it with myself and do it live. It''s tough to stay motivated, and it''s terrifying to put yourself out there, but as they say, \\"no risk, no gain\\" (that is a saying, right?).\\n\\nI don''t want to make a grand statement about how this is a \\"relaunch\\" of my blog, because it isn''t - it''s just a continuation minus the old content because it''s no longer relevant to what I hope to express. Some of the old stuff will inevitably find itself regurgitated in one way or another, but sometimes starting with a clean slate is the only way to start again at all.\\n\\nI''ve written blogs before - it shouldn''t be that difficult, right?\\n\\n...right?"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>After months of my phone asking, &quot;Are you going to write 1000 words tonight?&quot;, I sadly only have half a dozen partial posts. I kept myself convinced that building a backlog of potential posts was the right choice so I''d still have something to post when I get busy, but ultimately that''s just an excuse to be lazy. Instead, I''m going to stop talking about it with myself and do it live. It''s tough to stay motivated, and it''s terrifying to put yourself out there, but as they say, &quot;no risk, no gain&quot; (that is a saying, right?).</p>\n<p>I don''t want to make a grand statement about how this is a &quot;relaunch&quot; of my blog, because it isn''t - it''s just a continuation minus the old content because it''s no longer relevant to what I hope to express. Some of the old stuff will inevitably find itself regurgitated in one way or another, but sometimes starting with a clean slate is the only way to start again at all.</p>\n<p>I''ve written blogs before - it shouldn''t be that difficult, right?</p>\n<p>...right?</p>\n<!--kg-card-end: markdown-->', 'After months of my phone asking, "Are you going to write 1000 words tonight?", I sadly only have half a dozen partial posts. I kept myself convinced that building a backlog of potential posts was the right choice so I''d still have something to post when I get busy, but ultimately that''s just an excuse to be lazy. Instead, I''m going to stop talking about it with myself and do it live. It''s tough to stay motivated, and it''s terrifying to put yourself out there, but as they say, "no risk, no gain" ', NULL, 0, 'post', 'published', 'public', 'all', '2013-10-31 17:07:44', '1', '2013-10-31 17:14:59', '1', '2013-10-31 17:14:59', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('4ce2889404984f2c95e42c83', 'aef2b645d1f34c368f40f04c26ace595', 'Wordpress is Great, Wordpress is Terrible', 'wordpress-is-great-wordpress-is-terrible', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"_The blogging community has been flourishing for years with Wordpress at the lead, but to anyone involved it''s obvious that there''s room for improvement._\\n\\n###The Community\\n\\nFirst off, let''s just get out front that it now powers an estimated sixty million, or eighteen percent of websites, on the internet.\\n\\nHoly shit. \\n\\nNow while I won''t argue that something is great because it''s popular (I''m looking at you preppy high school kids), it still doesn''t mean that its widespread use is any less impressive. A quick look at the source of the top 30 articles on HackerNews at the time of writing this shows that at least 9 are powered by Wordpress. First impressions suggest that Wordpress is probably more pervasive in our cat-meme browsing lives than any other platform out there.\\n\\nAs every platform with more than ten users has started holding a conference if only for publicity''s sake (really Box/Dropbox/Trello/etc?), Wordpress has impressively held over 200 of their own Wordcamp''s worldwide since 2006. What''s impressive isn''t that Wordpress itself organized 200+ events (I''d label that as insanity), but that almost all of these events were organized by the community itself.\\n\\n###So what''s the problem?\\n\\nJohn O''Nolan, one of the designers of the Wordpress UI stated, \\n>What started out as a humble blogging platform targeted at enabling digital publishing for the masses, has evolved into a fully-fledged website CMS.\\n\\nThe problem is that Wordpress has long since deviated from being the pure blogging platform it started as, and in doing so has introduced a lot of confusion into it''s product direction. After years of its users hacking it to be more CMS-like it finally embraced this ideal, but years after its acceptance it still remains only CMS-like. Rather than growing into the open source CMS power house it should have been, it''s instead stuck in an awkward adolescent stage where anything is possible but never quite feels right. I can''t recall the last time I had to tell a client, \\"Wordpress can''t do that,\\" but sadly I find myself walking away unproud of the code I''ve left behind.\\n\\nLike a public school multi-purpose room, it can do anything, but is great for nothing in particular.\\n\\n###Content is King\\n\\n>There''s too much stuff everywhere, too much clutter, too many (so many) options getting in the way of what I really want to do: publish content.\\n\\nThis is one of the opening lines that leads O''Nolan to introduce his new \\"pure blog\\" platform, Ghost. While I so far love Ghost (I''m placing my bet on it with this blog), I think he missed the point that \\"publish[ing] content\\" should be the focus of every site, not just simple blogs.\\n\\nWhile the dashboard has visually stood the test of time with some grace, it doesn''t help the fact that it continues to have a steep learning curve for the casual user. Looking at the dashboard for a recent client site, I can quickly count at least 23 sidebar/header links without even getting into dropdown menus or the dashboard homepage content.\\n\\n![Wordpress Dashboard](__GHOST_URL__/content/images/2013/Oct/wordpress_screenshot.jpg)\\n_Why is my theme name, number of widgets, Wordpress version, and spam comments given a first-class location as soon as I log into the dashboard?_\\n\\nFor my client''s sake I''ve thankfully created a custom user role that gives them access to only the things necessary for most employees, but again it''s another fix to an issue that shouldn''t exist. Why are Appearance, Plugins, Users, Tools, and Settings all separate top-level items? At the end of the day these are all \\"Settings\\" that aren''t relevant to the normal content management process and should be organized as such.\\n\\n###Security\\nWith great power comes great responsibility, and Wordpress is no exception. With 60 million websites and an aging codebase susceptible to common attacks, it''s not uncommong ot hear about hacked Wordpress sites. I myself have had several occasions where old clients call asking why their description on Google is a bunch of gibberish about credit cards, only to find that a hidden block of text had been injected into their page from some foreign base64 encoded line within their theme or the core files.\\n\\nThe introduction of poorly written plugins brings even more risk of common attacks like an SQL injection. If anything, Wordpress should probably take the route of auto-escaping any inputs unless explicitly disabled on a case-by-case basis.\\n\\n###\\"The Loop...oh god, the loop\\"\\nA decade ago PHP was one of the most promising languages out there, but now it''s largely the subject of regular ridicule. While its been making great strides at modernizing itself since v5.3 (now on v5.5), it still has a long way to go compared to its younger, more nimble (and less stable) competitors. Given that PHP is making such big steps to modernize you''d think Wordpress would be right there with it, but instead we get a cop out on their inconsistent \\"Requirements\\" page:\\n\\n>We’re very aware that the latest versions of PHP and MySQL aren’t right for everyone, and that sometimes hosts can be slow or hesitant to upgrade their customers since upgrades to PHP and MySQL historically have broken applications.\\n\\nBeing conscious of not breaking your user''s websites is admirable, but when you''re supporting a version of an actively developed language that''s now 6 years old, it starts to raise some concerns. \\n\\nA large portion of the PHP community (and development world as a whole) accepted the benefits of separating logic from the view with languages like Twig/Handlebars/etc, yet we still have a muddled method of writing templates using Wordpress'' own PHP-based template tags. While I''m not much interested in arguing whether or not PHP is a templating language in its own right, with inconsistent Wordpress functions all mixed inside the god-forsaken the\\\\_loop() it becomes one big hack of if/while/else statements and \\"Wordpress PHP\\" that becomes near-impossible to consistently maintain long-term.\\n\\n###A Proposal for the Future\\n\\n**Modularize the core.** Don''t need a feature? Then don''t include it. Take some cues from the likes of node.js'' require and Rails 4''s separation of core features into modular gems. No need for a blog? Then stop including post-style functionality and instead just include pages with base templates that can be manipulated based on flexible sets of rules. Don''t need commenting? No problem.\\n\\n**Integrate the community.** No, really integrate them. Wordpress has one of the most active communities out there and they''re actively building the great plugin ecosystem that makes Wordpress so successful. Take a serious look at the \\"indispensable plugins\\" - the ones that are used on almost every website - and integrate them into the Wordpress core as optional modules. There''s no reason we should be installing the same breakable third-party plugins on every Wordpress site we build...I''m looking at you Gravity Forms and Advanced Custom Fields.\\n\\nDon''t get me wrong, Wordpress is still a great platform to build for small client sites for many reasons not listed here, but if it wants to continue to remain as relevant as it has been it needs to start looking toward the future.\\n\\n---\\nShare your thoughts on [HackerNews](https://news.ycombinator.com/item?id=6656816)"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p><em>The blogging community has been flourishing for years with Wordpress at the lead, but to anyone involved it''s obvious that there''s room for improvement.</em></p>\n<h3 id="thecommunity">The Community</h3>\n<p>First off, let''s just get out front that it now powers an estimated sixty million, or eighteen percent of websites, on the internet.</p>\n<p>Holy shit.</p>\n<p>Now while I won''t argue that something is great because it''s popular (I''m looking at you preppy high school kids), it still doesn''t mean that its widespread use is any less impressive. A quick look at the source of the top 30 articles on HackerNews at the time of writing this shows that at least 9 are powered by Wordpress. First impressions suggest that Wordpress is probably more pervasive in our cat-meme browsing lives than any other platform out there.</p>\n<p>As every platform with more than ten users has started holding a conference if only for publicity''s sake (really Box/Dropbox/Trello/etc?), Wordpress has impressively held over 200 of their own Wordcamp''s worldwide since 2006. What''s impressive isn''t that Wordpress itself organized 200+ events (I''d label that as insanity), but that almost all of these events were organized by the community itself.</p>\n<h3 id="sowhatstheproblem">So what''s the problem?</h3>\n<p>John O''Nolan, one of the designers of the Wordpress UI stated,</p>\n<blockquote>\n<p>What started out as a humble blogging platform targeted at enabling digital publishing for the masses, has evolved into a fully-fledged website CMS.</p>\n</blockquote>\n<p>The problem is that Wordpress has long since deviated from being the pure blogging platform it started as, and in doing so has introduced a lot of confusion into it''s product direction. After years of its users hacking it to be more CMS-like it finally embraced this ideal, but years after its acceptance it still remains only CMS-like. Rather than growing into the open source CMS power house it should have been, it''s instead stuck in an awkward adolescent stage where anything is possible but never quite feels right. I can''t recall the last time I had to tell a client, &quot;Wordpress can''t do that,&quot; but sadly I find myself walking away unproud of the code I''ve left behind.</p>\n<p>Like a public school multi-purpose room, it can do anything, but is great for nothing in particular.</p>\n<h3 id="contentisking">Content is King</h3>\n<blockquote>\n<p>There''s too much stuff everywhere, too much clutter, too many (so many) options getting in the way of what I really want to do: publish content.</p>\n</blockquote>\n<p>This is one of the opening lines that leads O''Nolan to introduce his new &quot;pure blog&quot; platform, Ghost. While I so far love Ghost (I''m placing my bet on it with this blog), I think he missed the point that &quot;publish[ing] content&quot; should be the focus of every site, not just simple blogs.</p>\n<p>While the dashboard has visually stood the test of time with some grace, it doesn''t help the fact that it continues to have a steep learning curve for the casual user. Looking at the dashboard for a recent client site, I can quickly count at least 23 sidebar/header links without even getting into dropdown menus or the dashboard homepage content.</p>\n<p><img src="__GHOST_URL__/content/images/2013/Oct/wordpress_screenshot.jpg" alt="Wordpress Dashboard" loading="lazy"><br>\n<em>Why is my theme name, number of widgets, Wordpress version, and spam comments given a first-class location as soon as I log into the dashboard?</em></p>\n<p>For my client''s sake I''ve thankfully created a custom user role that gives them access to only the things necessary for most employees, but again it''s another fix to an issue that shouldn''t exist. Why are Appearance, Plugins, Users, Tools, and Settings all separate top-level items? At the end of the day these are all &quot;Settings&quot; that aren''t relevant to the normal content management process and should be organized as such.</p>\n<h3 id="security">Security</h3>\n<p>With great power comes great responsibility, and Wordpress is no exception. With 60 million websites and an aging codebase susceptible to common attacks, it''s not uncommong ot hear about hacked Wordpress sites. I myself have had several occasions where old clients call asking why their description on Google is a bunch of gibberish about credit cards, only to find that a hidden block of text had been injected into their page from some foreign base64 encoded line within their theme or the core files.</p>\n<p>The introduction of poorly written plugins brings even more risk of common attacks like an SQL injection. If anything, Wordpress should probably take the route of auto-escaping any inputs unless explicitly disabled on a case-by-case basis.</p>\n<h3 id="theloopohgodtheloop">&quot;The Loop...oh god, the loop&quot;</h3>\n<p>A decade ago PHP was one of the most promising languages out there, but now it''s largely the subject of regular ridicule. While its been making great strides at modernizing itself since v5.3 (now on v5.5), it still has a long way to go compared to its younger, more nimble (and less stable) competitors. Given that PHP is making such big steps to modernize you''d think Wordpress would be right there with it, but instead we get a cop out on their inconsistent &quot;Requirements&quot; page:</p>\n<blockquote>\n<p>We’re very aware that the latest versions of PHP and MySQL aren’t right for everyone, and that sometimes hosts can be slow or hesitant to upgrade their customers since upgrades to PHP and MySQL historically have broken applications.</p>\n</blockquote>\n<p>Being conscious of not breaking your user''s websites is admirable, but when you''re supporting a version of an actively developed language that''s now 6 years old, it starts to raise some concerns.</p>\n<p>A large portion of the PHP community (and development world as a whole) accepted the benefits of separating logic from the view with languages like Twig/Handlebars/etc, yet we still have a muddled method of writing templates using Wordpress'' own PHP-based template tags. While I''m not much interested in arguing whether or not PHP is a templating language in its own right, with inconsistent Wordpress functions all mixed inside the god-forsaken the_loop() it becomes one big hack of if/while/else statements and &quot;Wordpress PHP&quot; that becomes near-impossible to consistently maintain long-term.</p>\n<h3 id="aproposalforthefuture">A Proposal for the Future</h3>\n<p><strong>Modularize the core.</strong> Don''t need a feature? Then don''t include it. Take some cues from the likes of node.js'' require and Rails 4''s separation of core features into modular gems. No need for a blog? Then stop including post-style functionality and instead just include pages with base templates that can be manipulated based on flexible sets of rules. Don''t need commenting? No problem.</p>\n<p><strong>Integrate the community.</strong> No, really integrate them. Wordpress has one of the most active communities out there and they''re actively building the great plugin ecosystem that makes Wordpress so successful. Take a serious look at the &quot;indispensable plugins&quot; - the ones that are used on almost every website - and integrate them into the Wordpress core as optional modules. There''s no reason we should be installing the same breakable third-party plugins on every Wordpress site we build...I''m looking at you Gravity Forms and Advanced Custom Fields.</p>\n<p>Don''t get me wrong, Wordpress is still a great platform to build for small client sites for many reasons not listed here, but if it wants to continue to remain as relevant as it has been it needs to start looking toward the future.</p>\n<hr>\n<p>Share your thoughts on <a href="https://news.ycombinator.com/item?id=6656816">HackerNews</a></p>\n<!--kg-card-end: markdown-->', 'The blogging community has been flourishing for years with Wordpress at the lead, but to anyone involved it''s obvious that there''s room for improvement.\n\n\n\nThe Community\n\n\nFirst off, let''s just get out front that it now powers an estimated sixty million, or eighteen percent of websites, on the internet.\n\n\nHoly shit.\n\n\nNow while I won''t argue that something is great because it''s popular (I''m looking at you preppy high school kids), it still doesn''t mean that its widespread use is any', NULL, 0, 'post', 'published', 'public', 'all', '2013-10-31 17:33:17', '1', '2013-11-01 22:08:31', '1', '2013-11-01 21:54:17', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('5b910d8d8e004a1d9c2e4469', '335445db04304d29ae541297c6893d24', 'Stop Freelancing', 'stop-freelancing', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"I''ve been \\"freelancing\\" part time for the better part of the past 4 years and full time for the past 8 months, and if there''s one thing I''ve learned it''s that telling people you freelance will garner responses that manage to combine a jealousy of your freedom and a subtle tone that silently says,\\n\\n\\"A freelancer? That''s cute.\\"\\n\\nSo what did I do? I stopped freelancing and started my own company. I came up with a business name<sup>[1]</sup>, filed for a business license, and as of recent finally even got myself a desk with a fancy \\"Suite\\" address in a coworking building.\\n\\nWhile the transition to me seamlessly occured over the course of several months, to the clients I pitched and worked with it was a sudden and jarring difference. Potential leads increased in quantity (and quality), a higher ratio of those leads converted to clients, and the level of control I had over the actual working relationship with clients improved exponentially. Behind the scenes barely anything has truly changed, but by presenting myself as a company it gave a much more professional image than that of some kid \\"webmaster\\" working from his parent''s basement<sup>[2]</sup>.\\n\\nRemember, you''re not a no-strings-attached temporary employee, you''re an expert in your field whom clients come to because they want the best product possible and can trust to guide them in the best direction possible.\\n\\nI''m not saying there aren''t plenty of talented, extremely professional freelancers out there (there are tons), but my experience has been that being a \\"freelancer\\" sets the unfortunate tone that you need your client, whereas in reality they are the one who needs you to help tell them how to make their business successful.\\n\\nTalk about it over on [Hacker News](https://news.ycombinator.com/item?id=6727378)\\n\\n---\\n\\n<small>1. Some people might want to continue to use their personal name, which is fine. Just be sure to position it as a company, not you. The difference between \\"Designer John Smith\\" and \\"John Smith Design Studio\\" can''t be underestimated when viewed by a prospective client.\\n2. No, I don''t work from my parent''s basement.</small>"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>I''ve been &quot;freelancing&quot; part time for the better part of the past 4 years and full time for the past 8 months, and if there''s one thing I''ve learned it''s that telling people you freelance will garner responses that manage to combine a jealousy of your freedom and a subtle tone that silently says,</p>\n<p>&quot;A freelancer? That''s cute.&quot;</p>\n<p>So what did I do? I stopped freelancing and started my own company. I came up with a business name<sup>[1]</sup>, filed for a business license, and as of recent finally even got myself a desk with a fancy &quot;Suite&quot; address in a coworking building.</p>\n<p>While the transition to me seamlessly occured over the course of several months, to the clients I pitched and worked with it was a sudden and jarring difference. Potential leads increased in quantity (and quality), a higher ratio of those leads converted to clients, and the level of control I had over the actual working relationship with clients improved exponentially. Behind the scenes barely anything has truly changed, but by presenting myself as a company it gave a much more professional image than that of some kid &quot;webmaster&quot; working from his parent''s basement<sup>[2]</sup>.</p>\n<p>Remember, you''re not a no-strings-attached temporary employee, you''re an expert in your field whom clients come to because they want the best product possible and can trust to guide them in the best direction possible.</p>\n<p>I''m not saying there aren''t plenty of talented, extremely professional freelancers out there (there are tons), but my experience has been that being a &quot;freelancer&quot; sets the unfortunate tone that you need your client, whereas in reality they are the one who needs you to help tell them how to make their business successful.</p>\n<p>Talk about it over on <a href="https://news.ycombinator.com/item?id=6727378">Hacker News</a></p>\n<hr>\n<p><small>1. Some people might want to continue to use their personal name, which is fine. Just be sure to position it as a company, not you. The difference between &quot;Designer John Smith&quot; and &quot;John Smith Design Studio&quot; can''t be underestimated when viewed by a prospective client.<br>\n2. No, I don''t work from my parent''s basement.</small></p>\n<!--kg-card-end: markdown-->', 'I''ve been "freelancing" part time for the better part of the past 4 years and full time for the past 8 months, and if there''s one thing I''ve learned it''s that telling people you freelance will garner responses that manage to combine a jealousy of your freedom and a subtle tone that silently says,\n\n\n"A freelancer? That''s cute."\n\n\nSo what did I do? I stopped freelancing and started my own company. I came up with a business name[1], filed for a business license, and as of recent finally even ', NULL, 0, 'post', 'published', 'public', 'all', '2013-11-13 05:19:15', '1', '2013-11-13 19:03:10', '1', '2013-11-13 18:42:32', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('1cad681fd81d44298618d756', '2cbd489efb2e47e1a2aa8948ec011258', 'MVP, not MVPOS', 'mvp-not-mvpos', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"If you live and work in the tech world, then \\"lean\\" or \\"agile\\" just might have been your first words.\\n\\nEvery meetup, conference, and startup in a 50 mile radius is talking about what it means to be a lean startup, and I have to say it’s been a great improvement over old-fashioned waterfall workflows. Unfortunately, another phrase that goes hand-in-hand with the lean/agile movement is the ever-present concept of the \\"MVP\\", otherwise known as the Minimum Viable Product.\\n\\nIn theory it''s a great idea - inputting the minimum amount of time necessary to validate a product/feature - but like many great ideas it seems to be frequently bastardized in practice and reinterpreted as what I like to call MVPOS, or Minimum Viable Piece of Shit.\\n\\nYes, I understand you want to move quickly; and yes, I do think you should be doing the minimum amount necessary to validate your idea. However, that is no excuse for it to look and function terribly (or not function at all). Save time on things that don''t scale <sup>[1]</sup> long-term but can be manually processed for the purposes of testing, but don''t cut corners on the things that directly affect the end-users'' perceivable quality of your product.\\n\\nShort of some weekend hackathon you did with your buddies or an internal tool your company uses that took off unexpectedly, every feature of any product you intend to sell or monetize should strive to be as polished as reasonably possible and function just as your end-user expects it should. Don’t be one of those startups that delivers broken features with the excuse, \\"It''s just the MVP., we''ll fix it later.\\"\\n\\n**Man up, admit it isn''t good enough, and fix it now.**\\n\\nOtherwise, you''re missing the entire point of the MVP in the first place - to iterate quickly on small features based on customer feedback and measurable data. If it doesn''t work right in the first place, the only feedback you''ll get is likely what you already know.\\n\\nShare your thoughts on [Hacker News](https://news.ycombinator.com/item?id=6755207)\\n\\n---\\n\\n<small>1. If you havn''t read Paul Graham''s [Do Things That Don''t Scale](http://paulgraham.com/ds.html), do yourself a favor and check it out."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>If you live and work in the tech world, then &quot;lean&quot; or &quot;agile&quot; just might have been your first words.</p>\n<p>Every meetup, conference, and startup in a 50 mile radius is talking about what it means to be a lean startup, and I have to say it’s been a great improvement over old-fashioned waterfall workflows. Unfortunately, another phrase that goes hand-in-hand with the lean/agile movement is the ever-present concept of the &quot;MVP&quot;, otherwise known as the Minimum Viable Product.</p>\n<p>In theory it''s a great idea - inputting the minimum amount of time necessary to validate a product/feature - but like many great ideas it seems to be frequently bastardized in practice and reinterpreted as what I like to call MVPOS, or Minimum Viable Piece of Shit.</p>\n<p>Yes, I understand you want to move quickly; and yes, I do think you should be doing the minimum amount necessary to validate your idea. However, that is no excuse for it to look and function terribly (or not function at all). Save time on things that don''t scale <sup>[1]</sup> long-term but can be manually processed for the purposes of testing, but don''t cut corners on the things that directly affect the end-users'' perceivable quality of your product.</p>\n<p>Short of some weekend hackathon you did with your buddies or an internal tool your company uses that took off unexpectedly, every feature of any product you intend to sell or monetize should strive to be as polished as reasonably possible and function just as your end-user expects it should. Don’t be one of those startups that delivers broken features with the excuse, &quot;It''s just the MVP., we''ll fix it later.&quot;</p>\n<p><strong>Man up, admit it isn''t good enough, and fix it now.</strong></p>\n<p>Otherwise, you''re missing the entire point of the MVP in the first place - to iterate quickly on small features based on customer feedback and measurable data. If it doesn''t work right in the first place, the only feedback you''ll get is likely what you already know.</p>\n<p>Share your thoughts on <a href="https://news.ycombinator.com/item?id=6755207">Hacker News</a></p>\n<hr>\n<p><small>1. If you havn''t read Paul Graham''s <a href="http://paulgraham.com/ds.html">Do Things That Don''t Scale</a>, do yourself a favor and check it out.</p>\n<!--kg-card-end: markdown-->', 'If you live and work in the tech world, then "lean" or "agile" just might have been your first words.\n\n\nEvery meetup, conference, and startup in a 50 mile radius is talking about what it means to be a lean startup, and I have to say it’s been a great improvement over old-fashioned waterfall workflows. Unfortunately, another phrase that goes hand-in-hand with the lean/agile movement is the ever-present concept of the "MVP", otherwise known as the Minimum Viable Product.\n\n\nIn theory it''s a g', NULL, 0, 'post', 'published', 'public', 'all', '2013-11-14 18:09:21', '1', '2014-06-18 19:53:53', '1', '2013-11-18 16:48:41', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('c51b57926d3241a5a017e83d', '8bbe9269507543078d27e69a559ece3f', 'Be Honest', 'be-honest', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"My friend Nathan will tell you I just hate people (jokingly, I think), but when it comes to business you can''t beat around the bush. Is someone''s work not up to par? Tell them they need to step things up. Is the client not holding up their end of the work? Sit them down and (politely) talk about what they and you can do to communicate or work together better.\\n\\nSometimes it''s going to be awkward and sometimes it''s going to take some time to fix. And yes, one day you''ll probably inadvertently burn a bridge or two, but more often than not it saves a lot of pain and headache that''ll come from avoiding the reality of the situation until it''s too late.\\n\\n---\\n\\nPipe in on [Hacker News](https://news.ycombinator.com/item?id=6741976)"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>My friend Nathan will tell you I just hate people (jokingly, I think), but when it comes to business you can''t beat around the bush. Is someone''s work not up to par? Tell them they need to step things up. Is the client not holding up their end of the work? Sit them down and (politely) talk about what they and you can do to communicate or work together better.</p>\n<p>Sometimes it''s going to be awkward and sometimes it''s going to take some time to fix. And yes, one day you''ll probably inadvertently burn a bridge or two, but more often than not it saves a lot of pain and headache that''ll come from avoiding the reality of the situation until it''s too late.</p>\n<hr>\n<p>Pipe in on <a href="https://news.ycombinator.com/item?id=6741976">Hacker News</a></p>\n<!--kg-card-end: markdown-->', 'My friend Nathan will tell you I just hate people (jokingly, I think), but when it comes to business you can''t beat around the bush. Is someone''s work not up to par? Tell them they need to step things up. Is the client not holding up their end of the work? Sit them down and (politely) talk about what they and you can do to communicate or work together better.\n\n\nSometimes it''s going to be awkward and sometimes it''s going to take some time to fix. And yes, one day you''ll probably inadvertently ', NULL, 0, 'post', 'published', 'public', 'all', '2013-11-15 20:25:55', '1', '2013-11-15 21:15:01', '1', '2013-11-15 20:28:13', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('5c8e7a0e40ca40c4b9a8e20c', '9724bcea935549c0abb6546f2b5c3dd7', 'The Most Important Part', 'the-most-important-part', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"While doing some research on OOCSS vs OOSCSS I stumbled across one by Chris Hansen at Pivotal Labs titled [Why we don’t use OOCSS (but we should)](http://pivotallabs.com/why-we-dont-use-oocss-but-we-should/). I have my own hesitations and thoughts regarding pure OOCSS, but was dumbstruck by one of his reasons for not using it:\\n\\n>HTML and CSS are just not as important as the server code or javascript for a web developer.\\n\\n###The Part Your Customers See Isn''t As Important?\\n\\nLet''s be honest, building out HTML/CSS templates can be pretty mundane at times, so to all the developers who grumble when they have to tediously build out a pixel perfect frontend - I understand. It''s actually one of the many reasons I believe all designers should learn to code their designs themselves. \\n\\nUnfortunately, it seems like this attitude extends beyond minor discontent and instead is an industry-wide attitude that the frontend is less important the innerworkings of your application, when I''d argue the exact opposite. \\n\\nYes, the backend is still *extremely* important, but most of your customers likely neither understand nor care how it actually works, so long as it does what it says it does. Unless your product is something targeted at the development community or some holy-grail with no competitor (Hint: It probably isn''t), chances are your customers are both consciously and subconsciously forming opinions about your product based on _how it looks_. When one of your customers inevitably runs into a bug (I promise they will), if it looks polished there''s a much better chance they''ll be forgiving and report the issue to you instead of switching to a competitor''s product. Better yet, if you respond promptly and work to help them through the issue and/or patch the bug there''s a good chance you can turn a negative situation into a positive memory of great service for your customer.\\n\\nOn the other hand, when one of your customers runs into a bug and your application looks like a POS, they''re going to assume that''s because it is a POS.\\n\\n---\\n\\nFeel free to voice your thoughts over on [HackerNews](https://news.ycombinator.com/item?id=6917559)"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>While doing some research on OOCSS vs OOSCSS I stumbled across one by Chris Hansen at Pivotal Labs titled <a href="http://pivotallabs.com/why-we-dont-use-oocss-but-we-should/">Why we don’t use OOCSS (but we should)</a>. I have my own hesitations and thoughts regarding pure OOCSS, but was dumbstruck by one of his reasons for not using it:</p>\n<blockquote>\n<p>HTML and CSS are just not as important as the server code or javascript for a web developer.</p>\n</blockquote>\n<h3 id="thepartyourcustomersseeisntasimportant">The Part Your Customers See Isn''t As Important?</h3>\n<p>Let''s be honest, building out HTML/CSS templates can be pretty mundane at times, so to all the developers who grumble when they have to tediously build out a pixel perfect frontend - I understand. It''s actually one of the many reasons I believe all designers should learn to code their designs themselves.</p>\n<p>Unfortunately, it seems like this attitude extends beyond minor discontent and instead is an industry-wide attitude that the frontend is less important the innerworkings of your application, when I''d argue the exact opposite.</p>\n<p>Yes, the backend is still <em>extremely</em> important, but most of your customers likely neither understand nor care how it actually works, so long as it does what it says it does. Unless your product is something targeted at the development community or some holy-grail with no competitor (Hint: It probably isn''t), chances are your customers are both consciously and subconsciously forming opinions about your product based on <em>how it looks</em>. When one of your customers inevitably runs into a bug (I promise they will), if it looks polished there''s a much better chance they''ll be forgiving and report the issue to you instead of switching to a competitor''s product. Better yet, if you respond promptly and work to help them through the issue and/or patch the bug there''s a good chance you can turn a negative situation into a positive memory of great service for your customer.</p>\n<p>On the other hand, when one of your customers runs into a bug and your application looks like a POS, they''re going to assume that''s because it is a POS.</p>\n<hr>\n<p>Feel free to voice your thoughts over on <a href="https://news.ycombinator.com/item?id=6917559">HackerNews</a></p>\n<!--kg-card-end: markdown-->', 'While doing some research on OOCSS vs OOSCSS I stumbled across one by Chris Hansen at Pivotal Labs titled Why we don’t use OOCSS (but we should). I have my own hesitations and thoughts regarding pure OOCSS, but was dumbstruck by one of his reasons for not using it:\n\n\n\n\n\nHTML and CSS are just not as important as the server code or javascript for a web developer.\n\n\n\n\nThe Part Your Customers See Isn''t As Important?\n\n\nLet''s be honest, building out HTML/CSS templates can be pretty munda', NULL, 0, 'post', 'published', 'public', 'all', '2013-12-04 04:13:59', '1', '2013-12-16 20:24:22', '1', '2013-12-16 18:25:44', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('03e79854efdd441994fc903e', '186d4d74bf264187ab727874a0c7efc8', 'Web Designers Code', 'web-designers-code', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"When I moved to San Francisco in 2012 I knew I wanted to get a job as a designer at a startup, but had never before dealt with the issue of needing to categorize myself into a certain role. In architecture there might be different types of designers (architect, landscape, etc), but they all overlap into a mesh of interdisciplinary collaboration that requires each person to be knowledgeable in the other person''s fields, regardless of their day-to-day responsibilities. \\n\\nDespite the oddity of having these arbitrary categories (especially at small startups), I applied to a few jobs as UI/UX designer and surprisingly got interviews within a week at all but one company (who interviewed me ~9 months later), got a lot of questions about whether or not I could do X or Y type of design, and landed a full time position at couple year old startup. At the time I didn''t know why I was having such a great response rate, but looking back I realized it was due to one thing: \\n\\n*I was a designer who could accurately code my designs.*\\n\\nAs a self taught designer/developer who never had anybody telling me what to learn or not to learn, this only seemed like common sense. If I''m passionate about my designs then why would I hand them off to someone who''s passion is in programming, not the tedious time-sink of HTML/CSS?\\n\\nUnfortunately the CTO at the time didn''t share this passion and I watched as designs were hackily assembled by a group of \\"full stack\\" developers, most of which who neither enjoyed nor cared about frontend presentation development, all with a hodge-podge of Bootstrap CSS and an over-abundance of bloated legacy CSS. While I pushed for media queries to be used to create a unified UI/UX across all devices, they were instead used to create an entirely different \\"mobile experience\\" and as an excuse to to throw \\"mobile app\\" and \\"responsive\\" onto the long list of marketing buzzwords.\\n\\nLet''s be honest, HTML/CSS is rarely fun and coding out your own designs probably isn''t that exciting to you, but as a designer you''re likely the one who most cares your designs being built accurately in their final medium, and as such you need to be able to take control of their execution. In some cases this means translating designs from PSD to HTML yourself or as is the case more and more often at [Atomi Design](http://atomidesign.com) - designing directly *in the browser<sup>[1](#f1)</sup>.*\\n\\nRegardless of how you setup your own workflow, the important thing is being able to take control of your designs from conceptualization through implementation. Even if aren''t coding frontend designs yourself, you need to have that knowledge as it helps inform the way you work and enables to start that discussion with the person who is coding it.\\n\\nTL;DR: If you call yourself web designer and you aren''t coding your designs, you better start.\\n\\n---\\n\\n**Shameless Plug:**\\nI''ve started a Meetup community called [Designers Who Code](http://dwc.io) that focuses on the intersection of design and development. We''re having a [Designer Drinkup](http://www.meetup.com/Designers-Who-Code/events/169900622/) on Wednesday, March 12th at Bloodhound in SoMa, and will be announcing upcoming workshops at our office in SoMa soon. If you''re in the San Francisco area and enjoy good beer and good company be sure to come check it out!\\n\\n---\\n\\n<sup><span id=\\"f1\\">1</span>. This is likely a topic for a larger discussion, but after having just finished our first project sans-Photoshop we''d like to think it still has a place in our workflow as a place for \\"digital sketches\\". Full page PSD mockups are out, but working in different analog and digital mediums always helps shake up the old design thinking.</sup>"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>When I moved to San Francisco in 2012 I knew I wanted to get a job as a designer at a startup, but had never before dealt with the issue of needing to categorize myself into a certain role. In architecture there might be different types of designers (architect, landscape, etc), but they all overlap into a mesh of interdisciplinary collaboration that requires each person to be knowledgeable in the other person''s fields, regardless of their day-to-day responsibilities.</p>\n<p>Despite the oddity of having these arbitrary categories (especially at small startups), I applied to a few jobs as UI/UX designer and surprisingly got interviews within a week at all but one company (who interviewed me ~9 months later), got a lot of questions about whether or not I could do X or Y type of design, and landed a full time position at couple year old startup. At the time I didn''t know why I was having such a great response rate, but looking back I realized it was due to one thing:</p>\n<p><em>I was a designer who could accurately code my designs.</em></p>\n<p>As a self taught designer/developer who never had anybody telling me what to learn or not to learn, this only seemed like common sense. If I''m passionate about my designs then why would I hand them off to someone who''s passion is in programming, not the tedious time-sink of HTML/CSS?</p>\n<p>Unfortunately the CTO at the time didn''t share this passion and I watched as designs were hackily assembled by a group of &quot;full stack&quot; developers, most of which who neither enjoyed nor cared about frontend presentation development, all with a hodge-podge of Bootstrap CSS and an over-abundance of bloated legacy CSS. While I pushed for media queries to be used to create a unified UI/UX across all devices, they were instead used to create an entirely different &quot;mobile experience&quot; and as an excuse to to throw &quot;mobile app&quot; and &quot;responsive&quot; onto the long list of marketing buzzwords.</p>\n<p>Let''s be honest, HTML/CSS is rarely fun and coding out your own designs probably isn''t that exciting to you, but as a designer you''re likely the one who most cares your designs being built accurately in their final medium, and as such you need to be able to take control of their execution. In some cases this means translating designs from PSD to HTML yourself or as is the case more and more often at <a href="http://atomidesign.com">Atomi Design</a> - designing directly <em>in the browser<sup><a href="#f1">1</a></sup>.</em></p>\n<p>Regardless of how you setup your own workflow, the important thing is being able to take control of your designs from conceptualization through implementation. Even if aren''t coding frontend designs yourself, you need to have that knowledge as it helps inform the way you work and enables to start that discussion with the person who is coding it.</p>\n<p>TL;DR: If you call yourself web designer and you aren''t coding your designs, you better start.</p>\n<hr>\n<p><strong>Shameless Plug:</strong><br>\nI''ve started a Meetup community called <a href="http://dwc.io">Designers Who Code</a> that focuses on the intersection of design and development. We''re having a <a href="http://www.meetup.com/Designers-Who-Code/events/169900622/">Designer Drinkup</a> on Wednesday, March 12th at Bloodhound in SoMa, and will be announcing upcoming workshops at our office in SoMa soon. If you''re in the San Francisco area and enjoy good beer and good company be sure to come check it out!</p>\n<hr>\n<p><sup><span id="f1">1</span>. This is likely a topic for a larger discussion, but after having just finished our first project sans-Photoshop we''d like to think it still has a place in our workflow as a place for &quot;digital sketches&quot;. Full page PSD mockups are out, but working in different analog and digital mediums always helps shake up the old design thinking.</sup></p>\n<!--kg-card-end: markdown-->', 'When I moved to San Francisco in 2012 I knew I wanted to get a job as a designer at a startup, but had never before dealt with the issue of needing to categorize myself into a certain role. In architecture there might be different types of designers (architect, landscape, etc), but they all overlap into a mesh of interdisciplinary collaboration that requires each person to be knowledgeable in the other person''s fields, regardless of their day-to-day responsibilities.\n\n\nDespite the oddity of h', NULL, 0, 'post', 'published', 'public', 'all', '2014-01-23 03:08:51', '1', '2014-03-11 00:20:24', '1', '2014-03-11 00:14:14', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('47c5311b8c7a41f296b4d051', '295ecc2601ba4ed3b56daa2d1506b8f9', 'Trust', 'trust', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"I recently read 37Signal''s newest book Remote: Office Not Required. The book itself left something to desire (it felt more like an advertisement for their products than anything else), but when discussing how they manage expenses within their company one part hit me:\\n\\n> At 37Signals we''ve created a number of ways to eradicate roadblocks. First, everyone gets a company credit card and is told to \\"spend wisely.\\" There''s no begging to spend money on needed equipment to get the work done, and there are no expense reports to fill out ...\\""}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>I recently read 37Signal''s newest book Remote: Office Not Required. The book itself left something to desire (it felt more like an advertisement for their products than anything else), but when discussing how they manage expenses within their company one part hit me:</p>\n<blockquote>\n<p>At 37Signals we''ve created a number of ways to eradicate roadblocks. First, everyone gets a company credit card and is told to &quot;spend wisely.&quot; There''s no begging to spend money on needed equipment to get the work done, and there are no expense reports to fill out ...&quot;</p>\n</blockquote>\n<!--kg-card-end: markdown-->', 'I recently read 37Signal''s newest book Remote: Office Not Required. The book itself left something to desire (it felt more like an advertisement for their products than anything else), but when discussing how they manage expenses within their company one part hit me:\n\n\n\n\n\nAt 37Signals we''ve created a number of ways to eradicate roadblocks. First, everyone gets a company credit card and is told to "spend wisely." There''s no begging to spend money on needed equipment to get the work done, an', NULL, 0, 'post', 'draft', 'public', 'all', '2014-01-23 03:12:18', '1', '2014-01-23 03:12:18', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('b3774f453bd242ae956b452b', '6a98f5e626fc4176bb5556c291916607', 'Life is (Finding) Meaning', 'life-is-finding-meaning', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"![The empty expanses of the Utah/Nevada desert along Highway 50](https://farm7.staticflickr.com/6183/6054999467_f7b952e799_b.jpg)\\n\\nI''ve only now just finished listening to Derek Siver''s latest conference talk \\"[The Meaning of Life](http://sivers.org/ml)\\", and can only encourage everyone else to watch (or listen to) it as soon as possible.\\n\\nAs someone whose life work exists on a series of computer hard drives it hits pretty close to home. I regularly question what I''d do if a massive solar flare hit Earth and wiped out every electronic known to man. I mean sure, my skills as a designer/developer are pretty damn valuable right now, but when everything''s reset back to the 1850''s would that skillset really matter? Should I be developing practical skills like hunting and fire building instead? It''s enough to give anyone an mid-life crisis.\\n\\nEither way, my main point in writing is that while I loved hearing Sivers so casually questioning the meaning of life with his children''s storybook reading voice (seriously), I unfortunately was disappointed by his ending. After working through the questions of \\"Life is Time\\", \\"Life is Memory\\", and \\"Life is Learning\\", he concludes that we all inevitably assign our own meaning to these different questions; and therefore apparently life is (just) life.\\n\\nWhile I don''t necessarily disagree with this statement, I think there''s a better answer than the one he gave - one hidden right in plain site throughout his entire presentation:\\n\\nLife is (Finding) Meaning\\n\\nTo some this might seem like a disappointing cop-out to a question for which we all want a singular clear answer, but I see it as a beautiful symbol of the unique quality of being human. While other species seem to exist purely to reproduce, we instead explore, invent, and question why we exist, and in doing so (hopefully) eventually find our own reason to persist. Whether that''s a religion, your spouse, or rock climbing in a remote mountain range hours from any sort of civilization, the meaning of life for yourself is whatever you find it to be."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p><img src="https://farm7.staticflickr.com/6183/6054999467_f7b952e799_b.jpg" alt="The empty expanses of the Utah/Nevada desert along Highway 50" loading="lazy"></p>\n<p>I''ve only now just finished listening to Derek Siver''s latest conference talk &quot;<a href="http://sivers.org/ml">The Meaning of Life</a>&quot;, and can only encourage everyone else to watch (or listen to) it as soon as possible.</p>\n<p>As someone whose life work exists on a series of computer hard drives it hits pretty close to home. I regularly question what I''d do if a massive solar flare hit Earth and wiped out every electronic known to man. I mean sure, my skills as a designer/developer are pretty damn valuable right now, but when everything''s reset back to the 1850''s would that skillset really matter? Should I be developing practical skills like hunting and fire building instead? It''s enough to give anyone an mid-life crisis.</p>\n<p>Either way, my main point in writing is that while I loved hearing Sivers so casually questioning the meaning of life with his children''s storybook reading voice (seriously), I unfortunately was disappointed by his ending. After working through the questions of &quot;Life is Time&quot;, &quot;Life is Memory&quot;, and &quot;Life is Learning&quot;, he concludes that we all inevitably assign our own meaning to these different questions; and therefore apparently life is (just) life.</p>\n<p>While I don''t necessarily disagree with this statement, I think there''s a better answer than the one he gave - one hidden right in plain site throughout his entire presentation:</p>\n<p>Life is (Finding) Meaning</p>\n<p>To some this might seem like a disappointing cop-out to a question for which we all want a singular clear answer, but I see it as a beautiful symbol of the unique quality of being human. While other species seem to exist purely to reproduce, we instead explore, invent, and question why we exist, and in doing so (hopefully) eventually find our own reason to persist. Whether that''s a religion, your spouse, or rock climbing in a remote mountain range hours from any sort of civilization, the meaning of life for yourself is whatever you find it to be.</p>\n<!--kg-card-end: markdown-->', '\n\n\nI''ve only now just finished listening to Derek Siver''s latest conference talk "The Meaning of Life", and can only encourage everyone else to watch (or listen to) it as soon as possible.\n\n\nAs someone whose life work exists on a series of computer hard drives it hits pretty close to home. I regularly question what I''d do if a massive solar flare hit Earth and wiped out every electronic known to man. I mean sure, my skills as a designer/developer are pretty damn valuable right now, but whe', NULL, 0, 'post', 'published', 'public', 'all', '2014-05-04 15:50:47', '1', '2014-05-04 17:42:48', '1', '2014-05-04 16:27:05', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('ef88b74f1a6545d9a5186787', '662d045aaf354366a403fea97be803b7', 'Why Designers Should Code', 'why-designers-should-code', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"Over the past several years the topic of the designer who codes has generated quite the lot of controversy within the tech community. Some camps believe designers shouldn''t distract themselves with code and instead maintain their roots in graphic design as pixel-pushers, while others think that designers should be getting their hands dirty with code down in the trenches alongside their developer cohorts.\\n\\nAs I''ve written on the topic on more than one occasion[^n] and non-coincidentally run a meetup group called [Designers Who Code](//dwc.io), it should come as no secret that I fall into the latter camp.\\n\\n##At the Outset\\n\\nWhen I first started teaching myself web design back in university I didn''t have any mentors to consult or tell me what to do. While I had plenty of friends in the computer science program, I was surprised to discover that they were all learning old-school Java/C++, and knew almost nothing in the realm of modern web languages nor web application development [^n]. I''d had some exposure to the world of table-based HTML layouts and `<font>` tags back in high school, so in my need to make extra money to pay for ~~beer~~ my rent, I figured I''d just learn by Googling the hell out of anything and everything.\\n\\nThis way of learning has its faults, but as I had nobody telling me what or what not to do, it just seemed like common sense that I''d code up my own designs too. At the time they were mostly simple static HTML/CSS layouts, so anything I didn''t already know I could quickly figure out (aka frantically Google and hit my head against the keyboard until 4am). It wasn''t until I moved to San Francisco in 2012 that I found out that designers coding wasn''t the norm, and what seemed like common sense to me was a foreign concept to most people I met.  \\n\\nThis quote from Jeremy Bell from the blog of [the regretfully defunct] Teehan + Lax sums up what I encountered and how I felt pretty accurately[^n]:\\n\\n> ...If I was to be a designer, I couldn’t be a developer. There was never an option to do both. Instead, I’d spend hours designing static pages in Photoshop that would simply be handed to the developers for reproduction in HTML. There was rarely an opportunity to collaborate throughout the process. Hell, we barely spoke. Sometimes we weren’t even in the same timezone, let alone the same room.<br /><br />That was 16 years ago, and not much has changed.\\n\\nAs I''ve previously written about, at my first full-time web design job I encountered the same problem — I was hired as the UI/UX Designer in party because I _could_ code and communicate with developers in a way they''d understand, but within the first few hours of my first day the CTO quickly asserted that, “Designers don''t touch code” (a huge sticking point that resulted in a relatively short-lived employment)[^n]. While the concept of designers being anything more than pixel-pushers still remains a foreign concept to many companies, it thankfully seem to have been gaining more and more traction over the past few years as job listings for UI/UX Designers now regularly include “HTML/CSS” as requirements or nice-to-haves, or are listed under the guise of a “UI Developer” position instead.\\n\\nYou might ask, “So what, why _should_ designers code?”\\n\\nThe full answer is a long one, but in short a [good] designer isn''t someone who just makes things “pretty” or “functional”, but someone who strives to understand the problems at hand and develop the optimal solution to that problem, whatever set of skills that might require. This isn''t to say a designers should do everything, but a good designer should know where they or their colleagues can deliver more value more efficiently and coordinate their role appropriately. In this case, there''s numerous clear benefits to the designer building the frontend templates themselves.\\n\\n##Tightening the Feedback Loop\\n\\nNearly every web designer, myself included, has numerous stories of handing off mockups to a developer only to have the built version look nothing like the mockups that were provided. At the time it''s always easy to rant and criticize the developer, but what else would you expect when you''re handing off the responsibility of implementing the design to someone whose job is only tangentially related to design, and often doesn''t care about the design nearly as much as you do?\\n\\nThis is by no means meant to criticize developers, but instead quite the opposite as I suspect a very similar problem would arise if the situation were reversed and developers gave designers specs to implement a new a feature. It might “work” in the designer’s eyes, but any experienced developer would likely cringe during the code review. Instead, a developer''s job should be to build complex features and applications, not to fret over a few pixels here, a font weight there, and the crazy nuances of cross-browser CSS — that''s the designer''s job, and it makes infinitely more sense for the designer to be able to tweak those nuances directly rather than hunting down, bothering, and distracting a developer from their own responsibilities.\\n\\nIn reading a great Medium article by David Cole[^n] I came across a rather strong quote from Jennifer Tidwell[^n]:\\n\\n> So there’s lots of good stuff to learn before you can create production-quality software systems. But here’s what I worry about: it takes years to learn it well, and this is what a lot of good software engineers do for 50+ hours per week, building knowledge and picking up new skills. Practice, practice, practice.<br /><br />Hey, designer. Can you afford to invest those years?\\n\\nCole goes on to dispute Tidwell by arguing that tools built for designers will help alleviate that learning curve, which while true to a certain degree, I think it misses the larger point at hand.\\n\\nDesigners don''t need to practice 50 hours/week on development because the skills they need to cover design responsibilities aren''t nearly as broad as your typical developer. Designers don''t need to build a full javascript single page app (SPA) or an efficient Rails API to implement their designs effectively[^n]; instead, they need to be able to work with primarily HTML and CSS (or SASS/LESS/etc), to build code-based static templates of their designs that can then (if needed) be taken by a developer and integrated into a larger application.\\n\\nA developer who isn''t trained in design nor practices it on a daily basis isn''t going to notice the minute pixel differences a designer does, and being able to directly and immediately make those changes yourself helps tighten the designer/developer feedback loop in a way that pawning off frontend development responsibilities will never be able to match. Instead of a 12+ step process of delayed designer-developer communication, it instead becomes something more akin to:\\n\\n1. Wireframes + Mockups\\n2. Build HTML rapid prototypes to test design elements.\\n3. Build templates from mockups, making edits and adjustments as needed along the way.\\n4. Iterate.\\n5. Hand off templates to developer.\\n\\nThis not only makes for a much faster iteration cycle, but results in both a better end-product and frees up developers time so they can focus on building features rather than making small design tweaks. Additionally, any time you''re discussing changes to an existing site with your product manager or management, rather than going through the full gambit of producing an updated mockup and iterating with your developer, you can instead often fire up Chrome Developer Tools or Firebug and test out the edits in real time, discuss, and make a fast decision right then and there.\\n\\n##Briefly on the topic of CSS & Javascript\\n\\nCSS itself as a “programming language” is incredibly easy to criticize given it''s problematic cross-browser history[^n] and inconsistent syntax, but if someone has to deal with its insane idiosyncrasies across half a dozen browsers across dozens of devices with versions dating back at least several years, who better than the one person who _really_ cares enough to fight their way through it all? And realistically, once you''ve used CSS long enough on a regular basis you start to quickly learn the quirks and ins and outs of the language, and how to use it in a way that''s effective and cross-browser friendly.\\n\\nTo add to the mockup-to-code problem, anyone who has worked both sides of design and front-end development knows that what works in Photoshop/Sketch/[InsertToolHere] almost never perfectly translates 1:1 to what various browsers do, and you always need to make adjustments along the way. The design''s not done until it''s shipped, and trying to freeze it after you deliver some mockups to your development team is only doing the job halfway, and any time you try to lock-in a project that requires creative thinking you''re going to achieve subpar results.\\n\\nRegarding javascript, I personally love to learn new things and ended up diving head-first into its dark and magical ecosystem of libraries, frameworks, and package managers that install other package managers. I don''t think this level of javascript knowledge is necessary for the majority of designers, but a minimal level of javascript knowledge goes a long way in communicating some of the finer points of your design. Want to simulate a panel or modal animating into view in a way that requires toggling or modifying style properties? Rather than mocking it up in After Effects or Keynote, you can actually _build_ that animation exactly how you want it the first time around, and not nitpick with a developer about how it''s off by 50ms or how it doesn''t feel “quite right”.\\n\\n##Final Thoughts\\n\\nThere''s much, _much_ more to be written about on this topic, and I intend to do so over the coming weeks (and probably months). I''ve only begun to scratch the tip of the iceberg in my research efforts, and already I have well over a dozen articles from other designers and developers on the topic. As I continue to write more I might circle back and make adjustments/additions, so if you have something to say on the topic feel free reach out by Googlechat at &#x72;&#x6F;&#x62;&#x65;&#x72;&#x74;&#x6E;&#x65;&#x61;&#x6C;&#x61;&#x6E;&#x40;&#x67;&#x6D;&#x61;&#x69;&#x6C;&#x2E;&#x63;&#x6F;&#x6D; or email me at <a href=\\"mailto:&#x72;&#x6F;&#x62;&#x40;&#x61;&#x74;&#x6F;&#x6D;&#x69;&#x64;&#x65;&#x73;&#x69;&#x67;&#x6E;&#x2E;&#x63;&#x6F;&#x6D;\\">&#x72;&#x6F;&#x62;&#x40;&#x61;&#x74;&#x6F;&#x6D;&#x69;&#x64;&#x65;&#x73;&#x69;&#x67;&#x6E;&#x2E;&#x63;&#x6F;&#x6D;</a> — I''d love to chat.\\n\\n---\\n\\n_This is the first in a planned series of articles on the topic of being a designer who codes. As I publish additional articles in the series they will appear here accordingly. Cover photo is a screenshot of the [Proton Radio Beta](//beta.protonradio.com), a just publicly launched client work-in-progress._\\n\\n[^n]: __GHOST_URL__/tools-for-designing-in-the-browser/ &amp; __GHOST_URL__/web-designers-code/ — Latter has strong overlap with this article but was more focused on personal experience than actionable insights.\\n[^n]: Last I heard they''ve finally started offering some more modern Python courses.\\n[^n]: http://www.teehanlax.com/blog/designing-with-code/\\n[^n]: To be fair, this CTO was brought in to fix a huge mess, and I''m sure some hothead, 22 year old designer wasn''t what they wanted to deal with in addition to everything else. In the end I received an offer from a former client to contract for them that I couldn''t turn down.\\n[^n]: https://medium.com/design-startups/designers-will-code-6c423fc5ccef\\n[^n]: http://designinginterfaces.com/2011/06/01/designers-that-code-a-response-to-jared-spool/\\n[^n]: But hey, if you can do all these things well definitely drop me a note.\\n[^n]: I''m looking at you Internet Explorer 6 through 10..."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>Over the past several years the topic of the designer who codes has generated quite the lot of controversy within the tech community. Some camps believe designers shouldn''t distract themselves with code and instead maintain their roots in graphic design as pixel-pushers, while others think that designers should be getting their hands dirty with code down in the trenches alongside their developer cohorts.</p>\n<p>As I''ve written on the topic on more than one occasion<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup> and non-coincidentally run a meetup group called <a href="//dwc.io">Designers Who Code</a>, it should come as no secret that I fall into the latter camp.</p>\n<h2 id="attheoutset">At the Outset</h2>\n<p>When I first started teaching myself web design back in university I didn''t have any mentors to consult or tell me what to do. While I had plenty of friends in the computer science program, I was surprised to discover that they were all learning old-school Java/C++, and knew almost nothing in the realm of modern web languages nor web application development <sup class="footnote-ref"><a href="#fn1" id="fnref1:1">[1:1]</a></sup>. I''d had some exposure to the world of table-based HTML layouts and <code>&lt;font&gt;</code> tags back in high school, so in my need to make extra money to pay for <s>beer</s> my rent, I figured I''d just learn by Googling the hell out of anything and everything.</p>\n<p>This way of learning has its faults, but as I had nobody telling me what or what not to do, it just seemed like common sense that I''d code up my own designs too. At the time they were mostly simple static HTML/CSS layouts, so anything I didn''t already know I could quickly figure out (aka frantically Google and hit my head against the keyboard until 4am). It wasn''t until I moved to San Francisco in 2012 that I found out that designers coding wasn''t the norm, and what seemed like common sense to me was a foreign concept to most people I met.</p>\n<p>This quote from Jeremy Bell from the blog of [the regretfully defunct] Teehan + Lax sums up what I encountered and how I felt pretty accurately<sup class="footnote-ref"><a href="#fn1" id="fnref1:2">[1:2]</a></sup>:</p>\n<blockquote>\n<p>...If I was to be a designer, I couldn’t be a developer. There was never an option to do both. Instead, I’d spend hours designing static pages in Photoshop that would simply be handed to the developers for reproduction in HTML. There was rarely an opportunity to collaborate throughout the process. Hell, we barely spoke. Sometimes we weren’t even in the same timezone, let alone the same room.<br /><br />That was 16 years ago, and not much has changed.</p>\n</blockquote>\n<p>As I''ve previously written about, at my first full-time web design job I encountered the same problem — I was hired as the UI/UX Designer in party because I <em>could</em> code and communicate with developers in a way they''d understand, but within the first few hours of my first day the CTO quickly asserted that, “Designers don''t touch code” (a huge sticking point that resulted in a relatively short-lived employment)<sup class="footnote-ref"><a href="#fn1" id="fnref1:3">[1:3]</a></sup>. While the concept of designers being anything more than pixel-pushers still remains a foreign concept to many companies, it thankfully seem to have been gaining more and more traction over the past few years as job listings for UI/UX Designers now regularly include “HTML/CSS” as requirements or nice-to-haves, or are listed under the guise of a “UI Developer” position instead.</p>\n<p>You might ask, “So what, why <em>should</em> designers code?”</p>\n<p>The full answer is a long one, but in short a [good] designer isn''t someone who just makes things “pretty” or “functional”, but someone who strives to understand the problems at hand and develop the optimal solution to that problem, whatever set of skills that might require. This isn''t to say a designers should do everything, but a good designer should know where they or their colleagues can deliver more value more efficiently and coordinate their role appropriately. In this case, there''s numerous clear benefits to the designer building the frontend templates themselves.</p>\n<h2 id="tighteningthefeedbackloop">Tightening the Feedback Loop</h2>\n<p>Nearly every web designer, myself included, has numerous stories of handing off mockups to a developer only to have the built version look nothing like the mockups that were provided. At the time it''s always easy to rant and criticize the developer, but what else would you expect when you''re handing off the responsibility of implementing the design to someone whose job is only tangentially related to design, and often doesn''t care about the design nearly as much as you do?</p>\n<p>This is by no means meant to criticize developers, but instead quite the opposite as I suspect a very similar problem would arise if the situation were reversed and developers gave designers specs to implement a new a feature. It might “work” in the designer’s eyes, but any experienced developer would likely cringe during the code review. Instead, a developer''s job should be to build complex features and applications, not to fret over a few pixels here, a font weight there, and the crazy nuances of cross-browser CSS — that''s the designer''s job, and it makes infinitely more sense for the designer to be able to tweak those nuances directly rather than hunting down, bothering, and distracting a developer from their own responsibilities.</p>\n<p>In reading a great Medium article by David Cole<sup class="footnote-ref"><a href="#fn1" id="fnref1:4">[1:4]</a></sup> I came across a rather strong quote from Jennifer Tidwell<sup class="footnote-ref"><a href="#fn1" id="fnref1:5">[1:5]</a></sup>:</p>\n<blockquote>\n<p>So there’s lots of good stuff to learn before you can create production-quality software systems. But here’s what I worry about: it takes years to learn it well, and this is what a lot of good software engineers do for 50+ hours per week, building knowledge and picking up new skills. Practice, practice, practice.<br /><br />Hey, designer. Can you afford to invest those years?</p>\n</blockquote>\n<p>Cole goes on to dispute Tidwell by arguing that tools built for designers will help alleviate that learning curve, which while true to a certain degree, I think it misses the larger point at hand.</p>\n<p>Designers don''t need to practice 50 hours/week on development because the skills they need to cover design responsibilities aren''t nearly as broad as your typical developer. Designers don''t need to build a full javascript single page app (SPA) or an efficient Rails API to implement their designs effectively<sup class="footnote-ref"><a href="#fn1" id="fnref1:6">[1:6]</a></sup>; instead, they need to be able to work with primarily HTML and CSS (or SASS/LESS/etc), to build code-based static templates of their designs that can then (if needed) be taken by a developer and integrated into a larger application.</p>\n<p>A developer who isn''t trained in design nor practices it on a daily basis isn''t going to notice the minute pixel differences a designer does, and being able to directly and immediately make those changes yourself helps tighten the designer/developer feedback loop in a way that pawning off frontend development responsibilities will never be able to match. Instead of a 12+ step process of delayed designer-developer communication, it instead becomes something more akin to:</p>\n<ol>\n<li>Wireframes + Mockups</li>\n<li>Build HTML rapid prototypes to test design elements.</li>\n<li>Build templates from mockups, making edits and adjustments as needed along the way.</li>\n<li>Iterate.</li>\n<li>Hand off templates to developer.</li>\n</ol>\n<p>This not only makes for a much faster iteration cycle, but results in both a better end-product and frees up developers time so they can focus on building features rather than making small design tweaks. Additionally, any time you''re discussing changes to an existing site with your product manager or management, rather than going through the full gambit of producing an updated mockup and iterating with your developer, you can instead often fire up Chrome Developer Tools or Firebug and test out the edits in real time, discuss, and make a fast decision right then and there.</p>\n<h2 id="brieflyonthetopicofcssjavascript">Briefly on the topic of CSS &amp; Javascript</h2>\n<p>CSS itself as a “programming language” is incredibly easy to criticize given it''s problematic cross-browser history<sup class="footnote-ref"><a href="#fn1" id="fnref1:7">[1:7]</a></sup> and inconsistent syntax, but if someone has to deal with its insane idiosyncrasies across half a dozen browsers across dozens of devices with versions dating back at least several years, who better than the one person who <em>really</em> cares enough to fight their way through it all? And realistically, once you''ve used CSS long enough on a regular basis you start to quickly learn the quirks and ins and outs of the language, and how to use it in a way that''s effective and cross-browser friendly.</p>\n<p>To add to the mockup-to-code problem, anyone who has worked both sides of design and front-end development knows that what works in Photoshop/Sketch/[InsertToolHere] almost never perfectly translates 1:1 to what various browsers do, and you always need to make adjustments along the way. The design''s not done until it''s shipped, and trying to freeze it after you deliver some mockups to your development team is only doing the job halfway, and any time you try to lock-in a project that requires creative thinking you''re going to achieve subpar results.</p>\n<p>Regarding javascript, I personally love to learn new things and ended up diving head-first into its dark and magical ecosystem of libraries, frameworks, and package managers that install other package managers. I don''t think this level of javascript knowledge is necessary for the majority of designers, but a minimal level of javascript knowledge goes a long way in communicating some of the finer points of your design. Want to simulate a panel or modal animating into view in a way that requires toggling or modifying style properties? Rather than mocking it up in After Effects or Keynote, you can actually <em>build</em> that animation exactly how you want it the first time around, and not nitpick with a developer about how it''s off by 50ms or how it doesn''t feel “quite right”.</p>\n<h2 id="finalthoughts">Final Thoughts</h2>\n<p>There''s much, <em>much</em> more to be written about on this topic, and I intend to do so over the coming weeks (and probably months). I''ve only begun to scratch the tip of the iceberg in my research efforts, and already I have well over a dozen articles from other designers and developers on the topic. As I continue to write more I might circle back and make adjustments/additions, so if you have something to say on the topic feel free reach out by Googlechat at robertnealan@gmail.com or email me at <a href="mailto:&#x72;&#x6F;&#x62;&#x40;&#x61;&#x74;&#x6F;&#x6D;&#x69;&#x64;&#x65;&#x73;&#x69;&#x67;&#x6E;&#x2E;&#x63;&#x6F;&#x6D;">rob@atomidesign.com</a> — I''d love to chat.</p>\n<hr>\n<p><em>This is the first in a planned series of articles on the topic of being a designer who codes. As I publish additional articles in the series they will appear here accordingly. Cover photo is a screenshot of the <a href="//beta.protonradio.com">Proton Radio Beta</a>, a just publicly launched client work-in-progress.</em></p>\n<hr class="footnotes-sep">\n<section class="footnotes">\n<ol class="footnotes-list">\n<li id="fn1" class="footnote-item"><p>I''m looking at you Internet Explorer 6 through 10... <a href="#fnref1" class="footnote-backref">↩︎</a> <a href="#fnref1:1" class="footnote-backref">↩︎</a> <a href="#fnref1:2" class="footnote-backref">↩︎</a> <a href="#fnref1:3" class="footnote-backref">↩︎</a> <a href="#fnref1:4" class="footnote-backref">↩︎</a> <a href="#fnref1:5" class="footnote-backref">↩︎</a> <a href="#fnref1:6" class="footnote-backref">↩︎</a> <a href="#fnref1:7" class="footnote-backref">↩︎</a></p>\n</li>\n</ol>\n</section>\n<!--kg-card-end: markdown-->', 'Over the past several years the topic of the designer who codes has generated quite the lot of controversy within the tech community. Some camps believe designers shouldn''t distract themselves with code and instead maintain their roots in graphic design as pixel-pushers, while others think that designers should be getting their hands dirty with code down in the trenches alongside their developer cohorts.\n\n\nAs I''ve written on the topic on more than one occasion[1] and non-coincidentally run a ', '__GHOST_URL__/content/images/2016/08/why-designers-should-code-header@2x.jpg', 0, 'post', 'published', 'public', 'all', '2014-05-21 14:59:42', '1', '2016-09-23 04:45:53', '1', '2016-08-22 08:00:00', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('83fca6f526dd4fe894b5204c', 'f46f7af73ab043728b2fd8c99ffce4c8', 'Craft Your First Impression', 'craft-your-first-impression', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"A few weeks ago I received a cold email from a local San Francisco startup called [Mighty Spring](http://www.mightyspring.com) asking me to demo their product. If you work in tech and have an internet presence you get used to receiving these things all the time (and generally saving them to the metaphorical circular filing cabinet[^n], but the simplicity and attention to details in this particular case left such a great first impression that I felt it''s worth sharing.\\n\\n![alt](__GHOST_URL__/content/images/2014/Jun/Screenshot-2014-06-09-13-41-07.png)\\n\\nRight off the bat they address me by name. This might seem like an obvious detail (especially given how easy it is to use mailing list merge tags), but you''d be surprised how emails I receive that even bother to do this much. Even better, he immediately tells me how he happened upon my contact info:\\n\\n\\"I just found your profile on Github...\\"\\n\\nHe''s no longer a stranger who found my email through some shady email list purchase but instead a compadre who at the very least knows the existence of Github – a major nexus of the developer community and something that I maintain a profile for the purpose of people finding my work[^n]. The second half, \\"...and am hoping to get your feedback on my startup, Mighty Spring,\\" doesn''t yet try to sell me on why this startup is going to change my life, but instead appeals to my emotion and ***asks*** for my help. \\n\\n*\\\\*slow clap*\\\\*\\n\\nWith only 21 words they''ve already addressed me by my name, told me how they found me, and asked for my help; and, in the next 33 words they manage to tell me what the startup is, how it''s going to benefit my life, and oh yeah, by the way – it''s free. If this is a product that has any appeal to a potential customer (most people who work full time positions), at this point I have to imagine their only question would be, \\"Why wouldn''t I sign up?\\"\\n\\n####A Little Magic\\nLastly, this isn''t just a normal invite, this is a *beta invite*. That in itself unfortunately isn''t that meaningful since the early days of Gmail save in special circumstances[^n], but again when I clicked the link I didn''t just land up on a signup page, but instead landed on a page that already knew who I am.\\n\\n![Screenshot of Mightyspring.com](__GHOST_URL__/content/images/2014/Jun/Screenshot-2014-06-04-17-46-23.png)\\n\\nAt first I was confused, but then I realized they used the same trick I used to rickroll all my friends back in the day. While the link appears to be https://www.mightspring.com/lumen/, in reality that''s the text of the anchor tag and the real URL is: https://www.mightyspring.com/lumen/?email=robertnealan@gmail.com. This is the oldest trick in the book, but really can add a hint of magic to the experience for those who either don''t code for a living or just aren''t paying that close of attention. It''s the little details that make a big first impression.\\n\\nAll in all, the email took me about 7 seconds to read at a leisurely pace, and I''m already sold on trying it out. While I personally don''t have much use for a passive recruiting given that I''m happily self-employedd at [Atomi Design](http://www.atomidesign.com), I''ll still be giving it a go to see how well they follow through on their promises and whether it''s worth recommending to friends.\\n\\nRemember – you only have one chance to make a first impression, and with this style of email outreach you have the advantage of being able control the situation. Take your time to *craft* your message and test it out before going public. Think it''s good? Wait a day and read it again. Good now? Pitch it to the next person who gets on the elevator and see how they respond. Lastly, be concise. Time is money, and most of us have a severe shortage of time these days. If you send a lengthy essay about your startup chances are most people aren''t going to read it.\\n\\n---\\n\\n[^1]: [Circular Filing Cabinet Reference](http://www.amazon.com/simplehuman-Fingerprint-Proof-Stainless-4-5-Liter-1-2-Gallon/dp/B00203PSRA/ref=lp_3744641_1_5?s=storageorganization&ie=UTF8&qid=1402337013&sr=1-5)</span>\\n[^n]: In reality [my profile](http://github.com/robertnealan) is pretty barren because 99% of my repos end up being private, but let''s ignore that for now.</span>\\n[^n]: I''m looking at you Dribbble...\\n\\n<sup>Thanks owed to [Clement Poisson](http://clement.poisson.me/) for proofreading.</sup>"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>A few weeks ago I received a cold email from a local San Francisco startup called <a href="http://www.mightyspring.com">Mighty Spring</a> asking me to demo their product. If you work in tech and have an internet presence you get used to receiving these things all the time (and generally saving them to the metaphorical circular filing cabinet<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup>, but the simplicity and attention to details in this particular case left such a great first impression that I felt it''s worth sharing.</p>\n<p><img src="__GHOST_URL__/content/images/2014/Jun/Screenshot-2014-06-09-13-41-07.png" alt="alt" loading="lazy"></p>\n<p>Right off the bat they address me by name. This might seem like an obvious detail (especially given how easy it is to use mailing list merge tags), but you''d be surprised how emails I receive that even bother to do this much. Even better, he immediately tells me how he happened upon my contact info:</p>\n<p>&quot;I just found your profile on Github...&quot;</p>\n<p>He''s no longer a stranger who found my email through some shady email list purchase but instead a compadre who at the very least knows the existence of Github – a major nexus of the developer community and something that I maintain a profile for the purpose of people finding my work<sup class="footnote-ref"><a href="#fn1" id="fnref1:1">[1:1]</a></sup>. The second half, &quot;...and am hoping to get your feedback on my startup, Mighty Spring,&quot; doesn''t yet try to sell me on why this startup is going to change my life, but instead appeals to my emotion and <em><strong>asks</strong></em> for my help.</p>\n<p><em>*slow clap</em>*</p>\n<p>With only 21 words they''ve already addressed me by my name, told me how they found me, and asked for my help; and, in the next 33 words they manage to tell me what the startup is, how it''s going to benefit my life, and oh yeah, by the way – it''s free. If this is a product that has any appeal to a potential customer (most people who work full time positions), at this point I have to imagine their only question would be, &quot;Why wouldn''t I sign up?&quot;</p>\n<h4 id="alittlemagic">A Little Magic</h4>\n<p>Lastly, this isn''t just a normal invite, this is a <em>beta invite</em>. That in itself unfortunately isn''t that meaningful since the early days of Gmail save in special circumstances<sup class="footnote-ref"><a href="#fn1" id="fnref1:2">[1:2]</a></sup>, but again when I clicked the link I didn''t just land up on a signup page, but instead landed on a page that already knew who I am.</p>\n<p><img src="__GHOST_URL__/content/images/2014/Jun/Screenshot-2014-06-04-17-46-23.png" alt="Screenshot of Mightyspring.com" loading="lazy"></p>\n<p>At first I was confused, but then I realized they used the same trick I used to rickroll all my friends back in the day. While the link appears to be <a href="https://www.mightspring.com/lumen/">https://www.mightspring.com/lumen/</a>, in reality that''s the text of the anchor tag and the real URL is: <a href="https://www.mightyspring.com/lumen/?email=robertnealan@gmail.com">https://www.mightyspring.com/lumen/?email=robertnealan@gmail.com</a>. This is the oldest trick in the book, but really can add a hint of magic to the experience for those who either don''t code for a living or just aren''t paying that close of attention. It''s the little details that make a big first impression.</p>\n<p>All in all, the email took me about 7 seconds to read at a leisurely pace, and I''m already sold on trying it out. While I personally don''t have much use for a passive recruiting given that I''m happily self-employedd at <a href="http://www.atomidesign.com">Atomi Design</a>, I''ll still be giving it a go to see how well they follow through on their promises and whether it''s worth recommending to friends.</p>\n<p>Remember – you only have one chance to make a first impression, and with this style of email outreach you have the advantage of being able control the situation. Take your time to <em>craft</em> your message and test it out before going public. Think it''s good? Wait a day and read it again. Good now? Pitch it to the next person who gets on the elevator and see how they respond. Lastly, be concise. Time is money, and most of us have a severe shortage of time these days. If you send a lengthy essay about your startup chances are most people aren''t going to read it.</p>\n<hr>\n<p><sup>Thanks owed to <a href="http://clement.poisson.me/">Clement Poisson</a> for proofreading.</sup></p>\n<hr class="footnotes-sep">\n<section class="footnotes">\n<ol class="footnotes-list">\n<li id="fn1" class="footnote-item"><p>I''m looking at you Dribbble... <a href="#fnref1" class="footnote-backref">↩︎</a> <a href="#fnref1:1" class="footnote-backref">↩︎</a> <a href="#fnref1:2" class="footnote-backref">↩︎</a></p>\n</li>\n</ol>\n</section>\n<!--kg-card-end: markdown-->', 'A few weeks ago I received a cold email from a local San Francisco startup called Mighty Spring asking me to demo their product. If you work in tech and have an internet presence you get used to receiving these things all the time (and generally saving them to the metaphorical circular filing cabinet[1], but the simplicity and attention to details in this particular case left such a great first impression that I felt it''s worth sharing.\n\n\n\n\n\nRight off the bat they address me by name. This ', NULL, 0, 'post', 'published', 'public', 'all', '2014-06-05 00:57:54', '1', '2015-01-18 01:07:03', '1', '2014-06-09 18:31:57', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('f38ae1285a6246c9903106a4', 'a44a67a46f6a4ca891d1592f2cf831f8', 'Tools for Designing in the Browser', 'tools-for-designing-in-the-browser', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"This post is intended to be a regularly updated list of tools, articles, and other goodies that help make designing in the browser both easier and more efficient. If you''re currently a designer-developer hopefully you might learn something new of use, while if you''re new to the game hopefully this will get you started off in the right direction. Tools that I currently use are marked with an (\\\\*), while others I have used in the past.\\n\\nHave something you use that think should be here? Email me with a link at rob at atomidesign.com, and I''ll be sure to check it out.\\n\\n*Last updated: June 12, 2014*\\n\\n---\\n\\n####Articles\\n* [5 Good Reasons Why Designers Should Code](http://blog.teamtreehouse.com/5-good-reasons-why-designers-should-code) by Team Treehouse\\n* [Designing With Code](http://www.teehanlax.com/blog/designing-with-code/) by Jeremy Bell @ Teehan + Lax\\n* [Designers Will Code](https://medium.com/design-startups/designers-will-code-6c423fc5ccef) by David Cole @ Quora\\n* [The Great Value of the Designer Who Codes](http://www.inc.com/garry-tan/the-great-value-of-the-designer-who-codes.html) by Garry Tan\\n\\n####Browser Inspectors\\n* [Firebug](https://getfirebug.com/)\\n* [Chrome Dev Tools](https://developer.chrome.com/devtools/index) \\\\*\\n\\n####CSS Preprocessors\\n* [Sass](http://sass-lang.com) + [Compass](http://compass-style.org) \\\\*\\n* [LESS](http://lesscss.org)\\n* [Stylus](https://learnboost.github.io/stylus/)\\n* [Myth](http://myth.io/)\\n\\n####Version Control\\n* [Git](http://git-scm.com/) \\\\*\\n* [Subversion](https://subversion.apache.org/)\\n\\n####Full Frontend Frameworks\\n* [Twitter Bootstrap](http://getbootstrap.com)\\n* [Zurb Foundation](http://foundation.zurb.com/)\\n\\n####Grid Systems\\n\\n* [Semantic Grid System](http://semantic.gs) \\\\*\\n* [Unsemantic](http://unsemantic.com/)\\n\\n####Templating Languages\\n* [Handlebars](http://handlebarsjs.com/) \\\\*\\n* [Mustache](https://mustache.github.io/)\\n* [HAML](http://haml.info/) - *Haml is mostly used in Ruby on Rails projects, but serves as a good example for an indentation-based language.*\\n\\n####Development Tools\\n* [MAMP](http://www.mamp.info/en/) \\\\*\\n* [LiveReload](http://livereload.com/)\\n* [CSSRefresh](http://cssrefresh.frebsite.nl/)\\n* [Grunt](http://gruntjs.com/) \\\\*\\n* [Gulp](http://gulpjs.com/)\\n* [Codekit](http://incident57.com/codekit/)\\n* [Faker.js](https://github.com/marak/Faker.js/)\\n* [Lorem Pixel](http://lorempixel.com/) \\\\*\\n\\n\\n####Static Site Generators\\n* [Jekyll](http://jekyllrb.com/)\\n* [Octopress](http://octopress.org/)\\n* [Middleman](http://middlemanapp.com/)\\n\\n\\n####Organized Development Approaches\\n* [OOCSS](http://oocss.org/) \\\\*\\n* [SMACSS](http://smacss.com/)\\n* [BEM](http://bem.info/method/)\\n* [Atomic Design](http://bradfrostweb.com/blog/post/atomic-web-design/) \\\\*"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>This post is intended to be a regularly updated list of tools, articles, and other goodies that help make designing in the browser both easier and more efficient. If you''re currently a designer-developer hopefully you might learn something new of use, while if you''re new to the game hopefully this will get you started off in the right direction. Tools that I currently use are marked with an (*), while others I have used in the past.</p>\n<p>Have something you use that think should be here? Email me with a link at rob at atomidesign.com, and I''ll be sure to check it out.</p>\n<p><em>Last updated: June 12, 2014</em></p>\n<hr>\n<h4 id="articles">Articles</h4>\n<ul>\n<li><a href="http://blog.teamtreehouse.com/5-good-reasons-why-designers-should-code">5 Good Reasons Why Designers Should Code</a> by Team Treehouse</li>\n<li><a href="http://www.teehanlax.com/blog/designing-with-code/">Designing With Code</a> by Jeremy Bell @ Teehan + Lax</li>\n<li><a href="https://medium.com/design-startups/designers-will-code-6c423fc5ccef">Designers Will Code</a> by David Cole @ Quora</li>\n<li><a href="http://www.inc.com/garry-tan/the-great-value-of-the-designer-who-codes.html">The Great Value of the Designer Who Codes</a> by Garry Tan</li>\n</ul>\n<h4 id="browserinspectors">Browser Inspectors</h4>\n<ul>\n<li><a href="https://getfirebug.com/">Firebug</a></li>\n<li><a href="https://developer.chrome.com/devtools/index">Chrome Dev Tools</a> *</li>\n</ul>\n<h4 id="csspreprocessors">CSS Preprocessors</h4>\n<ul>\n<li><a href="http://sass-lang.com">Sass</a> + <a href="http://compass-style.org">Compass</a> *</li>\n<li><a href="http://lesscss.org">LESS</a></li>\n<li><a href="https://learnboost.github.io/stylus/">Stylus</a></li>\n<li><a href="http://myth.io/">Myth</a></li>\n</ul>\n<h4 id="versioncontrol">Version Control</h4>\n<ul>\n<li><a href="http://git-scm.com/">Git</a> *</li>\n<li><a href="https://subversion.apache.org/">Subversion</a></li>\n</ul>\n<h4 id="fullfrontendframeworks">Full Frontend Frameworks</h4>\n<ul>\n<li><a href="http://getbootstrap.com">Twitter Bootstrap</a></li>\n<li><a href="http://foundation.zurb.com/">Zurb Foundation</a></li>\n</ul>\n<h4 id="gridsystems">Grid Systems</h4>\n<ul>\n<li><a href="http://semantic.gs">Semantic Grid System</a> *</li>\n<li><a href="http://unsemantic.com/">Unsemantic</a></li>\n</ul>\n<h4 id="templatinglanguages">Templating Languages</h4>\n<ul>\n<li><a href="http://handlebarsjs.com/">Handlebars</a> *</li>\n<li><a href="https://mustache.github.io/">Mustache</a></li>\n<li><a href="http://haml.info/">HAML</a> - <em>Haml is mostly used in Ruby on Rails projects, but serves as a good example for an indentation-based language.</em></li>\n</ul>\n<h4 id="developmenttools">Development Tools</h4>\n<ul>\n<li><a href="http://www.mamp.info/en/">MAMP</a> *</li>\n<li><a href="http://livereload.com/">LiveReload</a></li>\n<li><a href="http://cssrefresh.frebsite.nl/">CSSRefresh</a></li>\n<li><a href="http://gruntjs.com/">Grunt</a> *</li>\n<li><a href="http://gulpjs.com/">Gulp</a></li>\n<li><a href="http://incident57.com/codekit/">Codekit</a></li>\n<li><a href="https://github.com/marak/Faker.js/">Faker.js</a></li>\n<li><a href="http://lorempixel.com/">Lorem Pixel</a> *</li>\n</ul>\n<h4 id="staticsitegenerators">Static Site Generators</h4>\n<ul>\n<li><a href="http://jekyllrb.com/">Jekyll</a></li>\n<li><a href="http://octopress.org/">Octopress</a></li>\n<li><a href="http://middlemanapp.com/">Middleman</a></li>\n</ul>\n<h4 id="organizeddevelopmentapproaches">Organized Development Approaches</h4>\n<ul>\n<li><a href="http://oocss.org/">OOCSS</a> *</li>\n<li><a href="http://smacss.com/">SMACSS</a></li>\n<li><a href="http://bem.info/method/">BEM</a></li>\n<li><a href="http://bradfrostweb.com/blog/post/atomic-web-design/">Atomic Design</a> *</li>\n</ul>\n<!--kg-card-end: markdown-->', 'This post is intended to be a regularly updated list of tools, articles, and other goodies that help make designing in the browser both easier and more efficient. If you''re currently a designer-developer hopefully you might learn something new of use, while if you''re new to the game hopefully this will get you started off in the right direction. Tools that I currently use are marked with an (*), while others I have used in the past.\n\n\nHave something you use that think should be here? Email me', NULL, 0, 'post', 'published', 'public', 'all', '2014-06-11 23:52:04', '1', '2014-06-12 22:37:34', '1', '2014-06-12 22:10:04', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('c79cd08dc8cd4ade93b4b3b9', '47701407d77b41a2a4debdad33d112bd', 'Stop Using Stock Imagery', 'stop-using-stock-imagery', '{"version":"0.3.1","ghostVersion":"4.0","markups":[],"atoms":[],"cards":[],"sections":[[1,"p",[[0,[],0,""]]]]}', '', NULL, NULL, 0, 'post', 'draft', 'public', 'all', '2014-06-12 23:56:26', '1', '2016-08-14 14:13:03', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('5d45942fa9404860a04a9e29', 'd40a47cda1d04e60883ef12f19373eba', 'Working Hard or Hardly Working?', 'take-a-break', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"Back in 2012 the New York Times published an incredible op-ed titled \\"The Busy Trap\\" that discussed the state of \\"busy-ness\\" as a status symbol in modern America.\\n\\n>If you live in America in the 21st century you’ve probably had to listen to a lot of people tell you how busy they are. It’s become the default response when you ask anyone how they’re doing: “Busy!” “So busy.” “Crazy busy.” It is, pretty obviously, a boast disguised as a complaint. And the stock response is a kind of congratulation: “That’s a good problem to have,” or “Better than the opposite.”\\n\\nAs someone who has said those exact phrases on too many occasions in the past, the article resonated with where I was in my life two years ago. I vividly recall debating the merits of Kreider''s argument with a close friend then, and since continue to reread the article every several months to remind myself not to fall into the trap of false self-imposed busyness he lays out so clearly. Unfortunately, as someone who''s self-employed (aka a [\\"freelancer\\"](__GHOST_URL__/stop-freelancing/)) this is admittedly easier said than done. While running my own company has continued to be both one of the most rewarding experiences of my life, by its nature it also happens to be one of the most stressful. With the obscene number of responsibilities and roles you''re constantly juggling it''s entirely too easy for life to get out of balance where you find yourself working any minute you''re not asleep.\\n\\nBetween working on projects at [Atomi](http://atomidesign.com), organizing meetups for [Designers Who Code](http://dwc.io), struggling to find time to spend with friends/family, and daydreaming about working on one of my many hopefully side projects I''d like to think I''m legitimately busy. I wish this was the kind of busy the New York Times [talked about](http://opinionator.blogs.nytimes.com/2012/06/30/the-busy-trap/) where you sound like you''re complaining but actually bragging about how much you do, but unfortunately that''s not the case. It''s the other kind - the kind that leaves you feeling unbelievably satisfied but inevitably slowly drains away your energy bit by bit taxing you to the point that one day you wake up to find you don''t have the motivation to leave your bed. The kind that leaves you feeling completely exhausted and burnt out for days, weeks, and sometimes months on end, that leaves you oftentimes lying to yourself, friends, and family about how things or going and how you''re feeling, that makes your overall well-being (and by association your work) suffer. \\n\\nThe kind that causes you to burnout.\\n\\n\\n### Preventing Burnout\\n\\nSo how the question lies in how do you prevent burn out from happening? Most people''s answer would be to \\"do less\\", but if you''re anything like me that usually just makes you feel unproductive and guilty. No, I don''t think you necessarily need to do less, but instead restructure and rethink the way you do and don''t do work. While traditional jobs put emphasis on how many hours you''re at work (but not necessarily actually getting work done), when working for yourself or a small startup you can break this inaccurate and counterproductive measure of value. \\n\\nOne of the best decisions I ever made came on a beautiful anomaly of an 80 degree mid-January day in San Francisco. I was sitting in my local cafe of choice trying to make progress on a project only to finally accept I was getting nowhere, and in my frustration shut my laptop, put my phone on silent, and walked the 3 miles through Golden Gate Park to Ocean Beach and sat myself down on the sand. \\n\\nAt the time it felt like I was cheating my responsibilities as I took a client call looking over the Pacific, but in retrospect it saved me countless hours of lost productivity. I can''t count how many times I''ve stared down a my computer screen trying to \\"push through\\" my exhaustion only to realize in retrospect that the day went entirely to waste and cost productivity to subsequent days as I continued to feel burnt out. \\n\\n####Multi-Day Breaks\\n\\n\\ndo more for your own well-being. Rather than trying to mix your own personal interests into your chaotic work schedule, set aside intentional, focused breaks where you can disconnect from your normal work and concentrate on something entirely different. That \\"something different\\" might a vacation to the mountains, a side project, or a week of nothing but sitting by a pool and reading books, but regardless it''s a break with a clear intent for what you want to achieve.\\n\\nIt''s so easy to say \\"I don''t have time for that right now\\", but unless you can clearly answer to yourself when you will have time then you probably need to make a change.\\n\\n### Leading by Example\\n\\nI often like to pretend I''m immune to burnout, but while my tolerance for long periods of work and stress is higher than most, I do have my limits that I eventually will (and often have) hit. Over the years I''ve gotten more in tune with my own limits, but still every so often I''ll lose track of that creeping exhaustion only to find myself on a multiday Netflix binge.\\n\\nFor that reason I''m going to follow my own advice and take a week following the launch of [Hackbright''s new website](http://hackbrightacademy.com) to make the nightstand for my bedroom that I''ve been talking about for 6 months now (you would not believe how many glasses of water have been kicked over accidentally). It''s a sizable task that will require putting in long hours at the local shop designing and building it, but it''s a focused task that will both get my mind off my day-to-day work while allowing me to experience joy in a hobby I otherwise spend little time enjoying these days.\\n\\nLife is short, take some time to enjoy it."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>Back in 2012 the New York Times published an incredible op-ed titled &quot;The Busy Trap&quot; that discussed the state of &quot;busy-ness&quot; as a status symbol in modern America.</p>\n<blockquote>\n<p>If you live in America in the 21st century you’ve probably had to listen to a lot of people tell you how busy they are. It’s become the default response when you ask anyone how they’re doing: “Busy!” “So busy.” “Crazy busy.” It is, pretty obviously, a boast disguised as a complaint. And the stock response is a kind of congratulation: “That’s a good problem to have,” or “Better than the opposite.”</p>\n</blockquote>\n<p>As someone who has said those exact phrases on too many occasions in the past, the article resonated with where I was in my life two years ago. I vividly recall debating the merits of Kreider''s argument with a close friend then, and since continue to reread the article every several months to remind myself not to fall into the trap of false self-imposed busyness he lays out so clearly. Unfortunately, as someone who''s self-employed (aka a <a href="__GHOST_URL__/stop-freelancing/">&quot;freelancer&quot;</a>) this is admittedly easier said than done. While running my own company has continued to be both one of the most rewarding experiences of my life, by its nature it also happens to be one of the most stressful. With the obscene number of responsibilities and roles you''re constantly juggling it''s entirely too easy for life to get out of balance where you find yourself working any minute you''re not asleep.</p>\n<p>Between working on projects at <a href="http://atomidesign.com">Atomi</a>, organizing meetups for <a href="http://dwc.io">Designers Who Code</a>, struggling to find time to spend with friends/family, and daydreaming about working on one of my many hopefully side projects I''d like to think I''m legitimately busy. I wish this was the kind of busy the New York Times <a href="http://opinionator.blogs.nytimes.com/2012/06/30/the-busy-trap/">talked about</a> where you sound like you''re complaining but actually bragging about how much you do, but unfortunately that''s not the case. It''s the other kind - the kind that leaves you feeling unbelievably satisfied but inevitably slowly drains away your energy bit by bit taxing you to the point that one day you wake up to find you don''t have the motivation to leave your bed. The kind that leaves you feeling completely exhausted and burnt out for days, weeks, and sometimes months on end, that leaves you oftentimes lying to yourself, friends, and family about how things or going and how you''re feeling, that makes your overall well-being (and by association your work) suffer.</p>\n<p>The kind that causes you to burnout.</p>\n<h3 id="preventingburnout">Preventing Burnout</h3>\n<p>So how the question lies in how do you prevent burn out from happening? Most people''s answer would be to &quot;do less&quot;, but if you''re anything like me that usually just makes you feel unproductive and guilty. No, I don''t think you necessarily need to do less, but instead restructure and rethink the way you do and don''t do work. While traditional jobs put emphasis on how many hours you''re at work (but not necessarily actually getting work done), when working for yourself or a small startup you can break this inaccurate and counterproductive measure of value.</p>\n<p>One of the best decisions I ever made came on a beautiful anomaly of an 80 degree mid-January day in San Francisco. I was sitting in my local cafe of choice trying to make progress on a project only to finally accept I was getting nowhere, and in my frustration shut my laptop, put my phone on silent, and walked the 3 miles through Golden Gate Park to Ocean Beach and sat myself down on the sand.</p>\n<p>At the time it felt like I was cheating my responsibilities as I took a client call looking over the Pacific, but in retrospect it saved me countless hours of lost productivity. I can''t count how many times I''ve stared down a my computer screen trying to &quot;push through&quot; my exhaustion only to realize in retrospect that the day went entirely to waste and cost productivity to subsequent days as I continued to feel burnt out.</p>\n<h4 id="multidaybreaks">Multi-Day Breaks</h4>\n<p>do more for your own well-being. Rather than trying to mix your own personal interests into your chaotic work schedule, set aside intentional, focused breaks where you can disconnect from your normal work and concentrate on something entirely different. That &quot;something different&quot; might a vacation to the mountains, a side project, or a week of nothing but sitting by a pool and reading books, but regardless it''s a break with a clear intent for what you want to achieve.</p>\n<p>It''s so easy to say &quot;I don''t have time for that right now&quot;, but unless you can clearly answer to yourself when you will have time then you probably need to make a change.</p>\n<h3 id="leadingbyexample">Leading by Example</h3>\n<p>I often like to pretend I''m immune to burnout, but while my tolerance for long periods of work and stress is higher than most, I do have my limits that I eventually will (and often have) hit. Over the years I''ve gotten more in tune with my own limits, but still every so often I''ll lose track of that creeping exhaustion only to find myself on a multiday Netflix binge.</p>\n<p>For that reason I''m going to follow my own advice and take a week following the launch of <a href="http://hackbrightacademy.com">Hackbright''s new website</a> to make the nightstand for my bedroom that I''ve been talking about for 6 months now (you would not believe how many glasses of water have been kicked over accidentally). It''s a sizable task that will require putting in long hours at the local shop designing and building it, but it''s a focused task that will both get my mind off my day-to-day work while allowing me to experience joy in a hobby I otherwise spend little time enjoying these days.</p>\n<p>Life is short, take some time to enjoy it.</p>\n<!--kg-card-end: markdown-->', 'Back in 2012 the New York Times published an incredible op-ed titled "The Busy Trap" that discussed the state of "busy-ness" as a status symbol in modern America.\n\n\n\n\n\nIf you live in America in the 21st century you’ve probably had to listen to a lot of people tell you how busy they are. It’s become the default response when you ask anyone how they’re doing: “Busy!” “So busy.” “Crazy busy.” It is, pretty obviously, a boast disguised as a complaint. And the stock response is a kind of congra', NULL, 0, 'post', 'draft', 'public', 'all', '2014-06-18 00:16:45', '1', '2016-10-17 10:27:08', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('9bb300c4a88340a19dce3a95', 'b8ddd14fa99d48e6a002af212e4207d1', 'Contact', 'contact', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"Have a project, want to host an event via [Designers Who Code](http://dwc.io), or in ~~San Francisco~~ ~Koh Tao, Thailand~ [South Lake Tahoe, CA](https://www.google.com/maps/place/South+Lake+Tahoe,+CA+96150/@38.9227843,-120.0136198,13z/data=!3m1!4b1!4m5!3m4!1s0x80998589eea54fe1:0xdd1b2f46fb23918e!8m2!3d38.939926!4d-119.9771868) and want to chat over a cup of coffee or beer? \\n\\nFeel free to reach out by Googlechat at &#x72;&#x6F;&#x62;&#x65;&#x72;&#x74;&#x6E;&#x65;&#x61;&#x6C;&#x61;&#x6E;&#x40;&#x67;&#x6D;&#x61;&#x69;&#x6C;&#x2E;&#x63;&#x6F;&#x6D; or email me at <a href=\\"mailto:&#x72;&#x6F;&#x62;&#x40;&#x61;&#x74;&#x6F;&#x6D;&#x69;&#x64;&#x65;&#x73;&#x69;&#x67;&#x6E;&#x2E;&#x63;&#x6F;&#x6D;\\">&#x72;&#x6F;&#x62;&#x40;&#x61;&#x74;&#x6F;&#x6D;&#x69;&#x64;&#x65;&#x73;&#x69;&#x67;&#x6E;&#x2E;&#x63;&#x6F;&#x6D;</a>.\\n<br />\\n<br />\\n<br />\\n<hr />"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>Have a project, want to host an event via <a href="http://dwc.io">Designers Who Code</a>, or in <s>San Francisco</s> ~Koh Tao, Thailand~ <a href="https://www.google.com/maps/place/South+Lake+Tahoe,+CA+96150/@38.9227843,-120.0136198,13z/data=!3m1!4b1!4m5!3m4!1s0x80998589eea54fe1:0xdd1b2f46fb23918e!8m2!3d38.939926!4d-119.9771868">South Lake Tahoe, CA</a> and want to chat over a cup of coffee or beer?</p>\n<p>Feel free to reach out by Googlechat at robertnealan@gmail.com or email me at <a href="mailto:&#x72;&#x6F;&#x62;&#x40;&#x61;&#x74;&#x6F;&#x6D;&#x69;&#x64;&#x65;&#x73;&#x69;&#x67;&#x6E;&#x2E;&#x63;&#x6F;&#x6D;">rob@atomidesign.com</a>.<br>\n<br /><br>\n<br /><br>\n<br /></p>\n<hr /><!--kg-card-end: markdown-->', 'Have a project, want to host an event via Designers Who Code, or in San Francisco ~Koh Tao, Thailand~ South Lake Tahoe, CA and want to chat over a cup of coffee or beer?\n\n\nFeel free to reach out by Googlechat at robertnealan@gmail.com or email me at rob@atomidesign.com.\n\n\n\n\n\n\n\n\n\n', NULL, 0, 'page', 'published', 'public', 'all', '2014-07-09 21:17:12', '1', '2017-05-11 23:21:44', '1', '2014-07-09 21:17:12', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('fd9cf590585944748068e2d2', 'a6b6c052d5144543ae731598b08009fa', 'About', 'about', '{"version":"0.3.1","atoms":[],"cards":[],"markups":[["a"],["a",["href","http://sass-lang.com/"]],["a",["href","http://compass-style.org"]],["a",["href","http://handlebarsjs.com/"]],["a",["href","http://typekit.com"]]],"sections":[[1,"h2",[[0,[],0,"Hi, I''m Robert Nealan, and I''m a currently Denver based nomadic designer + developer working for Oyi Labs."]]],[1,"p",[[0,[],0,"Originally from the Bay Area in California, I stumbled into the tech industry by way of a high school rollercoaster fan-site, followed by freelancing my way through architecture school at Cal Poly San Luis Obispo."]]],[1,"p",[[0,[],0,"I''ve formerly lived in Lake Tahoe, San Francisco, Washington DC, Thailand, and Switzerland. With 28 countries and counting under my belt I''m always daydreaming of the next adventure on the horizon."]]],[1,"p",[[0,[],0,"This blog was designed/built by myself using "],[0,[0],1,"Ghost"],[0,[],0," with a dash of "],[0,[1],1,"SCSS"],[0,[],0," + "],[0,[2],1,"Compass"],[0,[],0,", "],[0,[3],1,"Handlebars"],[0,[],0,", "],[0,[4],1,"Typekit"],[0,[],0,", and a healthy amount of criticism from good friends. Most recently it was upgraded from Ghost v1 to v5 without any headaches (good job Ghost!)."]]],[1,"p",[[0,[],0,"Have a project or just want to chat? Email me at rob@atomidesign.com."]]]],"ghostVersion":"3.0"}', '<h2 id="hi-i-m-robert-nealan-and-i-m-a-currently-denver-based-nomadic-designer-developer-working-for-oyi-labs-">Hi, I''m Robert Nealan, and I''m a currently Denver based nomadic designer + developer working for Oyi Labs.</h2><p>Originally from the Bay Area in California, I stumbled into the tech industry by way of a high school rollercoaster fan-site, followed by freelancing my way through architecture school at Cal Poly San Luis Obispo.</p><p>I''ve formerly lived in Lake Tahoe, San Francisco, Washington DC, Thailand, and Switzerland. With 28 countries and counting under my belt I''m always daydreaming of the next adventure on the horizon.</p><p>This blog was designed/built by myself using <a>Ghost</a> with a dash of <a href="http://sass-lang.com/">SCSS</a> + <a href="http://compass-style.org">Compass</a>, <a href="http://handlebarsjs.com/">Handlebars</a>, <a href="http://typekit.com">Typekit</a>, and a healthy amount of criticism from good friends. Most recently it was upgraded from Ghost v1 to v5 without any headaches (good job Ghost!).</p><p>Have a project or just want to chat? Email me at rob@atomidesign.com.</p>', 'Hi, I''m Robert Nealan, and I''m a currently Denver based nomadic designer + developer working for Oyi Labs.\n\nOriginally from the Bay Area in California, I stumbled into the tech industry by way of a high school rollercoaster fan-site, followed by freelancing my way through architecture school at Cal Poly San Luis Obispo.\n\nI''ve formerly lived in Lake Tahoe, San Francisco, Washington DC, Thailand, and Switzerland. With 28 countries and counting under my belt I''m always daydreaming of the next a', NULL, 0, 'page', 'published', 'public', 'all', '2014-07-09 21:31:22', '1', '2023-07-06 02:00:16', '1', '2014-07-09 21:31:22', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('a06fe7f98b2a4de184041c45', 'bd7b57bb140e4ab5905d498415375a20', 'The Follow Through', 'the-follow-through', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"Play any sport as a kid and you can probably remember your coach constantly ~~screaming~~ encouraging you to \\"work on your follow through\\". Whether you''re swinging a baseball bat, kicking a soccer ball, or shooting a basketball free throw, you can always follow through better. No matter how much you practice, no matter how hard you try, that follow through will never be good enough for any coach worth the title.\\n\\n![49er''s Coach Jim Harbaugh in his usual state](__GHOST_URL__/content/images/2014/Nov/5390067_bin.jpg)\\n<small>San Francisco 49er''s coach Jim Harbaugh in his standard state of being.</small>\\n\\nAs a kid this was often a frustrating experience because you always aimed to reach that level where you were good enough for your coach, but never got there. Looking back now though, it''s clear that''s because the goal of the follow through is not to achieve a specific level of skill, but instead to reach your full potential throughout the entirety of whatever it is you''re doing.\\n\\nAs a designer (or most professional roles) you might be lucky enough to have a mentor, but chances are they aren''t a Harbaugh-style coach yelling over your should while you Photoshop. Instead, once you start working professionally you have to learn to recognize your own weaknesses and circumvent the issues they might cause, hopefully learning to improve along the way.\\n\\nA few months ago I realized that one of my key weaknesses in client projects has been the designer equivalent of the \\"follow through\\".\\n\\nEvery project starts out clean and clear, but at some point or another things start to get fuzzy as the project scope shifts, clients get busy with other tasks, and you as a contractor start focusing energy elsewhere. This taper off is natural and happens in some form or another to most creative jobs — towards the end of a project there''s admittedly much less to be done and chances are high that you''re quickly refocusing your energy on other projects. But, while this process of shifting focuses is a natural part of the design process it doesn''t mean the project you''re phasing has become any less important to you and especially not to your client.\\n\\nWhile you''re dedicating less time and energy towards that project, you need to ensure that you finish it on the same high note as your first meeting that landed you that project - clients will almost always remember and recommend you based on the least common denominator of your work. This doesn''t mean you should necessarily bend over backwards to accomplish every request a client might make (if you did you''d be setting yourself up to undermine your own value and have a project that never ends), but instead regularly communicate and set expectations for yourself and your client making adjustments whenever necessary.\\n\\nYour last impression is equally if not more important than your first – unfortunately, you don''t have the benefit of knowing when that last impression might happen. Treat each impression as though it might be the last and continue to follow through on all things you do until you look back and realize the project at hand already is and has been done."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>Play any sport as a kid and you can probably remember your coach constantly <s>screaming</s> encouraging you to &quot;work on your follow through&quot;. Whether you''re swinging a baseball bat, kicking a soccer ball, or shooting a basketball free throw, you can always follow through better. No matter how much you practice, no matter how hard you try, that follow through will never be good enough for any coach worth the title.</p>\n<p><img src="__GHOST_URL__/content/images/2014/Nov/5390067_bin.jpg" alt="49er''s Coach Jim Harbaugh in his usual state" loading="lazy"><br>\n<small>San Francisco 49er''s coach Jim Harbaugh in his standard state of being.</small></p>\n<p>As a kid this was often a frustrating experience because you always aimed to reach that level where you were good enough for your coach, but never got there. Looking back now though, it''s clear that''s because the goal of the follow through is not to achieve a specific level of skill, but instead to reach your full potential throughout the entirety of whatever it is you''re doing.</p>\n<p>As a designer (or most professional roles) you might be lucky enough to have a mentor, but chances are they aren''t a Harbaugh-style coach yelling over your should while you Photoshop. Instead, once you start working professionally you have to learn to recognize your own weaknesses and circumvent the issues they might cause, hopefully learning to improve along the way.</p>\n<p>A few months ago I realized that one of my key weaknesses in client projects has been the designer equivalent of the &quot;follow through&quot;.</p>\n<p>Every project starts out clean and clear, but at some point or another things start to get fuzzy as the project scope shifts, clients get busy with other tasks, and you as a contractor start focusing energy elsewhere. This taper off is natural and happens in some form or another to most creative jobs — towards the end of a project there''s admittedly much less to be done and chances are high that you''re quickly refocusing your energy on other projects. But, while this process of shifting focuses is a natural part of the design process it doesn''t mean the project you''re phasing has become any less important to you and especially not to your client.</p>\n<p>While you''re dedicating less time and energy towards that project, you need to ensure that you finish it on the same high note as your first meeting that landed you that project - clients will almost always remember and recommend you based on the least common denominator of your work. This doesn''t mean you should necessarily bend over backwards to accomplish every request a client might make (if you did you''d be setting yourself up to undermine your own value and have a project that never ends), but instead regularly communicate and set expectations for yourself and your client making adjustments whenever necessary.</p>\n<p>Your last impression is equally if not more important than your first – unfortunately, you don''t have the benefit of knowing when that last impression might happen. Treat each impression as though it might be the last and continue to follow through on all things you do until you look back and realize the project at hand already is and has been done.</p>\n<!--kg-card-end: markdown-->', 'Play any sport as a kid and you can probably remember your coach constantly screaming encouraging you to "work on your follow through". Whether you''re swinging a baseball bat, kicking a soccer ball, or shooting a basketball free throw, you can always follow through better. No matter how much you practice, no matter how hard you try, that follow through will never be good enough for any coach worth the title.\n\n\n\n\nSan Francisco 49er''s coach Jim Harbaugh in his standard state of being.\n\n\nAs', NULL, 0, 'post', 'draft', 'public', 'all', '2014-07-22 00:13:32', '1', '2014-12-17 01:23:38', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('f5223a8a1cb34da1890cc032', '0547896309714ab58faa3a5d5def60d1', 'A Temporary Life''s Work', 'nothing-lasts-forever', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"Nearly everyone wants a legacy, yet very few of us will actually have one. \\n\\nAs someone who studied architecture in the 21st century, I knew I''d be lucky if anything I designed stuck around for more than fifty years. As a web designer I consider myself lucky if a project sticks around for more than two.\\n\\nMost web designers have experienced that moment where you later revisit a client''s site and its been modified in one or more ways with which you disagree. Maybe it''s just a minor visual change or maybe the entire layout has been butchered to the point of being unrecognizable, but regardless it''s always a surprise to see something you poured your heart & soul into be different from when you last left it.\\n\\nFor most of my career I''ve fortunate to only have a few smaller projects be taken down or replaced, most of which I didn''t mind given they were early projects done in college. Recently however, I went to demo a project from 2012 to a prospective client only to find that it had been entirely replaced. Not modified, not redesigned, but the entire design/framework, 3+ months, and five figures worth of their budget thrown out for unknown reasons.\\n\\nJust try not to think about how your life''s work would be moot if a big enough solar flare fries our computers and electric grid."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>Nearly everyone wants a legacy, yet very few of us will actually have one.</p>\n<p>As someone who studied architecture in the 21st century, I knew I''d be lucky if anything I designed stuck around for more than fifty years. As a web designer I consider myself lucky if a project sticks around for more than two.</p>\n<p>Most web designers have experienced that moment where you later revisit a client''s site and its been modified in one or more ways with which you disagree. Maybe it''s just a minor visual change or maybe the entire layout has been butchered to the point of being unrecognizable, but regardless it''s always a surprise to see something you poured your heart &amp; soul into be different from when you last left it.</p>\n<p>For most of my career I''ve fortunate to only have a few smaller projects be taken down or replaced, most of which I didn''t mind given they were early projects done in college. Recently however, I went to demo a project from 2012 to a prospective client only to find that it had been entirely replaced. Not modified, not redesigned, but the entire design/framework, 3+ months, and five figures worth of their budget thrown out for unknown reasons.</p>\n<p>Just try not to think about how your life''s work would be moot if a big enough solar flare fries our computers and electric grid.</p>\n<!--kg-card-end: markdown-->', 'Nearly everyone wants a legacy, yet very few of us will actually have one.\n\n\nAs someone who studied architecture in the 21st century, I knew I''d be lucky if anything I designed stuck around for more than fifty years. As a web designer I consider myself lucky if a project sticks around for more than two.\n\n\nMost web designers have experienced that moment where you later revisit a client''s site and its been modified in one or more ways with which you disagree. Maybe it''s just a minor visual c', NULL, 0, 'post', 'draft', 'public', 'all', '2014-11-14 19:02:05', '1', '2016-02-18 07:10:50', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('8b9b27ce72a245c2a6ccad65', '45edb86621c9490ea7727db6959f0fe2', 'Suspend Disbelief', 'when-in-doubt-do', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"Everyone encounters their own equivalent of writer''s block at different points in their work — you find yourself sitting there staring at whatever it is you''re supposed to be working on, struggling to find the perfect solution to the problem at hand.\\n\\nThe actual solution?\\n\\nAs an old architecture professor once told my class of 18 tired and confused college students, \\"Suspend disbelief.\\"\\n\\nAt the time we had no idea what he was talking about, which had already become the norm. Looking back he definitely didn''t have all the answers, didn''t play the role of professor \\"know-it-all\\", and when you asked for advice you generally walked away more confused, but despite that everyone in our studio individually produced a volume of work that rivaled what we produced the rest of our college years.\\n\\nMost of it wasn''t worth keeping. Hell, well over half of it was trash, but in the process of making, creating, and being unbelievably confused we''d find small insights that we never would have discovered otherwise. Our professor spoke in riddles, going so far as to give us advice that he didn''t quite understand himself in the hope that we might derive our own meaning for ourselves, not because he told us the \\"right answer\\".\\n\\nSo what does it mean to \\"suspend disbelief\\"? Quite honestly, I''m still figuring that out, as demands to our professor to explain it only turned up answers of, \\"I have no idea.\\" A quick search turns up the Wikipedia article that references the \\"suspension of disbelief\\", a notion in storytelling that your audience will often disregard unbelievable notions or details for the sake of story''s integrity."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>Everyone encounters their own equivalent of writer''s block at different points in their work — you find yourself sitting there staring at whatever it is you''re supposed to be working on, struggling to find the perfect solution to the problem at hand.</p>\n<p>The actual solution?</p>\n<p>As an old architecture professor once told my class of 18 tired and confused college students, &quot;Suspend disbelief.&quot;</p>\n<p>At the time we had no idea what he was talking about, which had already become the norm. Looking back he definitely didn''t have all the answers, didn''t play the role of professor &quot;know-it-all&quot;, and when you asked for advice you generally walked away more confused, but despite that everyone in our studio individually produced a volume of work that rivaled what we produced the rest of our college years.</p>\n<p>Most of it wasn''t worth keeping. Hell, well over half of it was trash, but in the process of making, creating, and being unbelievably confused we''d find small insights that we never would have discovered otherwise. Our professor spoke in riddles, going so far as to give us advice that he didn''t quite understand himself in the hope that we might derive our own meaning for ourselves, not because he told us the &quot;right answer&quot;.</p>\n<p>So what does it mean to &quot;suspend disbelief&quot;? Quite honestly, I''m still figuring that out, as demands to our professor to explain it only turned up answers of, &quot;I have no idea.&quot; A quick search turns up the Wikipedia article that references the &quot;suspension of disbelief&quot;, a notion in storytelling that your audience will often disregard unbelievable notions or details for the sake of story''s integrity.</p>\n<!--kg-card-end: markdown-->', 'Everyone encounters their own equivalent of writer''s block at different points in their work — you find yourself sitting there staring at whatever it is you''re supposed to be working on, struggling to find the perfect solution to the problem at hand.\n\n\nThe actual solution?\n\n\nAs an old architecture professor once told my class of 18 tired and confused college students, "Suspend disbelief."\n\n\nAt the time we had no idea what he was talking about, which had already become the norm. Looking ', NULL, 0, 'post', 'draft', 'public', 'all', '2015-01-12 20:04:10', '1', '2015-09-14 18:01:48', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('ffef25ffc48342688f3c69e5', '7948a2afaa874177abcfededdde9e81c', 'Death by Inertial Scrolling', 'death-by-inertial-scrolling', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"Every year there''s a few design trends on the web that make their rounds. Some are recognized as good design patterns and persist while others gradually fade out. Thankfully most of these trends are tacky and cringeworthy at worst (web 2.0 rounded glossy buttons anybody?), but every so often there''s one that''s just so downright awful, so downright evil, that when I cross paths with it I can inevitably be witnessed at public cafes twitching and muttering swear words under my breath.\\n\\nCurrently that cardinal sin of a trend I continue to encounter is the introduction of javascript controlled accelerated scrolling on non-touch devices.\\n\\nIf you''re not sure what I''m talking about then hop over to [writefullapp.com](http://writefullapp.com) and try scrolling with either your laptop''s touchpad or a mouse scroll wheel. You should notice that it''s going a bit faster than normal and has a bit of a slingshot effect. This is what I''m referring to with accelerated scrolling. Rather than letting the browser treat scrolling like it does on 99.99% of other websites, a javascript library hijacks the scrolling action to create a *supposedly* more natural scroll that has inertial momentum.\\n\\nSo why is this bad?\\n\\nBecause good design should make a user''s experience as fluid and effortless as possible. We''re trained to expect certain differences in website''s designs, but at the core of our browsing experience we assume that the way we interact with them will be done in the same manner. When a new *feature* alters a basic interaction in an unexpected and inconsistent way, it requires heavy concentration from the end user that almost inevitably causes confusion and frustration.\\n\\nThis isn''t to say that inertial scrolling is a bad idea in and of itself — Windows could take a cue from OSX on that point — but it''s only good when it''s done in a way that both feels natural and is implemented system (or potentially application) wide.\\n\\nI''m all for new features that enhance our experience on the web, even when it''s ahead of the curve regarding browser support, but this new trend is definitely not one of them."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>Every year there''s a few design trends on the web that make their rounds. Some are recognized as good design patterns and persist while others gradually fade out. Thankfully most of these trends are tacky and cringeworthy at worst (web 2.0 rounded glossy buttons anybody?), but every so often there''s one that''s just so downright awful, so downright evil, that when I cross paths with it I can inevitably be witnessed at public cafes twitching and muttering swear words under my breath.</p>\n<p>Currently that cardinal sin of a trend I continue to encounter is the introduction of javascript controlled accelerated scrolling on non-touch devices.</p>\n<p>If you''re not sure what I''m talking about then hop over to <a href="http://writefullapp.com">writefullapp.com</a> and try scrolling with either your laptop''s touchpad or a mouse scroll wheel. You should notice that it''s going a bit faster than normal and has a bit of a slingshot effect. This is what I''m referring to with accelerated scrolling. Rather than letting the browser treat scrolling like it does on 99.99% of other websites, a javascript library hijacks the scrolling action to create a <em>supposedly</em> more natural scroll that has inertial momentum.</p>\n<p>So why is this bad?</p>\n<p>Because good design should make a user''s experience as fluid and effortless as possible. We''re trained to expect certain differences in website''s designs, but at the core of our browsing experience we assume that the way we interact with them will be done in the same manner. When a new <em>feature</em> alters a basic interaction in an unexpected and inconsistent way, it requires heavy concentration from the end user that almost inevitably causes confusion and frustration.</p>\n<p>This isn''t to say that inertial scrolling is a bad idea in and of itself — Windows could take a cue from OSX on that point — but it''s only good when it''s done in a way that both feels natural and is implemented system (or potentially application) wide.</p>\n<p>I''m all for new features that enhance our experience on the web, even when it''s ahead of the curve regarding browser support, but this new trend is definitely not one of them.</p>\n<!--kg-card-end: markdown-->', 'Every year there''s a few design trends on the web that make their rounds. Some are recognized as good design patterns and persist while others gradually fade out. Thankfully most of these trends are tacky and cringeworthy at worst (web 2.0 rounded glossy buttons anybody?), but every so often there''s one that''s just so downright awful, so downright evil, that when I cross paths with it I can inevitably be witnessed at public cafes twitching and muttering swear words under my breath.\n\n\nCurrentl', NULL, 0, 'post', 'published', 'public', 'all', '2015-02-16 17:20:04', '1', '2015-02-16 22:47:57', '1', '2015-02-16 22:21:20', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('c717d351b5cc4aa0b2718ac0', '7678783b87d140bc971422511ab5987e', 'Pricing Your First Client Projects', 'freelancer-pricing', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"##Getting Started\\n\\nI [regretfully] remember my first clients like they were yesterday. It was my third year of college, and a former professor had recently approached me about building a website for one of his many side projects in exchange for a unit of course credit; and being insane with 21 units of other courses, I agreed.\\n\\nAt the time I''d barely even call myself a \\"script kiddie\\". I''d customized my Myspace profile once upon a time and helped a friend manage our group''s rollercoaster website, but had never modified anything as simple as HTML let alone built a website from scratch. Thankfully, this was a professor who would regularly assign architecture projects with a 24 hour deadline requiring us to use 3d modeling programs and tools we''d never used before without any tutorial or explanation, so being in over my head was nothing new.\\n\\nAfter 2 months of reading and re-reading mediocre websites like W3Schools, copying verbatim entirely too many random snippets of Javascript from shady forums, making a vague attempt at learning proper CSS, and learning to hate IE6 like it was Satan incarnate, I managed to scrape together a half respectable website and collect my unit of architecture credit. While I still have no idea where he heard that I knew \\"web stuff\\", it was ultimately this never-to-be-used project that sparked the idea that I might just be able to turn this \\"web stuff\\" into a job.\\n\\nSo what''s a college student to do? I fired up the world-wide-web and instantly navigated to the Computer Gigs section of Craigslist...a mistake I''d later learn to regret.\\n\\n##Client Negotiations\\n\\nFast forward a week and I had my first potential client, a local jewelry maker who I''ll call \\"Sam\\". We''d conversed by email several times, and having gathered that she wanted a website to show off her jewelry we took the next step of connecting by phone.\\n\\nDoing my best not to stutter or sound clueless, we talked about her background in jewelry design, what she was looking for in a website, and how long I thought the project would take. Apparently I managed to not sound entirely incompetent because she wanted to meet at her house the next day to go over the project in detail, but first asked the question I''d dreaded hearing, \\"How much do you charge hourly?\\"\\n\\nLike most freelancers just getting started, I had no idea how much I was worth and decided to base my rate on what I made at my day job. Having once read somewhere that its better to start high in negotiations involving money, I opted to be ambitious and add an extra $5/hr to the price anticipating that Sam would try to negotiate it down to $10/hr (a price I was more than willing to accept if it meant I could spend less time in the campus cafeteria).\\n\\nSo after a pause long enough for my palms to start sweating I nervously replied, \\"Fifteen dollars per hour...\\"\\n\\n\\"Sounds great! See you tomorrow.\\"\\n\\n_...sigh of relief._\\n\\nI''d made it. Not only had someone agreed to pay me, but they agreed to pay me 50% more than I''d been actually aiming! While $15/hr was the most I''d ever made up until that point, I later learned that it was easily half market rate for someone with minimal skills and didn''t take into account  the healthcare, taxes, or any of the myriad of costs an employer typically covers.\\n\\n\\n, a move that doesn''t take into account healthcare, job security, paying your own taxes out of pocket, and so on. At the time it was just extra money, and compared to my day job serving tacos it seemed like I was on the path to the good life.\\n\\n\\nAlmost all freelancers remember the moment when they set a meeting with their first potential client, nervously dreading the moment they meet in person and that client sees straight through the charade of confidence \\nProbably more than you think.\\n\\n\\n\\nOn a few occasions I''ve met a few consultants with rates so mind-bogglingly high that at first you want to shake their hand in the hope you''ll absorb some of their voodoo magic - that is until you realize their secret to success is generally a combination of hard work and being good at business (which realistically doesn''t necessarily correlate to being good at the skills they''re selling).\\n\\nUnfortunately, I more often than not I meet talented freelancers billing so low that it''s borderline insulting to themselves.\\n\\n\\n###Common Excuses\\n\\n\\"But I''m just getting started.\\"\\n\\nDoesn''t matter.\\n\\nWhy? Because you''re building someone else''s company. You''re not someone being hired as a full time employee with job security[^n], you''re an outside consultant being brought in for your expertise to fix your client''s problem.\\n\\nFrequently, beginner or not, you might be the very backbone of the company you''re being contracted by — without you that company might realistically not ea.\\n\\n###A Real Life Example\\n\\nMost recently a friend came to me asking how much he should charge to skin a landing page for a client, posing amounts in the range of \\"$1-1.5k?\\" Upon skeptical glances (aka chat messages) he revised this to a \\"$2-2.5k?\\" \\n\\nSounds pretty good for a few days of work, right?\\n\\nLet''s step back. Skinning a single landing page sounds like a simple request but there were a few caveats — for starters it''s Thursday and it needs to be launched by Monday, so he''d undoubtedly be working both nights and the weekend. Second, while designs would be provided to some degree, he''d be improvising most of it as the landing page is built out.\\n\\nWhile a few grand for a small project sounds like a lot, I posed it in a different frame.\\n\\nFirst, he''s a designer AND Rails developer, so fair market value at a full time job would easily be north of six figures - let''s say $120,000/year for simplicity''s sake (sounds like a lot but $2,000+/month rents in San Francisco say otherwise). So at $120k/year he''d make $10,000/month or $2,500 per five days of work (pretax, again for simplicity''s sake).\\n\\nSo for those 4-5 days of work \\"$2-2.5k\\" sounds relatively fair, _except_ that commonly accepted consulting practice says to minimum double your full time salary value when you charge\\n\\nI''ve personally witnessed multiple situations (and heard many more) where the person or team behind a project hid so deeply behind the client''s lack of knowledge that it made Ponzi Scheme''s seem honest. If you''re someone that the client can trust not to just get the job done, but get the job done right and flat out say \\"this isn''t good enough\\" when it isn''t, then that''s one more notch that''ll pay off in the long run.\\n\\n[^n] Job security: A bit of an amusing joke in the modern \\"work-for-hire\\" employment environment, but on average admittedly still more stable than moving from client to client and all the business overhead involved."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><h2 id="gettingstarted">Getting Started</h2>\n<p>I [regretfully] remember my first clients like they were yesterday. It was my third year of college, and a former professor had recently approached me about building a website for one of his many side projects in exchange for a unit of course credit; and being insane with 21 units of other courses, I agreed.</p>\n<p>At the time I''d barely even call myself a &quot;script kiddie&quot;. I''d customized my Myspace profile once upon a time and helped a friend manage our group''s rollercoaster website, but had never modified anything as simple as HTML let alone built a website from scratch. Thankfully, this was a professor who would regularly assign architecture projects with a 24 hour deadline requiring us to use 3d modeling programs and tools we''d never used before without any tutorial or explanation, so being in over my head was nothing new.</p>\n<p>After 2 months of reading and re-reading mediocre websites like W3Schools, copying verbatim entirely too many random snippets of Javascript from shady forums, making a vague attempt at learning proper CSS, and learning to hate IE6 like it was Satan incarnate, I managed to scrape together a half respectable website and collect my unit of architecture credit. While I still have no idea where he heard that I knew &quot;web stuff&quot;, it was ultimately this never-to-be-used project that sparked the idea that I might just be able to turn this &quot;web stuff&quot; into a job.</p>\n<p>So what''s a college student to do? I fired up the world-wide-web and instantly navigated to the Computer Gigs section of Craigslist...a mistake I''d later learn to regret.</p>\n<h2 id="clientnegotiations">Client Negotiations</h2>\n<p>Fast forward a week and I had my first potential client, a local jewelry maker who I''ll call &quot;Sam&quot;. We''d conversed by email several times, and having gathered that she wanted a website to show off her jewelry we took the next step of connecting by phone.</p>\n<p>Doing my best not to stutter or sound clueless, we talked about her background in jewelry design, what she was looking for in a website, and how long I thought the project would take. Apparently I managed to not sound entirely incompetent because she wanted to meet at her house the next day to go over the project in detail, but first asked the question I''d dreaded hearing, &quot;How much do you charge hourly?&quot;</p>\n<p>Like most freelancers just getting started, I had no idea how much I was worth and decided to base my rate on what I made at my day job. Having once read somewhere that its better to start high in negotiations involving money, I opted to be ambitious and add an extra $5/hr to the price anticipating that Sam would try to negotiate it down to $10/hr (a price I was more than willing to accept if it meant I could spend less time in the campus cafeteria).</p>\n<p>So after a pause long enough for my palms to start sweating I nervously replied, &quot;Fifteen dollars per hour...&quot;</p>\n<p>&quot;Sounds great! See you tomorrow.&quot;</p>\n<p><em>...sigh of relief.</em></p>\n<p>I''d made it. Not only had someone agreed to pay me, but they agreed to pay me 50% more than I''d been actually aiming! While $15/hr was the most I''d ever made up until that point, I later learned that it was easily half market rate for someone with minimal skills and didn''t take into account  the healthcare, taxes, or any of the myriad of costs an employer typically covers.</p>\n<p>, a move that doesn''t take into account healthcare, job security, paying your own taxes out of pocket, and so on. At the time it was just extra money, and compared to my day job serving tacos it seemed like I was on the path to the good life.</p>\n<p>Almost all freelancers remember the moment when they set a meeting with their first potential client, nervously dreading the moment they meet in person and that client sees straight through the charade of confidence<br>\nProbably more than you think.</p>\n<p>On a few occasions I''ve met a few consultants with rates so mind-bogglingly high that at first you want to shake their hand in the hope you''ll absorb some of their voodoo magic - that is until you realize their secret to success is generally a combination of hard work and being good at business (which realistically doesn''t necessarily correlate to being good at the skills they''re selling).</p>\n<p>Unfortunately, I more often than not I meet talented freelancers billing so low that it''s borderline insulting to themselves.</p>\n<h3 id="commonexcuses">Common Excuses</h3>\n<p>&quot;But I''m just getting started.&quot;</p>\n<p>Doesn''t matter.</p>\n<p>Why? Because you''re building someone else''s company. You''re not someone being hired as a full time employee with job security[^n], you''re an outside consultant being brought in for your expertise to fix your client''s problem.</p>\n<p>Frequently, beginner or not, you might be the very backbone of the company you''re being contracted by — without you that company might realistically not ea.</p>\n<h3 id="areallifeexample">A Real Life Example</h3>\n<p>Most recently a friend came to me asking how much he should charge to skin a landing page for a client, posing amounts in the range of &quot;$1-1.5k?&quot; Upon skeptical glances (aka chat messages) he revised this to a &quot;$2-2.5k?&quot;</p>\n<p>Sounds pretty good for a few days of work, right?</p>\n<p>Let''s step back. Skinning a single landing page sounds like a simple request but there were a few caveats — for starters it''s Thursday and it needs to be launched by Monday, so he''d undoubtedly be working both nights and the weekend. Second, while designs would be provided to some degree, he''d be improvising most of it as the landing page is built out.</p>\n<p>While a few grand for a small project sounds like a lot, I posed it in a different frame.</p>\n<p>First, he''s a designer AND Rails developer, so fair market value at a full time job would easily be north of six figures - let''s say $120,000/year for simplicity''s sake (sounds like a lot but $2,000+/month rents in San Francisco say otherwise). So at $120k/year he''d make $10,000/month or $2,500 per five days of work (pretax, again for simplicity''s sake).</p>\n<p>So for those 4-5 days of work &quot;$2-2.5k&quot; sounds relatively fair, <em>except</em> that commonly accepted consulting practice says to minimum double your full time salary value when you charge</p>\n<p>I''ve personally witnessed multiple situations (and heard many more) where the person or team behind a project hid so deeply behind the client''s lack of knowledge that it made Ponzi Scheme''s seem honest. If you''re someone that the client can trust not to just get the job done, but get the job done right and flat out say &quot;this isn''t good enough&quot; when it isn''t, then that''s one more notch that''ll pay off in the long run.</p>\n<p>[^n] Job security: A bit of an amusing joke in the modern &quot;work-for-hire&quot; employment environment, but on average admittedly still more stable than moving from client to client and all the business overhead involved.</p>\n<!--kg-card-end: markdown-->', 'Getting Started\n\n\nI [regretfully] remember my first clients like they were yesterday. It was my third year of college, and a former professor had recently approached me about building a website for one of his many side projects in exchange for a unit of course credit; and being insane with 21 units of other courses, I agreed.\n\n\nAt the time I''d barely even call myself a "script kiddie". I''d customized my Myspace profile once upon a time and helped a friend manage our group''s rollercoaster w', NULL, 0, 'post', 'draft', 'public', 'all', '2015-03-06 01:04:04', '1', '2015-09-17 02:25:34', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('99f74d569fc24f7db4c78bb0', '150a08b9f6514d8cbccee19bf28a2a2c', 'Improving Parking & Pedestrian Life in American CIties', 'radical-sf-proposals-remove-curb-cuts', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"\\nIf you''ve at least visited San Francisco you''re probably readily aware of how much of a pain in the ass it can be to park a car. Sometimes you get lucky, but I can recount many nights spent circling blocks for upwards of 30+ minutes trying to find a spot just ever so slightly large enough that I can squeeze in without destroying someone''s bumper. More often than coming across a spot in-between cars that''s just *ever so slightly too small*, I come across a spot that leaves my bumper questionably close to blocking someone''s driveway, and after paying $500 years ago when a car I parked was (wrongfully) towed, that''s not a risk I''m willing to take.\\n\\nA blog post by a fellow San Francisco resident titled \\"How to Create 100,000 Parking Spots in San Francisco\\" calculated that we could increase our street parking capacity simply by rearranging driveways to be grouped together in more efficient patters - an interesting fact but one that even the author acknowledges as unrealistic. Instead, he suggests that we take driveway placement into account on new construction so as to gradually maintain or increase capacity in the future. It''s by no means a bad idea, but it does little to solve the immediate issue at hand.\\n\\nSo instead of proposing we rearrange driveways, or what''s known as \\"curb cuts\\", I propose that we aim to remove them entirely. Our city''s streets, sidewalks, and parking are all owned by the city and supposed to be for the public good, yet almost 33% of that space is unofficially privatized in a way that makes it unusable by the general public. While larger buildings with private garages likely add a net positive number of parking spaces, I''d be willing to bet that by removing many of the curb cuts for single car garages throughout the city we could both improve the parking situation for those without garages and make our city far more pedestrian friendly."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>If you''ve at least visited San Francisco you''re probably readily aware of how much of a pain in the ass it can be to park a car. Sometimes you get lucky, but I can recount many nights spent circling blocks for upwards of 30+ minutes trying to find a spot just ever so slightly large enough that I can squeeze in without destroying someone''s bumper. More often than coming across a spot in-between cars that''s just <em>ever so slightly too small</em>, I come across a spot that leaves my bumper questionably close to blocking someone''s driveway, and after paying $500 years ago when a car I parked was (wrongfully) towed, that''s not a risk I''m willing to take.</p>\n<p>A blog post by a fellow San Francisco resident titled &quot;How to Create 100,000 Parking Spots in San Francisco&quot; calculated that we could increase our street parking capacity simply by rearranging driveways to be grouped together in more efficient patters - an interesting fact but one that even the author acknowledges as unrealistic. Instead, he suggests that we take driveway placement into account on new construction so as to gradually maintain or increase capacity in the future. It''s by no means a bad idea, but it does little to solve the immediate issue at hand.</p>\n<p>So instead of proposing we rearrange driveways, or what''s known as &quot;curb cuts&quot;, I propose that we aim to remove them entirely. Our city''s streets, sidewalks, and parking are all owned by the city and supposed to be for the public good, yet almost 33% of that space is unofficially privatized in a way that makes it unusable by the general public. While larger buildings with private garages likely add a net positive number of parking spaces, I''d be willing to bet that by removing many of the curb cuts for single car garages throughout the city we could both improve the parking situation for those without garages and make our city far more pedestrian friendly.</p>\n<!--kg-card-end: markdown-->', 'If you''ve at least visited San Francisco you''re probably readily aware of how much of a pain in the ass it can be to park a car. Sometimes you get lucky, but I can recount many nights spent circling blocks for upwards of 30+ minutes trying to find a spot just ever so slightly large enough that I can squeeze in without destroying someone''s bumper. More often than coming across a spot in-between cars that''s just ever so slightly too small, I come across a spot that leaves my bumper questionably cl', NULL, 0, 'post', 'draft', 'public', 'all', '2015-03-26 21:56:54', '1', '2016-01-02 22:25:24', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('3fb8d40c21ff4eb2aefbfdd7', '6ec9927e0751414f939d231066284321', 'Gearing Up for the John Muir Trail', 'gearing-up-for-the-john-muir-trail', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"To those who know me personally it''s no secret that I love a good adventure. Whether it''s traveling in a foreign country or biking across my own, testing your limits by pushing yourself outside your normal comfort zone positively expands your character in a way that no other type of experience can quite compare.\\n\\nHaving gone backpacking for the first time earlier this summer in Paria Canyon (despite having lived out of a tent for several months of the past decade), it only made sense to immediately plan the longest backpacking trip I could manage between projects before the onset of winter''s freezing temperatures, [hopefully] snow in the Sierra Nevadas, and the El Niño-pocalypse that meteorologists are predicting for this year. So with a few months summer to spare, I immediately booked a late-season permit for two on the John Muir Trail and tricked a good friend into take two weeks off work to join me in the adventure — it still amazes me how much of a draw “backpacking the John Muir Trail” has over “backpacking in the mountains for two weeks”.\\n\\nWith the help of numerous other blogs, the JMT facebook group, and a bit of my own intuition I''ve come up with what should stand to be a setup that combines the best of comfort and weight savings as well as some gear that should serve future trips for years to come. Additionally, I''ve included a link to both my original Google Spreadsheet both as filled out by myself and blank for anyone else to use (WIP).\\n\\n\\n\\n<hr />\\n##The Gear\\n\\n*Spreadsheet Last Updated: Sep 14th, 2015 at 4:00PM PST*\\nhttps://docs.google.com/spreadsheets/d/1MQQqY0z0noiJg7CUWhkjYgsABQoRF7-l2W3Ub9ROlEE/edit?usp=sharing\\n\\n###Packing\\n* [Osprey Exos 58 Backpack](http://www.rei.com/product/864669/osprey-exos-58-pack) — *I''ve been nothing but impressed by the weight and comfort of this pack. At 2lbs it''s lighter than almost any other pack in its class but still provides the comforts of an internal frame pack.*\\n* Sea to Summit Medium Dry Cover\\n* [BearVault BV500 Bear Can](http://www.rei.com/product/768902/bearvault-bv500-food-container) — *Light as you could hope for, transparent, and doubles as a pretty sweet campfire chair.*\\n* 1 Osprey Dry Sack\\n* ~~2 Odor Bags~~ A few gallon sized Ziploc Bags\\n\\n###Shelter & Sleeping\\n* [Big Agnes Copper Spur UL1 Tent & Footprint](http://www.rei.com/product/865388/big-agnes-copper-spur-ul-1-tent) — *It was a tossup between this and the Fly Creek, but the CS won out despite the extra ounces primarily due to being freestanding and affording more space for my pack beneath the fly. As a huge bonus, having a side-door is way better than the Fly Creek''s front door in the rain, and gives you the option to sit inside your tent and hang out with your campmates when cold.*\\n* [REI Flash Sleeping Bag](http://www.rei.com/product/862529/rei-flash-sleeping-bag) — *It''s half the cost of any other sleeping bag in its weight/warmth class and packs down small. Only has a 30-degree rating, but I sleep pretty warm and am willing to layer up above 10,000''.*\\n* [Thermarest Z-Lite Foam Sleeping Pad](http://www.rei.com/product/829826/therm-a-rest-z-lite-sol-sleeping-pad) — *Not nearly has comfortable as inflatable sleeping pads, but much lighter and more reliable. Also double''s great as a seating pad outside the tent.*\\n\\n###Survival & Tools\\n* [Black Diamond Ergo Cork Trekking Poles](http://www.rei.com/product/863073/black-diamond-trail-ergo-cork-trekking-poles-pair) — *Usually keep me from toppling over when I''m tired.*\\n* [GSI Cathole Trowel](http://www.rei.com/product/799009/gsi-outdoors-cathole-sanitation-trowel) — *For when nature, gardening, or sand castle building calls.*\\n* [Petzyl Tikka XP Headlamp](http://www.rei.com/product/866989/petzl-tikka-xp-headlamp) — *Runs on AAA batteries for far longer than I would''ve guessed and is blindingly bright on its highest setting.*\\n* Zippo Lighter & Small Box Matches\\n\\n###Clothing & Accessories\\n* [Arc''teryx Cerium LT Hoodie Down Jacket](http://www.backcountry.com/arcteryx-cerium-lt-hooded-down-jacket-mens) — *Keeps me sweating even in freezing weather.*\\n* [Arc''teryx Beta AR Hardshell Jacket](http://www.backcountry.com/arcteryx-beta-ar-jacket-mens) — *The California drought has kept me from putting this to the test, but as with all Arc''teryx gear I doubt I''ll need to worry.*\\n* REI Waterproof Hiking Pants\\n* [Prana Mojo Shorts](http://www.rei.com/product/810264/prana-stretch-zion-shorts-mens) (Worn) — *These are my go-to climbing shorts but double as a pair of extremely comfortable hiking shorts.*\\n* [REI Sahara Shirt](http://www.rei.com/product/863045/rei-sahara-t-shirt-mens) (Worn)\\n* Patagonia Capilene Middle Weight Long Sleeve Baselayer \\n* Vasque Hiking Boots — *I''ve had these for at least 6 years and they''re still rock solid. Never have gotten a single blister nor had a single complaint.*\\n* Patagonia Capilene Heavyweight Baselayer Underwear\\n* [2 pairs Patagonia boxer briefs](http://www.patagonia.com/us/product/mens-capilene-daily-boxer-briefs?p=32477-0) (1 Pair Worn) — *Should stay much cleaner, much longer than cotton underwear.*\\n* 1 Pair Misc über thick alpaca wool socks\\n* [1 Pair REI quarter hiking socks](http://www.rei.com/product/712774/rei-lightweight-merino-wool-hiking-quarter-socks) (Worn)\\n* Rayban Wayfarer Liteforce (Worn) — *Just my polarized sunglasses of choice.*\\n\\n###Cooking & Hydration\\n* [Jetboil Flash](http://www.rei.com/product/791308/jetboil-flash-cooking-system) — *I''ve had this for going on 4 years and bring it anytime I''m camping (even if we have a full stove).*\\n* [Snow Peak Titanium Spork](http://www.amazon.com/Snow-Peak-SCT-004BL-Parent-Titanium-Spork/dp/B00GZJSJ9Y) — *Because.*\\n* [Camelbak 2L Water Bladder](http://www.rei.com/product/812089/camelbak-antidote-reservoir-70-fl-oz)\\n* ~~Nalgene Water Bottle — *If you don''t need/want something as sturdy as a Nalgene Smart Water bottles work great and weigh next to nothing.*~~\\n* ~~[Katydyn Hiker Pro Water Filter](http://www.rei.com/product/830745/katadyn-hiker-pro-water-filter) — *Quick and has a carbon filter that helps improve the taste when filtering impure water.*~~\\n* Sawyer Squeeze w/Smart Water Bottles — *The Katydyn unfortunately broke while on the trail, and after seeing/using several Sawyer Squeeze''s will be switching as soon as I make it to REI.*\\n\\n###Food\\n* [Big Sur Bars](https://bigsurbar.com/shop/) — *A college meal staple from the Central Coast of California. Buy them, you won''t regret it (original & white zest recommended).*\\n* Pro Meal Bars\\n* Justin''s Single Serve Peanut/Hazelnut/Almond Butter — *Ordered in bulk on Amazon.*\\n* Peanut M&M''s\\n* Beef Jerky\\n* Mountain House Meals — *Ordered in bulk online and repacked into ziplock bags to save space.*\\n\\n###Hygiene\\n* Toilet Paper\\n* Toothbrush\\n* Toothpaste\\n* REI Lite Mini Multi Towel — *Amusingly tiny but nonetheless handy in cleaning dishes and/or washing off.*\\n* ~~Dr Bronners Peppermint Soap (4oz)~~ — Realized I had no real use until I got off the trail and left it in the car.\\n\\n###Miscellaneous\\n* Banana Boat SPF50 Sunscreen (4oz) — *Because Irish/Italian/English people were not meant to get tan.*\\n* [Tom Harris JMT Maps](http://www.amazon.com/John-Muir-Trail-Map-Pack-Harrison/dp/1877689343) — *Great maps for great adventures.*\\n* Wallet (Rubber Band, ID, Credit Card, Debit Card)\\n* Ben''s 30% Insect Repellent — *Likely unnecessary in September, but critical for Sierra hiking earlier in May/June/July.*\\n* Duct Tape — *Rewrap some off the roll onto your trekking poles below the handles to save space in your pack.*\\n* iPhone 6 — *Will be off 99% of the time, but useful when we get out of the mountains.*\\n* Misc medical kit (bandages, medicine, etc)"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>To those who know me personally it''s no secret that I love a good adventure. Whether it''s traveling in a foreign country or biking across my own, testing your limits by pushing yourself outside your normal comfort zone positively expands your character in a way that no other type of experience can quite compare.</p>\n<p>Having gone backpacking for the first time earlier this summer in Paria Canyon (despite having lived out of a tent for several months of the past decade), it only made sense to immediately plan the longest backpacking trip I could manage between projects before the onset of winter''s freezing temperatures, [hopefully] snow in the Sierra Nevadas, and the El Niño-pocalypse that meteorologists are predicting for this year. So with a few months summer to spare, I immediately booked a late-season permit for two on the John Muir Trail and tricked a good friend into take two weeks off work to join me in the adventure — it still amazes me how much of a draw “backpacking the John Muir Trail” has over “backpacking in the mountains for two weeks”.</p>\n<p>With the help of numerous other blogs, the JMT facebook group, and a bit of my own intuition I''ve come up with what should stand to be a setup that combines the best of comfort and weight savings as well as some gear that should serve future trips for years to come. Additionally, I''ve included a link to both my original Google Spreadsheet both as filled out by myself and blank for anyone else to use (WIP).</p>\n<hr />\n##The Gear\n<p><em>Spreadsheet Last Updated: Sep 14th, 2015 at 4:00PM PST</em><br>\n<a href="https://docs.google.com/spreadsheets/d/1MQQqY0z0noiJg7CUWhkjYgsABQoRF7-l2W3Ub9ROlEE/edit?usp=sharing">https://docs.google.com/spreadsheets/d/1MQQqY0z0noiJg7CUWhkjYgsABQoRF7-l2W3Ub9ROlEE/edit?usp=sharing</a></p>\n<h3 id="packing">Packing</h3>\n<ul>\n<li><a href="http://www.rei.com/product/864669/osprey-exos-58-pack">Osprey Exos 58 Backpack</a> — <em>I''ve been nothing but impressed by the weight and comfort of this pack. At 2lbs it''s lighter than almost any other pack in its class but still provides the comforts of an internal frame pack.</em></li>\n<li>Sea to Summit Medium Dry Cover</li>\n<li><a href="http://www.rei.com/product/768902/bearvault-bv500-food-container">BearVault BV500 Bear Can</a> — <em>Light as you could hope for, transparent, and doubles as a pretty sweet campfire chair.</em></li>\n<li>1 Osprey Dry Sack</li>\n<li><s>2 Odor Bags</s> A few gallon sized Ziploc Bags</li>\n</ul>\n<h3 id="sheltersleeping">Shelter &amp; Sleeping</h3>\n<ul>\n<li><a href="http://www.rei.com/product/865388/big-agnes-copper-spur-ul-1-tent">Big Agnes Copper Spur UL1 Tent &amp; Footprint</a> — <em>It was a tossup between this and the Fly Creek, but the CS won out despite the extra ounces primarily due to being freestanding and affording more space for my pack beneath the fly. As a huge bonus, having a side-door is way better than the Fly Creek''s front door in the rain, and gives you the option to sit inside your tent and hang out with your campmates when cold.</em></li>\n<li><a href="http://www.rei.com/product/862529/rei-flash-sleeping-bag">REI Flash Sleeping Bag</a> — <em>It''s half the cost of any other sleeping bag in its weight/warmth class and packs down small. Only has a 30-degree rating, but I sleep pretty warm and am willing to layer up above 10,000''.</em></li>\n<li><a href="http://www.rei.com/product/829826/therm-a-rest-z-lite-sol-sleeping-pad">Thermarest Z-Lite Foam Sleeping Pad</a> — <em>Not nearly has comfortable as inflatable sleeping pads, but much lighter and more reliable. Also double''s great as a seating pad outside the tent.</em></li>\n</ul>\n<h3 id="survivaltools">Survival &amp; Tools</h3>\n<ul>\n<li><a href="http://www.rei.com/product/863073/black-diamond-trail-ergo-cork-trekking-poles-pair">Black Diamond Ergo Cork Trekking Poles</a> — <em>Usually keep me from toppling over when I''m tired.</em></li>\n<li><a href="http://www.rei.com/product/799009/gsi-outdoors-cathole-sanitation-trowel">GSI Cathole Trowel</a> — <em>For when nature, gardening, or sand castle building calls.</em></li>\n<li><a href="http://www.rei.com/product/866989/petzl-tikka-xp-headlamp">Petzyl Tikka XP Headlamp</a> — <em>Runs on AAA batteries for far longer than I would''ve guessed and is blindingly bright on its highest setting.</em></li>\n<li>Zippo Lighter &amp; Small Box Matches</li>\n</ul>\n<h3 id="clothingaccessories">Clothing &amp; Accessories</h3>\n<ul>\n<li><a href="http://www.backcountry.com/arcteryx-cerium-lt-hooded-down-jacket-mens">Arc''teryx Cerium LT Hoodie Down Jacket</a> — <em>Keeps me sweating even in freezing weather.</em></li>\n<li><a href="http://www.backcountry.com/arcteryx-beta-ar-jacket-mens">Arc''teryx Beta AR Hardshell Jacket</a> — <em>The California drought has kept me from putting this to the test, but as with all Arc''teryx gear I doubt I''ll need to worry.</em></li>\n<li>REI Waterproof Hiking Pants</li>\n<li><a href="http://www.rei.com/product/810264/prana-stretch-zion-shorts-mens">Prana Mojo Shorts</a> (Worn) — <em>These are my go-to climbing shorts but double as a pair of extremely comfortable hiking shorts.</em></li>\n<li><a href="http://www.rei.com/product/863045/rei-sahara-t-shirt-mens">REI Sahara Shirt</a> (Worn)</li>\n<li>Patagonia Capilene Middle Weight Long Sleeve Baselayer</li>\n<li>Vasque Hiking Boots — <em>I''ve had these for at least 6 years and they''re still rock solid. Never have gotten a single blister nor had a single complaint.</em></li>\n<li>Patagonia Capilene Heavyweight Baselayer Underwear</li>\n<li><a href="http://www.patagonia.com/us/product/mens-capilene-daily-boxer-briefs?p=32477-0">2 pairs Patagonia boxer briefs</a> (1 Pair Worn) — <em>Should stay much cleaner, much longer than cotton underwear.</em></li>\n<li>1 Pair Misc über thick alpaca wool socks</li>\n<li><a href="http://www.rei.com/product/712774/rei-lightweight-merino-wool-hiking-quarter-socks">1 Pair REI quarter hiking socks</a> (Worn)</li>\n<li>Rayban Wayfarer Liteforce (Worn) — <em>Just my polarized sunglasses of choice.</em></li>\n</ul>\n<h3 id="cookinghydration">Cooking &amp; Hydration</h3>\n<ul>\n<li><a href="http://www.rei.com/product/791308/jetboil-flash-cooking-system">Jetboil Flash</a> — <em>I''ve had this for going on 4 years and bring it anytime I''m camping (even if we have a full stove).</em></li>\n<li><a href="http://www.amazon.com/Snow-Peak-SCT-004BL-Parent-Titanium-Spork/dp/B00GZJSJ9Y">Snow Peak Titanium Spork</a> — <em>Because.</em></li>\n<li><a href="http://www.rei.com/product/812089/camelbak-antidote-reservoir-70-fl-oz">Camelbak 2L Water Bladder</a></li>\n<li><s>Nalgene Water Bottle — <em>If you don''t need/want something as sturdy as a Nalgene Smart Water bottles work great and weigh next to nothing.</em></s></li>\n<li><s><a href="http://www.rei.com/product/830745/katadyn-hiker-pro-water-filter">Katydyn Hiker Pro Water Filter</a> — <em>Quick and has a carbon filter that helps improve the taste when filtering impure water.</em></s></li>\n<li>Sawyer Squeeze w/Smart Water Bottles — <em>The Katydyn unfortunately broke while on the trail, and after seeing/using several Sawyer Squeeze''s will be switching as soon as I make it to REI.</em></li>\n</ul>\n<h3 id="food">Food</h3>\n<ul>\n<li><a href="https://bigsurbar.com/shop/">Big Sur Bars</a> — <em>A college meal staple from the Central Coast of California. Buy them, you won''t regret it (original &amp; white zest recommended).</em></li>\n<li>Pro Meal Bars</li>\n<li>Justin''s Single Serve Peanut/Hazelnut/Almond Butter — <em>Ordered in bulk on Amazon.</em></li>\n<li>Peanut M&amp;M''s</li>\n<li>Beef Jerky</li>\n<li>Mountain House Meals — <em>Ordered in bulk online and repacked into ziplock bags to save space.</em></li>\n</ul>\n<h3 id="hygiene">Hygiene</h3>\n<ul>\n<li>Toilet Paper</li>\n<li>Toothbrush</li>\n<li>Toothpaste</li>\n<li>REI Lite Mini Multi Towel — <em>Amusingly tiny but nonetheless handy in cleaning dishes and/or washing off.</em></li>\n<li><s>Dr Bronners Peppermint Soap (4oz)</s> — Realized I had no real use until I got off the trail and left it in the car.</li>\n</ul>\n<h3 id="miscellaneous">Miscellaneous</h3>\n<ul>\n<li>Banana Boat SPF50 Sunscreen (4oz) — <em>Because Irish/Italian/English people were not meant to get tan.</em></li>\n<li><a href="http://www.amazon.com/John-Muir-Trail-Map-Pack-Harrison/dp/1877689343">Tom Harris JMT Maps</a> — <em>Great maps for great adventures.</em></li>\n<li>Wallet (Rubber Band, ID, Credit Card, Debit Card)</li>\n<li>Ben''s 30% Insect Repellent — <em>Likely unnecessary in September, but critical for Sierra hiking earlier in May/June/July.</em></li>\n<li>Duct Tape — <em>Rewrap some off the roll onto your trekking poles below the handles to save space in your pack.</em></li>\n<li>iPhone 6 — <em>Will be off 99% of the time, but useful when we get out of the mountains.</em></li>\n<li>Misc medical kit (bandages, medicine, etc)</li>\n</ul>\n<!--kg-card-end: markdown-->', 'To those who know me personally it''s no secret that I love a good adventure. Whether it''s traveling in a foreign country or biking across my own, testing your limits by pushing yourself outside your normal comfort zone positively expands your character in a way that no other type of experience can quite compare.\n\n\nHaving gone backpacking for the first time earlier this summer in Paria Canyon (despite having lived out of a tent for several months of the past decade), it only made sense to imme', '__GHOST_URL__/content/images/2015/09/jtm-photo-1.jpg', 0, 'post', 'published', 'public', 'all', '2015-08-25 00:59:08', '1', '2016-08-19 06:24:44', '1', '2015-09-14 18:36:56', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('681b13fc353742b286c2fa07', '05e4898592f64706b3a9f35a57fd7cdf', 'Prioritizing Bicycles on the SF Wiggle', 'prioritizing-biking-on-the-sf-wiggle', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"If you live or have biked in San Francisco then there''s a good chance you''re familiar with the aptly-named \\"Wiggle\\" — a designated bicycle route that zigzags up the most shallow route from Market Street to the Panhandle in an attempt to thwart the bicyclist-unfriendly hills littered throughout the city.\\n\\nWhile cyclists are legally entitled to share the road with cars on this route, it remains a long-standing point of conflict between cyclists who believe cars should yield to them, and city drivers who all too often just want to get around cyclists and be on their way.\\n\\nFrom Market Street it dives unprotected across Buchanan St, to a glass and trash strewn bike path behind the Safeway, to a diagonal crossing across a 3-way car and 3-way train intersection (in different directions), only to leave you winding your way through residential streets alongside cars that wish nothing more than to get around you.\\n\\n"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>If you live or have biked in San Francisco then there''s a good chance you''re familiar with the aptly-named &quot;Wiggle&quot; — a designated bicycle route that zigzags up the most shallow route from Market Street to the Panhandle in an attempt to thwart the bicyclist-unfriendly hills littered throughout the city.</p>\n<p>While cyclists are legally entitled to share the road with cars on this route, it remains a long-standing point of conflict between cyclists who believe cars should yield to them, and city drivers who all too often just want to get around cyclists and be on their way.</p>\n<p>From Market Street it dives unprotected across Buchanan St, to a glass and trash strewn bike path behind the Safeway, to a diagonal crossing across a 3-way car and 3-way train intersection (in different directions), only to leave you winding your way through residential streets alongside cars that wish nothing more than to get around you.</p>\n<!--kg-card-end: markdown-->', 'If you live or have biked in San Francisco then there''s a good chance you''re familiar with the aptly-named "Wiggle" — a designated bicycle route that zigzags up the most shallow route from Market Street to the Panhandle in an attempt to thwart the bicyclist-unfriendly hills littered throughout the city.\n\n\nWhile cyclists are legally entitled to share the road with cars on this route, it remains a long-standing point of conflict between cyclists who believe cars should yield to them, and city d', NULL, 0, 'post', 'draft', 'public', 'all', '2015-08-25 17:39:33', '1', '2015-08-28 02:22:04', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('2292ef6bc3d94ef992b7e01e', '1905ed9aab774734b44b7cb254a81834', 'The John Muir Trail', 'the-john-muir-trail-post-mortem', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"I''m trying to think of a better title for this post as \\"post-mortem\\" sounds so morbid, but for now it''ll do.\\n\\nIt''s been just under a week since I exited at the Whitney Portal and already it feels like the trail is a lifetime away as I sit in a busy San Francisco cafe. The sounds of birds and the rumbling breeze has been replaced by cars and people, but as I cradle my fresh cup of ~~artisan~~ coffee I realize all things in life come with tradeoffs.\\n\\nHiking the trail was as as exhausting as I expected in some ways, and far more exhausting in others I didn''t. \\n\\n###Yosemite to Vermillion Valley Resort\\n\\nThe plan was to hike the entire trail with my friend, but as "}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>I''m trying to think of a better title for this post as &quot;post-mortem&quot; sounds so morbid, but for now it''ll do.</p>\n<p>It''s been just under a week since I exited at the Whitney Portal and already it feels like the trail is a lifetime away as I sit in a busy San Francisco cafe. The sounds of birds and the rumbling breeze has been replaced by cars and people, but as I cradle my fresh cup of <s>artisan</s> coffee I realize all things in life come with tradeoffs.</p>\n<p>Hiking the trail was as as exhausting as I expected in some ways, and far more exhausting in others I didn''t.</p>\n<h3 id="yosemitetovermillionvalleyresort">Yosemite to Vermillion Valley Resort</h3>\n<p>The plan was to hike the entire trail with my friend, but as</p>\n<!--kg-card-end: markdown-->', 'I''m trying to think of a better title for this post as "post-mortem" sounds so morbid, but for now it''ll do.\n\n\nIt''s been just under a week since I exited at the Whitney Portal and already it feels like the trail is a lifetime away as I sit in a busy San Francisco cafe. The sounds of birds and the rumbling breeze has been replaced by cars and people, but as I cradle my fresh cup of artisan coffee I realize all things in life come with tradeoffs.\n\n\nHiking the trail was as as exhausting as I ', NULL, 0, 'post', 'draft', 'public', 'all', '2015-10-07 22:21:33', '1', '2016-08-19 06:18:46', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('0fb2cbd5a81649f8b393c249', '6d1084443eb645cfa8988b817ac89424', 'Tips for the JMT', 'tips-for-the-jmt', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"1. Duct Tape — Wrap some around your hiking poles where you won''t notice it. It doesn''t always have an immediate use, but becomes infinitely helpful when the need arises (in my case duct taping my heels to prevent blisters).\\n2. Bring a Tube of super glue — Again one of those indispensable tools when the need arises, specifically any tent/fabric repairs or for quickly sealing any cuts (much faster/better than a bandaid).\\n3"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><ol>\n<li>Duct Tape — Wrap some around your hiking poles where you won''t notice it. It doesn''t always have an immediate use, but becomes infinitely helpful when the need arises (in my case duct taping my heels to prevent blisters).</li>\n<li>Bring a Tube of super glue — Again one of those indispensable tools when the need arises, specifically any tent/fabric repairs or for quickly sealing any cuts (much faster/better than a bandaid).<br>\n3</li>\n</ol>\n<!--kg-card-end: markdown-->', ' 1. Duct Tape — Wrap some around your hiking poles where you won''t notice it. It doesn''t always have an immediate use, but becomes infinitely helpful when the need arises (in my case duct taping my heels to prevent blisters).\n 2. Bring a Tube of super glue — Again one of those indispensable tools when the need arises, specifically any tent/fabric repairs or for quickly sealing any cuts (much faster/better than a bandaid).\n    \n    3\n', NULL, 0, 'post', 'draft', 'public', 'all', '2015-10-07 22:28:08', '1', '2015-10-07 22:31:12', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('25779c2c8ecb49a7a106cebc', 'a4df9639dba84d228c2cceb6df1a6240', 'Apple''s Growing Pains', 'apples-growing-pains-are-showing', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"I''ve owned an Apple laptop since 2007 and an iPhone (mostly_ since 2008. While I love the design and polish of their hardware and their software (generally), I''m also openly critical of them for their mishaps, privacy issues, and business moves that seem to undermine their overall brand. While some friends might think I''m an Apple fanboy, I''d gladly switch to another company if they made a superior product[^n].\\n\\nThat said, while their bank balance and stock prices continue to impress, my recent experiences as a long time customer of theirs continues to make me compare them with the other big corporations I use but dont care for (I''m looking at you Wells Fargo), rather than the hip, helpful, and \\"revolutionary\\" corporation that millions came to love and obsess over.\\n\\n###The Genius Bar\\n\\nDisregarding ridicule of their tech teams ridiculous name, anyone who visited the Genius Bar early on couldn''t argue that they were helpful and got things done. Rather than connecting you with a call center worker on another continent, you were able to walk into a store and talk to someone you could not only relate to, but who sympathized with your issue and gave the impression that they were _on your side_. This didn''t necessarily always result in the problem being fixed in an ideal manner, but when their manager''s manager''s manager denied an out-of-warranty repair request, it felt like they were shafted as much as yourself.\\n\\nNow, the Genius Bar has become a convoluted process of navigating their 10,000 step \\n\\nIn the past it wasn''t uncommon for someone to walk in with a broken laptop and no appointment, and walk out with a brand new laptop an hour later. In my own experience every time my first Macbook Pro (an unfortunate lemon of a machine) had an issue, it was quickly fixed, returned, and then eventually replaced with a brand new top-of-the-line model after several major repairs.\\n\\nNow I find myself making appointments a week out, only to show up on time and be required to wait 20-30 minutes before someone is actually free to tell me that they''ll need to send out my laptop for a 5-7 day repair. While the in-store employees are almost always polite and understanding, the only recommendation they''ve been able to make to my question of \\"how am I supposed to get work done?\\" is to purchase a temporary laptop, which has a 14 day no-questions asked return policy.\\n\\nCoincidentally, I actually did just that earlier this year as an excuse to test out one of their new Macbooks, only to find out that upon returning it they physically remove and shred the hard drive from that machine. I''m all for data security, but wasting an entire hard drive just so I can have a laptop for a week is a level of wastefulness I''m not entirely comfortable taking.\\n\\n###Ballooning Product Lines\\n\\nOne of the many changes Steve Jobs made when he returned to Apple in the early 2000''s was to focus on 4 core projects and shut down all others. It was this level of focus that didn''t just lead to them producing high quality computers, but computers that now have seats in design museums around the world.\\n\\nNow though, I go to Apple''s website or store and am overwhelmed with the breadth of options thrown at me. \\n\\nWhile still not nearly as overwhelming as trying to choose a laptop on Dell or HP''s websites, its a far cry from the 1 iPhone, 3 iPods, 3 Macbooks, and 3 Desktop options they offered 8 years ago.\\n\\nAt the time of my writing there are currently 5 models of iPad for sale in 23 different configurations and 2-3 color variations, 6 Macbook Pros (1 Non-Retina), 4 Macbook Airs (still all Non-Retina), 3 iMacs, 1 Mac Mini\\n\\n[^n]: The Microsoft Surface has been on my radar for some time, but there''s no way I could ever work on a touch-first device all the time. I''ll definitely be trying out the the Surface Book when it comes out, which looks to be extremely promising."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>I''ve owned an Apple laptop since 2007 and an iPhone (mostly_ since 2008. While I love the design and polish of their hardware and their software (generally), I''m also openly critical of them for their mishaps, privacy issues, and business moves that seem to undermine their overall brand. While some friends might think I''m an Apple fanboy, I''d gladly switch to another company if they made a superior product<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup>.</p>\n<p>That said, while their bank balance and stock prices continue to impress, my recent experiences as a long time customer of theirs continues to make me compare them with the other big corporations I use but dont care for (I''m looking at you Wells Fargo), rather than the hip, helpful, and &quot;revolutionary&quot; corporation that millions came to love and obsess over.</p>\n<h3 id="thegeniusbar">The Genius Bar</h3>\n<p>Disregarding ridicule of their tech teams ridiculous name, anyone who visited the Genius Bar early on couldn''t argue that they were helpful and got things done. Rather than connecting you with a call center worker on another continent, you were able to walk into a store and talk to someone you could not only relate to, but who sympathized with your issue and gave the impression that they were <em>on your side</em>. This didn''t necessarily always result in the problem being fixed in an ideal manner, but when their manager''s manager''s manager denied an out-of-warranty repair request, it felt like they were shafted as much as yourself.</p>\n<p>Now, the Genius Bar has become a convoluted process of navigating their 10,000 step</p>\n<p>In the past it wasn''t uncommon for someone to walk in with a broken laptop and no appointment, and walk out with a brand new laptop an hour later. In my own experience every time my first Macbook Pro (an unfortunate lemon of a machine) had an issue, it was quickly fixed, returned, and then eventually replaced with a brand new top-of-the-line model after several major repairs.</p>\n<p>Now I find myself making appointments a week out, only to show up on time and be required to wait 20-30 minutes before someone is actually free to tell me that they''ll need to send out my laptop for a 5-7 day repair. While the in-store employees are almost always polite and understanding, the only recommendation they''ve been able to make to my question of &quot;how am I supposed to get work done?&quot; is to purchase a temporary laptop, which has a 14 day no-questions asked return policy.</p>\n<p>Coincidentally, I actually did just that earlier this year as an excuse to test out one of their new Macbooks, only to find out that upon returning it they physically remove and shred the hard drive from that machine. I''m all for data security, but wasting an entire hard drive just so I can have a laptop for a week is a level of wastefulness I''m not entirely comfortable taking.</p>\n<h3 id="ballooningproductlines">Ballooning Product Lines</h3>\n<p>One of the many changes Steve Jobs made when he returned to Apple in the early 2000''s was to focus on 4 core projects and shut down all others. It was this level of focus that didn''t just lead to them producing high quality computers, but computers that now have seats in design museums around the world.</p>\n<p>Now though, I go to Apple''s website or store and am overwhelmed with the breadth of options thrown at me.</p>\n<p>While still not nearly as overwhelming as trying to choose a laptop on Dell or HP''s websites, its a far cry from the 1 iPhone, 3 iPods, 3 Macbooks, and 3 Desktop options they offered 8 years ago.</p>\n<p>At the time of my writing there are currently 5 models of iPad for sale in 23 different configurations and 2-3 color variations, 6 Macbook Pros (1 Non-Retina), 4 Macbook Airs (still all Non-Retina), 3 iMacs, 1 Mac Mini</p>\n<hr class="footnotes-sep">\n<section class="footnotes">\n<ol class="footnotes-list">\n<li id="fn1" class="footnote-item"><p>The Microsoft Surface has been on my radar for some time, but there''s no way I could ever work on a touch-first device all the time. I''ll definitely be trying out the the Surface Book when it comes out, which looks to be extremely promising. <a href="#fnref1" class="footnote-backref">↩︎</a></p>\n</li>\n</ol>\n</section>\n<!--kg-card-end: markdown-->', 'I''ve owned an Apple laptop since 2007 and an iPhone (mostly_ since 2008. While I love the design and polish of their hardware and their software (generally), I''m also openly critical of them for their mishaps, privacy issues, and business moves that seem to undermine their overall brand. While some friends might think I''m an Apple fanboy, I''d gladly switch to another company if they made a superior product[1].\n\n\nThat said, while their bank balance and stock prices continue to impress, my rece', NULL, 0, 'post', 'draft', 'public', 'all', '2015-10-12 22:24:26', '1', '2015-10-12 23:11:03', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('2b52f370965e438a920c066c', '362811bc00014845a58a812668696494', 'So You Want to Work for Yourself? Here''s What You Need to Know.', 'so-you-want-to-go-freelance', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"Most people seem to have dreamt of working for themselves at some point or another, but given that 70+% of Americans work as an employee for someone else it''s clear that for most people it will always be just that - a dream.\\n\\nBut I don''t blame them, working for yourself is hard work.\\n\\nMoreso than just hard work, it''s a drastic shift in _how_ you spend your time and work compared to a full time 40 hour work week.\\n\\n\\n##Upsides\\n\\n###Freedom and Flexibility\\n\\nThis is generally the number one item that motivates people to work for themselves. Having worked a job with a boss I hated on more than one occasion, there''s nothing like dreaming of the day you''ll be in charge and don''t have to take orders from someone else.\\n\\n###Choose Who You Work For\\n\\n###Rarely (If Ever) Need to Commute\\n\\n\\n##Downsides\\n\\n###You''re a One Man Business\\n\\nThis could be seen as a benefit because you have the freedom to do whatever you want, but whatever you choose you have to take on the work of several roles, many of which you''ll likely not have experience in previously.\\n\\n###Taxes\\n\\nIt''s easy to feel like you''re rolling in the money once you get your first few contracting checks, but you can never forget that this money is so far tax free (but won''t be for long). \\n\\nThe moment you start contracting you''re going to need to be meticulous about your taxes. I don''t mean just saving receipts in a dresser drawer, I mean legally filing as a business entity, opening business bank accounts to separate your finances, recording and categorizing all business purchases, and filing taxes quarterly lest you want to pay the IRS even more fees.\\n\\n\\n\\n###Flexible Schedule\\n\\n###No Office Culture\\n\\n###Extended Periods of Unemployment\\n\\nI''ve personally been lucky enough to never be out of work for more than a week, and in all those circumstances its largely been out of choice (and lack of motivation) as finding new work isn''t immediately necessary.\\n\\n###Benefits\\n\\n###Job Security\\n\\n###Job History\\n\\n"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>Most people seem to have dreamt of working for themselves at some point or another, but given that 70+% of Americans work as an employee for someone else it''s clear that for most people it will always be just that - a dream.</p>\n<p>But I don''t blame them, working for yourself is hard work.</p>\n<p>Moreso than just hard work, it''s a drastic shift in <em>how</em> you spend your time and work compared to a full time 40 hour work week.</p>\n<h2 id="upsides">Upsides</h2>\n<h3 id="freedomandflexibility">Freedom and Flexibility</h3>\n<p>This is generally the number one item that motivates people to work for themselves. Having worked a job with a boss I hated on more than one occasion, there''s nothing like dreaming of the day you''ll be in charge and don''t have to take orders from someone else.</p>\n<h3 id="choosewhoyouworkfor">Choose Who You Work For</h3>\n<h3 id="rarelyifeverneedtocommute">Rarely (If Ever) Need to Commute</h3>\n<h2 id="downsides">Downsides</h2>\n<h3 id="youreaonemanbusiness">You''re a One Man Business</h3>\n<p>This could be seen as a benefit because you have the freedom to do whatever you want, but whatever you choose you have to take on the work of several roles, many of which you''ll likely not have experience in previously.</p>\n<h3 id="taxes">Taxes</h3>\n<p>It''s easy to feel like you''re rolling in the money once you get your first few contracting checks, but you can never forget that this money is so far tax free (but won''t be for long).</p>\n<p>The moment you start contracting you''re going to need to be meticulous about your taxes. I don''t mean just saving receipts in a dresser drawer, I mean legally filing as a business entity, opening business bank accounts to separate your finances, recording and categorizing all business purchases, and filing taxes quarterly lest you want to pay the IRS even more fees.</p>\n<h3 id="flexibleschedule">Flexible Schedule</h3>\n<h3 id="noofficeculture">No Office Culture</h3>\n<h3 id="extendedperiodsofunemployment">Extended Periods of Unemployment</h3>\n<p>I''ve personally been lucky enough to never be out of work for more than a week, and in all those circumstances its largely been out of choice (and lack of motivation) as finding new work isn''t immediately necessary.</p>\n<h3 id="benefits">Benefits</h3>\n<h3 id="jobsecurity">Job Security</h3>\n<h3 id="jobhistory">Job History</h3>\n<!--kg-card-end: markdown-->', 'Most people seem to have dreamt of working for themselves at some point or another, but given that 70+% of Americans work as an employee for someone else it''s clear that for most people it will always be just that - a dream.\n\n\nBut I don''t blame them, working for yourself is hard work.\n\n\nMoreso than just hard work, it''s a drastic shift in how you spend your time and work compared to a full time 40 hour work week.\n\n\n\nUpsides\n\n\n\nFreedom and Flexibility\n\n\nThis is generally the numbe', NULL, 0, 'post', 'draft', 'public', 'all', '2015-10-16 22:38:52', '1', '2015-10-16 22:51:04', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('cb1e9b3568be49238a46b137', 'c2fee9e68fa540c4a3c1b21b3dc839b8', 'Turning Down the Noise', 'turning-down-the-noise', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"I still remember getting my first cell phone.\\n\\nThe year was 1999 and my mom passed down her beater of a silver Sprint flip phone. For the time it was high tech, featuring an exterior notification screen, polyphonic ringtones, and a few games that would later look “totally lame” next to Snake on my friend''s Nokia brick-phones. Despite the terror that is being a cell phone owned by an 11 year old kid, it lasted several years until I convinced my parents to upgrade me to a a new LG phone with a “totally cool” color screen (and countless software bugs).\\n\\nFast forward to 2008 where I found myself in need of a new phone having had my latest ~~victim~~ Razer flip phone split in half. In an effort to show mercy to my parents, I made the mature decision to get my own phone plan and a sexy, contract-subsidized iPhone 3G for _only_ $200.\\n\\nFor the first few years having an iPhone was similar to having a dumbphone, just with a better screen, a browser that worked, and countless other bells and whistles that were more of a novelty than necessity. Unfortunately, somewhere along the way those novelties gave way to alerts, push notifications, and constant buzzing, beeping, and blooping that turned the my “smart” into a constant point of annoyance and stress as it begged for my attention.\\n\\nIt''s for this reason that I''ve been diving into the _extremely_ extensive notification settings and turning off as many active notifications as possible (active being anything that makes my phone buzz, beep, or otherwise distract my attention when it''s not in front of my face). The only three apps for which I''ve left active notifications fully intact are “Phone”, “Messages”, and “Facetime”, or what I still consider to be the core functions a phone should provide (and even those are 100% silent at the flip the switch on the side of my iPhone).\\n\\nAdditionally, to help minimized distractions when I am on my phone I''ve also disabled the majority of passive notifications (badges, banner alerts, etc - anything that unobtrusively appears once you''re already on the phone), and only left them intact for the few work-critical apps like Mailbox, Slack, and Google Hangouts.\\n\\nA few weeks in I now check my email once or twice a day, Facebook a few times per week, and otherwise only pull out my phone when I have true downtime rather than out of habit. Surprisingly, I''ve yet to miss anything work-related that couldn''t wait until later, and what started out as an experiment in being able to focus better on work has turned into a much better balance between myself and what should be a tool rather than a constant distraction. If you find yourself distracted or pestered by your phone I''d recommend giving it a try.\\n\\nAs someone who works as a designer and developer I get it — the more we use our phone the better for your company, but as a human being with limited time and attention I have to wonder if there''s a better way? All things aside, that old Sprint phone had one feature that makes it appealing compared to phones of today — the damn thing was silent 99% of the time."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>I still remember getting my first cell phone.</p>\n<p>The year was 1999 and my mom passed down her beater of a silver Sprint flip phone. For the time it was high tech, featuring an exterior notification screen, polyphonic ringtones, and a few games that would later look “totally lame” next to Snake on my friend''s Nokia brick-phones. Despite the terror that is being a cell phone owned by an 11 year old kid, it lasted several years until I convinced my parents to upgrade me to a a new LG phone with a “totally cool” color screen (and countless software bugs).</p>\n<p>Fast forward to 2008 where I found myself in need of a new phone having had my latest <s>victim</s> Razer flip phone split in half. In an effort to show mercy to my parents, I made the mature decision to get my own phone plan and a sexy, contract-subsidized iPhone 3G for <em>only</em> $200.</p>\n<p>For the first few years having an iPhone was similar to having a dumbphone, just with a better screen, a browser that worked, and countless other bells and whistles that were more of a novelty than necessity. Unfortunately, somewhere along the way those novelties gave way to alerts, push notifications, and constant buzzing, beeping, and blooping that turned the my “smart” into a constant point of annoyance and stress as it begged for my attention.</p>\n<p>It''s for this reason that I''ve been diving into the <em>extremely</em> extensive notification settings and turning off as many active notifications as possible (active being anything that makes my phone buzz, beep, or otherwise distract my attention when it''s not in front of my face). The only three apps for which I''ve left active notifications fully intact are “Phone”, “Messages”, and “Facetime”, or what I still consider to be the core functions a phone should provide (and even those are 100% silent at the flip the switch on the side of my iPhone).</p>\n<p>Additionally, to help minimized distractions when I am on my phone I''ve also disabled the majority of passive notifications (badges, banner alerts, etc - anything that unobtrusively appears once you''re already on the phone), and only left them intact for the few work-critical apps like Mailbox, Slack, and Google Hangouts.</p>\n<p>A few weeks in I now check my email once or twice a day, Facebook a few times per week, and otherwise only pull out my phone when I have true downtime rather than out of habit. Surprisingly, I''ve yet to miss anything work-related that couldn''t wait until later, and what started out as an experiment in being able to focus better on work has turned into a much better balance between myself and what should be a tool rather than a constant distraction. If you find yourself distracted or pestered by your phone I''d recommend giving it a try.</p>\n<p>As someone who works as a designer and developer I get it — the more we use our phone the better for your company, but as a human being with limited time and attention I have to wonder if there''s a better way? All things aside, that old Sprint phone had one feature that makes it appealing compared to phones of today — the damn thing was silent 99% of the time.</p>\n<!--kg-card-end: markdown-->', 'I still remember getting my first cell phone.\n\n\nThe year was 1999 and my mom passed down her beater of a silver Sprint flip phone. For the time it was high tech, featuring an exterior notification screen, polyphonic ringtones, and a few games that would later look “totally lame” next to Snake on my friend''s Nokia brick-phones. Despite the terror that is being a cell phone owned by an 11 year old kid, it lasted several years until I convinced my parents to upgrade me to a a new LG phone with a', NULL, 0, 'post', 'published', 'public', 'all', '2015-11-18 02:50:34', '1', '2016-02-23 21:08:58', '1', '2016-02-23 21:08:31', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('ce8c624a120340b7916765b7', '4531a7df28924593b3041a7095c1b2b5', 'Getting Started with Marionette', 'getting-started-with-marionette-js', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"A few months ago I took on client with an ongoing project built on MarionetteJS, the Backbone-dependent framework I''d heard a lot about over the years but for one reason or another had never gotten around to checking out. A quick look at Marionette''s website immediately pitches that \\"Marionette simplifies your Backbone application code with robust views and architecture solutions.\\" After a few months of working with it I''d argue that \\"simplifies\\" is really a matter of app complexity (and opinion), but that it imposes a regular structure to otherwise wild and untamable *(!)* Backbone apps is undeniable. \\n\\nWith the uphill challenge of learning a new framework I excitedly dove straight in with a new feature, only to dive straight into a wall with no clear way around it. Whereas other frameworks like Ember and Angular have incredibly organized communities, Marionette feels a bit like the wild west. The information''s out there, but the official documentation is at times scant, and the answers you find can be inconsistent and contradictory. Additionally, there''s many features that have been (rightfully) deprecated over Marionette''s numerous releases, but with all references to them having been removed in the docs it''s often much more difficult to find out they''re deprecated than finding an outdated StackOverflow answer that references it. To top it all off, there''s a few features like Marionette''s built-in module system that are still widely used and supported, but have been deprecated (and deleted from the docs) with no alternative module system being officially endorsed. The creator of Marionette, Derick Bailey, has gone so far to admit he''s now using Browserify as [it was a mistake to introduce Marionette''s module system in the first place], but this still stops short of being the official recommendation the community needs for widespread adoption on their production apps.\\n\\nIssues aside, I''m still impressed by Marionette and will likely continue to use it on applications that don''t require the large scale architecture (and corresponding dependency size) that frameworks like Angular and Ember impose. Backbone made client-side applications a viable choice, but the lack of structure was a mistake in my opinion, and that''s where Marionette fills in the gaps.\\n\\n####Books\\n* [Marionette: A Gentle Introduction](https://leanpub.com/marionette-gentle-introduction) ([Source](https://github.com/davidsulc/marionette-gentle-introduction))\\n* [Marionette: A Serious Progression]() ([Source](https://github.com/davidsulc/marionette-serious-progression-app))\\n\\n####Blogs\\n* [Derick Bailey''s Blog](http://derickbailey.com/categories/marionettejs/)\\n\\n####Docs\\n* [MarionetteJS](http://marionettejs.com/docs/current/) — Docs for the actual Marionette library. Useful but often not nearly thorough enough to get a good understanding. Also lacks references to the other libraries Marionette leverages, so there''s often gaps in what it does and does not explain.\\n* [Backbone](http://backbonejs.org/) — Docs for the infamous BackboneJS, on which Marionette is built. If you don''t already know Backbone this will add to your learning curve, but it''s not a deal breaker.\\n* [Underscore](http://underscorejs.org/) — Docs for Underscore, a library that adds a myriad of utilities and helpers to javascript. Can alternatively be used with lodash, which is \\n* [Backbone.Wreqr]() — This is Marionette''s default events library. It''s currently being phased out, so only use it if you''re maintaining a legacy app.\\n* [Backbone.Radio]() - This is the new events library being officially introduced once Marionette 3.0 is released, but it can (and should) be used now if you''re building a new app.\\n* []()"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>A few months ago I took on client with an ongoing project built on MarionetteJS, the Backbone-dependent framework I''d heard a lot about over the years but for one reason or another had never gotten around to checking out. A quick look at Marionette''s website immediately pitches that &quot;Marionette simplifies your Backbone application code with robust views and architecture solutions.&quot; After a few months of working with it I''d argue that &quot;simplifies&quot; is really a matter of app complexity (and opinion), but that it imposes a regular structure to otherwise wild and untamable <em>(!)</em> Backbone apps is undeniable.</p>\n<p>With the uphill challenge of learning a new framework I excitedly dove straight in with a new feature, only to dive straight into a wall with no clear way around it. Whereas other frameworks like Ember and Angular have incredibly organized communities, Marionette feels a bit like the wild west. The information''s out there, but the official documentation is at times scant, and the answers you find can be inconsistent and contradictory. Additionally, there''s many features that have been (rightfully) deprecated over Marionette''s numerous releases, but with all references to them having been removed in the docs it''s often much more difficult to find out they''re deprecated than finding an outdated StackOverflow answer that references it. To top it all off, there''s a few features like Marionette''s built-in module system that are still widely used and supported, but have been deprecated (and deleted from the docs) with no alternative module system being officially endorsed. The creator of Marionette, Derick Bailey, has gone so far to admit he''s now using Browserify as [it was a mistake to introduce Marionette''s module system in the first place], but this still stops short of being the official recommendation the community needs for widespread adoption on their production apps.</p>\n<p>Issues aside, I''m still impressed by Marionette and will likely continue to use it on applications that don''t require the large scale architecture (and corresponding dependency size) that frameworks like Angular and Ember impose. Backbone made client-side applications a viable choice, but the lack of structure was a mistake in my opinion, and that''s where Marionette fills in the gaps.</p>\n<h4 id="books">Books</h4>\n<ul>\n<li><a href="https://leanpub.com/marionette-gentle-introduction">Marionette: A Gentle Introduction</a> (<a href="https://github.com/davidsulc/marionette-gentle-introduction">Source</a>)</li>\n<li><a href="">Marionette: A Serious Progression</a> (<a href="https://github.com/davidsulc/marionette-serious-progression-app">Source</a>)</li>\n</ul>\n<h4 id="blogs">Blogs</h4>\n<ul>\n<li><a href="http://derickbailey.com/categories/marionettejs/">Derick Bailey''s Blog</a></li>\n</ul>\n<h4 id="docs">Docs</h4>\n<ul>\n<li><a href="http://marionettejs.com/docs/current/">MarionetteJS</a> — Docs for the actual Marionette library. Useful but often not nearly thorough enough to get a good understanding. Also lacks references to the other libraries Marionette leverages, so there''s often gaps in what it does and does not explain.</li>\n<li><a href="http://backbonejs.org/">Backbone</a> — Docs for the infamous BackboneJS, on which Marionette is built. If you don''t already know Backbone this will add to your learning curve, but it''s not a deal breaker.</li>\n<li><a href="http://underscorejs.org/">Underscore</a> — Docs for Underscore, a library that adds a myriad of utilities and helpers to javascript. Can alternatively be used with lodash, which is</li>\n<li><a href="">Backbone.Wreqr</a> — This is Marionette''s default events library. It''s currently being phased out, so only use it if you''re maintaining a legacy app.</li>\n<li><a href="">Backbone.Radio</a> - This is the new events library being officially introduced once Marionette 3.0 is released, but it can (and should) be used now if you''re building a new app.</li>\n<li><a href=""></a></li>\n</ul>\n<!--kg-card-end: markdown-->', 'A few months ago I took on client with an ongoing project built on MarionetteJS, the Backbone-dependent framework I''d heard a lot about over the years but for one reason or another had never gotten around to checking out. A quick look at Marionette''s website immediately pitches that "Marionette simplifies your Backbone application code with robust views and architecture solutions." After a few months of working with it I''d argue that "simplifies" is really a matter of app complexity (and opinion', NULL, 0, 'post', 'draft', 'public', 'all', '2015-12-06 00:54:17', '1', '2015-12-12 20:43:51', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('22de5e4baa2a4472b51787c3', 'b45ea5dd44334ac680c9f703eb4357bc', 'Bulletproof Responsive Email Templates', 'building-maintainable-email-templates', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"_Or how to not hate everything._\\n\\nIf you''re a frontend developer in 2016 you''ve probably been unlucky enough to be faced with the hell that is building email templates. If you''re really unlucky then you were faced with building _responsive_ email templates.\\n\\nWhile building responsive email templates sounds like it should be simple in this day & age, anybody whose attempted to do so will tell you it''s ~~impossible~~ near impossible. All CSS styles have to be inlined in `style` tags in the HTML tags, you can''t use HTML5 tags, and everything has to be built using old-fashioned `<table>`-based layouts (don''t even think about using your fancy flexbox skills).\\n\\nSo how do we go about making circa-1995 style HTML templates play nice with our cutting-edge 2016 web application?\\n\\n###The Solution\\n\\n1. Template Partials\\n2. “External” Stylesheets\\n3. Email Frameworks\\n4. Premailer\\n5. Litmus\\n\\n###Template Partials\\n\\nWhen building a static website or web application no self-respecting developer would repeat the same code over and over again, so why are you doing this in your email templates? Whether you''re integrating your mail templates directly into an application or building standalone templates that you paste into Mandrill''s web editor, stop repeating yourself and start writing DRY code by using template partials for common components like the header and footer.\\n\\nIn an application this is as easy as breaking your templates up and using include template helpers, while otherwise you can locally taskrunners like use Gulp or Grunt (with grunt-contrib-include or gulp-include) to build your templates from partials into their finished state. \\n\\n###External Stylesheets\\n\\n“But you said you can''t use external stylesheets!” \\n\\nThat''s true, I did. You can''t use actual external stylesheets in a `<link>` tag like you would on a normal website, but there''s nothing stopping you from putting your CSS in a HTML `<style>` in a separate template partial, and then including it in the `<head>` of the email like you would any other component of the layout.\\n\\n###Premailer\\n\\nThe biggest hurdle in maintaining email templates is that you have to inline the CSS at some point prior to sending emails out. This means your either copying/pasting your CSS and template into a web based inliner every time you make an update or hacking on templates with the CSS already inlined. This is where Premailer comes in.\\n\\nCurrently available as Ruby Gem and a grunt module, it allows you to use standard HTML classes in your email templates and then auto-inlines all the styles accordingly at compile time (anytime it''s sent from Rails or on build for Grunt). This means you can have those wonderful BEM CSS `.cake__inner` classes you know and love.\\n\\nJust make sure that your git repo (you are using version control right?) doesn''t include the compiled templates, otherwise I can guarantee at some point some other developer will miss the beauty of your work and start hacking away on the inlined versions. \\n\\nWhile you''re at it, let''s make sure to add that compiled folder to the .gitignore, just to be safe.\\n\\n###Email Frameworks\\n\\nLaying out email templates from scratch is hell, but thankfully some generous people out there have gone through the trouble of going to hell and back to solve that problem for us. I can only speak for Zurb''s solution, but I''ve included a list of all promising looking options below:\\n\\n1. [Zurb Foundation for Emails](http://foundation.zurb.com/emails) (formerly Zurb Ink)\\n* [Cerberus](http://tedgoas.github.io/Cerberus/)\\n* [Brian Graves'' Response Email Patterns](http://briangraves.github.io/ResponsiveEmailPatterns/)\\n* [Antwort](http://internations.github.io/antwort/)\\n* [Mailchimp Email Blueprints](https://github.com/mailchimp/Email-Blueprints)\\n* [Email Framework](http://emailframe.work/)\\n\\nFurther reading can be found at [http://pages.litmus.com/RWDsummit](http://pages.litmus.com/RWDsummit). Stop reinventing the wheel when you don''t have to.\\n\\n###Litmus\\n\\nBefore you read this, sign up for an account at [Litmus](http://litmus.com). Yes, it''s $99/month. And yes, it''s completely worth it.\\n\\nAnd no, they''re not paying me to say this.\\n\\nSo what is Litmus? Per their website''s marketing it allows you to, “Build, test, and monitor your emails [...].” In non-marketing words, it provides you with an email address to send your test emails, and it proceeds to render them in every email client you''ve have (or haven''t) heard of and provide screenshots in a slick web interface. You might be thinking you can save $99/month and just test your emails in different clients yourself, but I can tell you now that you''ll spend more than $99 worth of billable time testing even one email template.\\n\\n_(If I could reach through the screen and shake your shoulders for emphasis on this point I would.)_\\n\\nBetter yet, they provide a 14 day free trial and you can cancel anytime.\\n\\n\\nSo let''s be straight — email templates _really...really_ suck, and that''s unlikely to change anytime soon. They''re the equivalent of needing to support IE6 through 11 while blindfolded and your hands tied behind your back, so when I look at client projects with pre-existing email templates I honestly can''t blame them for the unmaintainable pile of chaos they hand off to me."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p><em>Or how to not hate everything.</em></p>\n<p>If you''re a frontend developer in 2016 you''ve probably been unlucky enough to be faced with the hell that is building email templates. If you''re really unlucky then you were faced with building <em>responsive</em> email templates.</p>\n<p>While building responsive email templates sounds like it should be simple in this day &amp; age, anybody whose attempted to do so will tell you it''s <s>impossible</s> near impossible. All CSS styles have to be inlined in <code>style</code> tags in the HTML tags, you can''t use HTML5 tags, and everything has to be built using old-fashioned <code>&lt;table&gt;</code>-based layouts (don''t even think about using your fancy flexbox skills).</p>\n<p>So how do we go about making circa-1995 style HTML templates play nice with our cutting-edge 2016 web application?</p>\n<h3 id="thesolution">The Solution</h3>\n<ol>\n<li>Template Partials</li>\n<li>“External” Stylesheets</li>\n<li>Email Frameworks</li>\n<li>Premailer</li>\n<li>Litmus</li>\n</ol>\n<h3 id="templatepartials">Template Partials</h3>\n<p>When building a static website or web application no self-respecting developer would repeat the same code over and over again, so why are you doing this in your email templates? Whether you''re integrating your mail templates directly into an application or building standalone templates that you paste into Mandrill''s web editor, stop repeating yourself and start writing DRY code by using template partials for common components like the header and footer.</p>\n<p>In an application this is as easy as breaking your templates up and using include template helpers, while otherwise you can locally taskrunners like use Gulp or Grunt (with grunt-contrib-include or gulp-include) to build your templates from partials into their finished state.</p>\n<h3 id="externalstylesheets">External Stylesheets</h3>\n<p>“But you said you can''t use external stylesheets!”</p>\n<p>That''s true, I did. You can''t use actual external stylesheets in a <code>&lt;link&gt;</code> tag like you would on a normal website, but there''s nothing stopping you from putting your CSS in a HTML <code>&lt;style&gt;</code> in a separate template partial, and then including it in the <code>&lt;head&gt;</code> of the email like you would any other component of the layout.</p>\n<h3 id="premailer">Premailer</h3>\n<p>The biggest hurdle in maintaining email templates is that you have to inline the CSS at some point prior to sending emails out. This means your either copying/pasting your CSS and template into a web based inliner every time you make an update or hacking on templates with the CSS already inlined. This is where Premailer comes in.</p>\n<p>Currently available as Ruby Gem and a grunt module, it allows you to use standard HTML classes in your email templates and then auto-inlines all the styles accordingly at compile time (anytime it''s sent from Rails or on build for Grunt). This means you can have those wonderful BEM CSS <code>.cake__inner</code> classes you know and love.</p>\n<p>Just make sure that your git repo (you are using version control right?) doesn''t include the compiled templates, otherwise I can guarantee at some point some other developer will miss the beauty of your work and start hacking away on the inlined versions.</p>\n<p>While you''re at it, let''s make sure to add that compiled folder to the .gitignore, just to be safe.</p>\n<h3 id="emailframeworks">Email Frameworks</h3>\n<p>Laying out email templates from scratch is hell, but thankfully some generous people out there have gone through the trouble of going to hell and back to solve that problem for us. I can only speak for Zurb''s solution, but I''ve included a list of all promising looking options below:</p>\n<ol>\n<li><a href="http://foundation.zurb.com/emails">Zurb Foundation for Emails</a> (formerly Zurb Ink)</li>\n</ol>\n<ul>\n<li><a href="http://tedgoas.github.io/Cerberus/">Cerberus</a></li>\n<li><a href="http://briangraves.github.io/ResponsiveEmailPatterns/">Brian Graves'' Response Email Patterns</a></li>\n<li><a href="http://internations.github.io/antwort/">Antwort</a></li>\n<li><a href="https://github.com/mailchimp/Email-Blueprints">Mailchimp Email Blueprints</a></li>\n<li><a href="http://emailframe.work/">Email Framework</a></li>\n</ul>\n<p>Further reading can be found at <a href="http://pages.litmus.com/RWDsummit">http://pages.litmus.com/RWDsummit</a>. Stop reinventing the wheel when you don''t have to.</p>\n<h3 id="litmus">Litmus</h3>\n<p>Before you read this, sign up for an account at <a href="http://litmus.com">Litmus</a>. Yes, it''s $99/month. And yes, it''s completely worth it.</p>\n<p>And no, they''re not paying me to say this.</p>\n<p>So what is Litmus? Per their website''s marketing it allows you to, “Build, test, and monitor your emails [...].” In non-marketing words, it provides you with an email address to send your test emails, and it proceeds to render them in every email client you''ve have (or haven''t) heard of and provide screenshots in a slick web interface. You might be thinking you can save $99/month and just test your emails in different clients yourself, but I can tell you now that you''ll spend more than $99 worth of billable time testing even one email template.</p>\n<p><em>(If I could reach through the screen and shake your shoulders for emphasis on this point I would.)</em></p>\n<p>Better yet, they provide a 14 day free trial and you can cancel anytime.</p>\n<p>So let''s be straight — email templates <em>really...really</em> suck, and that''s unlikely to change anytime soon. They''re the equivalent of needing to support IE6 through 11 while blindfolded and your hands tied behind your back, so when I look at client projects with pre-existing email templates I honestly can''t blame them for the unmaintainable pile of chaos they hand off to me.</p>\n<!--kg-card-end: markdown-->', 'Or how to not hate everything.\n\n\nIf you''re a frontend developer in 2016 you''ve probably been unlucky enough to be faced with the hell that is building email templates. If you''re really unlucky then you were faced with building responsive email templates.\n\n\nWhile building responsive email templates sounds like it should be simple in this day & age, anybody whose attempted to do so will tell you it''s impossible near impossible. All CSS styles have to be inlined in style tags in the HTML tags', NULL, 0, 'post', 'draft', 'public', 'all', '2015-12-12 20:44:04', '1', '2016-01-16 02:16:17', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('b8d4204437f4444cbb8895f1', '4ccde97a1e2f4403afe79bb917a58003', '12 Resolutions for 2016', '2016-resolutions', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"I''ve always thought that if something in life is important enough you shouldn''t need a yearly resolution to make that change. Unfortunately life isn''t that simple, so after more than a decade of abstaining from resolutions I''ve decided to give it a go with an appropriate first item:\\n\\n1. Regularly re-evaluate pre-conceived ideas and opinions.\\n* Read daily.\\n* Start each morning by meditating. (No idea how this will go, but I figure it can''t hurt.)\\n* Write daily with the goal of writing a book this year.\\n* Build at least one product/application for myself.\\n* Build at least one product/application to sell to others.\\n* Go jogging at least 3 times per week, bouldering at least once per week, and biking at least once per week.\\n* Put a minimum of 20% of my 2016 pre-tax income towards savings/stocks/retirement/etc.\\n* Purchase food locally as frequently as possible (farmers markets, coop boxes, etc).\\n* Publish at least one article per month — can be on this blog or elsewhere.\\n* Cook something new at least once per week.\\n* Organize at least one meetup for Designers Who Code every other month (socials/happy hours don''t count).\\n\\nMaybe I''ll fail, maybe I won''t. What I do know is that 3 1/2 years out of college it''s far too easy to become content and fall into the same rhythmic pattern day-after-day, only to look back and realize not much has happened in the past few years. This thankfully hasn''t been the case, but I''m adamant to make sure that it doesn''t happen."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>I''ve always thought that if something in life is important enough you shouldn''t need a yearly resolution to make that change. Unfortunately life isn''t that simple, so after more than a decade of abstaining from resolutions I''ve decided to give it a go with an appropriate first item:</p>\n<ol>\n<li>Regularly re-evaluate pre-conceived ideas and opinions.</li>\n</ol>\n<ul>\n<li>Read daily.</li>\n<li>Start each morning by meditating. (No idea how this will go, but I figure it can''t hurt.)</li>\n<li>Write daily with the goal of writing a book this year.</li>\n<li>Build at least one product/application for myself.</li>\n<li>Build at least one product/application to sell to others.</li>\n<li>Go jogging at least 3 times per week, bouldering at least once per week, and biking at least once per week.</li>\n<li>Put a minimum of 20% of my 2016 pre-tax income towards savings/stocks/retirement/etc.</li>\n<li>Purchase food locally as frequently as possible (farmers markets, coop boxes, etc).</li>\n<li>Publish at least one article per month — can be on this blog or elsewhere.</li>\n<li>Cook something new at least once per week.</li>\n<li>Organize at least one meetup for Designers Who Code every other month (socials/happy hours don''t count).</li>\n</ul>\n<p>Maybe I''ll fail, maybe I won''t. What I do know is that 3 1/2 years out of college it''s far too easy to become content and fall into the same rhythmic pattern day-after-day, only to look back and realize not much has happened in the past few years. This thankfully hasn''t been the case, but I''m adamant to make sure that it doesn''t happen.</p>\n<!--kg-card-end: markdown-->', 'I''ve always thought that if something in life is important enough you shouldn''t need a yearly resolution to make that change. Unfortunately life isn''t that simple, so after more than a decade of abstaining from resolutions I''ve decided to give it a go with an appropriate first item:\n\n\n 1. Regularly re-evaluate pre-conceived ideas and opinions.\n\n\n * Read daily.\n * Start each morning by meditating. (No idea how this will go, but I figure it can''t hurt.)\n * Write daily with the goal of writ', NULL, 0, 'post', 'published', 'public', 'all', '2016-01-15 21:55:34', '1', '2016-01-15 23:35:43', '1', '2016-01-15 23:09:20', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('807ea0cb527942d1a204b839', '176b4bcfe2914b82a605413deee36b6b', 'Interesting', 'january-links', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"* [Great Books for Designers to Read in 2016](https://blog.pttrns.com/great-books-for-designers-to-read-in-2016-d2ebea3763f4#.80040l1vx)\\n* http://www.pocketjavascript.com/blog/2015/11/23/introducing-pokedex-org"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><ul>\n<li><a href="https://blog.pttrns.com/great-books-for-designers-to-read-in-2016-d2ebea3763f4#.80040l1vx">Great Books for Designers to Read in 2016</a></li>\n<li><a href="http://www.pocketjavascript.com/blog/2015/11/23/introducing-pokedex-org">http://www.pocketjavascript.com/blog/2015/11/23/introducing-pokedex-org</a></li>\n</ul>\n<!--kg-card-end: markdown-->', ' * Great Books for Designers to Read in 2016\n * http://www.pocketjavascript.com/blog/2015/11/23/introducing-pokedex-org\n', NULL, 0, 'post', 'draft', 'public', 'all', '2016-01-16 00:12:05', '1', '2016-01-16 00:12:51', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('8d674c9d228b4cffaa29f26b', '0bb422b04115418cb9807393e4826291', 'Is Self Hosted Blogging Dead?', 'is-self-hosted-blogging-dead', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"###Or, the case against hosted blogging options.\\n\\nMore and more I find myself reading articles on blog networks, and by networks I mean [Medium](http://medium.com). There was a promising short lived moment where smaller, topic-oriented blog networks like [Svbtle](http://svbtle.com) (amongst others) started appearing, but even those seem to have gone by the wayside and are increasingly being replaced by Medium.\\n\\nIt''s not that I have anything inherently against these sites; they are incredibly well designed and seem to be doing a fantastic job at fostering a community and discussion around the writing of people spanning the whole spectrum of society. What I do have a problem with is trusting all my writing to a third-party company, which may or may not decide to monetize my content, shutdown, or update their application in a way that makes it a moot platform for future writing.\\n\\nDon''t get me wrong, from those the few people I''ve met who work at Medium and Svbtle they seem like honest, top-notch people, but when I read through their Terms of Service it''s hard not to be a little concerned. \\n\\nLike this snippet from Svbtle:\\n\\n> “As a paid customer, you give Svbtle a perpetual world-wide license to use your company''s assets and logos, unless Svbtle agrees in writing otherwise. These assets and logos will be used purely for marketing and sales efforts, such as being displayed on the home page.”\\n\\nSo by posting to Svbtle once, they suddenly have a _perpetual_ license to use my company''s logo in way''s I''m forever unable to control unless they agree not to in writing, presumably before I ever use their service? It''s not that I think they''re necessarily going to do anything I disagree with right now or in the near future, but times **do** change — companies transition or are sold to a new owner, and you hear horror stories about formerly reputable companies like Sourceforge, the formerly ubiquitous choice for version control hosting, [hijacking GIMP''s unused Windows distribution account for their own profit](http://arstechnica.com/information-technology/2015/05/sourceforge-grabs-gimp-for-windows-account-wraps-installer-in-bundle-pushing-adware/).\\n\\nOr what about this one:\\n\\n> “Svbtle reserves the right, at its sole discretion, to modify or replace any part of this Agreement. It is your responsibility to check this Agreement periodically for changes. Your continued use of or access to the Services following the posting of any changes to this Agreement constitutes acceptance of those changes.”\\n\\nNot only can they update the Terms of Service at any point in time without notifying their users, but it''s the **user''s responsibility** to check it for changes? I''m not a lawyer, but it seems extremely questionable that they can''t commit to providing some sort of outreach before those changes take effect. This is the same type of shady practice that previously earned Facebook heaps of backlash from its users, and led to them adding a clause to their Terms of Service that they''ll transparently [communicating future changes in advance of them going into effect](https://www.facebook.com/terms.php).[^n]  I don''t know about you, but I highly doubt many people are checking the Terms of Service for changes every time they go to make a blog post.\\n\\nMedium.com''s Terms of Service are thankfully written in as much honest, plain-speaking words as possible with upfront statements like, “Even if your eyes normally glaze over the word “Terms,” it’s a good idea to read this agreement carefully before you use Medium.” and “You own the rights to the content you post on Medium. We don’t claim ownership over any of it.” \\n\\nStill though, you look further down and come across this piece: \\n\\n> “...we may change, terminate, or restrict access to any aspect of the service, at any time, without notice.”\\n\\nAs a web designer and developer, I get it — times inevitably change and you don''t want to find themselves in a lawsuit because someone''s favorite feature got removed, but still that risk doesn''t seem worth it. It''s hard enough to muster the time to put my thoughts into words, and the last thing I want is for all that effort to hinge on the decisions of a benign dictator.\\n\\nLastly, as great as the Medium community is currently, it''s still a walled garden. You write on Medium, read on Medium, discuss on Medium, and inevitably live or die based on the choices of the company behind Medium.\\n\\n##Long Live Self Hosted Blogs\\n\\nFor my own blog I personally self-host [Ghost''s open-source platform](http://ghost.org/download). As it''s still pre-1.0[^n] it requires a little bit of technical know-how to get setup, but with options like DigitalOcean''s pre-configured Ghost Droplet it''s getting easier and easier to manage. On the downside the only writing format it currently accepts is Markdown, which depending on your preferences will be a polarizing feature (I love it).\\n\\nSo maybe Ghost isn''t your jam, and that''s okay. That''s the beauty of self-hosting your own blog, there''s so many options out there! Things like [Wordpress](http://wordpress.org), [Jekyll](https://jekyllrb.com/), [Middleman](https://middlemanapp.com/), [Octopress](http://octopress.org/), [AnchorCMS](https://anchorcms.com/), [PicoCMS](http://picocms.org/), [Dropplets](http://dropplets.com/), _*takes breath*_ ...and at least hundred others are free and available for you to use, customize, update (or not), etc at your own choosing. That''s the beauty of having control over your own writing — the Ghost community might opt to add or remove a feature I disagree with, at which point I have full control to not update to the newest version and plan a transition to a different platform that fits my needs.\\n\\n[^n]: Section 13.1 if you''re that interested.\\n[^n]: [Version v0.7.5](http://dev.ghost.org/ghost-0-7-5/) at the time of this writing."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><h3 id="orthecaseagainsthostedbloggingoptions">Or, the case against hosted blogging options.</h3>\n<p>More and more I find myself reading articles on blog networks, and by networks I mean <a href="http://medium.com">Medium</a>. There was a promising short lived moment where smaller, topic-oriented blog networks like <a href="http://svbtle.com">Svbtle</a> (amongst others) started appearing, but even those seem to have gone by the wayside and are increasingly being replaced by Medium.</p>\n<p>It''s not that I have anything inherently against these sites; they are incredibly well designed and seem to be doing a fantastic job at fostering a community and discussion around the writing of people spanning the whole spectrum of society. What I do have a problem with is trusting all my writing to a third-party company, which may or may not decide to monetize my content, shutdown, or update their application in a way that makes it a moot platform for future writing.</p>\n<p>Don''t get me wrong, from those the few people I''ve met who work at Medium and Svbtle they seem like honest, top-notch people, but when I read through their Terms of Service it''s hard not to be a little concerned.</p>\n<p>Like this snippet from Svbtle:</p>\n<blockquote>\n<p>“As a paid customer, you give Svbtle a perpetual world-wide license to use your company''s assets and logos, unless Svbtle agrees in writing otherwise. These assets and logos will be used purely for marketing and sales efforts, such as being displayed on the home page.”</p>\n</blockquote>\n<p>So by posting to Svbtle once, they suddenly have a <em>perpetual</em> license to use my company''s logo in way''s I''m forever unable to control unless they agree not to in writing, presumably before I ever use their service? It''s not that I think they''re necessarily going to do anything I disagree with right now or in the near future, but times <strong>do</strong> change — companies transition or are sold to a new owner, and you hear horror stories about formerly reputable companies like Sourceforge, the formerly ubiquitous choice for version control hosting, <a href="http://arstechnica.com/information-technology/2015/05/sourceforge-grabs-gimp-for-windows-account-wraps-installer-in-bundle-pushing-adware/">hijacking GIMP''s unused Windows distribution account for their own profit</a>.</p>\n<p>Or what about this one:</p>\n<blockquote>\n<p>“Svbtle reserves the right, at its sole discretion, to modify or replace any part of this Agreement. It is your responsibility to check this Agreement periodically for changes. Your continued use of or access to the Services following the posting of any changes to this Agreement constitutes acceptance of those changes.”</p>\n</blockquote>\n<p>Not only can they update the Terms of Service at any point in time without notifying their users, but it''s the <strong>user''s responsibility</strong> to check it for changes? I''m not a lawyer, but it seems extremely questionable that they can''t commit to providing some sort of outreach before those changes take effect. This is the same type of shady practice that previously earned Facebook heaps of backlash from its users, and led to them adding a clause to their Terms of Service that they''ll transparently <a href="https://www.facebook.com/terms.php">communicating future changes in advance of them going into effect</a>.<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup>  I don''t know about you, but I highly doubt many people are checking the Terms of Service for changes every time they go to make a blog post.</p>\n<p>Medium.com''s Terms of Service are thankfully written in as much honest, plain-speaking words as possible with upfront statements like, “Even if your eyes normally glaze over the word “Terms,” it’s a good idea to read this agreement carefully before you use Medium.” and “You own the rights to the content you post on Medium. We don’t claim ownership over any of it.”</p>\n<p>Still though, you look further down and come across this piece:</p>\n<blockquote>\n<p>“...we may change, terminate, or restrict access to any aspect of the service, at any time, without notice.”</p>\n</blockquote>\n<p>As a web designer and developer, I get it — times inevitably change and you don''t want to find themselves in a lawsuit because someone''s favorite feature got removed, but still that risk doesn''t seem worth it. It''s hard enough to muster the time to put my thoughts into words, and the last thing I want is for all that effort to hinge on the decisions of a benign dictator.</p>\n<p>Lastly, as great as the Medium community is currently, it''s still a walled garden. You write on Medium, read on Medium, discuss on Medium, and inevitably live or die based on the choices of the company behind Medium.</p>\n<h2 id="longliveselfhostedblogs">Long Live Self Hosted Blogs</h2>\n<p>For my own blog I personally self-host <a href="http://ghost.org/download">Ghost''s open-source platform</a>. As it''s still pre-1.0<sup class="footnote-ref"><a href="#fn1" id="fnref1:1">[1:1]</a></sup> it requires a little bit of technical know-how to get setup, but with options like DigitalOcean''s pre-configured Ghost Droplet it''s getting easier and easier to manage. On the downside the only writing format it currently accepts is Markdown, which depending on your preferences will be a polarizing feature (I love it).</p>\n<p>So maybe Ghost isn''t your jam, and that''s okay. That''s the beauty of self-hosting your own blog, there''s so many options out there! Things like <a href="http://wordpress.org">Wordpress</a>, <a href="https://jekyllrb.com/">Jekyll</a>, <a href="https://middlemanapp.com/">Middleman</a>, <a href="http://octopress.org/">Octopress</a>, <a href="https://anchorcms.com/">AnchorCMS</a>, <a href="http://picocms.org/">PicoCMS</a>, <a href="http://dropplets.com/">Dropplets</a>, <em><em>takes breath</em></em> ...and at least hundred others are free and available for you to use, customize, update (or not), etc at your own choosing. That''s the beauty of having control over your own writing — the Ghost community might opt to add or remove a feature I disagree with, at which point I have full control to not update to the newest version and plan a transition to a different platform that fits my needs.</p>\n<hr class="footnotes-sep">\n<section class="footnotes">\n<ol class="footnotes-list">\n<li id="fn1" class="footnote-item"><p><a href="http://dev.ghost.org/ghost-0-7-5/">Version v0.7.5</a> at the time of this writing. <a href="#fnref1" class="footnote-backref">↩︎</a> <a href="#fnref1:1" class="footnote-backref">↩︎</a></p>\n</li>\n</ol>\n</section>\n<!--kg-card-end: markdown-->', 'Or, the case against hosted blogging options.\n\n\nMore and more I find myself reading articles on blog networks, and by networks I mean Medium. There was a promising short lived moment where smaller, topic-oriented blog networks like Svbtle (amongst others) started appearing, but even those seem to have gone by the wayside and are increasingly being replaced by Medium.\n\n\nIt''s not that I have anything inherently against these sites; they are incredibly well designed and seem to be doing a fan', NULL, 0, 'post', 'published', 'public', 'all', '2016-01-21 19:41:18', '1', '2016-01-21 21:24:29', '1', '2016-01-21 21:23:00', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('b9de6d9192804e43b82538ab', 'dbe096ebf3684b07a217b51887c0aa10', '2015 - Year in Review', '2015', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"It seemed like 2015 went by fast, but I''ve blinked twice and it''s already ~~almost the end of January~~ halfway through February (okay I''ve really been procrastinating on this post). For years I''ve read “years in review” by others in the tech community, but never did one of my own because it never seemed like my experience was worth sharing. While I''m still skeptical how much value others might get out of this, especially considering how informal it is, it''s at minimum helpful in collecting my own thoughts.\\n\\nSo to start, in general it was a _great_ year — not necessarily just for business, but all around it felt great. That''s not necessarily a quantifiable metric, but that''s what it was.\\n\\n##Client Work\\n\\nIn 2013 and 2014 my consulting business had always afforded me the freedom to work my own schedule and forgo an employed job, but never quite amounted to what I could have made working a market rate job. In the early days there were even a few of those “oh god I have no work lined up and can''t pay rent ” occasions that I''ll never forgot, but somehow it always worked out.\\n\\nTwenty Fifteen, on the other hand, seems to be the year that things have not only gotten extremely stable with an upward trend in income, but also in quality of clients, ongoing relationships with clients, and ease of finding work when needed (and turning it down when not).\\n\\n####By the Numbers\\n\\nIn 2015 I worked on a total of 17 different projects with 12 different clients — an insane amount compared to previous years and something I aim to curb moving forward (more on that below). Net income saw a 94.1% increase over the previous year, and gross income increased by 82.2%. While the prior is indicative of overall business health, the latter is effectively my take home pay as I don''t have a salaried job and all income after business expenses is personal income in the all-seeing eyes of the Internal Revenue Service.\\n\\nFor the visual learnings out there here''s a chart showing year-by-year income and revenue, as expressed in emoji (I was a full time student until 2012, so any income was minimal and likely to be spent on cheap beer).\\n\\nLooking back, this was a much better year than 2014, which saw a net income increase of 52.8% and gross income increase of 11.2% over 2013. If you factor in the fact that I was employed full time from January through April of 2013, I likely actually saw a negligible increase in income compared to the previous year.\\n\\nI unofficially had made a net income goal for 2015, which I exceeded by roughly 15%. My goal for 2016 is actually to maintain that same income level, but while working on client projects roughly 30% less. It''s always been my goal to design and build my own products (analog & digital), so I hope this extra time will be enough to start focusing more time on doing so compared to previous years.\\n\\n###What Went Wrong\\nThat said, it wasn''t all good.\\n\\nFirst, as mentioned before I worked on **seventeen projects**, which was _way_ too many for one person to handle. For the most part everything worked out, but at times I was stressed to the point I wanted to punch a wall (I didn''t), which is exactly the opposite of why I got into contracting.\\n\\nSecond, I took on a client that gave me \\"a bad feeling\\". That client also happened to coincide/cause that peak of stress partway through the year. As the project went on it became more and more demanding to the detriment of my other work, and worse yet it was a product I neither believed in nor thought should exist. In the end I talked to my friend on the project and we decided to let the client know we would be ending our contract after delivering the current project milestone in a few weeks. \\n\\nIt''s always hard to say no to someone trying to hand you a check, but being able to pays dividends in your personal well-being and being able to deliver the quality you already promised to your existing clients.\\n\\n##Designers Who Code\\n\\nDesigners Who Code has exceeded my wildest expectations. What started as a hunch that their might be other “designer-developers” out there has turned into a group of ~~2000~~ 2200 members. We hosted 6 events from January through April with companies like Heroku, Zurb, and Carbon Five, and had a total of 784 RSVP''s between those 6 events.\\n\\nAll things considered I think we had some great events and were able to engage a considerable number of people despite being dormant the latter half of the year.\\n\\nIn good news I recently launched a [new website](http://dwc.io) for the group that was designed/built intermittently over the course of a few months on top of Jekyll. It''s pretty minimal and still has gaps, but will serve as a good foundation for a myriad of other features I hope to include as I aim to allow the group to exist independent of Meetup.com''s platform.\\n\\nAdditionally, I''m in talks with friends about becoming co-organizers (so things don''t necessarily go dark when I do), and it''s looking like we''ll be having our first events outside San Francisco this year.\\n\\n##Backpacking Trips\\n\\nAs someone who loves the outdoors and is generally active, it surprised me when I realized that I''d never been on a proper backpacking trip. Fast forward to April and I''m trekking down an Arizona desert canyon riverbed with my girlfriend, her brother, and his girlfriend for 40 miles over 3 days. I could write an entire post to the trip alone, but put simply it was nothing short of amazing. While I''m not sure I''d ever want to live in the desert permanently, it''s an environment I appreciate and respect far and above any other.\\n\\n![Paria Canyon](__GHOST_URL__/content/images/2016/02/11401418_10153039948342023_8577766825221316792_n.jpg)\\n<center>_About 15 miles into Paria Canyon in the “narrows”._</center>\\nAfter the trip I couldn''t shake the feeling that I needed to go on a longer trip, so I naturally opted for the 212 mile John Muir Trail (40 miles to 212 miles...totally reasonable). I''ve written a post on my gear and preparing for the trip in general, but have yet to write anything detailed otherwise. I tried, but at the time any words I could put down seemed to pale in comparison to the awe and wonder two weeks in the Sierras instilled in myself.\\n\\n![Forester Pass](__GHOST_URL__/content/images/2016/02/12138612_10153269575487023_1653335228737265945_o.jpg)\\n<center>_Looking back down from the top of Forrester Pass at 13,500''_</center>\\n\\n##Looking to the Future\\n\\nI''m currently working with a colleague of mine on an app aimed at helping make freelancers lives easier. It''s still pretty early to say much, but I''m sure I''ll have a followup post down the line.\\n\\nAnd the big news for the year...my girlfriend and I will be traveling the world the second half of 2016! What started as an idea to be expats in Thailand has turned into a trip that includes the eastern US, a myriad of European countries, and an unplanned number of countries in Southeast Asia. As part of the trip I''m looking at writing a “digital nomad” series for those thinking about working and traveling at the same time.\\n\\nWords of Wisdom for 2016:\\n> “You have Cost, Quality, and Speed — Pick Two.”"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>It seemed like 2015 went by fast, but I''ve blinked twice and it''s already <s>almost the end of January</s> halfway through February (okay I''ve really been procrastinating on this post). For years I''ve read “years in review” by others in the tech community, but never did one of my own because it never seemed like my experience was worth sharing. While I''m still skeptical how much value others might get out of this, especially considering how informal it is, it''s at minimum helpful in collecting my own thoughts.</p>\n<p>So to start, in general it was a <em>great</em> year — not necessarily just for business, but all around it felt great. That''s not necessarily a quantifiable metric, but that''s what it was.</p>\n<h2 id="clientwork">Client Work</h2>\n<p>In 2013 and 2014 my consulting business had always afforded me the freedom to work my own schedule and forgo an employed job, but never quite amounted to what I could have made working a market rate job. In the early days there were even a few of those “oh god I have no work lined up and can''t pay rent ” occasions that I''ll never forgot, but somehow it always worked out.</p>\n<p>Twenty Fifteen, on the other hand, seems to be the year that things have not only gotten extremely stable with an upward trend in income, but also in quality of clients, ongoing relationships with clients, and ease of finding work when needed (and turning it down when not).</p>\n<h4 id="bythenumbers">By the Numbers</h4>\n<p>In 2015 I worked on a total of 17 different projects with 12 different clients — an insane amount compared to previous years and something I aim to curb moving forward (more on that below). Net income saw a 94.1% increase over the previous year, and gross income increased by 82.2%. While the prior is indicative of overall business health, the latter is effectively my take home pay as I don''t have a salaried job and all income after business expenses is personal income in the all-seeing eyes of the Internal Revenue Service.</p>\n<p>For the visual learnings out there here''s a chart showing year-by-year income and revenue, as expressed in emoji (I was a full time student until 2012, so any income was minimal and likely to be spent on cheap beer).</p>\n<p>Looking back, this was a much better year than 2014, which saw a net income increase of 52.8% and gross income increase of 11.2% over 2013. If you factor in the fact that I was employed full time from January through April of 2013, I likely actually saw a negligible increase in income compared to the previous year.</p>\n<p>I unofficially had made a net income goal for 2015, which I exceeded by roughly 15%. My goal for 2016 is actually to maintain that same income level, but while working on client projects roughly 30% less. It''s always been my goal to design and build my own products (analog &amp; digital), so I hope this extra time will be enough to start focusing more time on doing so compared to previous years.</p>\n<h3 id="whatwentwrong">What Went Wrong</h3>\n<p>That said, it wasn''t all good.</p>\n<p>First, as mentioned before I worked on <strong>seventeen projects</strong>, which was <em>way</em> too many for one person to handle. For the most part everything worked out, but at times I was stressed to the point I wanted to punch a wall (I didn''t), which is exactly the opposite of why I got into contracting.</p>\n<p>Second, I took on a client that gave me &quot;a bad feeling&quot;. That client also happened to coincide/cause that peak of stress partway through the year. As the project went on it became more and more demanding to the detriment of my other work, and worse yet it was a product I neither believed in nor thought should exist. In the end I talked to my friend on the project and we decided to let the client know we would be ending our contract after delivering the current project milestone in a few weeks.</p>\n<p>It''s always hard to say no to someone trying to hand you a check, but being able to pays dividends in your personal well-being and being able to deliver the quality you already promised to your existing clients.</p>\n<h2 id="designerswhocode">Designers Who Code</h2>\n<p>Designers Who Code has exceeded my wildest expectations. What started as a hunch that their might be other “designer-developers” out there has turned into a group of <s>2000</s> 2200 members. We hosted 6 events from January through April with companies like Heroku, Zurb, and Carbon Five, and had a total of 784 RSVP''s between those 6 events.</p>\n<p>All things considered I think we had some great events and were able to engage a considerable number of people despite being dormant the latter half of the year.</p>\n<p>In good news I recently launched a <a href="http://dwc.io">new website</a> for the group that was designed/built intermittently over the course of a few months on top of Jekyll. It''s pretty minimal and still has gaps, but will serve as a good foundation for a myriad of other features I hope to include as I aim to allow the group to exist independent of Meetup.com''s platform.</p>\n<p>Additionally, I''m in talks with friends about becoming co-organizers (so things don''t necessarily go dark when I do), and it''s looking like we''ll be having our first events outside San Francisco this year.</p>\n<h2 id="backpackingtrips">Backpacking Trips</h2>\n<p>As someone who loves the outdoors and is generally active, it surprised me when I realized that I''d never been on a proper backpacking trip. Fast forward to April and I''m trekking down an Arizona desert canyon riverbed with my girlfriend, her brother, and his girlfriend for 40 miles over 3 days. I could write an entire post to the trip alone, but put simply it was nothing short of amazing. While I''m not sure I''d ever want to live in the desert permanently, it''s an environment I appreciate and respect far and above any other.</p>\n<p><img src="__GHOST_URL__/content/images/2016/02/11401418_10153039948342023_8577766825221316792_n.jpg" alt="Paria Canyon" loading="lazy"></p>\n<center>_About 15 miles into Paria Canyon in the “narrows”._</center>\nAfter the trip I couldn''t shake the feeling that I needed to go on a longer trip, so I naturally opted for the 212 mile John Muir Trail (40 miles to 212 miles...totally reasonable). I''ve written a post on my gear and preparing for the trip in general, but have yet to write anything detailed otherwise. I tried, but at the time any words I could put down seemed to pale in comparison to the awe and wonder two weeks in the Sierras instilled in myself.\n<p><img src="__GHOST_URL__/content/images/2016/02/12138612_10153269575487023_1653335228737265945_o.jpg" alt="Forester Pass" loading="lazy"></p>\n<center>_Looking back down from the top of Forrester Pass at 13,500''_</center>\n<h2 id="lookingtothefuture">Looking to the Future</h2>\n<p>I''m currently working with a colleague of mine on an app aimed at helping make freelancers lives easier. It''s still pretty early to say much, but I''m sure I''ll have a followup post down the line.</p>\n<p>And the big news for the year...my girlfriend and I will be traveling the world the second half of 2016! What started as an idea to be expats in Thailand has turned into a trip that includes the eastern US, a myriad of European countries, and an unplanned number of countries in Southeast Asia. As part of the trip I''m looking at writing a “digital nomad” series for those thinking about working and traveling at the same time.</p>\n<p>Words of Wisdom for 2016:</p>\n<blockquote>\n<p>“You have Cost, Quality, and Speed — Pick Two.”</p>\n</blockquote>\n<!--kg-card-end: markdown-->', 'It seemed like 2015 went by fast, but I''ve blinked twice and it''s already almost the end of January halfway through February (okay I''ve really been procrastinating on this post). For years I''ve read “years in review” by others in the tech community, but never did one of my own because it never seemed like my experience was worth sharing. While I''m still skeptical how much value others might get out of this, especially considering how informal it is, it''s at minimum helpful in collecting my own t', NULL, 0, 'post', 'published', 'public', 'all', '2016-01-27 03:34:44', '1', '2017-10-11 08:06:39', '1', '2016-02-17 21:01:00', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('39e053fce9fa4934aa0c4c44', '9dc4937658cd4b29a2d132061d28505e', 'Setting Up SSL for Ghost on DigitalOcean with Lets Encrypt', 'setting-up-ssl-for-ghost-on-digitalocean-with-lets-encrypt', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"After reading entirely too many articles and a lot of trial & error, I''ve written this guide on how to get HTTPS working on a DigitalOcean-powered, Nginx-backed Ghost blog using LetsEncrypt''s free SSL certificates. For years people have argued whether it''s worth setting up SSL on websites that have no inherent need for strong security (credit card processing, user logins, etc), but now that SSL certificates are free for anyone and Google is prioritizing HTTPS sites over non-HTTP sites there''s no excuse not to.\\n\\nWhile DigitalOcean''s pre-made Ghost Droplet gets us pretty far, there''s still a few steps to get HTTPS and your custom domain running.\\n\\n##The Guide\\n\\nAll steps are written from the viewpoint of a Ghost blog that was setup on DigitalOcean using it''s one-click installer, but they''re likely applicable to most Nginx/Ghost setups in general. Regardless you should probably be familiar with using a [terminal](http://ashleynolan.co.uk/blog/getting-started-with-terminal) and [SSH](https://semaphoreci.com/community/tutorials/getting-started-with-ssh) — if you aren''t I *highly recommend* brushing up via those links before you get started.\\n\\n1. If you already have a Ghost blog setup then skip to step 2. If not, go ahead and create a new droplet on DigitalOcean using the Ghost “One-Click App” install (Ghost 1.2.11 on Ubuntu 16.04 as of this writing — we''ll update it to the latest Ghost version in a few steps!) with 512mb of memory[^1] (the $5/month option). Feel free to choose whichever datacenter is closest to yourself (or your users), and add an SSH key so you can access your Droplet via your local terminal.\\n2. Once the droplet is finished building, access your droplet over SSH via the terminal of your choosing with `ssh root@0.0.0.0`, where `0.0.0.0` is the IP address of your droplet as listed in your account. If it prompts you to trust the RSA key type `yes` and press `ENTER`.\\n3. Once you''re inside your server (synonymous with “droplet”), run `apt-get update && apt-get upgrade -y` to bring all Linux dependencies up to date. If it prompts you to setup mail config or provides a warning about the `/root/grub/menu.lst` I recommend choosing the default \\"No Configuration\\" and \\"Keep local...\\" unless you have reason to do otherwise.\\n4. Switch to the \\"ghost-mgr\\" user DigitalOcean already setup by running `su - ghost-mgr` (`su` = switch user).\\n5. Install Node Version Manager (NVM) so we can easily update to a more recent version of Node by running `curl -o- https://raw.githubusercontent.com/creationix/nvm/v0.33.11/install.sh | bash`. Activate the `nvm` bash alias by running `source ~/.bashrc` or `exit`''ing and switching back to the `ghost-mgr` user.\\n6. Install Node v8.9.3 and set it as the default by running `nvm install 8.9.3 && nvm alias default node`. You can check that the setup worked by running `node -v`, which should return `v8.9.3`.\\n7. Install the Ghost CLI with `sudo npm i -g ghost-cli` so we can easily upgrade to the latest version of Ghost (v1.23.0 as of current) now and upgrade easily in the future.\\n8. Run `cd /var/www/ghost/` to switch into your project''s folder, and then `ghost update` to update to the latest version.\\n9. Next let''s install LetsEncrypt''s CertBot to get our SSL certificate — type `exit` to go back to the `root` user (or start a new SSH session as root) and install the CertBot package with...\\n`sudo apt-get install software-properties-common`\\n`sudo add-apt-repository ppa:certbot/certbot`\\n`sudo apt-get update`\\n`sudo apt-get install python-certbot-nginx`\\n10. Run `sudo certbot --nginx` and follow the prompts along. Make sure to add a real email as they''ll send you SSL renewal reminders, and select `2: Redirect` when prompted so all visitors are forced to the HTTPS version of your site.\\n11. Run `vim /var/www/ghost/config.production.json` to edit the `url` attribute to reflect your site''s domain name (in my case `url: \\"https://robertnealan.com\\",`, exit, and then run `ghost restart` (make sure you''re in your project directory!).\\n12. Remove the default IP-based Nginx config by running `cd /etc/nginx/sites-available && ls`, and then removing the IP address file with `rm 0.0.0.0`. Next open the `default` config in vim and edit it to match the configuration file below, replacing all instances of `robertnealan.com` with your own respective domain name[^2].\\n13. Run `service nginx restart` — if you get any errors run `nginx -t` and it should point you to any syntax errors you might have made in the `/etc/nginx/sites-available/default` conf file.\\n14. Test `https://yourdomain.com` to make sure that SSL is working properly...if it is then celebrate! 🎉\\n15. Lastly, you''ll want to set up a cronjob to automatically renew the certificate every 60 days or so, otherwise they''ll expire after 90 days. First run `/usr/bin/certbot renew --dry-run` to make sure it''ll work as expected. Next go ahead and run `crontab -e` in your server terminal, and you should see something similar to the image below. On the last line add `0 0 1 */2 * /usr/bin/certbot renew --nginx --quiet`, which tells cron to rerun the certificate renewal for you on the first day of every other month. With this cron in place you can safely ignore the renewal emails from LetsEncrypt.\\n\\n![Crontab Screenshot](__GHOST_URL__/content/images/2018/05/Screenshot-2018-05-23-13.44.15.png)\\n\\nAnd that''s it! If you have any issues or find an error feel free to comment on the gist, [tweet at me](https://twitter.com/robertnealan), or message me via the [contact page](__GHOST_URL__/contact).\\n\\n### Nginx Config\\n<script src=\\"https://gist.github.com/robertnealan/891fe8cf3b7541e922e3b39e9ae9fd96.js\\"></script>\\n<noscript>\\n<pre>\\nserver {\\n    listen 80;\\n    listen [::]:80;\\n\\n    server_name robertnealan.com;\\n    root /var/www/ghost/system/nginx-root;\\n\\n    location / {\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        proxy_set_header X-Forwarded-Proto $scheme;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header Host $http_host;\\n        proxy_pass http://127.0.0.1:2368;\\n\\n    }\\n\\n    location ~ /.well-known {\\n        allow all;\\n    }\\n\\n    client_max_body_size 50m;\\n\\n    listen [::]:443 ssl ipv6only=on; # managed by Certbot\\n    listen 443 ssl; # managed by Certbot\\n    ssl_certificate /etc/letsencrypt/live/robertnealan.com/fullchain.pem; # managed by Certbot\\n    ssl_certificate_key /etc/letsencrypt/live/robertnealan.com/privkey.pem; # managed by Certbot\\n    include /etc/letsencrypt/options-ssl-nginx.conf; # managed by Certbot\\n    ssl_dhparam /etc/letsencrypt/ssl-dhparams.pem; # managed by Certbot\\n\\n}\\n\\nserver {\\n    if ($host = robertnealan.com) {\\n        return 301 https://$host$request_uri;\\n    } # managed by Certbot\\n\\n    listen 80 ;\\n    listen [::]:80 ;\\n    server_name robertnealan.com;\\n    return 404; # managed by Certbot\\n}\\n</pre>\\n</noscript>\\n\\n## Other Basic Ghost Setup Tasks\\n\\n### Redirecting From non-www to www Instead\\n\\nI''ve personally always favored non-www addresses, if you prefer to have the www version then make sure to use `www.yourdomain.com` during the CertBot registration, and subsequently make sure the `server_name` directives in the Nginx `default` conf file have `www.yourname.com` rather than `yourdomain.com`.\\n\\n### Locking Down Your Server\\n\\nComing soon!\\n\\n### Setting up Email Sending\\n\\nComing soon!\\n\\n## Reference Links\\n\\n* CertBot Documentation: https://certbot.eff.org/lets-encrypt/ubuntuxenial-nginx\\n* Ghost Production Setup: https://docs.ghost.org/docs/install#section-create-a-new-user\\n* Ghost Mail Configuration: https://docs.ghost.org/docs/mail-config\\n* Node Version Manager (NVM): https://github.com/creationix/nvm\\n\\n## Updates \\n\\n* _August 11, 2016: Updated guide to add steps breaking apart enabling HTTP, verifying LetsEncrypt, and enabling HTTPS._\\n* _October 19, 2016: Updated the Nginx config to have the default root directory as `/var/www/ghost` instead of just `/var/www`._\\n* _January 24, 2017: Updated the Nginx config to fix a bug where www to non-www redirects wouldn''t occur properly on HTTPS URLs, and added instructions on how to redirect from non-www to www instead._\\n* _July 3, 2017: Removed lines 59-61 in the Nginx config Gist and code snippet, which previously manually routed the robots.txt and sitemap.xml, as Ghost now handles these automatically for the past several major versions. Huge thanks to both [Tom Blackshire](https://twitter.com/tomblackshire?lang=en) & [Grant Whinney](https://github.com/grantwinney) for both giving me the heads up!_\\n* _May 23, 2018: Fully overhauled the post to use DigitalOcean''s newer Ghost Droplet, Ubuntu 16.04, the new Ghost CLI, and the latest version of LetsEncrypt''s CertBot._\\n\\n[^1]: If you''re worried about only having 512mb of memory feel free to upgrade, though this blog has handled upwards of 650 concurrent visitors without skipping a beat.\\n[^2]: If you''re interested in learning more about Nginx configuration you can read up on it on their official wiki, [https://www.nginx.com/resources/wiki/start/](https://www.nginx.com/resources/wiki/start/)."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>After reading entirely too many articles and a lot of trial &amp; error, I''ve written this guide on how to get HTTPS working on a DigitalOcean-powered, Nginx-backed Ghost blog using LetsEncrypt''s free SSL certificates. For years people have argued whether it''s worth setting up SSL on websites that have no inherent need for strong security (credit card processing, user logins, etc), but now that SSL certificates are free for anyone and Google is prioritizing HTTPS sites over non-HTTP sites there''s no excuse not to.</p>\n<p>While DigitalOcean''s pre-made Ghost Droplet gets us pretty far, there''s still a few steps to get HTTPS and your custom domain running.</p>\n<h2 id="theguide">The Guide</h2>\n<p>All steps are written from the viewpoint of a Ghost blog that was setup on DigitalOcean using it''s one-click installer, but they''re likely applicable to most Nginx/Ghost setups in general. Regardless you should probably be familiar with using a <a href="http://ashleynolan.co.uk/blog/getting-started-with-terminal">terminal</a> and <a href="https://semaphoreci.com/community/tutorials/getting-started-with-ssh">SSH</a> — if you aren''t I <em>highly recommend</em> brushing up via those links before you get started.</p>\n<ol>\n<li>If you already have a Ghost blog setup then skip to step 2. If not, go ahead and create a new droplet on DigitalOcean using the Ghost “One-Click App” install (Ghost 1.2.11 on Ubuntu 16.04 as of this writing — we''ll update it to the latest Ghost version in a few steps!) with 512mb of memory<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup> (the $5/month option). Feel free to choose whichever datacenter is closest to yourself (or your users), and add an SSH key so you can access your Droplet via your local terminal.</li>\n<li>Once the droplet is finished building, access your droplet over SSH via the terminal of your choosing with <code>ssh root@0.0.0.0</code>, where <code>0.0.0.0</code> is the IP address of your droplet as listed in your account. If it prompts you to trust the RSA key type <code>yes</code> and press <code>ENTER</code>.</li>\n<li>Once you''re inside your server (synonymous with “droplet”), run <code>apt-get update &amp;&amp; apt-get upgrade -y</code> to bring all Linux dependencies up to date. If it prompts you to setup mail config or provides a warning about the <code>/root/grub/menu.lst</code> I recommend choosing the default &quot;No Configuration&quot; and &quot;Keep local...&quot; unless you have reason to do otherwise.</li>\n<li>Switch to the &quot;ghost-mgr&quot; user DigitalOcean already setup by running <code>su - ghost-mgr</code> (<code>su</code> = switch user).</li>\n<li>Install Node Version Manager (NVM) so we can easily update to a more recent version of Node by running <code>curl -o- https://raw.githubusercontent.com/creationix/nvm/v0.33.11/install.sh | bash</code>. Activate the <code>nvm</code> bash alias by running <code>source ~/.bashrc</code> or <code>exit</code>''ing and switching back to the <code>ghost-mgr</code> user.</li>\n<li>Install Node v8.9.3 and set it as the default by running <code>nvm install 8.9.3 &amp;&amp; nvm alias default node</code>. You can check that the setup worked by running <code>node -v</code>, which should return <code>v8.9.3</code>.</li>\n<li>Install the Ghost CLI with <code>sudo npm i -g ghost-cli</code> so we can easily upgrade to the latest version of Ghost (v1.23.0 as of current) now and upgrade easily in the future.</li>\n<li>Run <code>cd /var/www/ghost/</code> to switch into your project''s folder, and then <code>ghost update</code> to update to the latest version.</li>\n<li>Next let''s install LetsEncrypt''s CertBot to get our SSL certificate — type <code>exit</code> to go back to the <code>root</code> user (or start a new SSH session as root) and install the CertBot package with...<br>\n<code>sudo apt-get install software-properties-common</code><br>\n<code>sudo add-apt-repository ppa:certbot/certbot</code><br>\n<code>sudo apt-get update</code><br>\n<code>sudo apt-get install python-certbot-nginx</code></li>\n<li>Run <code>sudo certbot --nginx</code> and follow the prompts along. Make sure to add a real email as they''ll send you SSL renewal reminders, and select <code>2: Redirect</code> when prompted so all visitors are forced to the HTTPS version of your site.</li>\n<li>Run <code>vim /var/www/ghost/config.production.json</code> to edit the <code>url</code> attribute to reflect your site''s domain name (in my case <code>url: &quot;https://robertnealan.com&quot;,</code>, exit, and then run <code>ghost restart</code> (make sure you''re in your project directory!).</li>\n<li>Remove the default IP-based Nginx config by running <code>cd /etc/nginx/sites-available &amp;&amp; ls</code>, and then removing the IP address file with <code>rm 0.0.0.0</code>. Next open the <code>default</code> config in vim and edit it to match the configuration file below, replacing all instances of <code>robertnealan.com</code> with your own respective domain name<sup class="footnote-ref"><a href="#fn2" id="fnref2">[2]</a></sup>.</li>\n<li>Run <code>service nginx restart</code> — if you get any errors run <code>nginx -t</code> and it should point you to any syntax errors you might have made in the <code>/etc/nginx/sites-available/default</code> conf file.</li>\n<li>Test <code>https://yourdomain.com</code> to make sure that SSL is working properly...if it is then celebrate! 🎉</li>\n<li>Lastly, you''ll want to set up a cronjob to automatically renew the certificate every 60 days or so, otherwise they''ll expire after 90 days. First run <code>/usr/bin/certbot renew --dry-run</code> to make sure it''ll work as expected. Next go ahead and run <code>crontab -e</code> in your server terminal, and you should see something similar to the image below. On the last line add <code>0 0 1 */2 * /usr/bin/certbot renew --nginx --quiet</code>, which tells cron to rerun the certificate renewal for you on the first day of every other month. With this cron in place you can safely ignore the renewal emails from LetsEncrypt.</li>\n</ol>\n<p><img src="__GHOST_URL__/content/images/2018/05/Screenshot-2018-05-23-13.44.15.png" alt="Crontab Screenshot" loading="lazy"></p>\n<p>And that''s it! If you have any issues or find an error feel free to comment on the gist, <a href="https://twitter.com/robertnealan">tweet at me</a>, or message me via the <a href="__GHOST_URL__/contact">contact page</a>.</p>\n<h3 id="nginxconfig">Nginx Config</h3>\n<script src="https://gist.github.com/robertnealan/891fe8cf3b7541e922e3b39e9ae9fd96.js"></script>\n<noscript>\n<pre>\nserver {\n    listen 80;\n    listen [::]:80;\n<pre><code>server_name robertnealan.com;\nroot /var/www/ghost/system/nginx-root;\n\nlocation / {\n    proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n    proxy_set_header X-Forwarded-Proto $scheme;\n    proxy_set_header X-Real-IP $remote_addr;\n    proxy_set_header Host $http_host;\n    proxy_pass http://127.0.0.1:2368;\n\n}\n\nlocation ~ /.well-known {\n    allow all;\n}\n\nclient_max_body_size 50m;\n\nlisten [::]:443 ssl ipv6only=on; # managed by Certbot\nlisten 443 ssl; # managed by Certbot\nssl_certificate /etc/letsencrypt/live/robertnealan.com/fullchain.pem; # managed by Certbot\nssl_certificate_key /etc/letsencrypt/live/robertnealan.com/privkey.pem; # managed by Certbot\ninclude /etc/letsencrypt/options-ssl-nginx.conf; # managed by Certbot\nssl_dhparam /etc/letsencrypt/ssl-dhparams.pem; # managed by Certbot\n</code></pre>\n<p>}</p>\n<p>server {<br>\nif ($host = robertnealan.com) {<br>\nreturn 301 https://$host$request_uri;<br>\n} # managed by Certbot</p>\n<pre><code>listen 80 ;\nlisten [::]:80 ;\nserver_name robertnealan.com;\nreturn 404; # managed by Certbot\n</code></pre>\n<p>}<br>\n</pre><br>\n</noscript></p>\n<h2 id="otherbasicghostsetuptasks">Other Basic Ghost Setup Tasks</h2>\n<h3 id="redirectingfromnonwwwtowwwinstead">Redirecting From non-www to www Instead</h3>\n<p>I''ve personally always favored non-www addresses, if you prefer to have the www version then make sure to use <code>www.yourdomain.com</code> during the CertBot registration, and subsequently make sure the <code>server_name</code> directives in the Nginx <code>default</code> conf file have <code>www.yourname.com</code> rather than <code>yourdomain.com</code>.</p>\n<h3 id="lockingdownyourserver">Locking Down Your Server</h3>\n<p>Coming soon!</p>\n<h3 id="settingupemailsending">Setting up Email Sending</h3>\n<p>Coming soon!</p>\n<h2 id="referencelinks">Reference Links</h2>\n<ul>\n<li>CertBot Documentation: <a href="https://certbot.eff.org/lets-encrypt/ubuntuxenial-nginx">https://certbot.eff.org/lets-encrypt/ubuntuxenial-nginx</a></li>\n<li>Ghost Production Setup: <a href="https://docs.ghost.org/docs/install#section-create-a-new-user">https://docs.ghost.org/docs/install#section-create-a-new-user</a></li>\n<li>Ghost Mail Configuration: <a href="https://docs.ghost.org/docs/mail-config">https://docs.ghost.org/docs/mail-config</a></li>\n<li>Node Version Manager (NVM): <a href="https://github.com/creationix/nvm">https://github.com/creationix/nvm</a></li>\n</ul>\n<h2 id="updates">Updates</h2>\n<ul>\n<li><em>August 11, 2016: Updated guide to add steps breaking apart enabling HTTP, verifying LetsEncrypt, and enabling HTTPS.</em></li>\n<li><em>October 19, 2016: Updated the Nginx config to have the default root directory as <code>/var/www/ghost</code> instead of just <code>/var/www</code>.</em></li>\n<li><em>January 24, 2017: Updated the Nginx config to fix a bug where www to non-www redirects wouldn''t occur properly on HTTPS URLs, and added instructions on how to redirect from non-www to www instead.</em></li>\n<li><em>July 3, 2017: Removed lines 59-61 in the Nginx config Gist and code snippet, which previously manually routed the robots.txt and sitemap.xml, as Ghost now handles these automatically for the past several major versions. Huge thanks to both <a href="https://twitter.com/tomblackshire?lang=en">Tom Blackshire</a> &amp; <a href="https://github.com/grantwinney">Grant Whinney</a> for both giving me the heads up!</em></li>\n<li><em>May 23, 2018: Fully overhauled the post to use DigitalOcean''s newer Ghost Droplet, Ubuntu 16.04, the new Ghost CLI, and the latest version of LetsEncrypt''s CertBot.</em></li>\n</ul>\n<hr class="footnotes-sep">\n<section class="footnotes">\n<ol class="footnotes-list">\n<li id="fn1" class="footnote-item"><p>If you''re worried about only having 512mb of memory feel free to upgrade, though this blog has handled upwards of 650 concurrent visitors without skipping a beat. <a href="#fnref1" class="footnote-backref">↩︎</a></p>\n</li>\n<li id="fn2" class="footnote-item"><p>If you''re interested in learning more about Nginx configuration you can read up on it on their official wiki, <a href="https://www.nginx.com/resources/wiki/start/">https://www.nginx.com/resources/wiki/start/</a>. <a href="#fnref2" class="footnote-backref">↩︎</a></p>\n</li>\n</ol>\n</section>\n<!--kg-card-end: markdown-->', 'After reading entirely too many articles and a lot of trial & error, I''ve written this guide on how to get HTTPS working on a DigitalOcean-powered, Nginx-backed Ghost blog using LetsEncrypt''s free SSL certificates. For years people have argued whether it''s worth setting up SSL on websites that have no inherent need for strong security (credit card processing, user logins, etc), but now that SSL certificates are free for anyone and Google is prioritizing HTTPS sites over non-HTTP sites there''s no', '__GHOST_URL__/content/images/2016/05/digitalocean-ghost-banner.png', 0, 'post', 'published', 'public', 'all', '2016-02-25 07:03:25', '1', '2018-07-26 16:38:57', '1', '2016-05-19 21:51:59', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('f17883f0d43543ec96e6c843', '5d3c009c17314d3ea4eb2fa1df7b03f6', 'On the Topic of Clients, Revisions, Kill Fees, & the Three Strike Policy', 'on-the-topic-of-clients-revisions-kill-fees-the-three-strike-policy', '{"version":"0.3.1","ghostVersion":"4.0","markups":[],"atoms":[],"cards":[],"sections":[[1,"p",[[0,[],0,""]]]]}', '', NULL, NULL, 0, 'post', 'draft', 'public', 'all', '2016-02-27 00:20:40', '1', '2016-02-27 00:20:43', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('0761a4a583524619a8743b50', '0da9c635087e4e6e9fe69d6947c050ba', 'On Working Remotely', 'on-working-remotely', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"Long story short, find a way to be productive that works for YOU."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>Long story short, find a way to be productive that works for YOU.</p>\n<!--kg-card-end: markdown-->', 'Long story short, find a way to be productive that works for YOU.\n', NULL, 0, 'post', 'draft', 'public', 'all', '2016-02-27 05:44:57', '1', '2016-02-27 05:45:28', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('4654f053013543e1b592f9c0', 'a3fcf69976304bd0815538ba520d44c7', 'Dreams Aren''t Forever', 'now-or-never', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"Stop saying you''ll achieve your dreams “someday”, “eventually”, or “when it''s convenient” — it will never be convenient, “eventually” will never come, and “someday” is today.\\n\\nAs a kid I was confident that one day I was going to be president...or a scientist...or an astronaut. In retrospect, I''m glad I didn''t pursue any of those options, but at the time I told my parents I was as sincere as a human being can be, child or otherwise.\\n\\nDreams may not be forever, but as I''ve reflected on my changing dreams throughout my life, it''s curious that more and more they''re not something I''m going to do, and instead something “I wish I could do” or “would like to do one day.” This doesn''t seem to just be with me, but with everyone around me.\\n\\n was something I was going to do.\\n\\n\\n\\n“I would love to do that one day.”\\n\\n“I wish I had time to do that.”\\n\\nDreams are rarely forever."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>Stop saying you''ll achieve your dreams “someday”, “eventually”, or “when it''s convenient” — it will never be convenient, “eventually” will never come, and “someday” is today.</p>\n<p>As a kid I was confident that one day I was going to be president...or a scientist...or an astronaut. In retrospect, I''m glad I didn''t pursue any of those options, but at the time I told my parents I was as sincere as a human being can be, child or otherwise.</p>\n<p>Dreams may not be forever, but as I''ve reflected on my changing dreams throughout my life, it''s curious that more and more they''re not something I''m going to do, and instead something “I wish I could do” or “would like to do one day.” This doesn''t seem to just be with me, but with everyone around me.</p>\n<p>was something I was going to do.</p>\n<p>“I would love to do that one day.”</p>\n<p>“I wish I had time to do that.”</p>\n<p>Dreams are rarely forever.</p>\n<!--kg-card-end: markdown-->', 'Stop saying you''ll achieve your dreams “someday”, “eventually”, or “when it''s convenient” — it will never be convenient, “eventually” will never come, and “someday” is today.\n\n\nAs a kid I was confident that one day I was going to be president...or a scientist...or an astronaut. In retrospect, I''m glad I didn''t pursue any of those options, but at the time I told my parents I was as sincere as a human being can be, child or otherwise.\n\n\nDreams may not be forever, but as I''ve reflected on my ', NULL, 0, 'post', 'draft', 'public', 'all', '2016-05-09 20:49:11', '1', '2016-05-13 01:26:17', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('4d70aaf3eb094b44873aa47b', '21244931499a4bf19e0e875d7bf13e4a', 'Working Remotely as a Digital Nomad While Traveling', 'working-remotely-as-a-digital-nomad-while-traveling', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"On June 3rd, 2016 my girlfriend and I left San Francisco for New York City, kicking off the start of a 6 1/2 month journey that would take us around the world until we return to California just before the Christmas holiday.\\n\\nWhile its all been _extremely_ exciting, traveling for the better half of a year presented an interesting predicament as traveling tends to be expensive, and I''m regretfully not rich (yet). The good news is I already almost always work remotely and most places we''ve been traveling are _significantly_ cheaper than living in San Francisco, so making the jump to being a digital nomad is relatively seamless. In fact, I did the math on our former San Francisco one bedroom apartment''s monthly rent, and it came out to an inane $77.71/day — more than we''ve generally spent on housing, food, and all living costs combined, especially now that we''re in Thailand.\\n\\nThat said, there''s still some considerations to be had and _a lot_ of preparation to be made in advance with this kind of trip. This is definitely written from the point of view of a web contractor, but will hopefully be applicable to anyone looking to transition to being a digital nomad for.\\n\\n##Talk to clients as early as possible!\\nI wanted to believe work would be a 100% seamless transition where clients wouldn''t even know I''m on an island in the Gulf of Thailand, but in reality there''s going to be a few hiccups along the way. Unless you plan on staying in one place long-term, assume you''ll have at least a few days where you don''t have a working cell phone and/or internet fast enough to upload your work (or no internet at all). Chances are this will happen more frequently if you''re traveling in second and third-world countries, but even in highly developed places like Europe you''ll likely find yourself with a few days that are a wash.\\n\\nWhile I do my best to avoid these situations whenever possible, you need clients who will be understanding when you do fall off the grid for 24-48 hours (power/internet here sometimes drops randomly for hours at a time!), and if anything be excited for the journey you''re about to take. In the event that an existing client (or employer) isn''t comfortable with that kind of possibility, you need to work with them to wind things down leading up to your departure, and if possible help them get your replacement up to speed sooner than later.\\n\\n##Be realistic about how much you can work and communicate when you can''t.\\nWorking constantly while traveling is not like working at home — it''s way more chaotic, exhausting, and ultimately takes time away from enjoying all the exciting things happening around you. 30 hour work weeks may sound like living the dream compared to the 40+ hour work weeks most people experience at home, but when you''re hopping around the world on planes and trains there''s a good chance those 30 hours will feel a lot more like 60. Plan your work ahead as much as possible, and talk to your client about working extra hours leading up to and following periods where you know you won''t be able to put in your normal amount of work. Research where you''re going ahead of time, and if you know internet might be spotty be sure to let your client know ahead of time.\\n\\n##Be honest and don''t be afraid to turn down clients.\\nThis is arguably good advice for even non-nomads, but it''s especially important when your traveling and time is limited. Be upfront and honest with both yourselves and your client(s)/potential client(s) about you can and can''t do, and strongly consider not just the number of hours you''ll be working, but also the responsibility you''ll owe to your client to do a quality job within the timeline you''re agreeing to. It''s always tough to say no when you''ve got dollar signs in your eyes, but unless you''re incredibly strapped for cash you should aim for a balance between work and enjoying the new culture around you.\\n\\n##Don''t compromise just because you''re traveling.\\nI have no idea what was in the water in July, but I personally had an onslaught of potential projects (at least 8!) thrown my way over a period of two weeks, and am forever thankful that I turned down all but one. Of the other ~7 that I turned down, at least 2 asked if I could relocate to their location earlier than the planned end of our trip, and one even asked what my discounted rate was as I was out of the country where cost of living is cheaper. (Spoiler Alert: I only offer “discounted” rates for long-term retainer-based contracts of 2+ months at 40+ hours/month or more as there''s an inherent benefit in not needing to constantly follow up on new project leads while managing a dozen different projects.). \\n\\nThere''s something to be said about full time salaries being adjusted based on cost of living, but as a contractor you''re selling your expertise, skill, and most importantly your time. If a client wants to hire a cheaper overseas contractor they are more than welcome to do so, but you shouldn''t make yourself that contractor.\\n\\n##The Internet is your friend (seriously).\\nThere''s a _huge_ wealth of resources out there to help you plan around your work needs — use them. My personal favorites have been a few travel staples like [lonelyplanet.com](lonelyplanet.com) and [wikitravel.org](wikitravel.org), and a few lesser known ones like [nomadlist.com](nomadlist.com) and [nomadforum.io](nomadforum.io). Also, if you''re going to Southeast Asia be sure to check out Facebook Groups — while we mostly use Facebook for connecting with friends in the United States, there seems to be a group in each city for literally _everything_, from meeting other expats to dating to renting an apartment.\\n\\n##Get used to working offline.\\nI might work as a web designer and developer, but not having internet can''t be an excuse for not getting any work done. In the weeks leading up to traveling try intentionally turning off your wifi for a half day at a time and figure out what you can and can''t do while offline. Work on gradually making sure anything you normally would need the internet for can be done offline, and if it can''t then give yourself a list of alternative tasks you can do in the meantime. Prior to leaving I gradually made sure all my web projects can run locally without an internet connection and training myself to use [Dash for OSX](https://kapeli.com/dash) to read docs rather than searching online. For one project it admittedly required a good few modifications to the backend server, but more than paid for itself when I was able to do a solid 8 hours of work while on the slow ferry from Athens to Milos in the Greek Isles.\\n\\nIf there''s any large uploads/downloads you''ll need to make be sure to do them either before you leave or while you''re in major cities where connections are fast and latency to US services are low — it''s easy to forget when living in the US or Europe, but uploading/downloading to a server on the other side of the world can take 100x as long even when you have a fast local connection.\\n\\n##Work Asynchronously\\nTaking 1AM calls is part of the deal you make when you choose to work remotely and travel the world, but it definitely shouldn''t be the norm. Make sure that whatever client''s you''re keeping or accepting are used to working in an asynchronous manner via either email, chat applications like Slack, or project management applications like [Github](https://github.com/), [Asana](https://asana.com/), or [Trello](https://trello.com/). My primary two clients have employees around the world across at least a dozen timezones, and using Slack for almost all our communication has made it barely any different than when I was living in San Francisco. The main thing you (and your client) need to keep in mind is that _every sentence counts_ when you get to be on a 12+ hour time difference. If you forget to say something or you''re not clear in what you need, that could mean another 24 hour delay from your original message.\\n\\nIf you haven''t already, check out [Remote by Jason Fried](https://www.amazon.com/Remote-Office-Required-Jason-Fried/dp/0804137501) (founder of [37Signals/Basecamp](https://basecamp.com/)). It''s admittedly at times a bit general, but overall it lays down a lot of common sense principals for both individuals and clients/employers that can help make working remotely successful.\\n\\n##Get a VPN (Virtual Private Network)\\nWhile using a VPN for security might be overkill in your situation, you''d be surprised how many websites don''t work properly when they detect you''re in another country. Paypal alone has already refused to let me access my account in both Greece and Thailand, and without a VPN to route my traffic through the US I wouldn''t have a way to get payments from one of my clients to my actual checking account. If you''re doing development work there''s also a good chance you''ll encounter public wifi that (for reasons unbeknownst to me) block port 22, making SSH worthless without a VPN.\\n\\nIf you need to sign up for one I can''t recommend [Private Internet Access](https://www.privateinternetaccess.com/) highly enough. Their setup isn''t the prettiest or fanciest, but their servers have so far been extremely reliable, as fast as one can expect when routing traffic halfway around the world and back, and they take their user''s privacy to an extreme by forcing you to use anonymous usernames, not maintaining logs of any user traffic, and allowing you to pay via (more) anonymous methods like Bitcoin. In at least one case over the past 6 months they''ve sent a newsletter letting all users know that they were retiring their Russian VPN locations due to concerns over new legislation that would potentially compromise their customer''s privacy.\\n\\n##If you''re starting a new business, give yourself at least 3 months to be revenue-positive.\\nLastly, traveling can be the perfect time to start a digital or online business, but remember that it takes time (and often money) to build something profitable from scratch (it took me almost 6 months of contracting back in 2012 before my income stream was stable). If you can, do as much of the upfront legwork before you leave, and make sure you have enough savings to pay for everything for at _least_ 3 months. In the highly possible event you aren''t making enough money by the time your savings starts to run dry, be sure to have a backup plan in place that either lets you jump ship for back home or pickup a local job that covers the bills.\\n\\n##Be Prepared for a “Worst Case [Technology] Scenario”\\nWithin a few weeks of starting our trip, my girlfriend encountered my worst fear: with no prior signs of issues her barely one year old Macbook Pro wouldn''t power on. I tried every combination of system reset keys in the book, but as it wouldn''t even begin to power on it looked like it was a hardware issue. Unfortunately, we were at the time in Dublin, Ireland where there''s oddly no official Apple Store and any secondary repair shops had a 3-5 day turnaround time...not promising when we had a flight to London in two days. We looked at getting it fixed in London, but all their Apple Store appointments were booked a full two weeks out, and the next Apple Store we''d encounter with open appointments wasn''t for two weeks in Milano, Italy.\\n\\nIn the end we thankfully we got it fixed (damn faulty Mac logic boards), but as it was just barely outside it''s warranty window _and_ under a US warranty (many companies, Apple included, don''t always honor warranties from different countries) it ended up being a few hundred dollar repair. There''s not a lot you can do to prepare for this one, but just remember that as reliable as your laptop is now, getting it repaired overseas might not be as simple as hopping down to the nearest Apple Store. If having a running laptop is crucial to your work, it''s worth having that emergency fund for that unexpected repair or replacement.\\n\\n##Final Thoughts\\nWorking remotely as a digital nomad can be an extremely rewarding experience, just make sure you have everything in order _before_ you hit the road and most of all: communicate, communicate, __COMMUNICATE__! Almost all problems that come from working remotely can be avoided if both parties are communicating clearly (and honestly) as early as possible.\\n\\nHave you or are you working as a digital nomad and have something you think would be worth adding? Email me at rob at atomidesign.com and let''s chat!\\n\\n<figure>\\n![Client meeting in progress](/content/images/2016/08/DSC_0534-edited.jpg)\\n<figcaption class=\\"figure__pull\\"><span class=\\"figure__title\\">When things don''t go according to plan.</span>An important client meeting in progress from Piraeus Port in Athens via mobile Google Hangouts. Our ferry from Santorini to Athens ran 3 hours late due to rough seas and I had to start the call while deboarding with a thousand other people.</figcaption>\\n</figure>"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>On June 3rd, 2016 my girlfriend and I left San Francisco for New York City, kicking off the start of a 6 1/2 month journey that would take us around the world until we return to California just before the Christmas holiday.</p>\n<p>While its all been <em>extremely</em> exciting, traveling for the better half of a year presented an interesting predicament as traveling tends to be expensive, and I''m regretfully not rich (yet). The good news is I already almost always work remotely and most places we''ve been traveling are <em>significantly</em> cheaper than living in San Francisco, so making the jump to being a digital nomad is relatively seamless. In fact, I did the math on our former San Francisco one bedroom apartment''s monthly rent, and it came out to an inane $77.71/day — more than we''ve generally spent on housing, food, and all living costs combined, especially now that we''re in Thailand.</p>\n<p>That said, there''s still some considerations to be had and <em>a lot</em> of preparation to be made in advance with this kind of trip. This is definitely written from the point of view of a web contractor, but will hopefully be applicable to anyone looking to transition to being a digital nomad for.</p>\n<h2 id="talktoclientsasearlyaspossible">Talk to clients as early as possible!</h2>\n<p>I wanted to believe work would be a 100% seamless transition where clients wouldn''t even know I''m on an island in the Gulf of Thailand, but in reality there''s going to be a few hiccups along the way. Unless you plan on staying in one place long-term, assume you''ll have at least a few days where you don''t have a working cell phone and/or internet fast enough to upload your work (or no internet at all). Chances are this will happen more frequently if you''re traveling in second and third-world countries, but even in highly developed places like Europe you''ll likely find yourself with a few days that are a wash.</p>\n<p>While I do my best to avoid these situations whenever possible, you need clients who will be understanding when you do fall off the grid for 24-48 hours (power/internet here sometimes drops randomly for hours at a time!), and if anything be excited for the journey you''re about to take. In the event that an existing client (or employer) isn''t comfortable with that kind of possibility, you need to work with them to wind things down leading up to your departure, and if possible help them get your replacement up to speed sooner than later.</p>\n<h2 id="berealisticabouthowmuchyoucanworkandcommunicatewhenyoucant">Be realistic about how much you can work and communicate when you can''t.</h2>\n<p>Working constantly while traveling is not like working at home — it''s way more chaotic, exhausting, and ultimately takes time away from enjoying all the exciting things happening around you. 30 hour work weeks may sound like living the dream compared to the 40+ hour work weeks most people experience at home, but when you''re hopping around the world on planes and trains there''s a good chance those 30 hours will feel a lot more like 60. Plan your work ahead as much as possible, and talk to your client about working extra hours leading up to and following periods where you know you won''t be able to put in your normal amount of work. Research where you''re going ahead of time, and if you know internet might be spotty be sure to let your client know ahead of time.</p>\n<h2 id="behonestanddontbeafraidtoturndownclients">Be honest and don''t be afraid to turn down clients.</h2>\n<p>This is arguably good advice for even non-nomads, but it''s especially important when your traveling and time is limited. Be upfront and honest with both yourselves and your client(s)/potential client(s) about you can and can''t do, and strongly consider not just the number of hours you''ll be working, but also the responsibility you''ll owe to your client to do a quality job within the timeline you''re agreeing to. It''s always tough to say no when you''ve got dollar signs in your eyes, but unless you''re incredibly strapped for cash you should aim for a balance between work and enjoying the new culture around you.</p>\n<h2 id="dontcompromisejustbecauseyouretraveling">Don''t compromise just because you''re traveling.</h2>\n<p>I have no idea what was in the water in July, but I personally had an onslaught of potential projects (at least 8!) thrown my way over a period of two weeks, and am forever thankful that I turned down all but one. Of the other ~7 that I turned down, at least 2 asked if I could relocate to their location earlier than the planned end of our trip, and one even asked what my discounted rate was as I was out of the country where cost of living is cheaper. (Spoiler Alert: I only offer “discounted” rates for long-term retainer-based contracts of 2+ months at 40+ hours/month or more as there''s an inherent benefit in not needing to constantly follow up on new project leads while managing a dozen different projects.).</p>\n<p>There''s something to be said about full time salaries being adjusted based on cost of living, but as a contractor you''re selling your expertise, skill, and most importantly your time. If a client wants to hire a cheaper overseas contractor they are more than welcome to do so, but you shouldn''t make yourself that contractor.</p>\n<h2 id="theinternetisyourfriendseriously">The Internet is your friend (seriously).</h2>\n<p>There''s a <em>huge</em> wealth of resources out there to help you plan around your work needs — use them. My personal favorites have been a few travel staples like <a href="lonelyplanet.com">lonelyplanet.com</a> and <a href="wikitravel.org">wikitravel.org</a>, and a few lesser known ones like <a href="nomadlist.com">nomadlist.com</a> and <a href="nomadforum.io">nomadforum.io</a>. Also, if you''re going to Southeast Asia be sure to check out Facebook Groups — while we mostly use Facebook for connecting with friends in the United States, there seems to be a group in each city for literally <em>everything</em>, from meeting other expats to dating to renting an apartment.</p>\n<h2 id="getusedtoworkingoffline">Get used to working offline.</h2>\n<p>I might work as a web designer and developer, but not having internet can''t be an excuse for not getting any work done. In the weeks leading up to traveling try intentionally turning off your wifi for a half day at a time and figure out what you can and can''t do while offline. Work on gradually making sure anything you normally would need the internet for can be done offline, and if it can''t then give yourself a list of alternative tasks you can do in the meantime. Prior to leaving I gradually made sure all my web projects can run locally without an internet connection and training myself to use <a href="https://kapeli.com/dash">Dash for OSX</a> to read docs rather than searching online. For one project it admittedly required a good few modifications to the backend server, but more than paid for itself when I was able to do a solid 8 hours of work while on the slow ferry from Athens to Milos in the Greek Isles.</p>\n<p>If there''s any large uploads/downloads you''ll need to make be sure to do them either before you leave or while you''re in major cities where connections are fast and latency to US services are low — it''s easy to forget when living in the US or Europe, but uploading/downloading to a server on the other side of the world can take 100x as long even when you have a fast local connection.</p>\n<h2 id="workasynchronously">Work Asynchronously</h2>\n<p>Taking 1AM calls is part of the deal you make when you choose to work remotely and travel the world, but it definitely shouldn''t be the norm. Make sure that whatever client''s you''re keeping or accepting are used to working in an asynchronous manner via either email, chat applications like Slack, or project management applications like <a href="https://github.com/">Github</a>, <a href="https://asana.com/">Asana</a>, or <a href="https://trello.com/">Trello</a>. My primary two clients have employees around the world across at least a dozen timezones, and using Slack for almost all our communication has made it barely any different than when I was living in San Francisco. The main thing you (and your client) need to keep in mind is that <em>every sentence counts</em> when you get to be on a 12+ hour time difference. If you forget to say something or you''re not clear in what you need, that could mean another 24 hour delay from your original message.</p>\n<p>If you haven''t already, check out <a href="https://www.amazon.com/Remote-Office-Required-Jason-Fried/dp/0804137501">Remote by Jason Fried</a> (founder of <a href="https://basecamp.com/">37Signals/Basecamp</a>). It''s admittedly at times a bit general, but overall it lays down a lot of common sense principals for both individuals and clients/employers that can help make working remotely successful.</p>\n<h2 id="getavpnvirtualprivatenetwork">Get a VPN (Virtual Private Network)</h2>\n<p>While using a VPN for security might be overkill in your situation, you''d be surprised how many websites don''t work properly when they detect you''re in another country. Paypal alone has already refused to let me access my account in both Greece and Thailand, and without a VPN to route my traffic through the US I wouldn''t have a way to get payments from one of my clients to my actual checking account. If you''re doing development work there''s also a good chance you''ll encounter public wifi that (for reasons unbeknownst to me) block port 22, making SSH worthless without a VPN.</p>\n<p>If you need to sign up for one I can''t recommend <a href="https://www.privateinternetaccess.com/">Private Internet Access</a> highly enough. Their setup isn''t the prettiest or fanciest, but their servers have so far been extremely reliable, as fast as one can expect when routing traffic halfway around the world and back, and they take their user''s privacy to an extreme by forcing you to use anonymous usernames, not maintaining logs of any user traffic, and allowing you to pay via (more) anonymous methods like Bitcoin. In at least one case over the past 6 months they''ve sent a newsletter letting all users know that they were retiring their Russian VPN locations due to concerns over new legislation that would potentially compromise their customer''s privacy.</p>\n<h2 id="ifyourestartinganewbusinessgiveyourselfatleast3monthstoberevenuepositive">If you''re starting a new business, give yourself at least 3 months to be revenue-positive.</h2>\n<p>Lastly, traveling can be the perfect time to start a digital or online business, but remember that it takes time (and often money) to build something profitable from scratch (it took me almost 6 months of contracting back in 2012 before my income stream was stable). If you can, do as much of the upfront legwork before you leave, and make sure you have enough savings to pay for everything for at <em>least</em> 3 months. In the highly possible event you aren''t making enough money by the time your savings starts to run dry, be sure to have a backup plan in place that either lets you jump ship for back home or pickup a local job that covers the bills.</p>\n<h2 id="bepreparedforaworstcasetechnologyscenario">Be Prepared for a “Worst Case [Technology] Scenario”</h2>\n<p>Within a few weeks of starting our trip, my girlfriend encountered my worst fear: with no prior signs of issues her barely one year old Macbook Pro wouldn''t power on. I tried every combination of system reset keys in the book, but as it wouldn''t even begin to power on it looked like it was a hardware issue. Unfortunately, we were at the time in Dublin, Ireland where there''s oddly no official Apple Store and any secondary repair shops had a 3-5 day turnaround time...not promising when we had a flight to London in two days. We looked at getting it fixed in London, but all their Apple Store appointments were booked a full two weeks out, and the next Apple Store we''d encounter with open appointments wasn''t for two weeks in Milano, Italy.</p>\n<p>In the end we thankfully we got it fixed (damn faulty Mac logic boards), but as it was just barely outside it''s warranty window <em>and</em> under a US warranty (many companies, Apple included, don''t always honor warranties from different countries) it ended up being a few hundred dollar repair. There''s not a lot you can do to prepare for this one, but just remember that as reliable as your laptop is now, getting it repaired overseas might not be as simple as hopping down to the nearest Apple Store. If having a running laptop is crucial to your work, it''s worth having that emergency fund for that unexpected repair or replacement.</p>\n<h2 id="finalthoughts">Final Thoughts</h2>\n<p>Working remotely as a digital nomad can be an extremely rewarding experience, just make sure you have everything in order <em>before</em> you hit the road and most of all: communicate, communicate, <strong>COMMUNICATE</strong>! Almost all problems that come from working remotely can be avoided if both parties are communicating clearly (and honestly) as early as possible.</p>\n<p>Have you or are you working as a digital nomad and have something you think would be worth adding? Email me at rob at atomidesign.com and let''s chat!</p>\n<figure>\n![Client meeting in progress](/content/images/2016/08/DSC_0534-edited.jpg)\n<figcaption class="figure__pull"><span class="figure__title">When things don''t go according to plan.</span>An important client meeting in progress from Piraeus Port in Athens via mobile Google Hangouts. Our ferry from Santorini to Athens ran 3 hours late due to rough seas and I had to start the call while deboarding with a thousand other people.</figcaption>\n</figure><!--kg-card-end: markdown-->', 'On June 3rd, 2016 my girlfriend and I left San Francisco for New York City, kicking off the start of a 6 1/2 month journey that would take us around the world until we return to California just before the Christmas holiday.\n\n\nWhile its all been extremely exciting, traveling for the better half of a year presented an interesting predicament as traveling tends to be expensive, and I''m regretfully not rich (yet). The good news is I already almost always work remotely and most places we''ve been t', '__GHOST_URL__/content/images/2016/08/digital-nomad-map.jpg', 0, 'post', 'published', 'public', 'all', '2016-05-19 22:43:19', '1', '2016-08-14 12:52:08', '1', '2016-08-14 09:40:00', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('7d4fccacc9c24089bcd52999', 'ffd3699432ab414c93a50cc9a38ade82', 'Ballpark Estimates and Budgets, Oh My!', 'dear-client-keep-asking-for-a-ballpark-estimate', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"Fresh from lunch with an old client, I sat down to ~~do work~~ read HackerNews and came across an article that struck a chord titled [Dear Client: Stop Asking For A Ballpark Estimate](http://www.christopherhawkins.com/2016/05/ballpark-estimate/). Intrigued and excited, I dove right in, only to find myself frustrated and annoyed by the author''s binary opinion and borderline childish finger criticism of clients.\\n\\nIn short, the author arrives at his point early on when he satirically expands the question of, “So, what''s a ballpark estimate of what that would cost?” to “So, can you guess exactly what’s required to make this thing we haven’t even fully-defined yet?”, and proceeds puts the blame on the client for asking what is, from their point-of-view, a completely rational and reasonable question.\\n\\n##It''s Called a Ballpark Estimate for a Reason\\nYes, you might not have enough information to provide a contract-binding estimate[^n], but as a consultant it''s frequently your job to help the client figure out what they really need and whether it''s reasonably within their budget. In rare cases a client might come to you with a well-defined scope off which you can give a reasonably accurate estimate range, but more often then not it''ll talk at least a few discussions and frequently a discovery day (paid hourly) to dig into the client''s issues and lock down a better defined scope off which a more accurate estimate can be based. \\n\\nThis isn''t a bad thing and doesn''t mean ballpark estimates are moot — the point of the ballpark estimate is that it''s supposed to be a vague and open-ended range that''s subject to change as new information arises during your discussions and discovery. If you give a ballpark estimate of $10,000-$25,000, and later have to revise it to $35,000 that''s fine, just deliver the news in a concise and professional manner with clear reasons as to why you''ve increased your estimate[^n]. If the project is so far out of your comfort zone that you don''t feel comfortable giving a ballpark estimate, it''s your responsibility to tell the client that you''ll need to do more research or talk to other people on your team, and will get back to them once you know more.\\n\\nBallpark estimates are the equivalent to you asking the client, “What''s your budget?” Some corporate clients might have specific dollar amounts, but many others are looking to you to know how much they need to set aside or authorize from their company to make the project possible.\\n\\nI do agree that a project discovery phase should indeed be the first phase of any project, but it''s not worth paying you the money on a discovery session if it''s already obvious that it''s going to be way out of the client''s budget.  [Basseq]() on HackerNews nailed it on the head:\\n\\n> “..can I afford it? Is it even worth paying you $1,000 for a discovery session if the implementation is going to cost me 10x my budget in any case? Is it worth taking the next meeting with you?”\\n\\nSure, making an extra grand is always nice, but I''d much rather help the client by saving them that money and referring them to another consultant who''s a better fit.\\n\\n[^n]: Not that you should be doing that at this stage anyway.\\n[^n]: If a potential client can''t respect you being upfront and honest, then they''re probably not the type of client you want to be working with."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>Fresh from lunch with an old client, I sat down to <s>do work</s> read HackerNews and came across an article that struck a chord titled <a href="http://www.christopherhawkins.com/2016/05/ballpark-estimate/">Dear Client: Stop Asking For A Ballpark Estimate</a>. Intrigued and excited, I dove right in, only to find myself frustrated and annoyed by the author''s binary opinion and borderline childish finger criticism of clients.</p>\n<p>In short, the author arrives at his point early on when he satirically expands the question of, “So, what''s a ballpark estimate of what that would cost?” to “So, can you guess exactly what’s required to make this thing we haven’t even fully-defined yet?”, and proceeds puts the blame on the client for asking what is, from their point-of-view, a completely rational and reasonable question.</p>\n<h2 id="itscalledaballparkestimateforareason">It''s Called a Ballpark Estimate for a Reason</h2>\n<p>Yes, you might not have enough information to provide a contract-binding estimate<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup>, but as a consultant it''s frequently your job to help the client figure out what they really need and whether it''s reasonably within their budget. In rare cases a client might come to you with a well-defined scope off which you can give a reasonably accurate estimate range, but more often then not it''ll talk at least a few discussions and frequently a discovery day (paid hourly) to dig into the client''s issues and lock down a better defined scope off which a more accurate estimate can be based.</p>\n<p>This isn''t a bad thing and doesn''t mean ballpark estimates are moot — the point of the ballpark estimate is that it''s supposed to be a vague and open-ended range that''s subject to change as new information arises during your discussions and discovery. If you give a ballpark estimate of $10,000-$25,000, and later have to revise it to $35,000 that''s fine, just deliver the news in a concise and professional manner with clear reasons as to why you''ve increased your estimate<sup class="footnote-ref"><a href="#fn1" id="fnref1:1">[1:1]</a></sup>. If the project is so far out of your comfort zone that you don''t feel comfortable giving a ballpark estimate, it''s your responsibility to tell the client that you''ll need to do more research or talk to other people on your team, and will get back to them once you know more.</p>\n<p>Ballpark estimates are the equivalent to you asking the client, “What''s your budget?” Some corporate clients might have specific dollar amounts, but many others are looking to you to know how much they need to set aside or authorize from their company to make the project possible.</p>\n<p>I do agree that a project discovery phase should indeed be the first phase of any project, but it''s not worth paying you the money on a discovery session if it''s already obvious that it''s going to be way out of the client''s budget.  <a href="">Basseq</a> on HackerNews nailed it on the head:</p>\n<blockquote>\n<p>“..can I afford it? Is it even worth paying you $1,000 for a discovery session if the implementation is going to cost me 10x my budget in any case? Is it worth taking the next meeting with you?”</p>\n</blockquote>\n<p>Sure, making an extra grand is always nice, but I''d much rather help the client by saving them that money and referring them to another consultant who''s a better fit.</p>\n<hr class="footnotes-sep">\n<section class="footnotes">\n<ol class="footnotes-list">\n<li id="fn1" class="footnote-item"><p>If a potential client can''t respect you being upfront and honest, then they''re probably not the type of client you want to be working with. <a href="#fnref1" class="footnote-backref">↩︎</a> <a href="#fnref1:1" class="footnote-backref">↩︎</a></p>\n</li>\n</ol>\n</section>\n<!--kg-card-end: markdown-->', 'Fresh from lunch with an old client, I sat down to do work read HackerNews and came across an article that struck a chord titled Dear Client: Stop Asking For A Ballpark Estimate. Intrigued and excited, I dove right in, only to find myself frustrated and annoyed by the author''s binary opinion and borderline childish finger criticism of clients.\n\n\nIn short, the author arrives at his point early on when he satirically expands the question of, “So, what''s a ballpark estimate of what that would co', NULL, 0, 'post', 'draft', 'public', 'all', '2016-05-20 20:55:42', '1', '2016-06-12 16:19:04', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('00b4e6908aca4938886f036b', 'd304ba3fde314ccb915765d5adf0f465', 'Leveraging Chrome Developer Tools as a Designer', 'leveraging-chrome-developer-tools-as-a-designer', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"_This is the second in a planned series of articles on the topic of being a designer who codes. As I publish additional articles in the series they will appear here accordingly._\\n\\n1. [Why Designers Should Code](__GHOST_URL__/why-designers-should-code/)\\n2. Leveraging Chrome Developer Tools as a Designer\\n\\nIn Part One of the series I touched on the idea that being a designer who codes not only allows you to have better control of the quality of the final product, but also vastly improves the speed at which you''re able to iterate on ideas, feedback, or bugs through the use of tools like Chrome Developer Tools or Firebug.\\n\\nIf you''re familiar with neither, Chrome Developer Tools is a suite of goodies bundled with Google Chrome by default that lets you do everything from edit live HTML & CSS, inspect network requests, throttle your network speed for testing, test at mobile resolutions, and a whole lot more. Firebug is similar in scope but is used as a browser plugin, most commonly with Firefox and Internet Explorer. For the purpose of this article we''ll be focusing on Chrome Developer Tools (or Dev Tools for short). Should you need to debug an issue in Safari they also have a near-identical suite of tools (both browsers are based on Webkit), but you need to enable them in the browser settings and they tend to be a buggier/less intuitive than their Chrome counterpart.\\n\\nWhile you could fill a book with the details of Chrome Dev Tools[^n], I want to focus on a few key aspects that will be of use to UI/UX designers looking to get their hands dirty.\\n\\n##Test Ideas in Realtime\\n\\nThis is the main use-case of Dev Tools for a designer, and probably my favorite to put to use when I''m collaborating on something with another designer or my client. While I _definitely_ still do use Sketch for static mockups, once I have a solid design direction going I''ll frequently start writing translating those designs into HTML/SCSS as early as possible so I can test how it actually looks and feels when in a native browser.\\n\\nIn another instance you''re in a meeting with a client reviewing a design, and you receive a run-of-the-mill request like, “Can we see the post titles in a larger font and in a darker font?”\\n\\nIf you''re reviewing static mockups these kind of requests can be a pain as it either means spending a few minutes pulling up Photoshop/Sketch to test those edits while everyone else in the meeting waits and watches, or it means you telling your client that you''ll make those edits later and email it to them.\\n\\nOn the other hand, if you''re reviewing a coded design you can right-click the post title in question, click `Inspect Element`, and tweak both the `font-size` and `color` CSS values with instant-feedback. Instead of continuing the lengthy cycle of emailing back-and-forth or scheduling ongoing meetings until you reach something that''s “acceptable”, you can discuss what your client or collaborators are thinking on the spot in a fraction of the time. In doing so you''re not only wasting less time, but also affording more flexibility within your client''s budget for you to focus on other, fun design details that you''re passionate about getting “just right”.\\n\\n##Throttle Your Bandwidth\\n\\nYou might be asking, why in the world would you do that? I thought that until I got to Thailand and found that a <1mbps wifi connection was pretty normal on the island I''m living on, and that when I was loading a US hosted site the problem became doubly bad.\\n\\nWhile the actual tasks needed to remedy poor loading time on on a slow connection are often in the realm of backend development or devops, bringing attention to any problems in the end-user''s experience still falls into yours, and [hopefully to a degree] everyone involved on the project''s responsibilities.\\n\\n[^n]: Actually, it looks like someone already did: [Google Chrome Developer Tools: Beginners Guide + Video Course](https://www.amazon.com/Google-Chrome-Developer-Tools-Beginners-ebook/dp/B00J4J8XG6)"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p><em>This is the second in a planned series of articles on the topic of being a designer who codes. As I publish additional articles in the series they will appear here accordingly.</em></p>\n<ol>\n<li><a href="__GHOST_URL__/why-designers-should-code/">Why Designers Should Code</a></li>\n<li>Leveraging Chrome Developer Tools as a Designer</li>\n</ol>\n<p>In Part One of the series I touched on the idea that being a designer who codes not only allows you to have better control of the quality of the final product, but also vastly improves the speed at which you''re able to iterate on ideas, feedback, or bugs through the use of tools like Chrome Developer Tools or Firebug.</p>\n<p>If you''re familiar with neither, Chrome Developer Tools is a suite of goodies bundled with Google Chrome by default that lets you do everything from edit live HTML &amp; CSS, inspect network requests, throttle your network speed for testing, test at mobile resolutions, and a whole lot more. Firebug is similar in scope but is used as a browser plugin, most commonly with Firefox and Internet Explorer. For the purpose of this article we''ll be focusing on Chrome Developer Tools (or Dev Tools for short). Should you need to debug an issue in Safari they also have a near-identical suite of tools (both browsers are based on Webkit), but you need to enable them in the browser settings and they tend to be a buggier/less intuitive than their Chrome counterpart.</p>\n<p>While you could fill a book with the details of Chrome Dev Tools<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup>, I want to focus on a few key aspects that will be of use to UI/UX designers looking to get their hands dirty.</p>\n<h2 id="testideasinrealtime">Test Ideas in Realtime</h2>\n<p>This is the main use-case of Dev Tools for a designer, and probably my favorite to put to use when I''m collaborating on something with another designer or my client. While I <em>definitely</em> still do use Sketch for static mockups, once I have a solid design direction going I''ll frequently start writing translating those designs into HTML/SCSS as early as possible so I can test how it actually looks and feels when in a native browser.</p>\n<p>In another instance you''re in a meeting with a client reviewing a design, and you receive a run-of-the-mill request like, “Can we see the post titles in a larger font and in a darker font?”</p>\n<p>If you''re reviewing static mockups these kind of requests can be a pain as it either means spending a few minutes pulling up Photoshop/Sketch to test those edits while everyone else in the meeting waits and watches, or it means you telling your client that you''ll make those edits later and email it to them.</p>\n<p>On the other hand, if you''re reviewing a coded design you can right-click the post title in question, click <code>Inspect Element</code>, and tweak both the <code>font-size</code> and <code>color</code> CSS values with instant-feedback. Instead of continuing the lengthy cycle of emailing back-and-forth or scheduling ongoing meetings until you reach something that''s “acceptable”, you can discuss what your client or collaborators are thinking on the spot in a fraction of the time. In doing so you''re not only wasting less time, but also affording more flexibility within your client''s budget for you to focus on other, fun design details that you''re passionate about getting “just right”.</p>\n<h2 id="throttleyourbandwidth">Throttle Your Bandwidth</h2>\n<p>You might be asking, why in the world would you do that? I thought that until I got to Thailand and found that a &lt;1mbps wifi connection was pretty normal on the island I''m living on, and that when I was loading a US hosted site the problem became doubly bad.</p>\n<p>While the actual tasks needed to remedy poor loading time on on a slow connection are often in the realm of backend development or devops, bringing attention to any problems in the end-user''s experience still falls into yours, and [hopefully to a degree] everyone involved on the project''s responsibilities.</p>\n<hr class="footnotes-sep">\n<section class="footnotes">\n<ol class="footnotes-list">\n<li id="fn1" class="footnote-item"><p>Actually, it looks like someone already did: <a href="https://www.amazon.com/Google-Chrome-Developer-Tools-Beginners-ebook/dp/B00J4J8XG6">Google Chrome Developer Tools: Beginners Guide + Video Course</a> <a href="#fnref1" class="footnote-backref">↩︎</a></p>\n</li>\n</ol>\n</section>\n<!--kg-card-end: markdown-->', 'This is the second in a planned series of articles on the topic of being a designer who codes. As I publish additional articles in the series they will appear here accordingly.\n\n\n 1. Why Designers Should Code\n 2. Leveraging Chrome Developer Tools as a Designer\n\n\nIn Part One of the series I touched on the idea that being a designer who codes not only allows you to have better control of the quality of the final product, but also vastly improves the speed at which you''re able to iterate on ', NULL, 0, 'post', 'draft', 'public', 'all', '2016-08-15 09:22:26', '1', '2016-09-05 09:25:35', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('1fe4d2ec1a2b45549f8654f7', 'dcb01da559e44cb1a81245ad2331c5b9', 'Designers Who Code Links', 'designers-who-code-links', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"##Pro\\n\\n* https://medium.com/@irondavy/designers-will-code-6c423fc5ccef#.eu4tg57xw\\n* http://irondavy.quora.com/Designers-Will-Code\\n* http://flyosity.com/application-design/if-you-can-think-design-code-you-win.php\\n* http://www.teehanlax.com/blog/designing-with-code/\\n\\n##Neutral\\n\\n* https://www.uie.com/brainsparks/2011/05/31/why-the-valley-wants-designers-that-can-code/\\n\\n##Against\\n\\n* http://designinginterfaces.com/2011/06/01/designers-that-code-a-response-to-jared-spool/\\n* http://jessicavallance.co.uk/2012/02/four-reasons-why-i-dont-think-a-designers-gotta-code/\\n\\n##Designer-Coders\\n\\n* http://www.brandonwalkin.com/blog/ & http://www.brandonwalkin.com/\\n* http://www.andreasilliger.com/\\n* http://www.michaelvillar.com/ ** (Head of design for Stripe Dashboard)\\n* http://radiantnode.com/\\n* http://9-bits.com/"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><h2 id="pro">Pro</h2>\n<ul>\n<li><a href="https://medium.com/@irondavy/designers-will-code-6c423fc5ccef#.eu4tg57xw">https://medium.com/@irondavy/designers-will-code-6c423fc5ccef#.eu4tg57xw</a></li>\n<li><a href="http://irondavy.quora.com/Designers-Will-Code">http://irondavy.quora.com/Designers-Will-Code</a></li>\n<li><a href="http://flyosity.com/application-design/if-you-can-think-design-code-you-win.php">http://flyosity.com/application-design/if-you-can-think-design-code-you-win.php</a></li>\n<li><a href="http://www.teehanlax.com/blog/designing-with-code/">http://www.teehanlax.com/blog/designing-with-code/</a></li>\n</ul>\n<h2 id="neutral">Neutral</h2>\n<ul>\n<li><a href="https://www.uie.com/brainsparks/2011/05/31/why-the-valley-wants-designers-that-can-code/">https://www.uie.com/brainsparks/2011/05/31/why-the-valley-wants-designers-that-can-code/</a></li>\n</ul>\n<h2 id="against">Against</h2>\n<ul>\n<li><a href="http://designinginterfaces.com/2011/06/01/designers-that-code-a-response-to-jared-spool/">http://designinginterfaces.com/2011/06/01/designers-that-code-a-response-to-jared-spool/</a></li>\n<li><a href="http://jessicavallance.co.uk/2012/02/four-reasons-why-i-dont-think-a-designers-gotta-code/">http://jessicavallance.co.uk/2012/02/four-reasons-why-i-dont-think-a-designers-gotta-code/</a></li>\n</ul>\n<h2 id="designercoders">Designer-Coders</h2>\n<ul>\n<li><a href="http://www.brandonwalkin.com/blog/">http://www.brandonwalkin.com/blog/</a> &amp; <a href="http://www.brandonwalkin.com/">http://www.brandonwalkin.com/</a></li>\n<li><a href="http://www.andreasilliger.com/">http://www.andreasilliger.com/</a></li>\n<li><a href="http://www.michaelvillar.com/">http://www.michaelvillar.com/</a> ** (Head of design for Stripe Dashboard)</li>\n<li><a href="http://radiantnode.com/">http://radiantnode.com/</a></li>\n<li><a href="http://9-bits.com/">http://9-bits.com/</a></li>\n</ul>\n<!--kg-card-end: markdown-->', 'Pro\n\n\n * https://medium.com/@irondavy/designers-will-code-6c423fc5ccef#.eu4tg57xw\n * http://irondavy.quora.com/Designers-Will-Code\n * http://flyosity.com/application-design/if-you-can-think-design-code-you-win.php\n * http://www.teehanlax.com/blog/designing-with-code/\n\n\n\nNeutral\n\n\n * https://www.uie.com/brainsparks/2011/05/31/why-the-valley-wants-designers-that-can-code/\n\n\n\nAgainst\n\n\n * http://designinginterfaces.com/2011/06/01/designers-that-code-a-response-to-jared-spool/\n ', NULL, 0, 'post', 'draft', 'public', 'all', '2016-08-18 15:13:53', '1', '2016-08-18 15:22:45', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('39f4b38214d84150a7af63b7', '26e3864934ec4754b4759f2b65afc7c8', 'Why You Need to Spend Time Optimizing Asset Size & Latency', 'why-you-need-to-spend-time-optimizing-asset-size-latency', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"Everyone seems to agree that websites and web application download sizes are getting bigger, but very few companies seem to be willing to devote the time and resources to actually optimizing against this trend.\\n\\nFacebook Feed - 4.4mb over 43.44s\\nFacebook Homepage - 242s over 1.3s, DCL 929ms, L 1.34s\\nTwitter Feed - 8.1mb over 1.6m, DCL 22.04s, L 48.11s\\nTwitter Homepage 842kb over 5.77s, DCL 2.14s, L 5.77s\\nReddit - 525kb over 28.72s, DCL 14.59s, L 27.81s\\nSF Streetsblog - 1.6mb over 9.55s, DCL 3.52s, L 8.6s\\nHoodline - 3.2mb over 12.21s, DCL 7.34s, L 10.08s\\nHacker News - 10.5kb over 2.26s, DCL 2.12s, L 2.26s\\nAnAndTech - 730kb over 16.62s, DCL 5.84s, L 16.20s\\nTechCrunch - 864kb over 25.29s, DCL 7.42s, L 18.56s\\nRobertNealan.com - 709kb over 18.13s, DCL 6.62s, L 18.14s\\nDesigners Who Code - 332kb over 5.35s, DCL 3.87s, L 5.07s\\nMeetup (Logged In) - 614kb over 9.80s, DCL 6.29s, L 7.25s\\nMedium - 955kb over 21.66s, DCL 14.16s, L 15.13s\\nEconomist - 2.8mb over 14.70s, DCL 4.22s, L 13.99s\\nGmail - 5.0mb over 18.52s, DCL 1.13s, L 2.52s\\nPinterest - 4.2mb over 9.99s, DCL 4.28s, L 8.08s\\nPinterest Homepage - 590kb over 12.13s, DCL 1.40s, L 1.64s"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>Everyone seems to agree that websites and web application download sizes are getting bigger, but very few companies seem to be willing to devote the time and resources to actually optimizing against this trend.</p>\n<p>Facebook Feed - 4.4mb over 43.44s<br>\nFacebook Homepage - 242s over 1.3s, DCL 929ms, L 1.34s<br>\nTwitter Feed - 8.1mb over 1.6m, DCL 22.04s, L 48.11s<br>\nTwitter Homepage 842kb over 5.77s, DCL 2.14s, L 5.77s<br>\nReddit - 525kb over 28.72s, DCL 14.59s, L 27.81s<br>\nSF Streetsblog - 1.6mb over 9.55s, DCL 3.52s, L 8.6s<br>\nHoodline - 3.2mb over 12.21s, DCL 7.34s, L 10.08s<br>\nHacker News - 10.5kb over 2.26s, DCL 2.12s, L 2.26s<br>\nAnAndTech - 730kb over 16.62s, DCL 5.84s, L 16.20s<br>\nTechCrunch - 864kb over 25.29s, DCL 7.42s, L 18.56s<br>\nRobertNealan.com - 709kb over 18.13s, DCL 6.62s, L 18.14s<br>\nDesigners Who Code - 332kb over 5.35s, DCL 3.87s, L 5.07s<br>\nMeetup (Logged In) - 614kb over 9.80s, DCL 6.29s, L 7.25s<br>\nMedium - 955kb over 21.66s, DCL 14.16s, L 15.13s<br>\nEconomist - 2.8mb over 14.70s, DCL 4.22s, L 13.99s<br>\nGmail - 5.0mb over 18.52s, DCL 1.13s, L 2.52s<br>\nPinterest - 4.2mb over 9.99s, DCL 4.28s, L 8.08s<br>\nPinterest Homepage - 590kb over 12.13s, DCL 1.40s, L 1.64s</p>\n<!--kg-card-end: markdown-->', 'Everyone seems to agree that websites and web application download sizes are getting bigger, but very few companies seem to be willing to devote the time and resources to actually optimizing against this trend.\n\n\nFacebook Feed - 4.4mb over 43.44s\n\nFacebook Homepage - 242s over 1.3s, DCL 929ms, L 1.34s\n\nTwitter Feed - 8.1mb over 1.6m, DCL 22.04s, L 48.11s\n\nTwitter Homepage 842kb over 5.77s, DCL 2.14s, L 5.77s\n\nReddit - 525kb over 28.72s, DCL 14.59s, L 27.81s\n\nSF Streetsblog - 1.6mb o', NULL, 0, 'post', 'draft', 'public', 'all', '2016-08-18 15:24:08', '1', '2016-08-18 16:05:41', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('f034a2bed6e14613af2e211c', '6d3f1d9ff38d4eb8bb79a65c36fbd8c3', 'NomadMap.io: Local Coffee, Wifi, and Co-Working Information for Digital Nomads', 'nomad-map', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"_TL;DR: Check out [nomadmap.io](//nomadmap.io) for great places to work while on the road. If you''re motivated to help contribute to a community cause (yes, you), keep reading below!_\\n\\n---\\n\\nIf you''ve never visited Thailand, it''s by _far_ one of the more developed Southeast Asian countries (second only to the city-country of Singapore), and that combined with its incredible natural beauty has made it one of the number one countries for tourists and digital nomads alike.\\n\\nYet despite all the digital nomads you cross paths with here, it seems as though the majority of high-quality information you find regarding the best places to go is still done by word-of-mouth or via trudging through archaic forums that are likely out of date[^n]. To be completely fair, this is part of the charm of traveling in the 2nd/3rd world, but when you''re a digital nomad with a work schedule, sometimes getting that information ASAP is the difference between shipping on time or being behind schedule (or worse, losing a client).\\n\\nAfter sharing my WIP map of Koh Tao coffeeshops on the NomadList Slack, Jordan Kerr and I decided to hack together [nomadmap.io](//nomadmap.io), an MVP for a crowdsourced map of all the best places for digital nomads to work from (or avoid) whether they''re a cafe, casual restaurant, jungle viewpoint, legit co-working office, or otherwise. \\n\\n##Why We Need Your Help\\n\\nWhile both Jordan and I _love_ traveling and working on the road, even one country like Thailand is too big for just two people to cover in detail, so we need everyone''s help to add their local knowledge to our super “high-tech” Google Spreadsheets (I told you this was an MVP) that feeds into the central Google Map at [nomadmap.io](nomadmap.io).\\n\\nEach spreadsheet covers one country, with a different tab for each city in that respective country, and an assortment of columns for each bit of data about that specific location (wifi speed, hours, power, etc). We''re adding the columns we can think of that are important, but if you think something else might be useful, feel free to add it to the right of the last column. New columns won''t immediately show up in the map until after we approve it, assuming it''s kosher/relevant I can''t see why it wouldn''t be.\\n\\n##Get to The Spreadsheets Already!\\n\\nCurrently Thailand is live on the map, whereas we''re in the information collecting phase for other Southeast Asian countries. Once we get enough entries for a given country/city to make it useful, we''ll push it live and encourage everyone to keep adding to it.\\n\\n###Live\\n* [Thailand]()\\n\\n###Coming Soon\\n* [Cambodia]()\\n* [Singapore]()\\n* [Malaysia]()\\n* [Vietnam]()\\n* [Phillipines]()\\n* [Laos]()\\n\\n_If you don''t see your country on here and are interested in contributing, [get in touch](__GHOST_URL__/contact). We want to cover other nomad areas too, but need people on the ground to help out._\\n\\n##How is this Different Than [InsertOtherCoworkingSite]?\\n\\nYou''re right, there''s quite a few of other coworking websites out there, but so far we''ve found none that cover much of anywhere in Asia (or much of anywhere outside the US for that matter). On top of that, they all seem to be either hyper-local and done by a small group based in that specific city, or hyper-global and consist of scraped data that''s low-quality, incomplete, or outdated to the point that we just end up using Yelp/Tripadvisor/FourSquare instead.\\n\\nWe already have lots and lots _and lots_ of ideas for “crazy-cool zoo-zab and bip-bop” features, but for now we''re launching this as a simple MVP to answer the question, “Can the digital nomad community help us make this happen?”\\n\\nOnce we have that figured out we have all kinds ideas lined up that aim to make this a portable, offline-accessible resource that encourages community participation and confirmation for as up-to-date information (or as up-to-date as humanly possible as place as fast moving as Southeast Asia).\\n\\nTo kickstart things, we''ve filled in everything we know or can find good information about in Thailand, but encourage you to add to the list if you know something we don''t. If you''re interested in getting more involved feel free to email me (see [contact page](__GHOST_URL__/contact)), or if you''re a member of [NomadList](nomadlist.io) message us on the Slack channel (@robnealan and @jfkerr respectively). \\n\\nA huge thanks to [TheTwoPercent](www.thetwopercent.co.uk) for his spreadsheets of Koh Samui and Koh Lanta! They were an excellent source of data points and helped inspire our choice to give this a go.\\n\\n[^n]: For example, half the information I''ve found about Thailand seems to date from before the 2014 military coup, which changed _a lot_ of the details about how things work in many areas."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p><em>TL;DR: Check out <a href="//nomadmap.io">nomadmap.io</a> for great places to work while on the road. If you''re motivated to help contribute to a community cause (yes, you), keep reading below!</em></p>\n<hr>\n<p>If you''ve never visited Thailand, it''s by <em>far</em> one of the more developed Southeast Asian countries (second only to the city-country of Singapore), and that combined with its incredible natural beauty has made it one of the number one countries for tourists and digital nomads alike.</p>\n<p>Yet despite all the digital nomads you cross paths with here, it seems as though the majority of high-quality information you find regarding the best places to go is still done by word-of-mouth or via trudging through archaic forums that are likely out of date<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup>. To be completely fair, this is part of the charm of traveling in the 2nd/3rd world, but when you''re a digital nomad with a work schedule, sometimes getting that information ASAP is the difference between shipping on time or being behind schedule (or worse, losing a client).</p>\n<p>After sharing my WIP map of Koh Tao coffeeshops on the NomadList Slack, Jordan Kerr and I decided to hack together <a href="//nomadmap.io">nomadmap.io</a>, an MVP for a crowdsourced map of all the best places for digital nomads to work from (or avoid) whether they''re a cafe, casual restaurant, jungle viewpoint, legit co-working office, or otherwise.</p>\n<h2 id="whyweneedyourhelp">Why We Need Your Help</h2>\n<p>While both Jordan and I <em>love</em> traveling and working on the road, even one country like Thailand is too big for just two people to cover in detail, so we need everyone''s help to add their local knowledge to our super “high-tech” Google Spreadsheets (I told you this was an MVP) that feeds into the central Google Map at <a href="nomadmap.io">nomadmap.io</a>.</p>\n<p>Each spreadsheet covers one country, with a different tab for each city in that respective country, and an assortment of columns for each bit of data about that specific location (wifi speed, hours, power, etc). We''re adding the columns we can think of that are important, but if you think something else might be useful, feel free to add it to the right of the last column. New columns won''t immediately show up in the map until after we approve it, assuming it''s kosher/relevant I can''t see why it wouldn''t be.</p>\n<h2 id="gettothespreadsheetsalready">Get to The Spreadsheets Already!</h2>\n<p>Currently Thailand is live on the map, whereas we''re in the information collecting phase for other Southeast Asian countries. Once we get enough entries for a given country/city to make it useful, we''ll push it live and encourage everyone to keep adding to it.</p>\n<h3 id="live">Live</h3>\n<ul>\n<li><a href="">Thailand</a></li>\n</ul>\n<h3 id="comingsoon">Coming Soon</h3>\n<ul>\n<li><a href="">Cambodia</a></li>\n<li><a href="">Singapore</a></li>\n<li><a href="">Malaysia</a></li>\n<li><a href="">Vietnam</a></li>\n<li><a href="">Phillipines</a></li>\n<li><a href="">Laos</a></li>\n</ul>\n<p><em>If you don''t see your country on here and are interested in contributing, <a href="__GHOST_URL__/contact">get in touch</a>. We want to cover other nomad areas too, but need people on the ground to help out.</em></p>\n<h2 id="howisthisdifferentthaninsertothercoworkingsite">How is this Different Than [InsertOtherCoworkingSite]?</h2>\n<p>You''re right, there''s quite a few of other coworking websites out there, but so far we''ve found none that cover much of anywhere in Asia (or much of anywhere outside the US for that matter). On top of that, they all seem to be either hyper-local and done by a small group based in that specific city, or hyper-global and consist of scraped data that''s low-quality, incomplete, or outdated to the point that we just end up using Yelp/Tripadvisor/FourSquare instead.</p>\n<p>We already have lots and lots <em>and lots</em> of ideas for “crazy-cool zoo-zab and bip-bop” features, but for now we''re launching this as a simple MVP to answer the question, “Can the digital nomad community help us make this happen?”</p>\n<p>Once we have that figured out we have all kinds ideas lined up that aim to make this a portable, offline-accessible resource that encourages community participation and confirmation for as up-to-date information (or as up-to-date as humanly possible as place as fast moving as Southeast Asia).</p>\n<p>To kickstart things, we''ve filled in everything we know or can find good information about in Thailand, but encourage you to add to the list if you know something we don''t. If you''re interested in getting more involved feel free to email me (see <a href="__GHOST_URL__/contact">contact page</a>), or if you''re a member of <a href="nomadlist.io">NomadList</a> message us on the Slack channel (@robnealan and @jfkerr respectively).</p>\n<p>A huge thanks to <a href="www.thetwopercent.co.uk">TheTwoPercent</a> for his spreadsheets of Koh Samui and Koh Lanta! They were an excellent source of data points and helped inspire our choice to give this a go.</p>\n<hr class="footnotes-sep">\n<section class="footnotes">\n<ol class="footnotes-list">\n<li id="fn1" class="footnote-item"><p>For example, half the information I''ve found about Thailand seems to date from before the 2014 military coup, which changed <em>a lot</em> of the details about how things work in many areas. <a href="#fnref1" class="footnote-backref">↩︎</a></p>\n</li>\n</ol>\n</section>\n<!--kg-card-end: markdown-->', 'TL;DR: Check out nomadmap.io for great places to work while on the road. If you''re motivated to help contribute to a community cause (yes, you), keep reading below!\n\n\n\nIf you''ve never visited Thailand, it''s by far one of the more developed Southeast Asian countries (second only to the city-country of Singapore), and that combined with its incredible natural beauty has made it one of the number one countries for tourists and digital nomads alike.\n\n\nYet despite all the digital nomads you cr', '__GHOST_URL__/content/images/2016/08/nomad-map-header@2x.jpg', 0, 'post', 'draft', 'public', 'all', '2016-08-19 04:57:18', '1', '2016-10-17 10:27:00', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('fc477090c5394831bd80b2b8', '9847ebbe4ba8476baa6c069f5bdfb910', 'Decreasing Customer Support in an Age of Increasing Connectedness', 'decreasing-customer-support-in-an-age-of-increasing-connectedness', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"There''s nothing better than the thought of calling "}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>There''s nothing better than the thought of calling</p>\n<!--kg-card-end: markdown-->', 'There''s nothing better than the thought of calling\n', NULL, 0, 'post', 'draft', 'public', 'all', '2016-08-20 09:48:22', '1', '2016-08-20 11:59:42', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('cb843ed8941642a0a7721af8', '9bb1b5a3f6f44b6e89a182aad8b64dbc', 'Getting a Permit for the John Muir Trail', 'getting-a-permit-for-the-john-muir-trail', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"Traffic on the John Muir Trail is at an all time high following a surge in popularity since the early 2000''s, due mostly to the availability of information about it via the internet and (for better or worse) due to the release of books/movies like Wild that feature it or the PCT.[^n]\\n\\nDespite the increase in popularity, the information about how to apply for permits still remains scattered across a handful of old government agency websites, making the process incredibly confusing to newcomers to the point that I was frequently unsure if I''d even done the right thing. To try and help people along, here''s a consolidated list all the ways you can get a JMT permit and how to apply, organized by park starting from the north at Yosemite to the south at Sequoia/Kings Canyon National Park.\\n\\n### Sections\\n\\n* [Yosemite National Park](#yosemitenationalpark)\\n* [Sierra National Forest](#sierranationalforest)\\n* [Inyo National Forest](#inyonationalforest)\\n* [Sequoia/Kings Canyon National Park](#sequoiakingscanyonnationalpark)\\n\\n## Yosemite National Park\\n\\nOutside of being one of the United States'' most popular National Parks, it also happens to be the traditional starting point of the John Muir Trail. This has the benefit of gradually increasing elevation over the course of the trail (versus starting at _the tallest_ peak in the continental United States), but also means you''ll be fighting for some of the most competitive backcountry permits in the United States.\\n\\n### Permit System Overview\\n\\nIn short, each trailhead in Yosemite (and most other parks) has a pre-defined number of permits issued per day in an effort to keep the backcountry...well, the backcountry. You can _always_ day hike anywhere in the park without a permit (excluding Half Dome), but will need one if you plan to stay overnight outside the Valley or a paid campground.\\n\\n### Backpackers Camps\\n\\nIf you have a backcountry permit you can stay at one of the Backpacker''s Camps in Yosemite Valley or Tuolumne Meadows for free the night before your permit is valid. These are both no-frills camps that have bathrooms and not much else. During the high season they''ll frequently fill up, but if you''re polite and ask around most people are more than happy to share their plot with a fellow backpacker.\\n\\nThere''s also a “Little Yosemite Valley” backpackers camp a few miles into the trail from the Happy Isles trailhead, but this requires your permit to already be valid to stay (and in some cases permits require you to stay there your first night).\\n\\n### The Application\\n\\nThe application for JMT Permits can be [found here](https://www.nps.gov/yose/planyourvisit/jmtfaq.htm). This used to be a PDF form in previous years, but has been updated to a web based system that attempts to walk you through each step. Note that this is a separate application from normal wilderness permits within the park.\\n\\nWhile there are numerous trailheads that will let you hike the parts of the John Muir Trail within Yosemite, the only four that allow you exit the park via Donahue Pass are:\\n\\n* From Yosemite Valley: Happy Isles to Little Yosemite Valley\\n* From Yosemite Valley: Happy Isles to Sunrise/Merced Lake (pass through)\\n* From Tuolumne Meadows: Lyell Canyon\\n* From Glacier Point: Glacier Point to Little Yosemite Valley\\n\\nIf you are adamant about hiking the full “true” trail from start to finish you''ll want a permit starting at “Happy Isles > Little Yosemite Valley”, but as this is the most competitive I encourage considering the alternatives. For the Exit Trailhead just write in “Whitney Portal” (assuming you want to do the whole trail). Be sure to reference the [NPS Wilderness'' PDF of full trailheads](https://www.nps.gov/yose/planyourvisit/upload/fulltrailheads.pdf) to make sure that the entry dates you''re choosing aren''t already listed as full for those trailheads, and that there''s enough available Donahue Pass exit permits left (latter half of the PDF). They tend to update this daily, so check back often until after you actually submit your application.\\n\\nNote that trailheads that list a second location (aka “to Little Yosemite Valley”) require you to camp in that area the first night your permit is valid. Lyell Canyon has become an increasingly popular alternative starting point as it lets you avoid the most over-crowded trail in Yosemite NP and skip the brutal (and hot) 6000'' climb out of the valley and over Cathedral Pass.\\n\\nExit date isn''t strict, so make sure to give yourself some breathing room in case you have any delays, or just feel like taking a few more days to enjoy the wilderness. I''ve never heard of a ranger busting someone for being a day or two past their exit date, so don''t fret too much if you''re running behind once on the trail. Also, they use these to keep track of who they expect to be out in the wilderness (and where) in the event someone goes missing.\\n\\nGiven how competitive permits can be for the high season, I highly recommend you submit your permit in the morning (Pacific time) 168 days in advance, so it''s as close to the top of the list for that day.\\n\\n### Walkup Permits\\n\\nGiven how cheap permits are and how far in advance you need to apply for permits, it''s not surprising that at least a few permit holders are no-shows, freeing up room for a lucky few each day. In order to get one of these, you''ll need to show up early and get in line with the other motivated backpackers before the office opens at 9am.\\n\\nHow early? It really depends on a mix of luck, what time of season you''re going, and how motivated you are to get a permit. If it''s high season (late June through early August) I''d recommend getting there at 6-7am at the latest, and leave yourself cushion days if you fail to get one and need to come back the next day. Assuming you do get one, it''s valid for starting the following day and let''s you stay in the backpacker''s camp that night.\\n\\nThere''s two relevant Wilderness Offices in Yosemite for the JMT - one in the middle of Yosemite Village (near the visitor center) and one in Tuolumne Meadows (east past the general store and post office, on the right side of the road just as you''re leaving the meadows area).\\n\\n### Resources\\n\\n* [Yosemite Wilderness Permit Information [Site]](https://www.nps.gov/yose/planyourvisit/wildpermits.htm)\\n* [Trailheads Map [PDF]](https://www.nps.gov/yose/planyourvisit/upload/wildernesstrailheads.pdf)\\n* [Trailheads Availability [PDF]](https://www.nps.gov/yose/planyourvisit/fulltrailheads.htm)\\n* [NPS JMT FAQ](https://www.nps.gov/yose/planyourvisit/jmtfaq.htm)\\n\\n## Sierra National Forest\\n\\nSierra National Forest is the region just south of Yosemite after crossing Donahue Pass, and encompasses parts of both the Ansel Adams Wilderness and John Muir Wilderness. While National Forest''s are notoriously more lax than National Parks regarding land use and preservation, both of these Wilderness regions have similar restrictions to those of a National Park given their natural beauty and popularity for backpacking[^n].\\n\\n### Permit Application\\n\\nPermits here are much less competitive and bit more old-fashioned than Yosemite. The application form is a relatively straightforward PDF ([available here](http://www.fs.usda.gov/Internet/FSE_DOCUMENTS/fseprd489406.pdf)), that similar to Yosemite requests three alternative plans for entry/exit dates and routes. \\n\\nUnlike Yosemite they also ask for approximate camping locations each night. While I''d encourage you to be as accurate as possible, rangers are pretty understanding that plans don''t always go perfectly in the backcountry. Prices are $5/person _except_ if you''re exiting via Mt Whitney, in which case it''s $15/person.\\n\\nPermit applications can only be submitted by mail to one of two offices (see bottom of application PDF), but actual permits can be picked up at one of four locations depending on where you''re starting your trip.\\n\\n### Resources\\n\\n* [Ansel Adams Wilderness [Website]](http://sierrawild.gov/wilderness/ansel-adams)\\n* [Sierra National Forest Permit Overview [Website]](http://www.fs.usda.gov/detail/sierra/passes-permits/?cid=fsbdev7_018115)\\n* [Sierra National Forest Permit Application [PDF]](http://www.fs.usda.gov/Internet/FSE_DOCUMENTS/fseprd489406.pdf)\\n \\n## Inyo National Forest\\n\\n### Resources\\n* [Inyo National Forest Wilderness Overview [Website]](http://www.fs.usda.gov/main/inyo/passes-permits/recreation#JMT%20PCT)\\n* [Inyo National Forest Permit Pickup Instructions [Website]](http://www.fs.usda.gov/detail/inyo/passes-permits/recreation/?cid=stelprdb5144746)\\n* [Inyo National Forest Trailhead Permit Quotas [PDF]](http://www.fs.usda.gov/Internet/FSE_DOCUMENTS/stelprdb5143453.pdf)\\n* [Inyo National Forest Wilderness Permit Application [Website]](http://www.recreation.gov/wildernessAreaDetails.do?contractCode=NRSO&parkId=72203)\\n* [Inyo National Forest Mt Whitney Wilderness Permit Application [Website]](http://www.recreation.gov/wildernessAreaDetails.do?contractCode=NRSO&parkId=72201)\\n* [Mt Whitney Zone Map [JPG]](https://fs.usda.gov/Internet/FSE_MEDIA/stelprdb5347548.jpg)\\n\\n## Sequoia/Kings Canyon National Park\\n\\n### Permit System\\n\\nSequoia/Kings Canyon operates similar to Yosemite and other National Parks. You can technically enter at any trailhead within the park, but it''s most common to enter from the eastern side of the Sierra Nevadas at the Whitney Portal as this is the other terminus of the JMT. \\n\\nIf you''re not able to get a permit from the Whitney Portal itself you can always look at getting one from Horseshoe Meadows just ~10 miles further south, and come up the backside of Mt Whitney. I''d personally choose this route as the Whitney Portal Trail is one of the worst maintained, most overused, and overall brutal trails in the Sierra Nevadas.\\n\\n### Resources\\n\\n* [Sequoia National Park Wilder Permits Overview [Website] ](https://www.nps.gov/seki/planyourvisit/wilderness_permits.htm)\\n\\n## The Other Stuff\\n\\n### Campfires & Cooking\\n\\nAssuming you plan to cook with a gas stove or build a fire while on the trail, make sure to also get a “campfire” permit before leaving to cover the section of the trail in Inyo National Forest at [http://www.preventwildfireca.org/Campfire-Permit/](http://www.preventwildfireca.org/Campfire-Permit/). The application requires you to watch a cheesy video and answer a few questions, but is free and is valid through the end of the current year. Contrary to the video, please _do not_ shovel a 10'' radius of dirt in the wilderness as this is a blatant violation of Leave No Trace (LNT) principals — use pre-existing fire pits (there''s plenty out there).\\n\\nAlso be sure to check up on the various fire restrictions for each area/park you''ll be traveling through. Each has varying restrictions on what elevation you have to be below to make a campfire (typically in the range of 9000-10000''), and frequently prohibit campfires during the height of summer when there''s high fire danger.\\n\\n### Altitude Sickness\\n\\nAltitude sickness is very real, and quite a few people who''ve never experienced it manage to find themselves with it while on the trail. Keep in mind that the southern sections of the trail go increasingly over higher mountain passes, and the sections between Glen Pass and the top of Whitney only briefly dips below 10,000''. The only fix for altitude sickness is to go to lower elevation, and in this area it''s all but impossible without going back up.\\n\\nIf possible camp at high elevation before you start the trail to acclimate as much as possible, especially if you''re starting at Whitney and going northbound. Onion Valley and Horseshoe Meadows are both great high elevation campgrounds on the Eastern Sierras that you can easily reach by car, allowing you to quickly drive back down to ~ 4,000'' should you start to feel sick.\\n\\n[^n]: Hopefully this might one day help promote more funding for the trail and the parks it passes through, but for the time being that seems to be a pipe dream.\\n[^n]: Probably helps that they''re barely accessible by car, so letting in the logging/mining industries is much less attractive."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>Traffic on the John Muir Trail is at an all time high following a surge in popularity since the early 2000''s, due mostly to the availability of information about it via the internet and (for better or worse) due to the release of books/movies like Wild that feature it or the PCT.<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup></p>\n<p>Despite the increase in popularity, the information about how to apply for permits still remains scattered across a handful of old government agency websites, making the process incredibly confusing to newcomers to the point that I was frequently unsure if I''d even done the right thing. To try and help people along, here''s a consolidated list all the ways you can get a JMT permit and how to apply, organized by park starting from the north at Yosemite to the south at Sequoia/Kings Canyon National Park.</p>\n<h3 id="sections">Sections</h3>\n<ul>\n<li><a href="#yosemitenationalpark">Yosemite National Park</a></li>\n<li><a href="#sierranationalforest">Sierra National Forest</a></li>\n<li><a href="#inyonationalforest">Inyo National Forest</a></li>\n<li><a href="#sequoiakingscanyonnationalpark">Sequoia/Kings Canyon National Park</a></li>\n</ul>\n<h2 id="yosemitenationalpark">Yosemite National Park</h2>\n<p>Outside of being one of the United States'' most popular National Parks, it also happens to be the traditional starting point of the John Muir Trail. This has the benefit of gradually increasing elevation over the course of the trail (versus starting at <em>the tallest</em> peak in the continental United States), but also means you''ll be fighting for some of the most competitive backcountry permits in the United States.</p>\n<h3 id="permitsystemoverview">Permit System Overview</h3>\n<p>In short, each trailhead in Yosemite (and most other parks) has a pre-defined number of permits issued per day in an effort to keep the backcountry...well, the backcountry. You can <em>always</em> day hike anywhere in the park without a permit (excluding Half Dome), but will need one if you plan to stay overnight outside the Valley or a paid campground.</p>\n<h3 id="backpackerscamps">Backpackers Camps</h3>\n<p>If you have a backcountry permit you can stay at one of the Backpacker''s Camps in Yosemite Valley or Tuolumne Meadows for free the night before your permit is valid. These are both no-frills camps that have bathrooms and not much else. During the high season they''ll frequently fill up, but if you''re polite and ask around most people are more than happy to share their plot with a fellow backpacker.</p>\n<p>There''s also a “Little Yosemite Valley” backpackers camp a few miles into the trail from the Happy Isles trailhead, but this requires your permit to already be valid to stay (and in some cases permits require you to stay there your first night).</p>\n<h3 id="theapplication">The Application</h3>\n<p>The application for JMT Permits can be <a href="https://www.nps.gov/yose/planyourvisit/jmtfaq.htm">found here</a>. This used to be a PDF form in previous years, but has been updated to a web based system that attempts to walk you through each step. Note that this is a separate application from normal wilderness permits within the park.</p>\n<p>While there are numerous trailheads that will let you hike the parts of the John Muir Trail within Yosemite, the only four that allow you exit the park via Donahue Pass are:</p>\n<ul>\n<li>From Yosemite Valley: Happy Isles to Little Yosemite Valley</li>\n<li>From Yosemite Valley: Happy Isles to Sunrise/Merced Lake (pass through)</li>\n<li>From Tuolumne Meadows: Lyell Canyon</li>\n<li>From Glacier Point: Glacier Point to Little Yosemite Valley</li>\n</ul>\n<p>If you are adamant about hiking the full “true” trail from start to finish you''ll want a permit starting at “Happy Isles &gt; Little Yosemite Valley”, but as this is the most competitive I encourage considering the alternatives. For the Exit Trailhead just write in “Whitney Portal” (assuming you want to do the whole trail). Be sure to reference the <a href="https://www.nps.gov/yose/planyourvisit/upload/fulltrailheads.pdf">NPS Wilderness'' PDF of full trailheads</a> to make sure that the entry dates you''re choosing aren''t already listed as full for those trailheads, and that there''s enough available Donahue Pass exit permits left (latter half of the PDF). They tend to update this daily, so check back often until after you actually submit your application.</p>\n<p>Note that trailheads that list a second location (aka “to Little Yosemite Valley”) require you to camp in that area the first night your permit is valid. Lyell Canyon has become an increasingly popular alternative starting point as it lets you avoid the most over-crowded trail in Yosemite NP and skip the brutal (and hot) 6000'' climb out of the valley and over Cathedral Pass.</p>\n<p>Exit date isn''t strict, so make sure to give yourself some breathing room in case you have any delays, or just feel like taking a few more days to enjoy the wilderness. I''ve never heard of a ranger busting someone for being a day or two past their exit date, so don''t fret too much if you''re running behind once on the trail. Also, they use these to keep track of who they expect to be out in the wilderness (and where) in the event someone goes missing.</p>\n<p>Given how competitive permits can be for the high season, I highly recommend you submit your permit in the morning (Pacific time) 168 days in advance, so it''s as close to the top of the list for that day.</p>\n<h3 id="walkuppermits">Walkup Permits</h3>\n<p>Given how cheap permits are and how far in advance you need to apply for permits, it''s not surprising that at least a few permit holders are no-shows, freeing up room for a lucky few each day. In order to get one of these, you''ll need to show up early and get in line with the other motivated backpackers before the office opens at 9am.</p>\n<p>How early? It really depends on a mix of luck, what time of season you''re going, and how motivated you are to get a permit. If it''s high season (late June through early August) I''d recommend getting there at 6-7am at the latest, and leave yourself cushion days if you fail to get one and need to come back the next day. Assuming you do get one, it''s valid for starting the following day and let''s you stay in the backpacker''s camp that night.</p>\n<p>There''s two relevant Wilderness Offices in Yosemite for the JMT - one in the middle of Yosemite Village (near the visitor center) and one in Tuolumne Meadows (east past the general store and post office, on the right side of the road just as you''re leaving the meadows area).</p>\n<h3 id="resources">Resources</h3>\n<ul>\n<li><a href="https://www.nps.gov/yose/planyourvisit/wildpermits.htm">Yosemite Wilderness Permit Information [Site]</a></li>\n<li><a href="https://www.nps.gov/yose/planyourvisit/upload/wildernesstrailheads.pdf">Trailheads Map [PDF]</a></li>\n<li><a href="https://www.nps.gov/yose/planyourvisit/fulltrailheads.htm">Trailheads Availability [PDF]</a></li>\n<li><a href="https://www.nps.gov/yose/planyourvisit/jmtfaq.htm">NPS JMT FAQ</a></li>\n</ul>\n<h2 id="sierranationalforest">Sierra National Forest</h2>\n<p>Sierra National Forest is the region just south of Yosemite after crossing Donahue Pass, and encompasses parts of both the Ansel Adams Wilderness and John Muir Wilderness. While National Forest''s are notoriously more lax than National Parks regarding land use and preservation, both of these Wilderness regions have similar restrictions to those of a National Park given their natural beauty and popularity for backpacking<sup class="footnote-ref"><a href="#fn1" id="fnref1:1">[1:1]</a></sup>.</p>\n<h3 id="permitapplication">Permit Application</h3>\n<p>Permits here are much less competitive and bit more old-fashioned than Yosemite. The application form is a relatively straightforward PDF (<a href="http://www.fs.usda.gov/Internet/FSE_DOCUMENTS/fseprd489406.pdf">available here</a>), that similar to Yosemite requests three alternative plans for entry/exit dates and routes.</p>\n<p>Unlike Yosemite they also ask for approximate camping locations each night. While I''d encourage you to be as accurate as possible, rangers are pretty understanding that plans don''t always go perfectly in the backcountry. Prices are $5/person <em>except</em> if you''re exiting via Mt Whitney, in which case it''s $15/person.</p>\n<p>Permit applications can only be submitted by mail to one of two offices (see bottom of application PDF), but actual permits can be picked up at one of four locations depending on where you''re starting your trip.</p>\n<h3 id="resources">Resources</h3>\n<ul>\n<li><a href="http://sierrawild.gov/wilderness/ansel-adams">Ansel Adams Wilderness [Website]</a></li>\n<li><a href="http://www.fs.usda.gov/detail/sierra/passes-permits/?cid=fsbdev7_018115">Sierra National Forest Permit Overview [Website]</a></li>\n<li><a href="http://www.fs.usda.gov/Internet/FSE_DOCUMENTS/fseprd489406.pdf">Sierra National Forest Permit Application [PDF]</a></li>\n</ul>\n<h2 id="inyonationalforest">Inyo National Forest</h2>\n<h3 id="resources">Resources</h3>\n<ul>\n<li><a href="http://www.fs.usda.gov/main/inyo/passes-permits/recreation#JMT%20PCT">Inyo National Forest Wilderness Overview [Website]</a></li>\n<li><a href="http://www.fs.usda.gov/detail/inyo/passes-permits/recreation/?cid=stelprdb5144746">Inyo National Forest Permit Pickup Instructions [Website]</a></li>\n<li><a href="http://www.fs.usda.gov/Internet/FSE_DOCUMENTS/stelprdb5143453.pdf">Inyo National Forest Trailhead Permit Quotas [PDF]</a></li>\n<li><a href="http://www.recreation.gov/wildernessAreaDetails.do?contractCode=NRSO&amp;parkId=72203">Inyo National Forest Wilderness Permit Application [Website]</a></li>\n<li><a href="http://www.recreation.gov/wildernessAreaDetails.do?contractCode=NRSO&amp;parkId=72201">Inyo National Forest Mt Whitney Wilderness Permit Application [Website]</a></li>\n<li><a href="https://fs.usda.gov/Internet/FSE_MEDIA/stelprdb5347548.jpg">Mt Whitney Zone Map [JPG]</a></li>\n</ul>\n<h2 id="sequoiakingscanyonnationalpark">Sequoia/Kings Canyon National Park</h2>\n<h3 id="permitsystem">Permit System</h3>\n<p>Sequoia/Kings Canyon operates similar to Yosemite and other National Parks. You can technically enter at any trailhead within the park, but it''s most common to enter from the eastern side of the Sierra Nevadas at the Whitney Portal as this is the other terminus of the JMT.</p>\n<p>If you''re not able to get a permit from the Whitney Portal itself you can always look at getting one from Horseshoe Meadows just ~10 miles further south, and come up the backside of Mt Whitney. I''d personally choose this route as the Whitney Portal Trail is one of the worst maintained, most overused, and overall brutal trails in the Sierra Nevadas.</p>\n<h3 id="resources">Resources</h3>\n<ul>\n<li><a href="https://www.nps.gov/seki/planyourvisit/wilderness_permits.htm">Sequoia National Park Wilder Permits Overview [Website] </a></li>\n</ul>\n<h2 id="theotherstuff">The Other Stuff</h2>\n<h3 id="campfirescooking">Campfires &amp; Cooking</h3>\n<p>Assuming you plan to cook with a gas stove or build a fire while on the trail, make sure to also get a “campfire” permit before leaving to cover the section of the trail in Inyo National Forest at <a href="http://www.preventwildfireca.org/Campfire-Permit/">http://www.preventwildfireca.org/Campfire-Permit/</a>. The application requires you to watch a cheesy video and answer a few questions, but is free and is valid through the end of the current year. Contrary to the video, please <em>do not</em> shovel a 10'' radius of dirt in the wilderness as this is a blatant violation of Leave No Trace (LNT) principals — use pre-existing fire pits (there''s plenty out there).</p>\n<p>Also be sure to check up on the various fire restrictions for each area/park you''ll be traveling through. Each has varying restrictions on what elevation you have to be below to make a campfire (typically in the range of 9000-10000''), and frequently prohibit campfires during the height of summer when there''s high fire danger.</p>\n<h3 id="altitudesickness">Altitude Sickness</h3>\n<p>Altitude sickness is very real, and quite a few people who''ve never experienced it manage to find themselves with it while on the trail. Keep in mind that the southern sections of the trail go increasingly over higher mountain passes, and the sections between Glen Pass and the top of Whitney only briefly dips below 10,000''. The only fix for altitude sickness is to go to lower elevation, and in this area it''s all but impossible without going back up.</p>\n<p>If possible camp at high elevation before you start the trail to acclimate as much as possible, especially if you''re starting at Whitney and going northbound. Onion Valley and Horseshoe Meadows are both great high elevation campgrounds on the Eastern Sierras that you can easily reach by car, allowing you to quickly drive back down to ~ 4,000'' should you start to feel sick.</p>\n<hr class="footnotes-sep">\n<section class="footnotes">\n<ol class="footnotes-list">\n<li id="fn1" class="footnote-item"><p>Probably helps that they''re barely accessible by car, so letting in the logging/mining industries is much less attractive. <a href="#fnref1" class="footnote-backref">↩︎</a> <a href="#fnref1:1" class="footnote-backref">↩︎</a></p>\n</li>\n</ol>\n</section>\n<!--kg-card-end: markdown-->', 'Traffic on the John Muir Trail is at an all time high following a surge in popularity since the early 2000''s, due mostly to the availability of information about it via the internet and (for better or worse) due to the release of books/movies like Wild that feature it or the PCT.[1]\n\n\nDespite the increase in popularity, the information about how to apply for permits still remains scattered across a handful of old government agency websites, making the process incredibly confusing to newcomers', NULL, 0, 'post', 'draft', 'public', 'all', '2016-08-23 07:12:41', '1', '2020-02-14 16:13:50', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('16f42eae2bf149fc8b956bc6', '41bb7df6c4b04fb8a15d20ea6a08ec4a', 'An Adventure in Blurring a Cross-Origin Image Client Side Using the HTML5 Canvas', 'an-adventure-in-blurring-a-cross-origin-image-client-side-using-the-html5-canvas', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"While working as a frontend developer means I get to experiment with new javascript frameworks on at least a yearly basis, it''s far less frequent that I get to interact with new, native browser technologies, let alone ones that have wide enough support to be used in production. Thankfully Proton Radio, one of my [amazing] long-running clients has provided the exciting opportunity to experiment with the Web Audio API (more on that later) as well as the HTML5 Canvas in order to implement a variety of features that wouldn''t otherwise have been possible.\\n\\n##The Project and the Problem\\n\\n[Proton Radio](http://beta.protonradio.com) is an online radio station that continuously streams ~1-2 hour electronic DJ mixes 24 hours a day, and features a custom banner image for most of those mixes (for those that don''t have their own banner image we have a variety of fallback images so they still look spiffy). As part of our new Beta redesign we really wanted to minimize the noise by putting these unique banners front and center, and started looking at ways we could make the landing page feel unique to the current DJ mix by applying a matching unique full-page background.\\n\\n<figure>\\n![Screenshot of Proton Beta prior to canvas background blur implementation.](/content/images/2016/10/1-1.jpg)\\n<figcaption class=\\"figure__pull\\"><span class=\\"figure__title\\">The Proton Beta prior to our canvas adventure.</span>We knew we wanted to take that image in the middle and apply it to the gray background in an elegant way, but we weren''t quite sure of the best way to make it happen.</figcaption>\\n</figure>\\n\\nUnfortunately, to make things more complicated all the original image assets were created at 578x291 pixel resolution (some dating from the early-2000''s), and stretching them out even on small screens causes them to quickly become extremely pixelated. While we hope to create new banners at higher resolutions in the future, redoing the entire back catalog of thousands of images just wouldn''t be practical. \\n\\n##Considering the Options\\n\\nWe initially discussed extracting the color profile from the image to a CSS gradient to the background, but this seemed like a halfway solution as it wouldn''t have nearly as much depth as the images itself. Instead, we decided to explore the possibility of scaling up and applying a gaussian blur to the image itself as it would both mask any evidence of pixelation and would give the page a great sense of depth between the foreground and background.\\n\\n###Process Images Server-Side\\n\\nThe most obvious solution was to process all the banner images server-side to have a new 1920x1080, pre-blurred copy that we could then apply as a fullscreen CSS `background-image` with `background-size: cover;` to keep it in proportion. From a technical standpoint this would actually be easy to implement as open source image processing libraries are plentiful and simple to use, but on the downside our users would suddenly need to download an additional 150-200kb+ image that exists only to add some blurred, superficial ambiance — something we wanted to avoid if at all possible in our mission to keep page load time down.\\n\\n###CSS3 Filters\\n\\nThe second suggested solution was to use the CSS3 Blur filter, but as I suspected support is still [pretty spotty](http://caniuse.com/#feat=css-filters), and the performance is abysmal enough to make the fans in my 2015 Macbook Pro sound like a jet engine about to take off. There''s also the annoying issue that the blur filter leaves a lighter ring around the image edge due to it assuming the off-canvas area is white/transparent, so you have to do temperamental negative margin hacks inside of a container element with `overflow: hidden;` set to get it looking right.\\n\\nI look forward to the day CSS3 filters are production ready, but I''m guessing we''ve still got at least a few years to go.\\n\\n###Image Processing With Javascript\\n\\nThis left us with our third option of processing the images client-side with javascript — an option I honestly wasn''t all too familiar with despite working in javascript on a daily basis, and assumed wouldn''t be reasonable from a performance standpoint on older devices. \\n\\nLooking into it I quickly figured out that we''d likely need to use a `<canvas>` element, which based on a [few different blog posts should allow me to apply almost any image filter imaginable](https://www.html5rocks.com/en/tutorials/canvas/imagefilters/). Unfortunately, up until this point I never completely grasped the purpose of the `<canvas>` element, so I decided to do some research and try to add some clarity, starting with the [Mozilla Developer Network (MDN)](https://developer.mozilla.org/en-US/docs/Web/API/Canvas_API/Tutorial) Canvas tutorial.\\n\\n> `<canvas>` is an HTML element which can be used to draw graphics using scripting (usually JavaScript). This can, for instance, be used to draw graphs, make photo composition or simple (and not so simple) animations...\\n\\nThis quick description along with the rest of the article helped, but I still had only a vague understanding and too many unanswered questions. Why do we need an element to draw to when we have the DOM? Why can''t we just use SVG? What''s better about the `<canvas>` compared to anything else? It wasn''t until I actually started playing around with the canvas in javascript and used some basic drawing methods that it really clicked.\\n\\nLooking back, I think the `<canvas>` can be better introduced as “a rectangular DOM element that contains a 2-dimensional grid of pixels, onto which you can draw arbitrary lines, shapes, or graphics using x,y or vector coordinates relative to the `<canvas>` element itself, without the performance overhead normally involved with manipulating DOM elements.” \\n\\nOr more simply, it''s kinda like MSPaint for the browser, except you draw with code instead of a paintbrush tool. And it''s fast...real fast.\\n\\n##Getting Knee Deep in Canvas Land\\n\\nWith all that in mind I quickly came across a few image blurring libraries, the most popular of which is an old-school standalone script called [Stackblur.js](http://www.quasimondo.com/StackBlurForCanvas/StackBlurDemo.html). At first glance I was a bit wary as its author''s website hasn''t been updated in years and it lacks an official Github page, but it thankfully turns out there''s several popular forks of it on Github, including a NPM module called [stackblur-canvas](https://github.com/flozz/StackBlur) that adds a few extra features. As a plus, this fork also has just short of 500 stars and the occasional Github issue filed, so I can be a little more confident there''s some community support to push patches should it needed to be updated in the future.\\n\\nWhile setting it up and blurring an image based on the README was surprisingly quick, there were a few gotchas we figured out along the way.\\n\\n###Canvas Elements Are Dumb by Design\\n\\nCanvas elements are by design unaware of anything you draw in them other than the color value of each pixel. This can be frustrating if you need to get intelligent information out of a canvas element, but its what helps make them so performant compared to manipulating full DOM elements. Rather than keeping track of the position of a bunch of vector elements, its just a X/Y grid with a native API to help you draw to it. The downside of this is it also means that the canvas element is unaware of your original image''s aspect ratio, so you have to do those calculations prior to drawing into it and recalculate anytime there''s a window resize event.\\n\\n<script src=\\"https://gist.github.com/robertnealan/aa96e1e7b455aba5f3b4d50ca146f705.js\\"></script>\\n<noscript>\\n<pre>\\n// resizeCanvas()\\n//\\n// Resizes the background canvas element to maintain img proportions\\n// while centering and stretching canvas to fill fullscreen.\\n\\nlet resizeCanvas = function(img_ratio) {\\n  let window_w = window.innerWidth;\\n  let window_h = window.innerHeight;\\n\\n  let window_ratio = window_w / window_h;\\n\\n  if (img_ratio > window_ratio) {\\n    $(''#dataCanvas'').css(''height'', window_h).css(''width'', ''auto'');\\n    let canvas_w = $(''#dataCanvas'').width();\\n    $(''#dataCanvas'').css(''left'', ((canvas_w - window_w)/2) * -1)\\n                    .css(''top'', ''auto'');\\n  } else if (img_ratio < window_ratio) {\\n    $(''#dataCanvas'').css(''height'', ''auto'')\\n                    .css(''width'', window_w);\\n    let canvas_h = $(''#dataCanvas'').height();\\n    $(''#dataCanvas'').css(''left'', ''auto'')\\n                    .css(''top'', ((canvas_h - window_h)/2) * -1);\\n  }\\n};\\n</pre>\\n</noscript>\\n\\n###Canvas Elements Require CORS Headers\\n\\nCanvas elements require proper CORS headers on images to be set prior to drawing, otherwise the canvas becomes “tainted” and you can no longer read information out of it due to the potential security implications. While we aren''t reading out any information for our application in an obvious way, behind the scenes it turns out Stackblur actually applies the image to the canvas, reads out all the pixel data, calculates the new blurred values, and then applies that over the original image. \\n\\nThe good news is that setting CORS headers for a specific directory is actually really simple in most HTTP servers, and for us amounted to adding the three lines of code below to our Apache `httpd.conf` file (in many cases this will/should actually be a separate `.conf` file in the `/etc/apache2/sites-available/` folder specific to the VirtualHost in question). You''ll also likely need to set the `img.crossorigin` attribute to `''''` or `''anonymous''` in order to prevent it from having issues in certain browsers (you can read more about [CORS enabled images on MDN''s article](https://developer.mozilla.org/en-US/docs/Web/HTML/CORS_enabled_image)), though browser support for this attribute seems to be inconsistently implemented at best.\\n\\n<script src=\\"https://gist.github.com/robertnealan/305663f6b5a40bef64a598824cfa65ad.js\\"></script>\\n<noscript>\\n<pre>\\n&lt;Directory \\"/path/to/folder/containing/images\\"&gt;\\n  # If you have specific sub-domains you can list them instead\\n  # of using the ''*'' wildcard.\\n  Header always set Access-Control-Allow-Origin \\"*\\"\\n&lt;/Directory&gt;\\n</pre>\\n</noscript>\\n\\n###Android 4.4 and Below Don''t Support Image CORS Rules\\nAndroid 4.4 and below aren''t a huge part of our user base, but at ~2.5% its still enough traffic to be concerned when there''s a application-breaking bug present. In our case we kept getting a cryptic “Uncaught Error: unable to access image data: Error: unable to access local image data: Error: SECURITY_ERR: DOM Exception 18” reported in [Bugsnag](http://bugsnag.com)[^n] for old Android devices that didn''t seem to be accurately working with sourcemaps and had no clear answer we could find on StackOverflow. As luck would have it though, I temporarily disabled the background blur for the better part of an afternoon and the error suddenly disappeared. With an Android emulator I was able to reproduce the error, which revealed a less-cryptic alert message I was then able to trace back to the uncompiled Stackblur.js library. I thought it might have to do with the outdated `netscape.security.PrivilegeManager` rules (the `stackblur-canvas` package has since removed these), but manually omitting them didn''t seem to make a difference.\\n\\nWhile I couldn''t find any answers via Google, I finally looked deeper into CORS rules and support to see if I was missing something — turns out that Android 4.3 and below specifically don''t support CORS for images in a canvas — exactly what we were trying to do! You''d think this would be a common point of discussion, but with Android <4.3 being on its way out I ended up discovering it in the footnotes of the [CanIUse CORS page](http://caniuse.com/#feat=cors) (only shows up “Show All” is enabled).\\n\\n<figure>\\n![Screenshot of CORS page on caniuse.com](/content/images/2016/10/2.jpg)\\n<figcaption class=\\"figure__pull\\"><span class=\\"figure__title\\">Screenshot of caniuse.com''s CORS Information</span>Always make sure to click “Show All” and double check the footnotes for potentially vital ~~life~~ time-saving information.</figcaption>\\n</figure>\\n\\nIf you''re serving images from the same domain as your client application this of course won''t matter, but in our case changing the infrastructure to serve our flyers off the same domain as our Beta, Staging, and local environments wasn''t worth the extra complexity it''d introduce to our already-complex infrastructure setup.\\n\\nAfter some deliberation we agreed that not having a blurred background image for older Android users was an acceptable level of “graceful degradation”, so I added a simple method to detect Android browser versions and skip over the `backgroundBlur` method for those with problems[^n]. Despite caniuse.com showing that Android 4.4 _should_ support CORS rules on images, we noticed that about half our Android 4.4 users were experiencing problems so we opted to exclude them also.\\n\\n<script src=\\"https://gist.github.com/robertnealan/9d5443d10a2978a411f6200cb63c7976.js\\"></script>\\n<noscript>\\n<pre>\\n// whichAndroid()\\n//\\n// Checks the userAgent to see if it''s an Android device and returns the version\\n// number if true. Returns false on all other browsers/devices.\\n\\nlet whichAndroid = function() {\\n  var userAgent = navigator.userAgent.toLowerCase();\\n  var check = userAgent.match(/android\\\\s([0-9\\\\.]*)/);\\n  return check ? check[1] : false;\\n};\\n</pre>\\n</noscript>\\n\\n##Chaining it All Together\\n\\nAfter a lot of research, some trial and error, and a bit of luck, we pushed our last update to the background blur several weeks back and haven''t seen any related bugs since. One last minute change was to hide the `<canvas>` element with the CSS opacity property until after it finishes blurring, then animate it in using the CSS `transition` property — this really tied it together and made the whole experience feel more elegant than if it flickered in and out until it was properly blurred. \\n\\nThe screenshot below is what it looks like right now, but you can check it out [live at Proton Beta](https://beta.protonradio.com).\\n\\n<figure>\\n![Screenshot of Proton Beta with background blur](/content/images/2016/10/3-1.jpg)\\n<figcaption class=\\"figure__pull\\"><span class=\\"figure__title\\">The Proton Beta with background blur applied.</span>It took a lot of work, but in the end we couldn''t be happier with how great the page looks with the blur effect.</figcaption>\\n</figure>\\n\\n\\nFor readability''s sake here''s a Gist with all the relevant code from my Marionette/Backbone view (excludes the Apache CORS rules). Depending on your choice of framework/tools it''ll likely need to be adapted, but it should be a good starting point for most views written in javascript.\\n\\n<script src=\\"https://gist.github.com/robertnealan/71222474e663777ba98befe6bdb6edce.js\\"></script>\\n<noscript>\\n####blurBackground Method\\n<pre>\\nShow.RadioView = Marionette.LayoutView.extend({\\n  blurBackground: function() {\\n    if(whichAndroid() > 4.4 || whichAndroid() === false) {\\n      const img = new Image();\\n      const canvas = document.getElementById(''dataCanvas'');\\n      const radius = 50;\\n\\n      // Make it work with CORS\\n      img.crossOrigin = '''';\\n      img.src = this.imageURL;\\n\\n      // Wait till image loads\\n      img.onload = (e) => {\\n        // Setup image vars\\n        let img_w = img.naturalWidth;\\n        let img_h = img.naturalHeight;\\n        let img_ratio = img_w / img_h;\\n\\n        let window_w = window.innerWidth;\\n        let window_h = window.innerHeight;\\n\\n        let canvas_h = window_h;\\n        let canvas_w = (window_h/img_h * img_w);\\n\\n        canvas.height = img_h;\\n        canvas.width = img_w;\\n\\n        // I have a global Backbone “resize” event that I listen \\n        // for in Marionette, but you can also listen manually here.\\n        // $(window).on(''resize'', () => resizeCanvas(img_ratio));\\n\\n        StackBlur.image(img, canvas, radius, false);\\n        resizeCanvas(img_ratio)\\n\\n        // Make the canvas visible once processing is done. I use a\\n        // CSS3 transition to have it fade in after the class is added.\\n        $(canvas).addClass(''is-visible'');\\n      }\\n    }\\n  }\\n});\\n\\n\\n// resizeCanvas()\\n//\\n// Resizes the background canvas element to maintain img proportions\\n// while centering and stretching canvas to fill fullscreen.\\n\\nlet resizeCanvas = function(img_ratio) {\\n  let window_w = window.innerWidth;\\n  let window_h = window.innerHeight;\\n\\n  let window_ratio = window_w / window_h;\\n\\n  if (img_ratio > window_ratio) {\\n    $(''#dataCanvas'').css(''height'', window_h).css(''width'', ''auto'');\\n    let canvas_w = $(''#dataCanvas'').width();\\n    $(''#dataCanvas'').css(''left'', ((canvas_w - window_w)/2) * -1)\\n                    .css(''top'', ''auto'');\\n  } else if (img_ratio < window_ratio) {\\n    $(''#dataCanvas'').css(''height'', ''auto'')\\n                    .css(''width'', window_w);\\n    let canvas_h = $(''#dataCanvas'').height();\\n    $(''#dataCanvas'').css(''left'', ''auto'')\\n                    .css(''top'', ((canvas_h - window_h)/2) * -1);\\n  }\\n};\\n\\nlet whichAndroid = function() {\\n  var userAgent = navigator.userAgent.toLowerCase();\\n  var check = userAgent.match(/android\\\\s([0-9\\\\.]*)/);\\n  return check ? check[1] : false;\\n};\\n</pre>\\n</noscript>\\n\\n\\nNotice something amiss or want to chat? Feel free to get in touch with me at <a href=\\"mailto:&#x72;&#x6F;&#x62;&#x40;&#x61;&#x74;&#x6F;&#x6D;&#x69;&#x64;&#x65;&#x73;&#x69;&#x67;&#x6E;&#x2E;&#x63;&#x6F;&#x6D;\\">&#x72;&#x6F;&#x62;&#x40;&#x61;&#x74;&#x6F;&#x6D;&#x69;&#x64;&#x65;&#x73;&#x69;&#x67;&#x6E;&#x2E;&#x63;&#x6F;&#x6D;</a>!\\n\\n[^n]: As an aside, if you''re not using anything to log client side errors I _highly_ recommend [Bugsnag](https://bugsnag.com). At $29/month it''s still a steal of a deal as it easily pays for itself severalfold each month. In my experience its saved my clients **thousands** of dollars in billable time we would''ve otherwise spent tracking down bugs, as well as prevented bugs from floating around that we could never otherwise be aware of without testing every browser on every device.\\n[^n]: I normally wouldn''t condone using User Agent sniffing in production, but in this case there''s no accurate way to detect support for this feature in a “progressive enhancement” manner, and the browser in question is old enough that its highly unlikely that the UserAgent will ever change."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>While working as a frontend developer means I get to experiment with new javascript frameworks on at least a yearly basis, it''s far less frequent that I get to interact with new, native browser technologies, let alone ones that have wide enough support to be used in production. Thankfully Proton Radio, one of my [amazing] long-running clients has provided the exciting opportunity to experiment with the Web Audio API (more on that later) as well as the HTML5 Canvas in order to implement a variety of features that wouldn''t otherwise have been possible.</p>\n<h2 id="theprojectandtheproblem">The Project and the Problem</h2>\n<p><a href="http://beta.protonradio.com">Proton Radio</a> is an online radio station that continuously streams ~1-2 hour electronic DJ mixes 24 hours a day, and features a custom banner image for most of those mixes (for those that don''t have their own banner image we have a variety of fallback images so they still look spiffy). As part of our new Beta redesign we really wanted to minimize the noise by putting these unique banners front and center, and started looking at ways we could make the landing page feel unique to the current DJ mix by applying a matching unique full-page background.</p>\n<figure>\n![Screenshot of Proton Beta prior to canvas background blur implementation.](/content/images/2016/10/1-1.jpg)\n<figcaption class="figure__pull"><span class="figure__title">The Proton Beta prior to our canvas adventure.</span>We knew we wanted to take that image in the middle and apply it to the gray background in an elegant way, but we weren''t quite sure of the best way to make it happen.</figcaption>\n</figure>\n<p>Unfortunately, to make things more complicated all the original image assets were created at 578x291 pixel resolution (some dating from the early-2000''s), and stretching them out even on small screens causes them to quickly become extremely pixelated. While we hope to create new banners at higher resolutions in the future, redoing the entire back catalog of thousands of images just wouldn''t be practical.</p>\n<h2 id="consideringtheoptions">Considering the Options</h2>\n<p>We initially discussed extracting the color profile from the image to a CSS gradient to the background, but this seemed like a halfway solution as it wouldn''t have nearly as much depth as the images itself. Instead, we decided to explore the possibility of scaling up and applying a gaussian blur to the image itself as it would both mask any evidence of pixelation and would give the page a great sense of depth between the foreground and background.</p>\n<h3 id="processimagesserverside">Process Images Server-Side</h3>\n<p>The most obvious solution was to process all the banner images server-side to have a new 1920x1080, pre-blurred copy that we could then apply as a fullscreen CSS <code>background-image</code> with <code>background-size: cover;</code> to keep it in proportion. From a technical standpoint this would actually be easy to implement as open source image processing libraries are plentiful and simple to use, but on the downside our users would suddenly need to download an additional 150-200kb+ image that exists only to add some blurred, superficial ambiance — something we wanted to avoid if at all possible in our mission to keep page load time down.</p>\n<h3 id="css3filters">CSS3 Filters</h3>\n<p>The second suggested solution was to use the CSS3 Blur filter, but as I suspected support is still <a href="http://caniuse.com/#feat=css-filters">pretty spotty</a>, and the performance is abysmal enough to make the fans in my 2015 Macbook Pro sound like a jet engine about to take off. There''s also the annoying issue that the blur filter leaves a lighter ring around the image edge due to it assuming the off-canvas area is white/transparent, so you have to do temperamental negative margin hacks inside of a container element with <code>overflow: hidden;</code> set to get it looking right.</p>\n<p>I look forward to the day CSS3 filters are production ready, but I''m guessing we''ve still got at least a few years to go.</p>\n<h3 id="imageprocessingwithjavascript">Image Processing With Javascript</h3>\n<p>This left us with our third option of processing the images client-side with javascript — an option I honestly wasn''t all too familiar with despite working in javascript on a daily basis, and assumed wouldn''t be reasonable from a performance standpoint on older devices.</p>\n<p>Looking into it I quickly figured out that we''d likely need to use a <code>&lt;canvas&gt;</code> element, which based on a <a href="https://www.html5rocks.com/en/tutorials/canvas/imagefilters/">few different blog posts should allow me to apply almost any image filter imaginable</a>. Unfortunately, up until this point I never completely grasped the purpose of the <code>&lt;canvas&gt;</code> element, so I decided to do some research and try to add some clarity, starting with the <a href="https://developer.mozilla.org/en-US/docs/Web/API/Canvas_API/Tutorial">Mozilla Developer Network (MDN)</a> Canvas tutorial.</p>\n<blockquote>\n<p><code>&lt;canvas&gt;</code> is an HTML element which can be used to draw graphics using scripting (usually JavaScript). This can, for instance, be used to draw graphs, make photo composition or simple (and not so simple) animations...</p>\n</blockquote>\n<p>This quick description along with the rest of the article helped, but I still had only a vague understanding and too many unanswered questions. Why do we need an element to draw to when we have the DOM? Why can''t we just use SVG? What''s better about the <code>&lt;canvas&gt;</code> compared to anything else? It wasn''t until I actually started playing around with the canvas in javascript and used some basic drawing methods that it really clicked.</p>\n<p>Looking back, I think the <code>&lt;canvas&gt;</code> can be better introduced as “a rectangular DOM element that contains a 2-dimensional grid of pixels, onto which you can draw arbitrary lines, shapes, or graphics using x,y or vector coordinates relative to the <code>&lt;canvas&gt;</code> element itself, without the performance overhead normally involved with manipulating DOM elements.”</p>\n<p>Or more simply, it''s kinda like MSPaint for the browser, except you draw with code instead of a paintbrush tool. And it''s fast...real fast.</p>\n<h2 id="gettingkneedeepincanvasland">Getting Knee Deep in Canvas Land</h2>\n<p>With all that in mind I quickly came across a few image blurring libraries, the most popular of which is an old-school standalone script called <a href="http://www.quasimondo.com/StackBlurForCanvas/StackBlurDemo.html">Stackblur.js</a>. At first glance I was a bit wary as its author''s website hasn''t been updated in years and it lacks an official Github page, but it thankfully turns out there''s several popular forks of it on Github, including a NPM module called <a href="https://github.com/flozz/StackBlur">stackblur-canvas</a> that adds a few extra features. As a plus, this fork also has just short of 500 stars and the occasional Github issue filed, so I can be a little more confident there''s some community support to push patches should it needed to be updated in the future.</p>\n<p>While setting it up and blurring an image based on the README was surprisingly quick, there were a few gotchas we figured out along the way.</p>\n<h3 id="canvaselementsaredumbbydesign">Canvas Elements Are Dumb by Design</h3>\n<p>Canvas elements are by design unaware of anything you draw in them other than the color value of each pixel. This can be frustrating if you need to get intelligent information out of a canvas element, but its what helps make them so performant compared to manipulating full DOM elements. Rather than keeping track of the position of a bunch of vector elements, its just a X/Y grid with a native API to help you draw to it. The downside of this is it also means that the canvas element is unaware of your original image''s aspect ratio, so you have to do those calculations prior to drawing into it and recalculate anytime there''s a window resize event.</p>\n<script src="https://gist.github.com/robertnealan/aa96e1e7b455aba5f3b4d50ca146f705.js"></script>\n<noscript>\n<pre>\n// resizeCanvas()\n//\n// Resizes the background canvas element to maintain img proportions\n// while centering and stretching canvas to fill fullscreen.\n<p>let resizeCanvas = function(img_ratio) {<br>\nlet window_w = window.innerWidth;<br>\nlet window_h = window.innerHeight;</p>\n<p>let window_ratio = window_w / window_h;</p>\n<p>if (img_ratio &gt; window_ratio) {<br>\n$(''#dataCanvas'').css(''height'', window_h).css(''width'', ''auto'');<br>\nlet canvas_w = $(''#dataCanvas'').width();<br>\n$(''#dataCanvas'').css(''left'', ((canvas_w - window_w)/2) * -1)<br>\n.css(''top'', ''auto'');<br>\n} else if (img_ratio &lt; window_ratio) {<br>\n$(''#dataCanvas'').css(''height'', ''auto'')<br>\n.css(''width'', window_w);<br>\nlet canvas_h = $(''#dataCanvas'').height();<br>\n$(''#dataCanvas'').css(''left'', ''auto'')<br>\n.css(''top'', ((canvas_h - window_h)/2) * -1);<br>\n}<br>\n};<br>\n</pre><br>\n</noscript></p>\n<h3 id="canvaselementsrequirecorsheaders">Canvas Elements Require CORS Headers</h3>\n<p>Canvas elements require proper CORS headers on images to be set prior to drawing, otherwise the canvas becomes “tainted” and you can no longer read information out of it due to the potential security implications. While we aren''t reading out any information for our application in an obvious way, behind the scenes it turns out Stackblur actually applies the image to the canvas, reads out all the pixel data, calculates the new blurred values, and then applies that over the original image.</p>\n<p>The good news is that setting CORS headers for a specific directory is actually really simple in most HTTP servers, and for us amounted to adding the three lines of code below to our Apache <code>httpd.conf</code> file (in many cases this will/should actually be a separate <code>.conf</code> file in the <code>/etc/apache2/sites-available/</code> folder specific to the VirtualHost in question). You''ll also likely need to set the <code>img.crossorigin</code> attribute to <code>''''</code> or <code>''anonymous''</code> in order to prevent it from having issues in certain browsers (you can read more about <a href="https://developer.mozilla.org/en-US/docs/Web/HTML/CORS_enabled_image">CORS enabled images on MDN''s article</a>), though browser support for this attribute seems to be inconsistently implemented at best.</p>\n<script src="https://gist.github.com/robertnealan/305663f6b5a40bef64a598824cfa65ad.js"></script>\n<noscript>\n<pre>\n&lt;Directory "/path/to/folder/containing/images"&gt;\n  # If you have specific sub-domains you can list them instead\n  # of using the ''*'' wildcard.\n  Header always set Access-Control-Allow-Origin "*"\n&lt;/Directory&gt;\n</pre>\n</noscript>\n<h3 id="android44andbelowdontsupportimagecorsrules">Android 4.4 and Below Don''t Support Image CORS Rules</h3>\n<p>Android 4.4 and below aren''t a huge part of our user base, but at ~2.5% its still enough traffic to be concerned when there''s a application-breaking bug present. In our case we kept getting a cryptic “Uncaught Error: unable to access image data: Error: unable to access local image data: Error: SECURITY_ERR: DOM Exception 18” reported in <a href="http://bugsnag.com">Bugsnag</a><sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup> for old Android devices that didn''t seem to be accurately working with sourcemaps and had no clear answer we could find on StackOverflow. As luck would have it though, I temporarily disabled the background blur for the better part of an afternoon and the error suddenly disappeared. With an Android emulator I was able to reproduce the error, which revealed a less-cryptic alert message I was then able to trace back to the uncompiled Stackblur.js library. I thought it might have to do with the outdated <code>netscape.security.PrivilegeManager</code> rules (the <code>stackblur-canvas</code> package has since removed these), but manually omitting them didn''t seem to make a difference.</p>\n<p>While I couldn''t find any answers via Google, I finally looked deeper into CORS rules and support to see if I was missing something — turns out that Android 4.3 and below specifically don''t support CORS for images in a canvas — exactly what we were trying to do! You''d think this would be a common point of discussion, but with Android &lt;4.3 being on its way out I ended up discovering it in the footnotes of the <a href="http://caniuse.com/#feat=cors">CanIUse CORS page</a> (only shows up “Show All” is enabled).</p>\n<figure>\n![Screenshot of CORS page on caniuse.com](/content/images/2016/10/2.jpg)\n<figcaption class="figure__pull"><span class="figure__title">Screenshot of caniuse.com''s CORS Information</span>Always make sure to click “Show All” and double check the footnotes for potentially vital ~~life~~ time-saving information.</figcaption>\n</figure>\n<p>If you''re serving images from the same domain as your client application this of course won''t matter, but in our case changing the infrastructure to serve our flyers off the same domain as our Beta, Staging, and local environments wasn''t worth the extra complexity it''d introduce to our already-complex infrastructure setup.</p>\n<p>After some deliberation we agreed that not having a blurred background image for older Android users was an acceptable level of “graceful degradation”, so I added a simple method to detect Android browser versions and skip over the <code>backgroundBlur</code> method for those with problems<sup class="footnote-ref"><a href="#fn1" id="fnref1:1">[1:1]</a></sup>. Despite caniuse.com showing that Android 4.4 <em>should</em> support CORS rules on images, we noticed that about half our Android 4.4 users were experiencing problems so we opted to exclude them also.</p>\n<script src="https://gist.github.com/robertnealan/9d5443d10a2978a411f6200cb63c7976.js"></script>\n<noscript>\n<pre>\n// whichAndroid()\n//\n// Checks the userAgent to see if it''s an Android device and returns the version\n// number if true. Returns false on all other browsers/devices.\n<p>let whichAndroid = function() {<br>\nvar userAgent = navigator.userAgent.toLowerCase();<br>\nvar check = userAgent.match(/android\\s([0-9.]*)/);<br>\nreturn check ? check[1] : false;<br>\n};<br>\n</pre><br>\n</noscript></p>\n<h2 id="chainingitalltogether">Chaining it All Together</h2>\n<p>After a lot of research, some trial and error, and a bit of luck, we pushed our last update to the background blur several weeks back and haven''t seen any related bugs since. One last minute change was to hide the <code>&lt;canvas&gt;</code> element with the CSS opacity property until after it finishes blurring, then animate it in using the CSS <code>transition</code> property — this really tied it together and made the whole experience feel more elegant than if it flickered in and out until it was properly blurred.</p>\n<p>The screenshot below is what it looks like right now, but you can check it out <a href="https://beta.protonradio.com">live at Proton Beta</a>.</p>\n<figure>\n![Screenshot of Proton Beta with background blur](/content/images/2016/10/3-1.jpg)\n<figcaption class="figure__pull"><span class="figure__title">The Proton Beta with background blur applied.</span>It took a lot of work, but in the end we couldn''t be happier with how great the page looks with the blur effect.</figcaption>\n</figure>\n<p>For readability''s sake here''s a Gist with all the relevant code from my Marionette/Backbone view (excludes the Apache CORS rules). Depending on your choice of framework/tools it''ll likely need to be adapted, but it should be a good starting point for most views written in javascript.</p>\n<script src="https://gist.github.com/robertnealan/71222474e663777ba98befe6bdb6edce.js"></script>\n<noscript>\n####blurBackground Method\n<pre>\nShow.RadioView = Marionette.LayoutView.extend({\n  blurBackground: function() {\n    if(whichAndroid() > 4.4 || whichAndroid() === false) {\n      const img = new Image();\n      const canvas = document.getElementById(''dataCanvas'');\n      const radius = 50;\n<pre><code>  // Make it work with CORS\n  img.crossOrigin = '''';\n  img.src = this.imageURL;\n\n  // Wait till image loads\n  img.onload = (e) =&gt; {\n    // Setup image vars\n    let img_w = img.naturalWidth;\n    let img_h = img.naturalHeight;\n    let img_ratio = img_w / img_h;\n\n    let window_w = window.innerWidth;\n    let window_h = window.innerHeight;\n\n    let canvas_h = window_h;\n    let canvas_w = (window_h/img_h * img_w);\n\n    canvas.height = img_h;\n    canvas.width = img_w;\n\n    // I have a global Backbone “resize” event that I listen \n    // for in Marionette, but you can also listen manually here.\n    // $(window).on(''resize'', () =&gt; resizeCanvas(img_ratio));\n\n    StackBlur.image(img, canvas, radius, false);\n    resizeCanvas(img_ratio)\n\n    // Make the canvas visible once processing is done. I use a\n    // CSS3 transition to have it fade in after the class is added.\n    $(canvas).addClass(''is-visible'');\n  }\n}\n</code></pre>\n<p>}<br>\n});</p>\n<p>// resizeCanvas()<br>\n//<br>\n// Resizes the background canvas element to maintain img proportions<br>\n// while centering and stretching canvas to fill fullscreen.</p>\n<p>let resizeCanvas = function(img_ratio) {<br>\nlet window_w = window.innerWidth;<br>\nlet window_h = window.innerHeight;</p>\n<p>let window_ratio = window_w / window_h;</p>\n<p>if (img_ratio &gt; window_ratio) {<br>\n$(''#dataCanvas'').css(''height'', window_h).css(''width'', ''auto'');<br>\nlet canvas_w = $(''#dataCanvas'').width();<br>\n$(''#dataCanvas'').css(''left'', ((canvas_w - window_w)/2) * -1)<br>\n.css(''top'', ''auto'');<br>\n} else if (img_ratio &lt; window_ratio) {<br>\n$(''#dataCanvas'').css(''height'', ''auto'')<br>\n.css(''width'', window_w);<br>\nlet canvas_h = $(''#dataCanvas'').height();<br>\n$(''#dataCanvas'').css(''left'', ''auto'')<br>\n.css(''top'', ((canvas_h - window_h)/2) * -1);<br>\n}<br>\n};</p>\n<p>let whichAndroid = function() {<br>\nvar userAgent = navigator.userAgent.toLowerCase();<br>\nvar check = userAgent.match(/android\\s([0-9.]*)/);<br>\nreturn check ? check[1] : false;<br>\n};<br>\n</pre><br>\n</noscript></p>\n<p>Notice something amiss or want to chat? Feel free to get in touch with me at <a href="mailto:&#x72;&#x6F;&#x62;&#x40;&#x61;&#x74;&#x6F;&#x6D;&#x69;&#x64;&#x65;&#x73;&#x69;&#x67;&#x6E;&#x2E;&#x63;&#x6F;&#x6D;">rob@atomidesign.com</a>!</p>\n<hr class="footnotes-sep">\n<section class="footnotes">\n<ol class="footnotes-list">\n<li id="fn1" class="footnote-item"><p>I normally wouldn''t condone using User Agent sniffing in production, but in this case there''s no accurate way to detect support for this feature in a “progressive enhancement” manner, and the browser in question is old enough that its highly unlikely that the UserAgent will ever change. <a href="#fnref1" class="footnote-backref">↩︎</a> <a href="#fnref1:1" class="footnote-backref">↩︎</a></p>\n</li>\n</ol>\n</section>\n<!--kg-card-end: markdown-->', 'While working as a frontend developer means I get to experiment with new javascript frameworks on at least a yearly basis, it''s far less frequent that I get to interact with new, native browser technologies, let alone ones that have wide enough support to be used in production. Thankfully Proton Radio, one of my [amazing] long-running clients has provided the exciting opportunity to experiment with the Web Audio API (more on that later) as well as the HTML5 Canvas in order to implement a variety', '__GHOST_URL__/content/images/2016/10/canvas-misadventures.jpg', 0, 'post', 'published', 'public', 'all', '2016-09-23 04:42:16', '1', '2016-10-21 03:53:07', '1', '2016-10-21 02:45:00', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('81b34d952a3a49e6b8f51645', 'c84dd51da9d348a184e997ca2a0fc040', 'Day 1 of Writing a Webapp: Getting My Hands Dirty with NodeJS, Express, and MongoDB', 'day-1-of-writing-a-webapp-getting-my-hands-dirty-with-nodejs-express-and-mongodb', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"On any given day I probably have at least a dozen new ideas of what to build floating around in my head, but for one reason or another most come and go without much further thought. About a year ago now one of those ideas floated into my head, and ever since it hasn''t left.\\n\\nRather than letting this idea continue to nag at the back of my mind I''ve finally decided to do something about it, and will periodically blog about it along the way to help keep myself accountable and self-reflect along the way.\\n\\n##The Problem, The Solution\\n\\nWithout a doubt the _biggest_ pain year-after-year as a self-employed individual is keeping my finances in order and paying my taxes upfront/on time. Almost every how-to or blog article about getting started on your own business repeatedly screams  at you to stay on top of your finances, yet it seems to repeatedly be one of the most common problems for almost every recently self-employed individual I meet. There''s tons of financial software out there, but it''s almost always targeted at accountants or larger businesses (overkill for a contractor), or is meant for people who are employed full time by the same company. Instead, contractors/freelancers are left hodge-podging all their finance information together using various different software that provide subpar solutions[^1]. Ironically the best piece of software I''ve used for tracking my expenses has been Freshbooks, an amazing SAAS product whose primary purpose is instead for invoicing.\\n\\nEnter Transact — my plan for a simple web and mobile app that helps me keep track of not only my income and expenses, but also details about each expense to create a clear paper trail. Right now I''m just trying to ~~hit my head against a wall~~ build a [mostly] functional webapp that consumes its own API, that can then be reused to connect to from a React Native powered iOS/Android application.\\n\\nThis might be naive, but I figure if I can build an app that I personally find useful and streamlined enough to use on a day-to-day basis, then there''s probably other self-employed people out there who will find value in it.\\n\\n##Stepping Off the Deep End\\n\\nI''m a designer and frontend developer by practice, so delving into backend code is always a little awkward. On the other hand, writing a backend application from scratch feels completely insane.\\n\\nPrior to leaving San Francisco I briefly started working on the same idea with my friend and backend developer extraordinaire Dev, who started hobbling together a proof-of-concept Rails API for our purposes. \\n\\nUnfortunately, I don''t know Rails.\\n\\nOn more than one occasion I''ve tried to teach myself, but without the ability to dedicate a long period of time to learning the syntax, lingo, and other \\"gotchas\\" of the Rails ecosystem it would be an excruciatingly slow, painful march of progress, and at this point I just want to get something rolling.\\n\\nThe good news is I _do_ know javascript, and have spent my fair share of time working within the confines of NodeJS/Express applications in the past (albeit mostly on the frontend). I''m sure there''s a hundred reasons why “Framework A is more suited to this than NodeJS” or how “NodeJS really sucks and is going to cause problems in a year”, but for now I just need to optimize for progress based on what I already know and am at least vaguely familiar with.\\n\\n<figure>\\n![Screenshot of ExpressJS App Source](/content/images/2016/10/1-2.jpg)\\n<figcaption class=\\"figure__pull\\"><span class=\\"figure__title\\">Screenshot of the code-in-progress...</span>So far its been a constant “be confused for 2+ hours, solve one tiny problem” sort of day.</figcaption>\\n</figure>\\n\\n###Progress So Far\\n\\nI''m writing this as a brief break from coding, but as of this afternoon I''ve managed to scrape together a basic ExpressJS + MongoDB application with user authentication using the Node Passport package that has its own API that it self-consumes so adding other clients (iOS/Android) in the future will be a much smoother process. Currently I''m using Babel to enable using ES2015 (ES6) syntax and ESLint to help keep my code quality in check. \\n\\nI''m admittedly a little wary of using MongoDB as heard some of the scaling horror stories, but for now it''s the fastest and easiest way to get things up and moving (famous last words?). So far its running without a hitch, though I''m still a little fuzzy on some of the core concepts, especially around how Mongoose abstracts interacting with Mongo and how you properly reference models from one another using Mongoose''s helpers.\\n\\nFor getting bank transaction data I''m testing out the Plaid API, which as far as I can tell is the only option out there short of writing your own custom bank integrations (no thanks). Thankfully, their documentation and API are in the best of their class and they include libraries for most major backend languages/frameworks.\\n\\n<figure>\\n![Screenshot of Plaid Documentation](/content/images/2016/10/2-1.jpg)\\n<figcaption class=\\"figure__pull\\"><span class=\\"figure__title\\">Think you''ve got good docs?</span>Here''s a snippet of Plaid''s Connect docs, which is the basic endpoint allowing you to pull in both general bank account information as well as detailed transaction data. They''re without a doubt some of the clearest, best docs I''ve ever seen.</figcaption>\\n</figure>\\n\\nOverall I have to say I''m really impressed with how the Node ecosystem has grown since I last looked at it, and how quickly I''ve been able to get a basic server application running. On the downside, it seems to be weirdly difficult to find good, complex Node/Express applications to use as a point of reference compared to other large communities (aka Rails, Backbone, React, etc). Over the next few days I hope to better learn how Mongoose (the Mongo ODM) works, be able to pull real bank data from my own Wells Fargo business accounts, and start calculating a rough estimated amount for how much tax I owe based a simple calculation of income minus expenses.\\n\\n[^1]: I tested out Intuit''s “Quickbooks Self Employed” but received an error when trying to connect my Wells Fargo Business Account. That aside, after connecting my person account it still seemed to be riddled with bugs and didn''t serve the purpose I''m looking to fill. That said, the fact that a company as large as Intuit is working a product targeting self-employed workers only helps prove how large of a market freelancers are becoming, especially with the proliferation of contractor-based companies like Uber."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>On any given day I probably have at least a dozen new ideas of what to build floating around in my head, but for one reason or another most come and go without much further thought. About a year ago now one of those ideas floated into my head, and ever since it hasn''t left.</p>\n<p>Rather than letting this idea continue to nag at the back of my mind I''ve finally decided to do something about it, and will periodically blog about it along the way to help keep myself accountable and self-reflect along the way.</p>\n<h2 id="theproblemthesolution">The Problem, The Solution</h2>\n<p>Without a doubt the <em>biggest</em> pain year-after-year as a self-employed individual is keeping my finances in order and paying my taxes upfront/on time. Almost every how-to or blog article about getting started on your own business repeatedly screams  at you to stay on top of your finances, yet it seems to repeatedly be one of the most common problems for almost every recently self-employed individual I meet. There''s tons of financial software out there, but it''s almost always targeted at accountants or larger businesses (overkill for a contractor), or is meant for people who are employed full time by the same company. Instead, contractors/freelancers are left hodge-podging all their finance information together using various different software that provide subpar solutions<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup>. Ironically the best piece of software I''ve used for tracking my expenses has been Freshbooks, an amazing SAAS product whose primary purpose is instead for invoicing.</p>\n<p>Enter Transact — my plan for a simple web and mobile app that helps me keep track of not only my income and expenses, but also details about each expense to create a clear paper trail. Right now I''m just trying to <s>hit my head against a wall</s> build a [mostly] functional webapp that consumes its own API, that can then be reused to connect to from a React Native powered iOS/Android application.</p>\n<p>This might be naive, but I figure if I can build an app that I personally find useful and streamlined enough to use on a day-to-day basis, then there''s probably other self-employed people out there who will find value in it.</p>\n<h2 id="steppingoffthedeepend">Stepping Off the Deep End</h2>\n<p>I''m a designer and frontend developer by practice, so delving into backend code is always a little awkward. On the other hand, writing a backend application from scratch feels completely insane.</p>\n<p>Prior to leaving San Francisco I briefly started working on the same idea with my friend and backend developer extraordinaire Dev, who started hobbling together a proof-of-concept Rails API for our purposes.</p>\n<p>Unfortunately, I don''t know Rails.</p>\n<p>On more than one occasion I''ve tried to teach myself, but without the ability to dedicate a long period of time to learning the syntax, lingo, and other &quot;gotchas&quot; of the Rails ecosystem it would be an excruciatingly slow, painful march of progress, and at this point I just want to get something rolling.</p>\n<p>The good news is I <em>do</em> know javascript, and have spent my fair share of time working within the confines of NodeJS/Express applications in the past (albeit mostly on the frontend). I''m sure there''s a hundred reasons why “Framework A is more suited to this than NodeJS” or how “NodeJS really sucks and is going to cause problems in a year”, but for now I just need to optimize for progress based on what I already know and am at least vaguely familiar with.</p>\n<figure>\n![Screenshot of ExpressJS App Source](/content/images/2016/10/1-2.jpg)\n<figcaption class="figure__pull"><span class="figure__title">Screenshot of the code-in-progress...</span>So far its been a constant “be confused for 2+ hours, solve one tiny problem” sort of day.</figcaption>\n</figure>\n<h3 id="progresssofar">Progress So Far</h3>\n<p>I''m writing this as a brief break from coding, but as of this afternoon I''ve managed to scrape together a basic ExpressJS + MongoDB application with user authentication using the Node Passport package that has its own API that it self-consumes so adding other clients (iOS/Android) in the future will be a much smoother process. Currently I''m using Babel to enable using ES2015 (ES6) syntax and ESLint to help keep my code quality in check.</p>\n<p>I''m admittedly a little wary of using MongoDB as heard some of the scaling horror stories, but for now it''s the fastest and easiest way to get things up and moving (famous last words?). So far its running without a hitch, though I''m still a little fuzzy on some of the core concepts, especially around how Mongoose abstracts interacting with Mongo and how you properly reference models from one another using Mongoose''s helpers.</p>\n<p>For getting bank transaction data I''m testing out the Plaid API, which as far as I can tell is the only option out there short of writing your own custom bank integrations (no thanks). Thankfully, their documentation and API are in the best of their class and they include libraries for most major backend languages/frameworks.</p>\n<figure>\n![Screenshot of Plaid Documentation](/content/images/2016/10/2-1.jpg)\n<figcaption class="figure__pull"><span class="figure__title">Think you''ve got good docs?</span>Here''s a snippet of Plaid''s Connect docs, which is the basic endpoint allowing you to pull in both general bank account information as well as detailed transaction data. They''re without a doubt some of the clearest, best docs I''ve ever seen.</figcaption>\n</figure>\n<p>Overall I have to say I''m really impressed with how the Node ecosystem has grown since I last looked at it, and how quickly I''ve been able to get a basic server application running. On the downside, it seems to be weirdly difficult to find good, complex Node/Express applications to use as a point of reference compared to other large communities (aka Rails, Backbone, React, etc). Over the next few days I hope to better learn how Mongoose (the Mongo ODM) works, be able to pull real bank data from my own Wells Fargo business accounts, and start calculating a rough estimated amount for how much tax I owe based a simple calculation of income minus expenses.</p>\n<hr class="footnotes-sep">\n<section class="footnotes">\n<ol class="footnotes-list">\n<li id="fn1" class="footnote-item"><p>I tested out Intuit''s “Quickbooks Self Employed” but received an error when trying to connect my Wells Fargo Business Account. That aside, after connecting my person account it still seemed to be riddled with bugs and didn''t serve the purpose I''m looking to fill. That said, the fact that a company as large as Intuit is working a product targeting self-employed workers only helps prove how large of a market freelancers are becoming, especially with the proliferation of contractor-based companies like Uber. <a href="#fnref1" class="footnote-backref">↩︎</a></p>\n</li>\n</ol>\n</section>\n<!--kg-card-end: markdown-->', 'On any given day I probably have at least a dozen new ideas of what to build floating around in my head, but for one reason or another most come and go without much further thought. About a year ago now one of those ideas floated into my head, and ever since it hasn''t left.\n\n\nRather than letting this idea continue to nag at the back of my mind I''ve finally decided to do something about it, and will periodically blog about it along the way to help keep myself accountable and self-reflect along', '__GHOST_URL__/content/images/2016/10/transact-banner.jpg', 0, 'post', 'published', 'public', 'all', '2016-10-17 08:42:54', '1', '2016-10-21 04:02:33', '1', '2016-10-18 03:47:00', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('b3093154b8a348a19c982d2b', '0b4ff257e047437581e1b4ce690b8a1a', 'Why You Shouldn''t Use Meetup.com for Your Next Meetup', 'why-you-shouldnt-use-meetup-com-for-your-next-meetup', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"_Please note that for the purposes of this post that a “meetup” and Meetup.com are two different things. Meetups existed for years before Meetup.com became a platform to help enable them, and will continue to exist in some form long after Meetup.com._\\n\\nDesigners Who Code had been running in San Francisco for just over two years when I proposed to my friend Eric that he should consider opening up a New York chapter. We''d met when he attended my first trainwreck of a \\"Intro to Designing in the Browser\\" event (he ended up doing at least half the teaching), and had been involved in the group in some manner off and on ever since. A few months and Eric setup a shiny new \\"Designers Who Code NYC\\" Meetup group, I linked to it from the [DWC website](http://dwc.io), and we started planning our first event at MongoDB''s office in Midtown Manhattan.\\n\\n##Losing Control of a Group\\n\\nIt wasn''t until a few months and another event later that I got a suspicious looking email from “Eric” via DWC NYC advertising events for a group called NYCSQL, followed by a reply from Eric''s personal email address letting everyone know he hadn''t sent it and was investigating what was going on. From what we''ve been able to piece together the group subscription was up for the twice-yearly renewal fee (it recently changed to a monthly fee), and Eric wasn''t receiving the email notifications letting him know he needed to pay.\\n\\nUnfortunately, rather than reaching out directly or just suspending the group until payment is received, Meetup.com instead puts up a notice on the groups Meetup.com page advertising that it''s is looking for a new Organizer who _conveniently_ will be required to start paying the group fees. This feature appears well-intentioned — if the sole organizer abandons a community then someone else can take over and keep it running (along with Meetup''s revenue source), but it unfortunately also allows for someone to take over for malicious purposes with no oversight or vetting process.\\n\\nIn our instance it looks like someone from a group called NYCSQL paid for the group to get access to the mail list and has since been spamming our members with information about their own events.\\n\\nI''ve already emailed their group''s organizer directly and just reached out to Meetup.com support for the second time, but as far as I can tell they have no process to handle this kind of situation and don''t seem to particularly care as long as they''re getting their $100+/year.\\n\\n##Attempting to Leave Meetup.com\\n\\nMeetup.com had admittedly worked amazingly for getting the group off the ground despite all its quirks, but after two years I''d already been planning to gradually make a break from the platform in the interest of having more control over how and where we advertised our events. With the loss of our NYC chapter having just occurred and no clear resolution on the horizon, I decided to fast track those long-procrastinated plans by downloading the member list and importing it into Mailchimp. I quickly found a link titled “Download member list” on the members page that created an `.xls` format spreadsheet of all users, opened it up in Excel to see how the data was formatted, and found that the user emails _aren''t listed_. \\n\\nThinking that was “peculiar”, I took to the internet to find out how I was supposed to get the emails to the 2,500+ members of my Meetup.com group. After some confused Googling I found the answer on Stackoverflow: you can''t.\\n\\nThere is no provided feature to access members emails regardless of whether you''re the group organizer, a \\"Pro\\" Meetup group, or otherwise. In looking through their API the only email-related attribute response is a true/false boolean that lets you know if emails to that user have been sending successfully or bouncing. I even did some digging through their javascript source to find that they''ve abstracted all user messages and emails using `IDs`, and no response or form ever exposes the user''s real email. \\n\\nSome people have suggested adding a question on event signups that requires the users email, requiring emails at event checkin, and/or reaching out to our email list requesting people to respond with their email, but these are all partial fixes to a problem that shouldn''t exist.\\n\\nRather than attracting and retaining meetup groups by building the best platform possible, Meetup.com has opted to hide member emails behind their \\"Email Members\\" feature and trap groups under the threat of losing a large portion of your userbase. What''s worse is that this also forces you to continue paying Meetup.com $80 every 6 months unless you want to delete the group (and lose all your members), or step down as the organizer and risk someone malicious taking over like with our NYC chapter''s group.\\n\\n##The Bottom Line\\n\\nIt''s for these two reasons alone that I unfortunately can not only no longer recommend, but would _actively discourage_ others from using Meetup.com if at all possible. \\n\\nThe only manner in which I might suggest using it is as an extra source of traffic to a reservation system hosted on your own site or another application, which already seems to be commonplace for many long-running Meetup.com groups. Unfortunately this practice is both confusing to new members who \\"RSVP\\" not realizing they need to RSVP or purchase a ticket on another site[^n] and still supports Meetup.com''s poor practices with monthly subscription fees.\\n\\nWhile I understand that Meetup.com is a business and requires fees to sustain itself[^n], it''s extremely disappointing to see an application that''s meant to enable communities instead trapping them for its own bottom line.\\n\\n[^n]: I unfortunately found this out the hard way when I RSVP''d to one of [CascadeSF''s](http://cascadesf.com/) events not realizing I needed to purchase a ticket via their Eventbrite link. While I would''ve been glad to buy a ticket I found out that the event was already full...after traveling halfway across San Francisco...doh! 😑\\n[^n]: I''ve happily given them somewhere close to $400 out of my own pocket over the past 2 1/2 years.💰💰💰"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p><em>Please note that for the purposes of this post that a “meetup” and Meetup.com are two different things. Meetups existed for years before Meetup.com became a platform to help enable them, and will continue to exist in some form long after Meetup.com.</em></p>\n<p>Designers Who Code had been running in San Francisco for just over two years when I proposed to my friend Eric that he should consider opening up a New York chapter. We''d met when he attended my first trainwreck of a &quot;Intro to Designing in the Browser&quot; event (he ended up doing at least half the teaching), and had been involved in the group in some manner off and on ever since. A few months and Eric setup a shiny new &quot;Designers Who Code NYC&quot; Meetup group, I linked to it from the <a href="http://dwc.io">DWC website</a>, and we started planning our first event at MongoDB''s office in Midtown Manhattan.</p>\n<h2 id="losingcontrolofagroup">Losing Control of a Group</h2>\n<p>It wasn''t until a few months and another event later that I got a suspicious looking email from “Eric” via DWC NYC advertising events for a group called NYCSQL, followed by a reply from Eric''s personal email address letting everyone know he hadn''t sent it and was investigating what was going on. From what we''ve been able to piece together the group subscription was up for the twice-yearly renewal fee (it recently changed to a monthly fee), and Eric wasn''t receiving the email notifications letting him know he needed to pay.</p>\n<p>Unfortunately, rather than reaching out directly or just suspending the group until payment is received, Meetup.com instead puts up a notice on the groups Meetup.com page advertising that it''s is looking for a new Organizer who <em>conveniently</em> will be required to start paying the group fees. This feature appears well-intentioned — if the sole organizer abandons a community then someone else can take over and keep it running (along with Meetup''s revenue source), but it unfortunately also allows for someone to take over for malicious purposes with no oversight or vetting process.</p>\n<p>In our instance it looks like someone from a group called NYCSQL paid for the group to get access to the mail list and has since been spamming our members with information about their own events.</p>\n<p>I''ve already emailed their group''s organizer directly and just reached out to Meetup.com support for the second time, but as far as I can tell they have no process to handle this kind of situation and don''t seem to particularly care as long as they''re getting their $100+/year.</p>\n<h2 id="attemptingtoleavemeetupcom">Attempting to Leave Meetup.com</h2>\n<p>Meetup.com had admittedly worked amazingly for getting the group off the ground despite all its quirks, but after two years I''d already been planning to gradually make a break from the platform in the interest of having more control over how and where we advertised our events. With the loss of our NYC chapter having just occurred and no clear resolution on the horizon, I decided to fast track those long-procrastinated plans by downloading the member list and importing it into Mailchimp. I quickly found a link titled “Download member list” on the members page that created an <code>.xls</code> format spreadsheet of all users, opened it up in Excel to see how the data was formatted, and found that the user emails <em>aren''t listed</em>.</p>\n<p>Thinking that was “peculiar”, I took to the internet to find out how I was supposed to get the emails to the 2,500+ members of my Meetup.com group. After some confused Googling I found the answer on Stackoverflow: you can''t.</p>\n<p>There is no provided feature to access members emails regardless of whether you''re the group organizer, a &quot;Pro&quot; Meetup group, or otherwise. In looking through their API the only email-related attribute response is a true/false boolean that lets you know if emails to that user have been sending successfully or bouncing. I even did some digging through their javascript source to find that they''ve abstracted all user messages and emails using <code>IDs</code>, and no response or form ever exposes the user''s real email.</p>\n<p>Some people have suggested adding a question on event signups that requires the users email, requiring emails at event checkin, and/or reaching out to our email list requesting people to respond with their email, but these are all partial fixes to a problem that shouldn''t exist.</p>\n<p>Rather than attracting and retaining meetup groups by building the best platform possible, Meetup.com has opted to hide member emails behind their &quot;Email Members&quot; feature and trap groups under the threat of losing a large portion of your userbase. What''s worse is that this also forces you to continue paying Meetup.com $80 every 6 months unless you want to delete the group (and lose all your members), or step down as the organizer and risk someone malicious taking over like with our NYC chapter''s group.</p>\n<h2 id="thebottomline">The Bottom Line</h2>\n<p>It''s for these two reasons alone that I unfortunately can not only no longer recommend, but would <em>actively discourage</em> others from using Meetup.com if at all possible.</p>\n<p>The only manner in which I might suggest using it is as an extra source of traffic to a reservation system hosted on your own site or another application, which already seems to be commonplace for many long-running Meetup.com groups. Unfortunately this practice is both confusing to new members who &quot;RSVP&quot; not realizing they need to RSVP or purchase a ticket on another site<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup> and still supports Meetup.com''s poor practices with monthly subscription fees.</p>\n<p>While I understand that Meetup.com is a business and requires fees to sustain itself<sup class="footnote-ref"><a href="#fn1" id="fnref1:1">[1:1]</a></sup>, it''s extremely disappointing to see an application that''s meant to enable communities instead trapping them for its own bottom line.</p>\n<hr class="footnotes-sep">\n<section class="footnotes">\n<ol class="footnotes-list">\n<li id="fn1" class="footnote-item"><p>I''ve happily given them somewhere close to $400 out of my own pocket over the past 2 1/2 years.💰💰💰 <a href="#fnref1" class="footnote-backref">↩︎</a> <a href="#fnref1:1" class="footnote-backref">↩︎</a></p>\n</li>\n</ol>\n</section>\n<!--kg-card-end: markdown-->', 'Please note that for the purposes of this post that a “meetup” and Meetup.com are two different things. Meetups existed for years before Meetup.com became a platform to help enable them, and will continue to exist in some form long after Meetup.com.\n\n\nDesigners Who Code had been running in San Francisco for just over two years when I proposed to my friend Eric that he should consider opening up a New York chapter. We''d met when he attended my first trainwreck of a "Intro to Designing in the B', NULL, 0, 'post', 'draft', 'public', 'all', '2016-12-08 05:49:57', '1', '2016-12-08 08:11:32', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('e7d4d6449c4b49989fd943f1', '02109f4b8bf540cca0bcd13d6b8f96bb', 'Using the Wordpress REST API with React.js', 'using-the-wordpress-rest-api-with-custom-post-types-custom-metadata', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"It''d been a few (happy) years since I last used Wordpress for a client project, but with its now (questionably-)stable REST API it came up last year as a potential candidate for backing a React-based magazine/news site. After doing some digging it became clear that it was not only a possible candidate, but a frontrunner amongst the options as it would provide ~80% of what we needed with minimal work, potentially providing huge time and cost savings to our client.\\n\\nUnfortunately, its cryptic documentation left something to be desired and most articles around the web were either for v1.x, out of date with current v2.x changes, or just plain wrong. So as usual with Wordpress, it was up to us to sort out that other 20% for ourselves.\\n\\n* [Adding Endpoints for Custom Post Types](#addingendpointsforcustomposttypes)\\n* [Adding Custom Metadata to API Responses](#addingcustommetadatatoapiresponses)\\n* [Adding the Featured Thumbnail to Single Post Responses](#addingthefeaturedthumbnailtosinglepostresponses)\\n\\n## Adding Endpoints for Custom Post Types\\n\\nIn our project''s case we are using the default Wordpress “Post” post-type for the bulk of the site''s news and blog articles (sorted into categories), but needed to add [Custom Post Types](https://codex.wordpress.org/Post_Types#Custom_Post_Types) for our other content types like Events &amp; Videos.\\n\\nIf you''re familiar with adding Custom Post Types (CPTs) the snippet below for our “Events” CPT should look familiar (if not I recommend reading up on them first in the [Wordpress Codex](https://codex.wordpress.org/Post_Types#Custom_Post_Types) or on Elegant Themes'' excellent [guide to Custom Post Types](https://www.elegantthemes.com/blog/tips-tricks/creating-custom-post-types-in-wordpress)). There''s a lot going on this, but lines 35-37 are the specific part relevant to making the CPT accessible through the REST API.\\n\\n<script src=\\"https://gist.github.com/robertnealan/87958908001fdbd697c6c283908c0c1f.js\\"></script>\\n\\n**Line 35** tells Wordpress to expose this CPT in the rest API (pretty self explanatory). \\n\\n**Line 36** gives the CPT a URL base within the API. Rather than query `/wp-json/wp/v2/posts/` for a normal Post, this tells Wordpress you want to be able to query this CPT at `/wp-json/wp/v2/events/`. You can change this to be anything you want as long as it doesn''t collide with another CPT or built-in post types (Post, Page, etc), though it generally makes sense to keep it the same as the CPT''s name.\\n\\n**Line 37** tells Wordpress to extend the default WP\\\\_REST\\\\_Posts\\\\_Controller for functionality related to handling API calls. It''s technically possible to heavily extend or customize this, but that''s outside the scope of this article.\\n\\nFor our purposes we''re using these CPT endpoints as read-only GET requests, but they can also be used for your standard POST/PATCH/DELETE requests if you setup an auth layer to verify those requests.\\n\\n## Adding Custom Metadata to API Responses\\n\\nNow that we have a CPT setup we can query the API for a list of events, a single event, and more (all documented reasonably well [here on the REST API Handbook](https://developer.wordpress.org/rest-api/reference/posts/)). Unfortunately, if you''re creating a CPT there''s a good chance the default schema won''t store everything you need and you''ll need to customize the response to add additional fields. There''s two ways of doing this that we explored and found as viable routes:\\n\\n### The Native Wordpress Way\\n\\nTo add additional fields without using a plugin you''ll have to use the register_meta hook in your `functions.php`. This is documented here, but is formatted as `register_meta(post_type, meta_field_name, array($args));`. In our case wanted to add the city our event was taking place in (amongst other things):\\n\\n```\\nregister_meta(''event'', ''city'', array(\\n     ''type''         => ''string'',\\n     ''description''  => ''An string containing the city in which the event is taking place.'',\\n     ''single''       => true,\\n     ''show_in_rest'' => true\\n ));\\n```\\n\\n* `event` is our custom post type from earlier, and `city` is the name of the metadata field we''re adding.\\n* `type` can be either a `string`, `object`, or `integer`.\\n* `description` should be a plain English explanation for what the field is used.\\n* `single` tells Wordpress that this meta field should be used on an individual (or “single”) post.\\n* `show_in_rest` is what actually exposes the field on the API response.\\n\\n### Using Advanced Custom Fields (ACF) for Custom Metadata\\n\\nThe above way of registering custom metadata works well, but unfortunately left us with the issue of needing to either build custom metaboxes or having our client edit the content using the clunky default metaboxes, which wouldn''t work for fields where there might be zero, one, or several repeating items depending on the “Event” — enter using ACF Pro.\\n\\nACF has been a staple of most Wordpress projects I''ve built in the past several years, and is one of maybe two or three plugins I can actively recommend using on a site[^n]. It''s _extremely_ easy to setup and customize, and by default has a much improved editing experience for editors than the default Wordpress metaboxes. Unfortunately integrating it with the Wordpress REST API isn''t officially supported just yet, and there wasn''t a clear answer on the best way to add data input through ACF forms to each API response.\\n\\n## Adding the Featured Thumbnail to Single Post Responses\\n\\nOddly the Wordpress API only exposes the media ID for post‘s featured image rather than embedding it directly. While it would be pretty easy to get the image URL by querying the [media endpoint](https://developer.wordpress.org/rest-api/reference/media/) after receiving the first response it seemed wasteful to make multiple API calls if it could be avoided, and this wouldn''t scale well once we start showing lists of posts where they all have featured images. Enter the `_embed` query param.\\n\\nThis is briefly documented on the [Linking &amp; Embedding](https://developer.wordpress.org/rest-api/using-the-rest-api/linking-and-embedding) page of the API Handbook, but simply requires adding a `?_embed` query param to the end of your request, so a GET request to `/wp-json/wp/v2/events/` becomes `/wp-json/wp/v2/events?_embed`. It''s not entirely clear why the Wordpress team has taken this approach, but it updates the response to include an attribute called `wp:embedded` on the response object, which includes all details about attached featured images.\\n\\nJust be wary if you''re fetching a large number of posts as this can balloon the JSON response size substantially.\\n\\n[^n]: I otherwise avoid plugins at all costs as they tend to trade flexibility for stability, and are rarely written correctly."}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>It''d been a few (happy) years since I last used Wordpress for a client project, but with its now (questionably-)stable REST API it came up last year as a potential candidate for backing a React-based magazine/news site. After doing some digging it became clear that it was not only a possible candidate, but a frontrunner amongst the options as it would provide ~80% of what we needed with minimal work, potentially providing huge time and cost savings to our client.</p>\n<p>Unfortunately, its cryptic documentation left something to be desired and most articles around the web were either for v1.x, out of date with current v2.x changes, or just plain wrong. So as usual with Wordpress, it was up to us to sort out that other 20% for ourselves.</p>\n<ul>\n<li><a href="#addingendpointsforcustomposttypes">Adding Endpoints for Custom Post Types</a></li>\n<li><a href="#addingcustommetadatatoapiresponses">Adding Custom Metadata to API Responses</a></li>\n<li><a href="#addingthefeaturedthumbnailtosinglepostresponses">Adding the Featured Thumbnail to Single Post Responses</a></li>\n</ul>\n<h2 id="addingendpointsforcustomposttypes">Adding Endpoints for Custom Post Types</h2>\n<p>In our project''s case we are using the default Wordpress “Post” post-type for the bulk of the site''s news and blog articles (sorted into categories), but needed to add <a href="https://codex.wordpress.org/Post_Types#Custom_Post_Types">Custom Post Types</a> for our other content types like Events &amp; Videos.</p>\n<p>If you''re familiar with adding Custom Post Types (CPTs) the snippet below for our “Events” CPT should look familiar (if not I recommend reading up on them first in the <a href="https://codex.wordpress.org/Post_Types#Custom_Post_Types">Wordpress Codex</a> or on Elegant Themes'' excellent <a href="https://www.elegantthemes.com/blog/tips-tricks/creating-custom-post-types-in-wordpress">guide to Custom Post Types</a>). There''s a lot going on this, but lines 35-37 are the specific part relevant to making the CPT accessible through the REST API.</p>\n<script src="https://gist.github.com/robertnealan/87958908001fdbd697c6c283908c0c1f.js"></script>\n<p><strong>Line 35</strong> tells Wordpress to expose this CPT in the rest API (pretty self explanatory).</p>\n<p><strong>Line 36</strong> gives the CPT a URL base within the API. Rather than query <code>/wp-json/wp/v2/posts/</code> for a normal Post, this tells Wordpress you want to be able to query this CPT at <code>/wp-json/wp/v2/events/</code>. You can change this to be anything you want as long as it doesn''t collide with another CPT or built-in post types (Post, Page, etc), though it generally makes sense to keep it the same as the CPT''s name.</p>\n<p><strong>Line 37</strong> tells Wordpress to extend the default WP_REST_Posts_Controller for functionality related to handling API calls. It''s technically possible to heavily extend or customize this, but that''s outside the scope of this article.</p>\n<p>For our purposes we''re using these CPT endpoints as read-only GET requests, but they can also be used for your standard POST/PATCH/DELETE requests if you setup an auth layer to verify those requests.</p>\n<h2 id="addingcustommetadatatoapiresponses">Adding Custom Metadata to API Responses</h2>\n<p>Now that we have a CPT setup we can query the API for a list of events, a single event, and more (all documented reasonably well <a href="https://developer.wordpress.org/rest-api/reference/posts/">here on the REST API Handbook</a>). Unfortunately, if you''re creating a CPT there''s a good chance the default schema won''t store everything you need and you''ll need to customize the response to add additional fields. There''s two ways of doing this that we explored and found as viable routes:</p>\n<h3 id="thenativewordpressway">The Native Wordpress Way</h3>\n<p>To add additional fields without using a plugin you''ll have to use the register_meta hook in your <code>functions.php</code>. This is documented here, but is formatted as <code>register_meta(post_type, meta_field_name, array($args));</code>. In our case wanted to add the city our event was taking place in (amongst other things):</p>\n<pre><code>register_meta(''event'', ''city'', array(\n     ''type''         =&gt; ''string'',\n     ''description''  =&gt; ''An string containing the city in which the event is taking place.'',\n     ''single''       =&gt; true,\n     ''show_in_rest'' =&gt; true\n ));\n</code></pre>\n<ul>\n<li><code>event</code> is our custom post type from earlier, and <code>city</code> is the name of the metadata field we''re adding.</li>\n<li><code>type</code> can be either a <code>string</code>, <code>object</code>, or <code>integer</code>.</li>\n<li><code>description</code> should be a plain English explanation for what the field is used.</li>\n<li><code>single</code> tells Wordpress that this meta field should be used on an individual (or “single”) post.</li>\n<li><code>show_in_rest</code> is what actually exposes the field on the API response.</li>\n</ul>\n<h3 id="usingadvancedcustomfieldsacfforcustommetadata">Using Advanced Custom Fields (ACF) for Custom Metadata</h3>\n<p>The above way of registering custom metadata works well, but unfortunately left us with the issue of needing to either build custom metaboxes or having our client edit the content using the clunky default metaboxes, which wouldn''t work for fields where there might be zero, one, or several repeating items depending on the “Event” — enter using ACF Pro.</p>\n<p>ACF has been a staple of most Wordpress projects I''ve built in the past several years, and is one of maybe two or three plugins I can actively recommend using on a site<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup>. It''s <em>extremely</em> easy to setup and customize, and by default has a much improved editing experience for editors than the default Wordpress metaboxes. Unfortunately integrating it with the Wordpress REST API isn''t officially supported just yet, and there wasn''t a clear answer on the best way to add data input through ACF forms to each API response.</p>\n<h2 id="addingthefeaturedthumbnailtosinglepostresponses">Adding the Featured Thumbnail to Single Post Responses</h2>\n<p>Oddly the Wordpress API only exposes the media ID for post‘s featured image rather than embedding it directly. While it would be pretty easy to get the image URL by querying the <a href="https://developer.wordpress.org/rest-api/reference/media/">media endpoint</a> after receiving the first response it seemed wasteful to make multiple API calls if it could be avoided, and this wouldn''t scale well once we start showing lists of posts where they all have featured images. Enter the <code>_embed</code> query param.</p>\n<p>This is briefly documented on the <a href="https://developer.wordpress.org/rest-api/using-the-rest-api/linking-and-embedding">Linking &amp; Embedding</a> page of the API Handbook, but simply requires adding a <code>?_embed</code> query param to the end of your request, so a GET request to <code>/wp-json/wp/v2/events/</code> becomes <code>/wp-json/wp/v2/events?_embed</code>. It''s not entirely clear why the Wordpress team has taken this approach, but it updates the response to include an attribute called <code>wp:embedded</code> on the response object, which includes all details about attached featured images.</p>\n<p>Just be wary if you''re fetching a large number of posts as this can balloon the JSON response size substantially.</p>\n<hr class="footnotes-sep">\n<section class="footnotes">\n<ol class="footnotes-list">\n<li id="fn1" class="footnote-item"><p>I otherwise avoid plugins at all costs as they tend to trade flexibility for stability, and are rarely written correctly. <a href="#fnref1" class="footnote-backref">↩︎</a></p>\n</li>\n</ol>\n</section>\n<!--kg-card-end: markdown-->', 'It''d been a few (happy) years since I last used Wordpress for a client project, but with its now (questionably-)stable REST API it came up last year as a potential candidate for backing a React-based magazine/news site. After doing some digging it became clear that it was not only a possible candidate, but a frontrunner amongst the options as it would provide ~80% of what we needed with minimal work, potentially providing huge time and cost savings to our client.\n\n\nUnfortunately, its cryptic ', '__GHOST_URL__/content/images/2018/11/181102_wordpress-api-with-reactjs.png', 0, 'post', 'published', 'public', 'all', '2017-03-12 22:52:54', '1', '2018-11-03 00:02:49', '1', '2018-11-03 00:02:17', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('8742205c166d4357b4339b2d', '471efbbef0a340689ec9aad1c701d6ec', 'Building a Real Time Waveform with the Web Audio API & SoundManager', 'building-a-real-time-waveform-with-the-html5-audio-api-2', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"A little over a year ago a client''s designer asked if it''d be possible to do a real-time waveform visualization for their Shoutcast radio stream. I knew it was possible back in ye'' olde Flash days, and having heard of the new and shiny HTML5 Audio API I figured it should be even easier now, right? \\n\\nHow wrong I was... 😞\\n\\nIf you''re unfamiliar with the Web Audio API I think [this article](http://blog.mecheye.net/2017/09/i-dont-know-who-the-web-audio-api-is-designed-for/) described it best as: \\n> “...hopelessly huge, with features I can’t imagine anybody using, core abstractions that are hopelessly expensive, and basic functionality basically missing._”\\n\\n## Creating Our First AudioContext\\n\\nA cursory glance at the [MDN documentation](https://developer.mozilla.org/en-US/docs/Web/API/Web_Audio_API) showed I had my work cut out for me, but that building a waveform should be possible. The answer I didn''t have was whether it would be performant enough to utilize in production without making our user''s computers sound like a jet airplane, nor whether it''d work across most major browsers.\\n\\n* With that in mind we hit the ground running and created our first `AudioContext` – this is what we more-or-less pipe our source audio into to be able to access in various ways using the Audio API''s notion of “AudioNodes”, each of which can read or manipulate the source audio in various ways. To see a full list of the available AudioNodes read MDN''s [AudioNode reference page](https://developer.mozilla.org/en-US/docs/Web/API/AudioNode).\\n\\n```\\nconst AudioContext = window.AudioContext || window.webkitAudioContext;\\nif (!AudioContext) throw new Error(''AudioContext not supported'');\\n\\nthis.audioContext = new AudioContext(); // We''ll attach most things to “this” for ease of access across several methods within the React component\\n\\nthis.audioContext.maxChannelCount = 2;\\nthis.canvasContext = this.canvas.getContext(''2d'');\\n\\n// If you''re not using SoundManager you can just reference an in-page HTML5 <Audio> object.\\nthis.audioElement = window.soundManager.sounds[window.soundManager.soundIDs[''0'']]._a;\\nthis.audioElement.crossOrigin = ''anonymous'';\\n\\nthis.audioSource = audioContext.createMediaElementSource(audioElement);\\n```\\n\\nStraight off the bat we check to make sure there isn''t already an existing `AudioContext`, and then create either an `AudioContext` or `webkitAudioContext` off the global `window` object (odd way to access an API but so be it). If for some reason the browser doesn''t support the Web Audio API it will `throw` an error and be done with it.\\n\\nRather than have a CORS-like standard for processing cross-origin audio sources, you instead set `audioContext.crossOrigin = ''anonymous''` on the actual audioContext. This wouldn''t be _so_ bad, except it''s not  actually part of the [Web Audio API spec](https://www.w3.org/TR/webaudio/), nor is it documented anywhere I could find other than obscure StackOverflow comments.\\n\\nLastly we actually set what audio is going to be _inside_ the `AudioContext` using either `createBufferSource()`, `createMediaStreamSource()`, or `createMediaElementSource()`.\\n\\nIn our case we''re using #3, which creates an audio source from an existing in-page `<Audio>` object (in our case this is created in the background by SoundManager) and allows us to access it by attaching avrious \\"AudioNodes\\" from the Web Audio API. In our instance we''re going to attach what''s called an `AnalyserNode`, documented by MDN as:\\n\\n> The AnalyserNode interface represents a node able to provide real-time frequency and time-domain analysis information. It is an AudioNode that passes the audio stream unchanged from the input to the output, but allows you to take the generated data, process it, and create audio visualizations.\\n\\nRather than naming the method to create any given node after itself you instead use “Create” it on the audio context and then connect it to the actual audio source using using the `connect` method (why you can''t just create it on the `audioSource` itself remains a mystery).\\n\\n```\\nthis.analyser = audioContext.createAnalyser();\\nthis.analyser.smoothingTimeConstant = 0.85;\\nthis.analyser.fftSize = 256;\\nthis.audioSource.connect(analyser); // Connect audioSource to analyser\\nthis.audioSource.connect(audioContext.destination); // Connect audioSource back out to the destination — the speakers in this case — so you still actually hear the audio\\n\\nthis.frequencyData = new Uint8Array(this.analyser.frequencyBinCount);\\nthis.resampledData = new Uint8Array(this.state.numberOfBars);\\n```\\n\\n_(See footnotes for information on smoothingTimeConstant[^n] and fftSize[^n].)_\\n\\nAfter creating an analyser we have to connect the audioSource twice — first to the analyser itself, and second to the `audioContext.destination` — in this instance the speakers themselves as you won''t hear audio otherwise.\\n\\n`this.frequencyData` is where we''ll store the raw frequency data coming out of the audio analyser, while `this.resampledData` is where we''ll save the frequency data after resampling it to fit our waveform''s size.\\n\\n```\\nrenderWaveform() {\\n    // For now, don''t animate on Firefox and Safari.\\n    // - Firefox: performance is bad.\\n    // - Safari: this doesn''t work.\\n    if (userAgent.isFirefox || userAgent.isSafari) return;\\n\\n    if (_isEmpty(window.soundManager.sounds)) return;\\n\\n    try {\\n      this.createAudioContext();\\n    } catch (e) {\\n      if (e.message === ''AudioContext not supported'') return;\\n      throw e;\\n    }\\n\\n    this.resizeWaveform();\\n    this.loop();\\n}\\n```\\n\\nDid I mention that Firefox''s performance is too laggy to use pre-Quantum and Safari likes to throw inexplicable errors? Yeah, the Web Audio API is that great.\\n\\n\\n\\n[^n]: “” [MDN AnalyserNode.smoothingTimeConstant\\n](https://developer.mozilla.org/en-US/docs/Web/API/AnalyserNode/smoothingTimeConstant)\\n[^n]: “The fftSize property of the AnalyserNode interface is an unsigned long value and represents the window size in samples that is used when performing a Fast Fourier Transform (FFT) to get frequency domain data.” [MDN AnalyserNode.fftSize](https://developer.mozilla.org/en-US/docs/Web/API/AnalyserNode/fftSize)"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>A little over a year ago a client''s designer asked if it''d be possible to do a real-time waveform visualization for their Shoutcast radio stream. I knew it was possible back in ye'' olde Flash days, and having heard of the new and shiny HTML5 Audio API I figured it should be even easier now, right?</p>\n<p>How wrong I was... 😞</p>\n<p>If you''re unfamiliar with the Web Audio API I think <a href="http://blog.mecheye.net/2017/09/i-dont-know-who-the-web-audio-api-is-designed-for/">this article</a> described it best as:</p>\n<blockquote>\n<p>“...hopelessly huge, with features I can’t imagine anybody using, core abstractions that are hopelessly expensive, and basic functionality basically missing._”</p>\n</blockquote>\n<h2 id="creatingourfirstaudiocontext">Creating Our First AudioContext</h2>\n<p>A cursory glance at the <a href="https://developer.mozilla.org/en-US/docs/Web/API/Web_Audio_API">MDN documentation</a> showed I had my work cut out for me, but that building a waveform should be possible. The answer I didn''t have was whether it would be performant enough to utilize in production without making our user''s computers sound like a jet airplane, nor whether it''d work across most major browsers.</p>\n<ul>\n<li>With that in mind we hit the ground running and created our first <code>AudioContext</code> – this is what we more-or-less pipe our source audio into to be able to access in various ways using the Audio API''s notion of “AudioNodes”, each of which can read or manipulate the source audio in various ways. To see a full list of the available AudioNodes read MDN''s <a href="https://developer.mozilla.org/en-US/docs/Web/API/AudioNode">AudioNode reference page</a>.</li>\n</ul>\n<pre><code>const AudioContext = window.AudioContext || window.webkitAudioContext;\nif (!AudioContext) throw new Error(''AudioContext not supported'');\n\nthis.audioContext = new AudioContext(); // We''ll attach most things to “this” for ease of access across several methods within the React component\n\nthis.audioContext.maxChannelCount = 2;\nthis.canvasContext = this.canvas.getContext(''2d'');\n\n// If you''re not using SoundManager you can just reference an in-page HTML5 &lt;Audio&gt; object.\nthis.audioElement = window.soundManager.sounds[window.soundManager.soundIDs[''0'']]._a;\nthis.audioElement.crossOrigin = ''anonymous'';\n\nthis.audioSource = audioContext.createMediaElementSource(audioElement);\n</code></pre>\n<p>Straight off the bat we check to make sure there isn''t already an existing <code>AudioContext</code>, and then create either an <code>AudioContext</code> or <code>webkitAudioContext</code> off the global <code>window</code> object (odd way to access an API but so be it). If for some reason the browser doesn''t support the Web Audio API it will <code>throw</code> an error and be done with it.</p>\n<p>Rather than have a CORS-like standard for processing cross-origin audio sources, you instead set <code>audioContext.crossOrigin = ''anonymous''</code> on the actual audioContext. This wouldn''t be <em>so</em> bad, except it''s not  actually part of the <a href="https://www.w3.org/TR/webaudio/">Web Audio API spec</a>, nor is it documented anywhere I could find other than obscure StackOverflow comments.</p>\n<p>Lastly we actually set what audio is going to be <em>inside</em> the <code>AudioContext</code> using either <code>createBufferSource()</code>, <code>createMediaStreamSource()</code>, or <code>createMediaElementSource()</code>.</p>\n<p>In our case we''re using #3, which creates an audio source from an existing in-page <code>&lt;Audio&gt;</code> object (in our case this is created in the background by SoundManager) and allows us to access it by attaching avrious &quot;AudioNodes&quot; from the Web Audio API. In our instance we''re going to attach what''s called an <code>AnalyserNode</code>, documented by MDN as:</p>\n<blockquote>\n<p>The AnalyserNode interface represents a node able to provide real-time frequency and time-domain analysis information. It is an AudioNode that passes the audio stream unchanged from the input to the output, but allows you to take the generated data, process it, and create audio visualizations.</p>\n</blockquote>\n<p>Rather than naming the method to create any given node after itself you instead use “Create” it on the audio context and then connect it to the actual audio source using using the <code>connect</code> method (why you can''t just create it on the <code>audioSource</code> itself remains a mystery).</p>\n<pre><code>this.analyser = audioContext.createAnalyser();\nthis.analyser.smoothingTimeConstant = 0.85;\nthis.analyser.fftSize = 256;\nthis.audioSource.connect(analyser); // Connect audioSource to analyser\nthis.audioSource.connect(audioContext.destination); // Connect audioSource back out to the destination — the speakers in this case — so you still actually hear the audio\n\nthis.frequencyData = new Uint8Array(this.analyser.frequencyBinCount);\nthis.resampledData = new Uint8Array(this.state.numberOfBars);\n</code></pre>\n<p><em>(See footnotes for information on smoothingTimeConstant<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup> and fftSize<sup class="footnote-ref"><a href="#fn1" id="fnref1:1">[1:1]</a></sup>.)</em></p>\n<p>After creating an analyser we have to connect the audioSource twice — first to the analyser itself, and second to the <code>audioContext.destination</code> — in this instance the speakers themselves as you won''t hear audio otherwise.</p>\n<p><code>this.frequencyData</code> is where we''ll store the raw frequency data coming out of the audio analyser, while <code>this.resampledData</code> is where we''ll save the frequency data after resampling it to fit our waveform''s size.</p>\n<pre><code>renderWaveform() {\n    // For now, don''t animate on Firefox and Safari.\n    // - Firefox: performance is bad.\n    // - Safari: this doesn''t work.\n    if (userAgent.isFirefox || userAgent.isSafari) return;\n\n    if (_isEmpty(window.soundManager.sounds)) return;\n\n    try {\n      this.createAudioContext();\n    } catch (e) {\n      if (e.message === ''AudioContext not supported'') return;\n      throw e;\n    }\n\n    this.resizeWaveform();\n    this.loop();\n}\n</code></pre>\n<p>Did I mention that Firefox''s performance is too laggy to use pre-Quantum and Safari likes to throw inexplicable errors? Yeah, the Web Audio API is that great.</p>\n<hr class="footnotes-sep">\n<section class="footnotes">\n<ol class="footnotes-list">\n<li id="fn1" class="footnote-item"><p>“The fftSize property of the AnalyserNode interface is an unsigned long value and represents the window size in samples that is used when performing a Fast Fourier Transform (FFT) to get frequency domain data.” <a href="https://developer.mozilla.org/en-US/docs/Web/API/AnalyserNode/fftSize">MDN AnalyserNode.fftSize</a> <a href="#fnref1" class="footnote-backref">↩︎</a> <a href="#fnref1:1" class="footnote-backref">↩︎</a></p>\n</li>\n</ol>\n</section>\n<!--kg-card-end: markdown-->', 'A little over a year ago a client''s designer asked if it''d be possible to do a real-time waveform visualization for their Shoutcast radio stream. I knew it was possible back in ye'' olde Flash days, and having heard of the new and shiny HTML5 Audio API I figured it should be even easier now, right?\n\n\nHow wrong I was... 😞\n\n\nIf you''re unfamiliar with the Web Audio API I think this article described it best as:\n\n\n\n\n\n“...hopelessly huge, with features I can’t imagine anybody using, core a', NULL, 0, 'post', 'draft', 'public', 'all', '2017-09-17 22:14:34', '1', '2018-11-25 01:38:19', '1', NULL, NULL, NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('3dc849958bf14d48bbd3f868', '917dd05838434de18f2625642bf4e367', 'Weekly Roundup #1', 'weekly-roundup-1', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"Credit to my colleague (and new office mate!) Dave Paola for the inspiration of the weekly roundup post format. Also, winter is here!\\n\\n* Senator Ron Wyden introduced [a bill that would impose GDPR-like fines and even stricter prison sentences](https://www.reuters.com/article/us-usa-internet-privacy/prison-time-hefty-fines-for-data-privacy-violations-draft-u-s-senate-bill-idUSKCN1N65U2) for data privacy violations. Don''t see this passing with the current Congress, but inspiring to see some concern for internet privacy at a federal level nonetheless.\\n* Old but great article on the [art of setting bouldering routes](https://www.outsideonline.com/2017711/path-beta-flash-resistance-route-setters) from the 2016 World Championships\\n* California High Speed Rail finally [cleared a lawsuit](https://www.sacbee.com/news/state/california/article220956380.html) alleging the state was improperly using state bond funds. While there''s still plenty of work to be done this was a suit that could''ve halted the project.\\n* Someone launched a [\\"Do Not Disturb\\" feature for Gmail](https://adios.ai/) that allows you to schedule your email deliveries at set times through the day. Super tempting, but can''t say I''m too crazy about giving full permissions to view my email to a third-party. Reminds me of Tim Ferris discussing years ago about his transition to only responding to email once a day, and eventually once a week.\\n* Recently declassified information verified [a solar storm likely detonated dozens of sea mines during the Vietnam War](https://gizmodo.com/a-powerful-solar-storm-likely-detonated-dozens-of-u-s-1830321540). I never actually realized they were set off by magnetic disturbances rather than collisions.\\n* Two men are attempting to [cross Antarctica unsupported for the first time](https://www.nytimes.com/2018/11/11/sports/antarctica-race.html). In reading this I came across the books [Mind Over Matter](https://www.amazon.com/Mind-over-Matter-Ranulph-Fiennes/dp/0099435128) and [Shadows Wasteland](https://www.amazon.com/Shadows-Wasteland-Crossing-Antarctica-Ranulph/dp/0879516364/r) by a former supported crossing duo I''ll need to read, and an incredible article by [the New Yorker from earlier this year](https://www.nytimes.com/2018/11/12/sports/calgary-winter-olympics.html).\\n* Google is pushing ahead a [proposed spec for a browser API](https://developers.google.com/web/updates/2018/11/writable-files) that would allow web applications to write to a computer''s file system in a supposedly secure way. Sounds powerful but a potential massive security issue. \\n* Troy Hunt [writes about 2FA, U2F, and other ways](https://www.troyhunt.com/beyond-passwords-2fa-u2f-and-google-advanced-protection/) to secure our accounts beyond just passwords. "}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p>Credit to my colleague (and new office mate!) Dave Paola for the inspiration of the weekly roundup post format. Also, winter is here!</p>\n<ul>\n<li>Senator Ron Wyden introduced <a href="https://www.reuters.com/article/us-usa-internet-privacy/prison-time-hefty-fines-for-data-privacy-violations-draft-u-s-senate-bill-idUSKCN1N65U2">a bill that would impose GDPR-like fines and even stricter prison sentences</a> for data privacy violations. Don''t see this passing with the current Congress, but inspiring to see some concern for internet privacy at a federal level nonetheless.</li>\n<li>Old but great article on the <a href="https://www.outsideonline.com/2017711/path-beta-flash-resistance-route-setters">art of setting bouldering routes</a> from the 2016 World Championships</li>\n<li>California High Speed Rail finally <a href="https://www.sacbee.com/news/state/california/article220956380.html">cleared a lawsuit</a> alleging the state was improperly using state bond funds. While there''s still plenty of work to be done this was a suit that could''ve halted the project.</li>\n<li>Someone launched a <a href="https://adios.ai/">&quot;Do Not Disturb&quot; feature for Gmail</a> that allows you to schedule your email deliveries at set times through the day. Super tempting, but can''t say I''m too crazy about giving full permissions to view my email to a third-party. Reminds me of Tim Ferris discussing years ago about his transition to only responding to email once a day, and eventually once a week.</li>\n<li>Recently declassified information verified <a href="https://gizmodo.com/a-powerful-solar-storm-likely-detonated-dozens-of-u-s-1830321540">a solar storm likely detonated dozens of sea mines during the Vietnam War</a>. I never actually realized they were set off by magnetic disturbances rather than collisions.</li>\n<li>Two men are attempting to <a href="https://www.nytimes.com/2018/11/11/sports/antarctica-race.html">cross Antarctica unsupported for the first time</a>. In reading this I came across the books <a href="https://www.amazon.com/Mind-over-Matter-Ranulph-Fiennes/dp/0099435128">Mind Over Matter</a> and <a href="https://www.amazon.com/Shadows-Wasteland-Crossing-Antarctica-Ranulph/dp/0879516364/r">Shadows Wasteland</a> by a former supported crossing duo I''ll need to read, and an incredible article by <a href="https://www.nytimes.com/2018/11/12/sports/calgary-winter-olympics.html">the New Yorker from earlier this year</a>.</li>\n<li>Google is pushing ahead a <a href="https://developers.google.com/web/updates/2018/11/writable-files">proposed spec for a browser API</a> that would allow web applications to write to a computer''s file system in a supposedly secure way. Sounds powerful but a potential massive security issue.</li>\n<li>Troy Hunt <a href="https://www.troyhunt.com/beyond-passwords-2fa-u2f-and-google-advanced-protection/">writes about 2FA, U2F, and other ways</a> to secure our accounts beyond just passwords.</li>\n</ul>\n<!--kg-card-end: markdown-->', 'Credit to my colleague (and new office mate!) Dave Paola for the inspiration of the weekly roundup post format. Also, winter is here!\n\n\n * Senator Ron Wyden introduced a bill that would impose GDPR-like fines and even stricter prison sentences for data privacy violations. Don''t see this passing with the current Congress, but inspiring to see some concern for internet privacy at a federal level nonetheless.\n * Old but great article on the art of setting bouldering routes from the 2016 World C', '__GHOST_URL__/content/images/2018/11/IMG_7497.jpg', 0, 'post', 'published', 'public', 'all', '2018-11-04 18:45:39', '1', '2018-11-19 17:54:02', '1', '2018-11-19 17:54:02', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('cf7d72b7b90d4b94bcfeb054', '87ee4a4a06b442f9b4ea498690a27161', 'Weekly Roundup #2', 'weekly-roundup-2', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"_This is actually a 2-3 week roundup as I didn''t come across much to share until this past week._\\n\\n* An amazing tweet thread showing off [retro 1980''s \\"CGI\\"](https://threader.app/thread/1066284025600339968) from movies that was actually done using physical models\\n* The previous reminded me of this great [~10 minute documentary](https://www.youtube.com/watch?v=agS6ZXBrcng) showing how one of the original HBO intro''s was filmed using real life models and cameras.\\n* Software engineer talking about how [fancy tech like progress web apps](http://tonsky.me/blog/pwa/) (PWA) and Google''s AMP aren''t fixing your performance issues.\\n* While Frank Lloyd Wright is considered an American architectural icon, it turns out one of his protegés took on a project [designing a place for a princess in Iran](https://yomadic.com/shams-palace-iran-tour/) in the 1960''s. It''s sadly in disrepair today, but the photos are nonetheless stunning.\\n* Dan Abramov [launched a blog writing](https://overreacted.io/) about some of the lesser understood inner workings of React.\\n* A video (48:26) showcasing the [now defunct Metropolitan Railway in London](https://www.dailymotion.com/video/x5i3sp7). \\n* [Cover.com''s CEO talks about spending $825k on the domain cover.com](https://entrepreneurshandbook.co/you-should-never-spend-825k-on-a-domain-but-heres-why-i-m-glad-i-did-7139f9c00728). The article itself is a bit contradictory, but provides some insight into the dark and complicated world of domain brokers. \\n* [Kristen Wong writes about manually tracking her expenses for a month](https://www.nytimes.com/2018/11/28/smarter-living/budget-money-lessons.html), revealing how much she was really spending on day-to-day expenses. After reading this I''m planning to do the same in my notebook this coming month.[^n]\\n* [Do we need to change the way the Supreme Court works](https://fivethirtyeight.com/features/why-a-fringe-idea-about-the-supreme-court-is-taking-over-the-left/)? I''d argue we should revisit a lot of our assumptions about how our government works (election management, size of the House of Representatives, etc), but I''m wary of making changes to our highest court driven by political motives.\\n* Who would win in a fight, [an anaconda or a komodo dragon](https://fivethirtyeight.com/features/who-would-win-a-fight-between-an-anaconda-and-a-komodo-dragon/)? Having visited Komodo National Park in Indonesia a few years ago I know who my money is on.\\n\\n[^n]: Some people will mention Mint.com, but I''ve always been a strong believer in manually doing tasks like this. Automating it is convenient, but makes you far less aware of what''s actually happening on a day-to-day basis.\\n"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p><em>This is actually a 2-3 week roundup as I didn''t come across much to share until this past week.</em></p>\n<ul>\n<li>An amazing tweet thread showing off <a href="https://threader.app/thread/1066284025600339968">retro 1980''s &quot;CGI&quot;</a> from movies that was actually done using physical models</li>\n<li>The previous reminded me of this great <a href="https://www.youtube.com/watch?v=agS6ZXBrcng">~10 minute documentary</a> showing how one of the original HBO intro''s was filmed using real life models and cameras.</li>\n<li>Software engineer talking about how <a href="http://tonsky.me/blog/pwa/">fancy tech like progress web apps</a> (PWA) and Google''s AMP aren''t fixing your performance issues.</li>\n<li>While Frank Lloyd Wright is considered an American architectural icon, it turns out one of his protegés took on a project <a href="https://yomadic.com/shams-palace-iran-tour/">designing a place for a princess in Iran</a> in the 1960''s. It''s sadly in disrepair today, but the photos are nonetheless stunning.</li>\n<li>Dan Abramov <a href="https://overreacted.io/">launched a blog writing</a> about some of the lesser understood inner workings of React.</li>\n<li>A video (48:26) showcasing the <a href="https://www.dailymotion.com/video/x5i3sp7">now defunct Metropolitan Railway in London</a>.</li>\n<li><a href="https://entrepreneurshandbook.co/you-should-never-spend-825k-on-a-domain-but-heres-why-i-m-glad-i-did-7139f9c00728">Cover.com''s CEO talks about spending $825k on the domain cover.com</a>. The article itself is a bit contradictory, but provides some insight into the dark and complicated world of domain brokers.</li>\n<li><a href="https://www.nytimes.com/2018/11/28/smarter-living/budget-money-lessons.html">Kristen Wong writes about manually tracking her expenses for a month</a>, revealing how much she was really spending on day-to-day expenses. After reading this I''m planning to do the same in my notebook this coming month.<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup></li>\n<li><a href="https://fivethirtyeight.com/features/why-a-fringe-idea-about-the-supreme-court-is-taking-over-the-left/">Do we need to change the way the Supreme Court works</a>? I''d argue we should revisit a lot of our assumptions about how our government works (election management, size of the House of Representatives, etc), but I''m wary of making changes to our highest court driven by political motives.</li>\n<li>Who would win in a fight, <a href="https://fivethirtyeight.com/features/who-would-win-a-fight-between-an-anaconda-and-a-komodo-dragon/">an anaconda or a komodo dragon</a>? Having visited Komodo National Park in Indonesia a few years ago I know who my money is on.</li>\n</ul>\n<hr class="footnotes-sep">\n<section class="footnotes">\n<ol class="footnotes-list">\n<li id="fn1" class="footnote-item"><p>Some people will mention Mint.com, but I''ve always been a strong believer in manually doing tasks like this. Automating it is convenient, but makes you far less aware of what''s actually happening on a day-to-day basis. <a href="#fnref1" class="footnote-backref">↩︎</a></p>\n</li>\n</ol>\n</section>\n<!--kg-card-end: markdown-->', 'This is actually a 2-3 week roundup as I didn''t come across much to share until this past week.\n\n\n * An amazing tweet thread showing off retro 1980''s "CGI" from movies that was actually done using physical models\n * The previous reminded me of this great ~10 minute documentary showing how one of the original HBO intro''s was filmed using real life models and cameras.\n * Software engineer talking about how fancy tech like progress web apps (PWA) and Google''s AMP aren''t fixing your performance', '__GHOST_URL__/content/images/2018/12/IMG_7622.jpg', 0, 'post', 'published', 'public', 'all', '2018-11-25 01:30:37', '1', '2018-12-07 18:49:24', '1', '2018-12-07 18:49:24', '1', NULL);
INSERT INTO posts (id, uuid, title, slug, mobiledoc, html, plaintext, feature_image, featured, type, status, visibility, email_recipient_filter, created_at, created_by, updated_at, updated_by, published_at, published_by, custom_excerpt) VALUES ('2fffcee2afbf40a4b8bab7af', '7a7a0c345f744999ada3c7d9f25dd948', 'Link Roundup #3', 'weekly-roundup-3', '{"version":"0.3.1","markups":[],"atoms":[],"cards":[["markdown",{"cardName":"card-markdown","markdown":"https://tympanus.net/codrops/2019/12/20/how-to-create-the-apple-fifth-avenue-cube-in-webgl/\\nhttps://overreacted.io/on-let-vs-const/\\nhttps://www.theatlantic.com/technology/archive/2015/11/why-dont-we-know-where-all-the-trains-are/415152/\\nhttps://www.perceptivetravel.com/issues/1218/kelly.html\\nhttps://www.atlasobscura.com/articles/exploring-myst-25-years-later\\nhttps://developer.apple.com/design/human-interface-guidelines/macos/overview/visual-index/"}]],"sections":[[10,0]],"ghostVersion":"3.0"}', '<!--kg-card-begin: markdown--><p><a href="https://tympanus.net/codrops/2019/12/20/how-to-create-the-apple-fifth-avenue-cube-in-webgl/">https://tympanus.net/codrops/2019/12/20/how-to-create-the-apple-fifth-avenue-cube-in-webgl/</a><br>\n<a href="https://overreacted.io/on-let-vs-const/">https://overreacted.io/on-let-vs-const/</a><br>\n<a href="https://www.theatlantic.com/technology/archive/2015/11/why-dont-we-know-where-all-the-trains-are/415152/">https://www.theatlantic.com/technology/archive/2015/11/why-dont-we-know-where-all-the-trains-are/415152/</a><br>\n<a href="https://www.perceptivetravel.com/issues/1218/kelly.html">https://www.perceptivetravel.com/issues/1218/kelly.html</a><br>\n<a href="https://www.atlasobscura.com/articles/exploring-myst-25-years-later">https://www.atlasobscura.com/articles/exploring-myst-25-years-later</a><br>\n<a href="https://developer.apple.com/design/human-interface-guidelines/macos/overview/visual-index/">https://developer.apple.com/design/human-interface-guidelines/macos/overview/visual-index/</a></p>\n<!--kg-card-end: markdown-->', 'https://tympanus.net/codrops/2019/12/20/how-to-create-the-apple-fifth-avenue-cube-in-webgl/\n\nhttps://overreacted.io/on-let-vs-const/\n\nhttps://www.theatlantic.com/technology/archive/2015/11/why-dont-we-know-where-all-the-trains-are/415152/\n\nhttps://www.perceptivetravel.com/issues/1218/kelly.html\n\nhttps://www.atlasobscura.com/articles/exploring-myst-25-years-later\n\nhttps://developer.apple.com/design/human-interface-guidelines/macos/overview/visual-index/\n', NULL, 0, 'post', 'draft', 'public', 'all', '2018-12-10 16:01:49', '1', '2019-12-24 00:18:51', '1', NULL, NULL, NULL);

